/* guard-data.js — Security Guard (Unarmed) license practice. 6 topics, all 6 languages.
   window.GUARD = { cats:[{id,name,blurb}], q:[{cat,a,q,o,e}] }
   120 questions: legal(20), patrol(20), emergency(20), reports(20), access(20), conduct(20) */
window.GUARD = {"cats":[{"id":"legal","name":{"en":"Legal Powers & Limits","es":"Facultades y límites legales","ru":"Правовые полномочия и ограничения","tr":"Yasal Yetkiler ve Sınırlar","hi":"कानूनी शक्तियाँ और सीमाएँ","ar":"الصلاحيات والحدود القانونية"},"blurb":{"en":"Citizen's arrest, detention vs. arrest, reasonable force, search limits, trespass, and liability.","es":"Arresto ciudadano, detención vs. arresto, fuerza razonable, límites de registro, allanamiento y responsabilidad.","ru":"Гражданский арест, задержание против ареста, разумная сила, пределы обыска, незаконное проникновение и ответственность.","tr":"Vatandaş tutuklaması, gözaltı ile tutuklama, makul güç, arama sınırları, izinsiz giriş ve sorumluluk.","hi":"नागरिक गिरफ्तारी, हिरासत बनाम गिरफ्तारी, उचित बल, तलाशी की सीमाएँ, अतिक्रमण और दायित्व।","ar":"الاعتقال المدني، الاحتجاز مقابل الاعتقال، القوة المعقولة، حدود التفتيش، التعدي، والمسؤولية."}},{"id":"patrol","name":{"en":"Patrol & Observation","es":"Patrullaje y observación","ru":"Патрулирование и наблюдение","tr":"Devriye ve Gözlem","hi":"गश्त और अवलोकन","ar":"الدورية والملاحظة"},"blurb":{"en":"Patrol patterns, observation and memory, suspicious behavior, key control, and alarm response.","es":"Patrones de patrullaje, observación y memoria, conducta sospechosa, control de llaves y respuesta a alarmas.","ru":"Схемы патрулирования, наблюдение и память, подозрительное поведение, контроль ключей и реагирование на тревогу.","tr":"Devriye desenleri, gözlem ve hafıza, şüpheli davranış, anahtar kontrolü ve alarm müdahalesi.","hi":"गश्त के तरीके, अवलोकन और स्मृति, संदिग्ध व्यवहार, चाबी नियंत्रण और अलार्म प्रतिक्रिया।","ar":"أنماط الدورية، الملاحظة والذاكرة، السلوك المشبوه، التحكم بالمفاتيح، والاستجابة للإنذار."}},{"id":"emergency","name":{"en":"Emergency Response","es":"Respuesta a emergencias","ru":"Реагирование на чрезвычайные ситуации","tr":"Acil Durum Müdahalesi","hi":"आपातकालीन प्रतिक्रिया","ar":"الاستجابة للطوارئ"},"blurb":{"en":"Fire classes and extinguishers, evacuation, medical basics, bomb threats, and active-threat response.","es":"Clases de fuego y extintores, evacuación, primeros auxilios, amenazas de bomba y amenazas activas.","ru":"Классы пожаров и огнетушители, эвакуация, основы первой помощи, угрозы взрыва и реагирование на активную угрозу.","tr":"Yangın sınıfları ve söndürücüler, tahliye, temel tıbbi bilgi, bomba tehditleri ve aktif tehdit müdahalesi.","hi":"आग की श्रेणियाँ और अग्निशामक, निकासी, चिकित्सा मूल बातें, बम धमकियाँ और सक्रिय खतरा प्रतिक्रिया।","ar":"فئات الحرائق وطفايات الحريق، الإخلاء، الإسعافات الأولية، تهديدات القنابل، والاستجابة للتهديد النشط."}},{"id":"reports","name":{"en":"Report Writing & Communication","es":"Redacción de informes y comunicación","ru":"Составление отчётов и связь","tr":"Rapor Yazımı ve İletişim","hi":"रिपोर्ट लेखन और संचार","ar":"كتابة التقارير والتواصل"},"blurb":{"en":"Field notes, incident report elements, chain of custody, radio codes, and testifying.","es":"Notas de campo, elementos del informe de incidentes, cadena de custodia, códigos de radio y testificar.","ru":"Полевые заметки, элементы отчёта об инциденте, цепочка хранения, радиокоды и дача показаний.","tr":"Saha notları, olay raporu unsurları, delil zinciri, telsiz kodları ve tanıklık.","hi":"क्षेत्र नोट्स, घटना रिपोर्ट तत्व, अभिरक्षा श्रृंखला, रेडियो कोड और गवाही देना।","ar":"الملاحظات الميدانية، عناصر تقرير الحادث، سلسلة الحيازة، رموز الراديو، والإدلاء بالشهادة."}},{"id":"access","name":{"en":"Access Control","es":"Control de acceso","ru":"Контроль доступа","tr":"Erişim Kontrolü","hi":"पहुँच नियंत्रण","ar":"التحكم في الدخول"},"blurb":{"en":"ID verification, visitor management, screening, gate and lobby posts, tailgating, and CCTV ethics.","es":"Verificación de identidad, gestión de visitantes, inspección, portería y vestíbulo, colarse y ética de CCTV.","ru":"Проверка удостоверений, управление посетителями, досмотр, посты у ворот и в холле, проход «на хвосте» и этика видеонаблюдения.","tr":"Kimlik doğrulama, ziyaretçi yönetimi, tarama, kapı ve lobi görevleri, takip girişi ve CCTV etiği.","hi":"पहचान सत्यापन, आगंतुक प्रबंधन, जाँच, गेट और लॉबी चौकियाँ, टेलगेटिंग और सीसीटीवी नैतिकता।","ar":"التحقق من الهوية، إدارة الزوار، الفحص، مراكز البوابة والردهة، الدخول التابع، وأخلاقيات كاميرات المراقبة."}},{"id":"conduct","name":{"en":"Professional Conduct & Ethics","es":"Conducta profesional y ética","ru":"Профессиональное поведение и этика","tr":"Mesleki Davranış ve Etik","hi":"पेशेवर आचरण और नैतिकता","ar":"السلوك المهني والأخلاقيات"},"blurb":{"en":"Uniform and demeanor, confidentiality, conflicts of interest, de-escalation, and when to call police.","es":"Uniforme y actitud, confidencialidad, conflictos de interés, desescalada y cuándo llamar a la policía.","ru":"Форма и поведение, конфиденциальность, конфликт интересов, деэскалация и когда вызывать полицию.","tr":"Üniforma ve tavır, gizlilik, çıkar çatışması, gerginliği azaltma ve ne zaman polis çağrılır.","hi":"वर्दी और आचरण, गोपनीयता, हितों का टकराव, तनाव कम करना और पुलिस को कब बुलाएँ।","ar":"الزي والسلوك، السرية، تضارب المصالح، تهدئة التصعيد، ومتى تُستدعى الشرطة."}}],"q":[{"cat":"legal","a":0,"q":{"en":"What is the legal status of an unarmed security guard when it comes to arrest powers?","es":"¿Cuál es el estatus legal de un guardia de seguridad desarmado en cuanto a las facultades de arresto?","ru":"Каков правовой статус невооружённого охранника в отношении полномочий на арест?","tr":"Silahsız bir güvenlik görevlisinin tutuklama yetkileri konusundaki yasal statüsü nedir?","hi":"गिरफ्तारी की शक्तियों के संबंध में एक निहत्थे सुरक्षा गार्ड की कानूनी स्थिति क्या है?","ar":"ما هو الوضع القانوني لحارس الأمن غير المسلح فيما يتعلق بصلاحيات الاعتقال؟"},"o":[{"en":"A private citizen with no more arrest authority than any other private person","es":"Un ciudadano privado sin más autoridad de arresto que cualquier otra persona privada","ru":"Частное лицо, не обладающее большими полномочиями на арест, чем любой другой частный человек","tr":"Herhangi bir özel kişiden fazla tutuklama yetkisi olmayan özel bir vatandaş","hi":"एक निजी नागरिक जिसके पास किसी अन्य निजी व्यक्ति से अधिक गिरफ्तारी का अधिकार नहीं है","ar":"مواطن عادي لا يملك سلطة اعتقال أكثر من أي شخص عادي آخر"},{"en":"A sworn peace officer with full police arrest powers","es":"Un agente del orden juramentado con plenas facultades de arresto policial","ru":"Присягнувший офицер правопорядка с полными полицейскими полномочиями на арест","tr":"Tam polis tutuklama yetkisine sahip yeminli bir kolluk görevlisi","hi":"पूर्ण पुलिस गिरफ्तारी शक्तियों वाला एक शपथबद्ध शांति अधिकारी","ar":"ضابط أمن محلَّف يتمتع بكامل صلاحيات الاعتقال الشرطية"},{"en":"A federal agent authorized to arrest anywhere in the country","es":"Un agente federal autorizado para arrestar en cualquier parte del país","ru":"Федеральный агент, уполномоченный арестовывать в любой точке страны","tr":"Ülkenin her yerinde tutuklama yapmaya yetkili bir federal ajan","hi":"देश में कहीं भी गिरफ्तारी के लिए अधिकृत एक संघीय एजेंट","ar":"عميل فيدرالي مخوَّل بالاعتقال في أي مكان في البلاد"},{"en":"A court officer who can issue arrest warrants","es":"Un funcionario judicial que puede emitir órdenes de arresto","ru":"Судебный служащий, который может выдавать ордера на арест","tr":"Tutuklama emri çıkarabilen bir mahkeme görevlisi","hi":"एक न्यायालय अधिकारी जो गिरफ्तारी वारंट जारी कर सकता है","ar":"موظف قضائي يمكنه إصدار مذكرات اعتقال"}],"e":{"en":"An unarmed security guard is a private citizen, not a police officer, and has only the same limited arrest authority as any private person.","es":"Un guardia de seguridad desarmado es un ciudadano privado, no un policía, y solo tiene la misma autoridad de arresto limitada que cualquier persona privada.","ru":"Невооружённый охранник — это частное лицо, а не полицейский, и обладает лишь такими же ограниченными полномочиями на арест, как любой частный человек.","tr":"Silahsız bir güvenlik görevlisi bir polis değil, özel bir vatandaştır ve yalnızca herhangi bir özel kişiyle aynı sınırlı tutuklama yetkisine sahiptir.","hi":"एक निहत्था सुरक्षा गार्ड एक निजी नागरिक है, पुलिस अधिकारी नहीं, और उसके पास किसी भी निजी व्यक्ति के समान ही सीमित गिरफ्तारी अधिकार होता है।","ar":"حارس الأمن غير المسلح مواطن عادي وليس ضابط شرطة، ولا يملك سوى سلطة الاعتقال المحدودة نفسها التي يملكها أي شخص عادي."}},{"cat":"legal","a":1,"q":{"en":"After a security guard makes a lawful citizen's arrest, what must they do next?","es":"Después de que un guardia de seguridad realiza un arresto ciudadano legal, ¿qué debe hacer a continuación?","ru":"После того как охранник произвёл законный гражданский арест, что он должен сделать далее?","tr":"Bir güvenlik görevlisi yasal bir vatandaşlık tutuklaması yaptıktan sonra bir sonraki adımda ne yapmalıdır?","hi":"एक सुरक्षा गार्ड द्वारा वैध नागरिक गिरफ्तारी करने के बाद, उसे आगे क्या करना चाहिए?","ar":"بعد أن يقوم حارس الأمن باعتقال مدني قانوني، ماذا يجب أن يفعل بعد ذلك؟"},"o":[{"en":"Interrogate the suspect to obtain a confession","es":"Interrogar al sospechoso para obtener una confesión","ru":"Допросить подозреваемого, чтобы получить признание","tr":"İtiraf almak için şüpheliyi sorgulamak","hi":"स्वीकारोक्ति प्राप्त करने के लिए संदिग्ध से पूछताछ करना","ar":"استجواب المشتبه به للحصول على اعتراف"},{"en":"Turn the person over to the police without unreasonable delay","es":"Entregar a la persona a la policía sin demora irrazonable","ru":"Передать человека полиции без необоснованной задержки","tr":"Kişiyi makul olmayan bir gecikme olmadan polise teslim etmek","hi":"व्यक्ति को बिना किसी अनुचित देरी के पुलिस को सौंप देना","ar":"تسليم الشخص إلى الشرطة دون تأخير غير مبرر"},{"en":"Decide on an appropriate punishment for the suspect","es":"Decidir un castigo apropiado para el sospechoso","ru":"Определить подходящее наказание для подозреваемого","tr":"Şüpheli için uygun bir ceza belirlemek","hi":"संदिग्ध के लिए उचित सजा तय करना","ar":"تحديد عقوبة مناسبة للمشتبه به"},{"en":"Release the person immediately after taking their photo","es":"Liberar a la persona inmediatamente después de tomarle una foto","ru":"Отпустить человека сразу после того, как сфотографировал его","tr":"Fotoğrafını çektikten sonra kişiyi hemen serbest bırakmak","hi":"व्यक्ति की तस्वीर लेने के तुरंत बाद उसे छोड़ देना","ar":"إطلاق سراح الشخص فوراً بعد التقاط صورته"}],"e":{"en":"A private person who makes a citizen's arrest must turn the arrestee over to law enforcement without unreasonable delay; guards do not punish or interrogate suspects.","es":"Una persona privada que realiza un arresto ciudadano debe entregar al arrestado a las autoridades sin demora irrazonable; los guardias no castigan ni interrogan a los sospechosos.","ru":"Частное лицо, произведшее гражданский арест, должно передать задержанного правоохранительным органам без необоснованной задержки; охранники не наказывают и не допрашивают подозреваемых.","tr":"Vatandaşlık tutuklaması yapan özel bir kişi, tutukladığı kişiyi makul olmayan bir gecikme olmadan kolluk kuvvetlerine teslim etmelidir; güvenlik görevlileri şüphelileri cezalandırmaz veya sorgulamaz.","hi":"नागरिक गिरफ्तारी करने वाले निजी व्यक्ति को गिरफ्तार व्यक्ति को बिना किसी अनुचित देरी के कानून प्रवर्तन को सौंपना चाहिए; गार्ड संदिग्धों को दंडित या पूछताछ नहीं करते।","ar":"يجب على الشخص العادي الذي يقوم باعتقال مدني تسليم الموقوف إلى جهات إنفاذ القانون دون تأخير غير مبرر؛ فالحراس لا يعاقبون المشتبه بهم ولا يستجوبونهم."}},{"cat":"legal","a":2,"q":{"en":"Do security guards need to read Miranda warnings before questioning a suspect they have detained?","es":"¿Los guardias de seguridad deben leer las advertencias Miranda antes de interrogar a un sospechoso que han detenido?","ru":"Должны ли охранники зачитывать предупреждения Миранды перед допросом задержанного ими подозреваемого?","tr":"Güvenlik görevlileri gözaltına aldıkları bir şüpheliyi sorgulamadan önce Miranda uyarılarını okumak zorunda mıdır?","hi":"क्या सुरक्षा गार्डों को अपने द्वारा हिरासत में लिए गए संदिग्ध से पूछताछ करने से पहले मिरांडा चेतावनी पढ़नी चाहिए?","ar":"هل يتعين على حراس الأمن تلاوة تحذيرات ميراندا قبل استجواب مشتبه به قاموا باحتجازه؟"},"o":[{"en":"Yes, they must always read Miranda before any questions","es":"Sí, siempre deben leer Miranda antes de cualquier pregunta","ru":"Да, они всегда должны зачитывать Миранду перед любыми вопросами","tr":"Evet, herhangi bir soru sormadan önce her zaman Miranda'yı okumalıdırlar","hi":"हाँ, उन्हें किसी भी प्रश्न से पहले हमेशा मिरांडा पढ़नी चाहिए","ar":"نعم، يجب عليهم دائماً تلاوة ميراندا قبل أي أسئلة"},{"en":"Yes, but only if the suspect asks for a lawyer first","es":"Sí, pero solo si el sospechoso pide primero un abogado","ru":"Да, но только если подозреваемый сначала попросит адвоката","tr":"Evet, ama yalnızca şüpheli önce bir avukat isterse","hi":"हाँ, लेकिन केवल तभी जब संदिग्ध पहले वकील माँगे","ar":"نعم، ولكن فقط إذا طلب المشتبه به محامياً أولاً"},{"en":"No, Miranda applies only to custodial interrogation by law enforcement, not private guards","es":"No, Miranda solo se aplica al interrogatorio bajo custodia por parte de las fuerzas del orden, no a los guardias privados","ru":"Нет, Миранда применяется только к допросу под стражей сотрудниками правопорядка, а не частными охранниками","tr":"Hayır, Miranda yalnızca kolluk kuvvetlerinin gözaltındaki sorgulamasına uygulanır, özel güvenlik görevlilerine değil","hi":"नहीं, मिरांडा केवल कानून प्रवर्तन द्वारा हिरासत में पूछताछ पर लागू होती है, निजी गार्डों पर नहीं","ar":"لا، تنطبق ميراندا فقط على الاستجواب أثناء الاحتجاز من قبل جهات إنفاذ القانون، وليس على الحراس الخاصين"},{"en":"No, because Miranda has been abolished nationwide","es":"No, porque Miranda ha sido abolida en todo el país","ru":"Нет, потому что Миранда была отменена по всей стране","tr":"Hayır, çünkü Miranda ülke genelinde kaldırılmıştır","hi":"नहीं, क्योंकि मिरांडा को पूरे देश में समाप्त कर दिया गया है","ar":"لا، لأن ميراندا قد أُلغيت في جميع أنحاء البلاد"}],"e":{"en":"Miranda warnings apply to custodial interrogation by law enforcement or government agents. Private security guards are not required to give them.","es":"Las advertencias Miranda se aplican al interrogatorio bajo custodia por parte de las fuerzas del orden o agentes del gobierno. Los guardias de seguridad privados no están obligados a darlas.","ru":"Предупреждения Миранды применяются к допросу под стражей сотрудниками правопорядка или государственными агентами. Частные охранники не обязаны их давать.","tr":"Miranda uyarıları, kolluk kuvvetleri veya devlet görevlileri tarafından yapılan gözaltı sorgulamasına uygulanır. Özel güvenlik görevlilerinin bunları vermesi gerekmez.","hi":"मिरांडा चेतावनियाँ कानून प्रवर्तन या सरकारी एजेंटों द्वारा हिरासत में पूछताछ पर लागू होती हैं। निजी सुरक्षा गार्डों को इन्हें देने की आवश्यकता नहीं है।","ar":"تنطبق تحذيرات ميراندا على الاستجواب أثناء الاحتجاز من قبل جهات إنفاذ القانون أو موظفي الحكومة. ولا يُلزم حراس الأمن الخاصون بتلاوتها."}},{"cat":"legal","a":3,"q":{"en":"When may a security guard use deadly force?","es":"¿Cuándo puede un guardia de seguridad usar fuerza letal?","ru":"Когда охранник может применить смертоносную силу?","tr":"Bir güvenlik görevlisi ne zaman öldürücü güç kullanabilir?","hi":"एक सुरक्षा गार्ड कब घातक बल का प्रयोग कर सकता है?","ar":"متى يجوز لحارس الأمن استخدام القوة المميتة؟"},"o":[{"en":"To stop a person from fleeing after a minor theft","es":"Para impedir que una persona huya después de un hurto menor","ru":"Чтобы остановить человека, убегающего после мелкой кражи","tr":"Küçük bir hırsızlıktan sonra kaçan bir kişiyi durdurmak için","hi":"एक छोटी चोरी के बाद भाग रहे व्यक्ति को रोकने के लिए","ar":"لمنع شخص من الفرار بعد سرقة بسيطة"},{"en":"To protect valuable property from being damaged","es":"Para proteger propiedad valiosa de ser dañada","ru":"Чтобы защитить ценное имущество от повреждения","tr":"Değerli mülkün zarar görmesini önlemek için","hi":"मूल्यवान संपत्ति को क्षति से बचाने के लिए","ar":"لحماية ممتلكات ثمينة من التلف"},{"en":"Whenever a trespasser refuses to leave the property","es":"Siempre que un intruso se niegue a abandonar la propiedad","ru":"Каждый раз, когда нарушитель отказывается покинуть территорию","tr":"Bir izinsiz giren kişi mülkü terk etmeyi reddettiğinde","hi":"जब भी कोई अतिक्रमणकर्ता संपत्ति छोड़ने से इनकार करे","ar":"كلما رفض متعدٍّ مغادرة الممتلكات"},{"en":"Only as a last resort to defend against an imminent threat to life","es":"Solo como último recurso para defenderse contra una amenaza inminente a la vida","ru":"Только в крайнем случае для защиты от неминуемой угрозы жизни","tr":"Yalnızca hayata yönelik yakın bir tehdide karşı savunma amacıyla son çare olarak","hi":"केवल अंतिम उपाय के रूप में जीवन के लिए तत्काल खतरे से बचाव के लिए","ar":"فقط كملاذ أخير للدفاع ضد تهديد وشيك للحياة"}],"e":{"en":"Deadly force is justified only as a last resort in defense of life against an imminent deadly threat. It may never be used solely to protect property.","es":"La fuerza letal solo se justifica como último recurso en defensa de la vida contra una amenaza mortal inminente. Nunca puede usarse únicamente para proteger la propiedad.","ru":"Смертоносная сила оправдана только в крайнем случае для защиты жизни от неминуемой смертельной угрозы. Её никогда нельзя применять исключительно для защиты имущества.","tr":"Öldürücü güç yalnızca yakın ölümcül bir tehdide karşı hayatı savunmak için son çare olarak haklıdır. Asla yalnızca mülkü korumak için kullanılamaz.","hi":"घातक बल केवल जीवन की रक्षा में तत्काल घातक खतरे के विरुद्ध अंतिम उपाय के रूप में उचित है। इसका उपयोग कभी भी केवल संपत्ति की रक्षा के लिए नहीं किया जा सकता।","ar":"القوة المميتة مبررة فقط كملاذ أخير للدفاع عن الحياة ضد تهديد مميت وشيك. ولا يجوز استخدامها أبداً لمجرد حماية الممتلكات."}},{"cat":"legal","a":0,"q":{"en":"Under the \"shopkeeper's privilege,\" what may a guard do with someone reasonably suspected of shoplifting?","es":"Bajo el \"privilegio del comerciante\", ¿qué puede hacer un guardia con alguien razonablemente sospechoso de hurto en tiendas?","ru":"В рамках «привилегии владельца магазина» что может сделать охранник с лицом, обоснованно подозреваемым в магазинной краже?","tr":"\"Esnaf ayrıcalığı\" kapsamında, bir güvenlik görevlisi mağaza hırsızlığından makul şekilde şüphelenilen biriyle ne yapabilir?","hi":"\"दुकानदार के विशेषाधिकार\" के तहत, एक गार्ड दुकान से चोरी के उचित संदेह वाले व्यक्ति के साथ क्या कर सकता है?","ar":"بموجب \"امتياز صاحب المتجر\"، ماذا يجوز للحارس أن يفعل بشخص يُشتبه بشكل معقول في سرقته من المتجر؟"},"o":[{"en":"Detain them briefly and reasonably to investigate","es":"Detenerlo breve y razonablemente para investigar","ru":"Ненадолго и разумно задержать его для проведения проверки","tr":"Onları soruşturmak için kısa ve makul bir süre gözaltında tutmak","hi":"जाँच के लिए उन्हें संक्षिप्त और उचित रूप से हिरासत में रखना","ar":"احتجازهم لفترة وجيزة ومعقولة للتحقيق"},{"en":"Hold them indefinitely until they confess","es":"Retenerlo indefinidamente hasta que confiese","ru":"Удерживать его неограниченно долго, пока он не признается","tr":"İtiraf edene kadar süresiz olarak tutmak","hi":"स्वीकारोक्ति तक उन्हें अनिश्चित काल तक रोके रखना","ar":"احتجازهم إلى أجل غير مسمى حتى يعترفوا"},{"en":"Strip-search them to find hidden merchandise","es":"Desnudarlo para encontrar mercancía oculta","ru":"Провести личный досмотр с раздеванием, чтобы найти спрятанный товар","tr":"Gizlenmiş malı bulmak için üzerini soyarak aramak","hi":"छिपा हुआ माल खोजने के लिए उनकी वस्त्रहीन तलाशी लेना","ar":"تفتيشهم بتجريدهم من ملابسهم للعثور على بضاعة مخبأة"},{"en":"Take their wallet and keys as collateral","es":"Tomar su billetera y llaves como garantía","ru":"Забрать его кошелёк и ключи в качестве залога","tr":"Cüzdanını ve anahtarlarını teminat olarak almak","hi":"जमानत के रूप में उनका बटुआ और चाबियाँ ले लेना","ar":"أخذ محفظتهم ومفاتيحهم كضمان"}],"e":{"en":"The shopkeeper's privilege allows a brief, reasonable detention of a suspected shoplifter to investigate; it does not permit indefinite holding, forced searches, or seizing property.","es":"El privilegio del comerciante permite una detención breve y razonable de un presunto ladrón para investigar; no permite retención indefinida, registros forzados ni incautación de bienes.","ru":"Привилегия владельца магазина позволяет ненадолго и разумно задержать подозреваемого в краже для проверки; она не допускает бессрочного удержания, принудительных обысков или изъятия имущества.","tr":"Esnaf ayrıcalığı, şüpheli bir hırsızın soruşturulması için kısa ve makul bir gözaltına izin verir; süresiz tutmaya, zorla aramaya veya mala el koymaya izin vermez.","hi":"दुकानदार का विशेषाधिकार जाँच के लिए संदिग्ध चोर की संक्षिप्त, उचित हिरासत की अनुमति देता है; यह अनिश्चितकालीन रोक, जबरन तलाशी या संपत्ति जब्त करने की अनुमति नहीं देता।","ar":"يسمح امتياز صاحب المتجر باحتجاز وجيز ومعقول للمشتبه في سرقته للتحقيق؛ ولا يسمح بالاحتجاز إلى أجل غير مسمى أو التفتيش القسري أو مصادرة الممتلكات."}},{"cat":"legal","a":1,"q":{"en":"Can a private security guard search a person or their bag without permission?","es":"¿Puede un guardia de seguridad privado registrar a una persona o su bolso sin permiso?","ru":"Может ли частный охранник обыскать человека или его сумку без разрешения?","tr":"Özel bir güvenlik görevlisi izin almadan bir kişiyi veya çantasını arayabilir mi?","hi":"क्या एक निजी सुरक्षा गार्ड बिना अनुमति के किसी व्यक्ति या उसके बैग की तलाशी ले सकता है?","ar":"هل يمكن لحارس أمن خاص تفتيش شخص أو حقيبته دون إذن؟"},"o":[{"en":"Yes, guards can search anyone at any time","es":"Sí, los guardias pueden registrar a cualquiera en cualquier momento","ru":"Да, охранники могут обыскивать любого в любое время","tr":"Evet, güvenlik görevlileri herkesi her zaman arayabilir","hi":"हाँ, गार्ड किसी को भी किसी भी समय तलाशी ले सकते हैं","ar":"نعم، يمكن للحراس تفتيش أي شخص في أي وقت"},{"en":"Generally no; a search normally requires the person's voluntary consent","es":"Generalmente no; un registro normalmente requiere el consentimiento voluntario de la persona","ru":"Как правило, нет; обыск обычно требует добровольного согласия человека","tr":"Genellikle hayır; bir arama normalde kişinin gönüllü rızasını gerektirir","hi":"आम तौर पर नहीं; तलाशी के लिए सामान्यतः व्यक्ति की स्वैच्छिक सहमति आवश्यक होती है","ar":"لا بشكل عام؛ يتطلب التفتيش عادةً موافقة الشخص الطوعية"},{"en":"Yes, but only if the guard suspects a weapon","es":"Sí, pero solo si el guardia sospecha de un arma","ru":"Да, но только если охранник подозревает наличие оружия","tr":"Evet, ama yalnızca güvenlik görevlisi bir silahtan şüphelenirse","hi":"हाँ, लेकिन केवल तभी जब गार्ड को हथियार का संदेह हो","ar":"نعم، ولكن فقط إذا اشتبه الحارس في وجود سلاح"},{"en":"Yes, once the guard has detained the person","es":"Sí, una vez que el guardia ha detenido a la persona","ru":"Да, как только охранник задержал человека","tr":"Evet, güvenlik görevlisi kişiyi gözaltına aldıktan sonra","hi":"हाँ, एक बार जब गार्ड ने व्यक्ति को हिरासत में ले लिया हो","ar":"نعم، بمجرد أن يحتجز الحارس الشخص"}],"e":{"en":"A private guard generally cannot search a person or their belongings without voluntary consent (or an agreed condition of entry). Guards cannot conduct forcible searches like police.","es":"Un guardia privado generalmente no puede registrar a una persona ni sus pertenencias sin consentimiento voluntario (o una condición de entrada acordada). Los guardias no pueden realizar registros forzosos como la policía.","ru":"Частный охранник, как правило, не может обыскивать человека или его вещи без добровольного согласия (или согласованного условия входа). Охранники не могут проводить принудительные обыски, как полиция.","tr":"Özel bir güvenlik görevlisi genellikle gönüllü rıza (veya kabul edilmiş bir giriş koşulu) olmadan bir kişiyi veya eşyalarını arayamaz. Güvenlik görevlileri polis gibi zorla arama yapamaz.","hi":"एक निजी गार्ड आम तौर पर स्वैच्छिक सहमति (या सहमत प्रवेश शर्त) के बिना किसी व्यक्ति या उसकी वस्तुओं की तलाशी नहीं ले सकता। गार्ड पुलिस की तरह जबरन तलाशी नहीं कर सकते।","ar":"لا يمكن للحارس الخاص عموماً تفتيش شخص أو متعلقاته دون موافقة طوعية (أو شرط دخول متفق عليه). ولا يمكن للحراس إجراء تفتيش قسري مثل الشرطة."}},{"cat":"legal","a":2,"q":{"en":"What is the guiding principle of the use-of-force continuum for security guards?","es":"¿Cuál es el principio rector del continuo de uso de la fuerza para los guardias de seguridad?","ru":"Каков руководящий принцип континуума применения силы для охранников?","tr":"Güvenlik görevlileri için güç kullanımı sürekliliğinin temel ilkesi nedir?","hi":"सुरक्षा गार्डों के लिए बल-प्रयोग निरंतरता का मार्गदर्शक सिद्धांत क्या है?","ar":"ما هو المبدأ الموجِّه لتدرج استخدام القوة بالنسبة لحراس الأمن؟"},"o":[{"en":"Always use the maximum force allowed to ensure compliance","es":"Usar siempre la fuerza máxima permitida para asegurar el cumplimiento","ru":"Всегда применять максимально разрешённую силу для обеспечения подчинения","tr":"Uyumu sağlamak için her zaman izin verilen azami gücü kullanmak","hi":"अनुपालन सुनिश्चित करने के लिए हमेशा अनुमत अधिकतम बल का प्रयोग करना","ar":"استخدام أقصى قوة مسموح بها دائماً لضمان الامتثال"},{"en":"Use force only after receiving written approval from a supervisor","es":"Usar la fuerza solo después de recibir aprobación escrita de un supervisor","ru":"Применять силу только после получения письменного одобрения от руководителя","tr":"Yalnızca bir amirden yazılı onay aldıktan sonra güç kullanmak","hi":"बल का प्रयोग केवल पर्यवेक्षक से लिखित अनुमोदन प्राप्त करने के बाद करना","ar":"استخدام القوة فقط بعد الحصول على موافقة خطية من المشرف"},{"en":"Use only the minimum force reasonable and proportional to the threat","es":"Usar solo la fuerza mínima razonable y proporcional a la amenaza","ru":"Применять только минимальную силу, разумную и соразмерную угрозе","tr":"Yalnızca tehdide makul ve orantılı asgari gücü kullanmak","hi":"केवल न्यूनतम बल का प्रयोग करना जो खतरे के अनुपात में उचित हो","ar":"استخدام الحد الأدنى فقط من القوة المعقولة والمتناسبة مع التهديد"},{"en":"Match force to the value of the property being protected","es":"Ajustar la fuerza al valor de la propiedad que se protege","ru":"Соотносить силу со стоимостью защищаемого имущества","tr":"Gücü korunan mülkün değerine göre ayarlamak","hi":"बल को संरक्षित की जा रही संपत्ति के मूल्य के अनुरूप बनाना","ar":"مطابقة القوة مع قيمة الممتلكات التي تتم حمايتها"}],"e":{"en":"Force must be reasonable and proportional to the threat, using only enough to control the situation. Excessive force exposes the guard and employer to liability.","es":"La fuerza debe ser razonable y proporcional a la amenaza, usando solo la suficiente para controlar la situación. La fuerza excesiva expone al guardia y al empleador a responsabilidad.","ru":"Сила должна быть разумной и соразмерной угрозе, применяя только столько, сколько достаточно для контроля ситуации. Чрезмерная сила подвергает охранника и работодателя ответственности.","tr":"Güç, tehdide makul ve orantılı olmalı, yalnızca durumu kontrol altına alacak kadar kullanılmalıdır. Aşırı güç, güvenlik görevlisini ve işvereni sorumlulukla karşı karşıya bırakır.","hi":"बल खतरे के अनुपात में उचित होना चाहिए, केवल स्थिति को नियंत्रित करने के लिए पर्याप्त का प्रयोग करते हुए। अत्यधिक बल गार्ड और नियोक्ता को दायित्व में डालता है।","ar":"يجب أن تكون القوة معقولة ومتناسبة مع التهديد، باستخدام ما يكفي فقط للسيطرة على الموقف. والقوة المفرطة تعرّض الحارس وصاحب العمل للمساءلة."}},{"cat":"legal","a":3,"q":{"en":"If a guard arrests someone without a lawful basis, what legal claim might the person bring?","es":"Si un guardia arresta a alguien sin fundamento legal, ¿qué reclamo legal podría presentar la persona?","ru":"Если охранник арестует кого-либо без законных оснований, какой правовой иск может предъявить этот человек?","tr":"Bir güvenlik görevlisi birini yasal dayanak olmadan tutuklarsa, kişi hangi hukuki iddiayı öne sürebilir?","hi":"यदि कोई गार्ड बिना वैध आधार के किसी को गिरफ्तार करता है, तो वह व्यक्ति कौन सा कानूनी दावा कर सकता है?","ar":"إذا اعتقل حارس شخصاً دون أساس قانوني، فما الدعوى القانونية التي قد يرفعها الشخص؟"},"o":[{"en":"Breach of contract","es":"Incumplimiento de contrato","ru":"Нарушение договора","tr":"Sözleşme ihlali","hi":"अनुबंध का उल्लंघन","ar":"الإخلال بالعقد"},{"en":"Copyright infringement","es":"Infracción de derechos de autor","ru":"Нарушение авторских прав","tr":"Telif hakkı ihlali","hi":"कॉपीराइट उल्लंघन","ar":"انتهاك حقوق النشر"},{"en":"Product liability","es":"Responsabilidad por productos","ru":"Ответственность за качество продукции","tr":"Ürün sorumluluğu","hi":"उत्पाद दायित्व","ar":"المسؤولية عن المنتج"},{"en":"False arrest / false imprisonment","es":"Arresto falso / detención ilegal","ru":"Незаконный арест / незаконное лишение свободы","tr":"Haksız tutuklama / haksız hürriyeti kısıtlama","hi":"झूठी गिरफ्तारी / झूठा कारावास","ar":"الاعتقال الكاذب / الحبس غير القانوني"}],"e":{"en":"An unlawful arrest can lead to civil liability for false arrest or false imprisonment, and the guard and employer can both be sued.","es":"Un arresto ilegal puede dar lugar a responsabilidad civil por arresto falso o detención ilegal, y tanto el guardia como el empleador pueden ser demandados.","ru":"Незаконный арест может повлечь гражданскую ответственность за незаконный арест или незаконное лишение свободы, и в суд можно подать как на охранника, так и на работодателя.","tr":"Yasadışı bir tutuklama, haksız tutuklama veya haksız hürriyeti kısıtlama nedeniyle hukuki sorumluluğa yol açabilir ve hem güvenlik görevlisi hem de işveren dava edilebilir.","hi":"अवैध गिरफ्तारी झूठी गिरफ्तारी या झूठे कारावास के लिए नागरिक दायित्व का कारण बन सकती है, और गार्ड तथा नियोक्ता दोनों पर मुकदमा किया जा सकता है।","ar":"قد يؤدي الاعتقال غير القانوني إلى مسؤولية مدنية عن الاعتقال الكاذب أو الحبس غير القانوني، ويمكن مقاضاة كل من الحارس وصاحب العمل."}},{"cat":"legal","a":0,"q":{"en":"For what kind of offense may a private person (including a guard) typically make a citizen's arrest?","es":"¿Por qué tipo de delito puede una persona privada (incluido un guardia) normalmente realizar un arresto ciudadano?","ru":"За какое правонарушение частное лицо (включая охранника) обычно может произвести гражданский арест?","tr":"Özel bir kişi (bir güvenlik görevlisi dahil) tipik olarak hangi tür suç için vatandaşlık tutuklaması yapabilir?","hi":"किस प्रकार के अपराध के लिए एक निजी व्यक्ति (गार्ड सहित) आमतौर पर नागरिक गिरफ्तारी कर सकता है?","ar":"لأي نوع من الجرائم يمكن للشخص العادي (بما في ذلك الحارس) عادةً إجراء اعتقال مدني؟"},"o":[{"en":"A crime committed or attempted in the guard's presence","es":"Un delito cometido o intentado en presencia del guardia","ru":"Преступление, совершённое или которое пытались совершить в присутствии охранника","tr":"Güvenlik görevlisinin huzurunda işlenen veya işlenmeye teşebbüs edilen bir suç","hi":"गार्ड की उपस्थिति में किया गया या प्रयास किया गया अपराध","ar":"جريمة ارتُكبت أو حُوول ارتكابها في حضور الحارس"},{"en":"Any crime a coworker mentions might have happened last week","es":"Cualquier delito que un compañero mencione que pudo haber ocurrido la semana pasada","ru":"Любое преступление, о котором коллега упомянул, что оно могло произойти на прошлой неделе","tr":"Bir iş arkadaşının geçen hafta olmuş olabileceğini söylediği herhangi bir suç","hi":"कोई भी अपराध जिसके बारे में सहकर्मी बताए कि पिछले सप्ताह हुआ हो सकता है","ar":"أي جريمة يذكر زميل أنها ربما وقعت الأسبوع الماضي"},{"en":"Only offenses reported to the guard by an anonymous phone call","es":"Solo delitos reportados al guardia mediante una llamada anónima","ru":"Только правонарушения, о которых охраннику сообщили анонимным телефонным звонком","tr":"Yalnızca güvenlik görevlisine anonim bir telefon çağrısıyla bildirilen suçlar","hi":"केवल वे अपराध जो गार्ड को एक गुमनाम फोन कॉल द्वारा बताए जाएँ","ar":"فقط الجرائم التي أُبلغ بها الحارس عبر مكالمة هاتفية مجهولة"},{"en":"Any suspicious behavior even if no crime occurred","es":"Cualquier comportamiento sospechoso incluso si no ocurrió ningún delito","ru":"Любое подозрительное поведение, даже если преступления не было","tr":"Hiçbir suç işlenmemiş olsa bile herhangi bir şüpheli davranış","hi":"कोई भी संदिग्ध व्यवहार, भले ही कोई अपराध न हुआ हो","ar":"أي سلوك مشبوه حتى لو لم تقع أي جريمة"}],"e":{"en":"A private person generally may make a citizen's arrest for a crime committed or attempted in their presence. Rules on felonies vary by state, but presence is the common standard for guards.","es":"Una persona privada generalmente puede realizar un arresto ciudadano por un delito cometido o intentado en su presencia. Las reglas sobre delitos graves varían según el estado, pero la presencia es el estándar común para los guardias.","ru":"Частное лицо, как правило, может произвести гражданский арест за преступление, совершённое или которое пытались совершить в его присутствии. Правила в отношении тяжких преступлений различаются по штатам, но присутствие — общий стандарт для охранников.","tr":"Özel bir kişi genellikle huzurunda işlenen veya teşebbüs edilen bir suç için vatandaşlık tutuklaması yapabilir. Ağır suçlara ilişkin kurallar eyalete göre değişir, ancak huzurda olma güvenlik görevlileri için ortak standarttır.","hi":"एक निजी व्यक्ति आम तौर पर अपनी उपस्थिति में किए गए या प्रयास किए गए अपराध के लिए नागरिक गिरफ्तारी कर सकता है। गंभीर अपराधों के नियम राज्य के अनुसार भिन्न होते हैं, लेकिन उपस्थिति गार्डों के लिए सामान्य मानक है।","ar":"يجوز للشخص العادي عموماً إجراء اعتقال مدني لجريمة ارتُكبت أو حُووِل ارتكابها في حضوره. تختلف قواعد الجنايات باختلاف الولاية، لكن الحضور هو المعيار الشائع للحراس."}},{"cat":"legal","a":1,"q":{"en":"When does a person become a criminal trespasser on private property?","es":"¿Cuándo se convierte una persona en un intruso criminal en propiedad privada?","ru":"Когда человек становится нарушителем границ частной собственности в уголовном смысле?","tr":"Bir kişi özel mülkte ne zaman cezai anlamda izinsiz giren biri hâline gelir?","hi":"एक व्यक्ति निजी संपत्ति पर आपराधिक अतिक्रमणकर्ता कब बनता है?","ar":"متى يصبح الشخص متعدياً جنائياً على ملكية خاصة؟"},"o":[{"en":"The moment they step onto any private property for any reason","es":"En el momento en que pisa cualquier propiedad privada por cualquier motivo","ru":"В тот момент, когда он ступает на любую частную собственность по любой причине","tr":"Herhangi bir nedenle herhangi bir özel mülke adım attıkları an","hi":"जिस क्षण वे किसी भी कारण से किसी निजी संपत्ति पर कदम रखते हैं","ar":"في اللحظة التي يطأون فيها أي ملكية خاصة لأي سبب"},{"en":"When they refuse to leave after being lawfully asked to do so","es":"Cuando se niega a irse después de que se le pidiera legalmente que lo hiciera","ru":"Когда он отказывается уйти после законного требования сделать это","tr":"Yasal olarak ayrılmaları istendikten sonra ayrılmayı reddettiklerinde","hi":"जब वे कानूनी रूप से जाने के लिए कहे जाने के बाद जाने से इनकार करते हैं","ar":"عندما يرفضون المغادرة بعد أن يُطلب منهم ذلك بشكل قانوني"},{"en":"Only if they damage something on the property","es":"Solo si daña algo en la propiedad","ru":"Только если он что-то повредит на территории","tr":"Yalnızca mülkte bir şeye zarar verirlerse","hi":"केवल तभी जब वे संपत्ति पर किसी चीज़ को नुकसान पहुँचाते हैं","ar":"فقط إذا أتلفوا شيئاً في الممتلكات"},{"en":"Never, because the public may enter any business freely","es":"Nunca, porque el público puede entrar libremente a cualquier negocio","ru":"Никогда, потому что публика может свободно входить в любое коммерческое заведение","tr":"Asla, çünkü halk herhangi bir işletmeye özgürce girebilir","hi":"कभी नहीं, क्योंकि जनता किसी भी व्यवसाय में स्वतंत्र रूप से प्रवेश कर सकती है","ar":"أبداً، لأنه يجوز للجمهور دخول أي منشأة تجارية بحرية"}],"e":{"en":"A person typically becomes a criminal trespasser when they remain after being lawfully directed to leave by someone with authority over the property. Specific trespass laws vary by state.","es":"Una persona normalmente se convierte en intruso criminal cuando permanece después de que alguien con autoridad sobre la propiedad le ordena legalmente que se vaya. Las leyes específicas de allanamiento varían según el estado.","ru":"Человек обычно становится нарушителем в уголовном смысле, когда остаётся после законного требования покинуть территорию от лица, имеющего полномочия над собственностью. Конкретные законы о нарушении границ различаются по штатам.","tr":"Bir kişi genellikle, mülk üzerinde yetkisi olan biri tarafından yasal olarak ayrılması söylendikten sonra kaldığında cezai anlamda izinsiz giren biri hâline gelir. Belirli izinsiz giriş yasaları eyalete göre değişir.","hi":"एक व्यक्ति आम तौर पर आपराधिक अतिक्रमणकर्ता तब बनता है जब वह संपत्ति पर अधिकार रखने वाले किसी व्यक्ति द्वारा कानूनी रूप से जाने के लिए निर्देशित किए जाने के बाद भी रुका रहता है। विशिष्ट अतिक्रमण कानून राज्य के अनुसार भिन्न होते हैं।","ar":"يصبح الشخص عادةً متعدياً جنائياً عندما يبقى بعد أن يوجَّه إليه بشكل قانوني بالمغادرة من قبل شخص يملك سلطة على الممتلكات. تختلف قوانين التعدي المحددة باختلاف الولاية."}},{"cat":"legal","a":2,"q":{"en":"What is the key difference between a detention and an arrest by a security guard?","es":"¿Cuál es la diferencia clave entre una detención y un arresto por parte de un guardia de seguridad?","ru":"В чём ключевое различие между задержанием и арестом со стороны охранника?","tr":"Bir güvenlik görevlisinin yaptığı gözaltı ile tutuklama arasındaki temel fark nedir?","hi":"एक सुरक्षा गार्ड द्वारा हिरासत और गिरफ्तारी के बीच मुख्य अंतर क्या है?","ar":"ما الفرق الرئيسي بين الاحتجاز والاعتقال من قبل حارس الأمن؟"},"o":[{"en":"A detention requires a warrant, while an arrest does not","es":"Una detención requiere una orden judicial, mientras que un arresto no","ru":"Задержание требует ордера, а арест — нет","tr":"Gözaltı bir emir gerektirir, tutuklama ise gerektirmez","hi":"हिरासत के लिए वारंट चाहिए, जबकि गिरफ्तारी के लिए नहीं","ar":"يتطلب الاحتجاز مذكرة، بينما لا يتطلب الاعتقال ذلك"},{"en":"There is no difference; the terms mean exactly the same thing","es":"No hay diferencia; los términos significan exactamente lo mismo","ru":"Разницы нет; эти термины означают совершенно одно и то же","tr":"Fark yoktur; terimler tam olarak aynı anlama gelir","hi":"कोई अंतर नहीं है; दोनों शब्दों का बिल्कुल एक ही अर्थ है","ar":"لا فرق بينهما؛ المصطلحان يعنيان الشيء ذاته تماماً"},{"en":"A detention is a brief, temporary hold to investigate, while an arrest is taking a person into custody","es":"Una detención es una retención breve y temporal para investigar, mientras que un arresto es poner a una persona bajo custodia","ru":"Задержание — это краткое, временное удержание для проверки, а арест — это взятие человека под стражу","tr":"Gözaltı, soruşturmak için kısa ve geçici bir tutmadır; tutuklama ise bir kişiyi gözaltına almaktır","hi":"हिरासत जाँच के लिए एक संक्षिप्त, अस्थायी रोक है, जबकि गिरफ्तारी किसी व्यक्ति को अभिरक्षा में लेना है","ar":"الاحتجاز هو إمساك وجيز ومؤقت للتحقيق، بينما الاعتقال هو وضع الشخص رهن التحفظ"},{"en":"A detention can last for days, but an arrest must end within an hour","es":"Una detención puede durar días, pero un arresto debe terminar en una hora","ru":"Задержание может длиться днями, но арест должен закончиться в течение часа","tr":"Gözaltı günlerce sürebilir, ancak tutuklama bir saat içinde sona ermelidir","hi":"हिरासत कई दिनों तक चल सकती है, लेकिन गिरफ्तारी एक घंटे के भीतर समाप्त होनी चाहिए","ar":"يمكن أن يستمر الاحتجاز أياماً، لكن الاعتقال يجب أن ينتهي خلال ساعة"}],"e":{"en":"A detention is a brief, temporary hold to investigate a reasonable suspicion, done in a reasonable time and manner. An arrest is taking a person into custody to turn over to police.","es":"Una detención es una retención breve y temporal para investigar una sospecha razonable, realizada de manera y tiempo razonables. Un arresto es poner a una persona bajo custodia para entregarla a la policía.","ru":"Задержание — это краткое, временное удержание для проверки обоснованного подозрения, проводимое в разумное время и разумным образом. Арест — это взятие человека под стражу для передачи полиции.","tr":"Gözaltı, makul bir şüpheyi soruşturmak için makul bir süre ve şekilde yapılan kısa ve geçici bir tutmadır. Tutuklama ise bir kişiyi polise teslim etmek üzere gözaltına almaktır.","hi":"हिरासत एक उचित संदेह की जाँच के लिए संक्षिप्त, अस्थायी रोक है, जो उचित समय और तरीके से की जाती है। गिरफ्तारी किसी व्यक्ति को पुलिस को सौंपने के लिए अभिरक्षा में लेना है।","ar":"الاحتجاز هو إمساك وجيز ومؤقت للتحقيق في اشتباه معقول، يُجرى في وقت وطريقة معقولين. أما الاعتقال فهو وضع الشخص رهن التحفظ لتسليمه إلى الشرطة."}},{"cat":"legal","a":3,"q":{"en":"A guard shoves and injures a cooperative visitor who posed no threat. What is the most likely legal consequence?","es":"Un guardia empuja y lesiona a un visitante cooperativo que no representaba ninguna amenaza. ¿Cuál es la consecuencia legal más probable?","ru":"Охранник толкнул и травмировал сотрудничавшего посетителя, не представлявшего угрозы. Каково наиболее вероятное правовое последствие?","tr":"Bir güvenlik görevlisi, hiçbir tehdit oluşturmayan işbirlikçi bir ziyaretçiyi iterek yaralıyor. En olası hukuki sonuç nedir?","hi":"एक गार्ड ने एक सहयोगी आगंतुक को धक्का देकर घायल कर दिया जिससे कोई खतरा नहीं था। सबसे संभावित कानूनी परिणाम क्या है?","ar":"يدفع حارس زائراً متعاوناً لا يشكّل أي تهديد ويصيبه. ما النتيجة القانونية الأرجح؟"},"o":[{"en":"Nothing, because guards are immune from lawsuits","es":"Nada, porque los guardias son inmunes a las demandas","ru":"Ничего, потому что охранники неприкосновенны для исков","tr":"Hiçbir şey, çünkü güvenlik görevlileri davalardan muaftır","hi":"कुछ नहीं, क्योंकि गार्ड मुकदमों से प्रतिरक्षित हैं","ar":"لا شيء، لأن الحراس محصنون من الدعاوى"},{"en":"The visitor must pay the guard for resisting","es":"El visitante debe pagar al guardia por resistirse","ru":"Посетитель должен заплатить охраннику за сопротивление","tr":"Ziyaretçi, direndiği için güvenlik görevlisine ödeme yapmalıdır","hi":"आगंतुक को विरोध करने के लिए गार्ड को भुगतान करना होगा","ar":"يجب على الزائر أن يدفع للحارس بسبب مقاومته"},{"en":"Only the employer is affected, never the guard personally","es":"Solo el empleador se ve afectado, nunca el guardia personalmente","ru":"Затрагивается только работодатель, но никогда лично охранник","tr":"Yalnızca işveren etkilenir, güvenlik görevlisi kişisel olarak asla etkilenmez","hi":"केवल नियोक्ता प्रभावित होता है, कभी भी व्यक्तिगत रूप से गार्ड नहीं","ar":"يتأثر صاحب العمل فقط، ولا يتأثر الحارس شخصياً أبداً"},{"en":"The guard may be liable for assault and battery (and criminal charges are possible)","es":"El guardia puede ser responsable de agresión y lesiones (y son posibles cargos penales)","ru":"Охранник может нести ответственность за нападение и побои (возможны и уголовные обвинения)","tr":"Güvenlik görevlisi darp ve saldırıdan sorumlu tutulabilir (ve cezai suçlamalar mümkündür)","hi":"गार्ड हमले और मारपीट के लिए उत्तरदायी हो सकता है (और आपराधिक आरोप भी संभव हैं)","ar":"قد يكون الحارس مسؤولاً عن الاعتداء والضرب (وقد توجَّه تهم جنائية أيضاً)"}],"e":{"en":"Using force against someone who poses no threat can be unlawful, exposing the guard to civil liability for assault and battery and possible criminal charges.","es":"Usar fuerza contra alguien que no representa una amenaza puede ser ilegal, exponiendo al guardia a responsabilidad civil por agresión y lesiones y a posibles cargos penales.","ru":"Применение силы против того, кто не представляет угрозы, может быть незаконным, что подвергает охранника гражданской ответственности за нападение и побои и возможным уголовным обвинениям.","tr":"Hiçbir tehdit oluşturmayan birine karşı güç kullanmak yasadışı olabilir ve güvenlik görevlisini darp ve saldırıdan hukuki sorumlulukla ve olası cezai suçlamalarla karşı karşıya bırakır.","hi":"किसी ऐसे व्यक्ति के विरुद्ध बल का प्रयोग जो कोई खतरा नहीं है, अवैध हो सकता है, जिससे गार्ड हमले और मारपीट के लिए नागरिक दायित्व और संभावित आपराधिक आरोपों के अधीन हो जाता है।","ar":"قد يكون استخدام القوة ضد شخص لا يشكّل تهديداً غير قانوني، مما يعرّض الحارس لمسؤولية مدنية عن الاعتداء والضرب واحتمال توجيه تهم جنائية."}},{"cat":"legal","a":0,"q":{"en":"A guard falsely tells others that a customer is a known thief, damaging their reputation. This could be a claim for what?","es":"Un guardia les dice falsamente a otros que un cliente es un ladrón conocido, dañando su reputación. ¿Esto podría ser un reclamo por qué?","ru":"Охранник ложно говорит другим, что клиент — известный вор, портя его репутацию. Это может стать основанием для иска о чём?","tr":"Bir güvenlik görevlisi, bir müşterinin tanınmış bir hırsız olduğunu başkalarına yanlış bir şekilde söyleyerek itibarına zarar veriyor. Bu ne için bir dava konusu olabilir?","hi":"एक गार्ड झूठा कहता है कि एक ग्राहक एक ज्ञात चोर है, जिससे उसकी प्रतिष्ठा को नुकसान पहुँचता है। यह किसका दावा हो सकता है?","ar":"يخبر حارس آخرين زوراً بأن عميلاً لصٌّ معروف، مما يضر بسمعته. ما الدعوى التي قد يشكّلها ذلك؟"},"o":[{"en":"Defamation","es":"Difamación","ru":"Клевета","tr":"İftira (hakaret)","hi":"मानहानि","ar":"التشهير"},{"en":"Trespass","es":"Allanamiento","ru":"Нарушение границ владения","tr":"İzinsiz girme","hi":"अतिक्रमण","ar":"التعدي على الممتلكات"},{"en":"Negligent driving","es":"Conducción negligente","ru":"Небрежное вождение","tr":"İhmalkâr sürüş","hi":"लापरवाही से वाहन चलाना","ar":"القيادة المتهورة"},{"en":"Copyright infringement","es":"Infracción de derechos de autor","ru":"Нарушение авторских прав","tr":"Telif hakkı ihlali","hi":"कॉपीराइट उल्लंघन","ar":"انتهاك حقوق النشر"}],"e":{"en":"Making false statements of fact that harm someone's reputation can be defamation. Guards should stick to facts and avoid accusatory, unproven statements.","es":"Hacer declaraciones falsas de hecho que dañen la reputación de alguien puede ser difamación. Los guardias deben limitarse a los hechos y evitar declaraciones acusatorias no probadas.","ru":"Ложные утверждения о фактах, наносящие вред чьей-либо репутации, могут являться клеветой. Охранники должны придерживаться фактов и избегать обвинительных, недоказанных заявлений.","tr":"Birinin itibarına zarar veren yanlış olgusal beyanlarda bulunmak iftira olabilir. Güvenlik görevlileri gerçeklere bağlı kalmalı ve suçlayıcı, kanıtlanmamış beyanlardan kaçınmalıdır.","hi":"किसी की प्रतिष्ठा को नुकसान पहुँचाने वाले झूठे तथ्यात्मक बयान देना मानहानि हो सकता है। गार्डों को तथ्यों पर टिके रहना चाहिए और आरोपात्मक, असिद्ध बयानों से बचना चाहिए।","ar":"الإدلاء ببيانات وقائعية كاذبة تضر بسمعة شخص ما قد يشكّل تشهيراً. وعلى الحراس التمسك بالحقائق وتجنب العبارات الاتهامية غير المثبتة."}},{"cat":"legal","a":1,"q":{"en":"When a guard confronts a shoplifting suspect, on whom does the burden generally rest to justify the detention?","es":"Cuando un guardia confronta a un sospechoso de hurto, ¿sobre quién recae generalmente la carga de justificar la detención?","ru":"Когда охранник задерживает подозреваемого в краже, на ком, как правило, лежит бремя обоснования задержания?","tr":"Bir güvenlik görevlisi bir hırsızlık şüphelisiyle karşılaştığında, gözaltını haklı çıkarma yükü genellikle kimin üzerindedir?","hi":"जब एक गार्ड दुकान से चोरी के संदिग्ध का सामना करता है, तो हिरासत को उचित ठहराने का भार आम तौर पर किस पर होता है?","ar":"عندما يواجه حارس مشتبهاً في سرقته من المتجر، على من يقع عبء تبرير الاحتجاز عموماً؟"},"o":[{"en":"On the suspect, who must prove their innocence","es":"Sobre el sospechoso, que debe probar su inocencia","ru":"На подозреваемом, который должен доказать свою невиновность","tr":"Masumiyetini kanıtlaması gereken şüphelinin üzerinde","hi":"संदिग्ध पर, जिसे अपनी निर्दोषता साबित करनी होगी","ar":"على المشتبه به الذي يجب أن يثبت براءته"},{"en":"On the guard/employer, who must have reasonable grounds for the detention","es":"Sobre el guardia/empleador, que debe tener motivos razonables para la detención","ru":"На охраннике/работодателе, у которого должны быть разумные основания для задержания","tr":"Gözaltı için makul gerekçelere sahip olması gereken güvenlik görevlisinin/işverenin üzerinde","hi":"गार्ड/नियोक्ता पर, जिनके पास हिरासत के लिए उचित आधार होने चाहिए","ar":"على الحارس/صاحب العمل الذي يجب أن تكون لديه أسباب معقولة للاحتجاز"},{"en":"On the police, who must approve every detention in advance","es":"Sobre la policía, que debe aprobar cada detención por adelantado","ru":"На полиции, которая должна заранее одобрять каждое задержание","tr":"Her gözaltını önceden onaylaması gereken polisin üzerinde","hi":"पुलिस पर, जिसे हर हिरासत को पहले से मंजूरी देनी होगी","ar":"على الشرطة التي يجب أن توافق مسبقاً على كل احتجاز"},{"en":"On any witnesses present at the scene","es":"Sobre cualquier testigo presente en la escena","ru":"На любых свидетелях, присутствующих на месте","tr":"Olay yerinde bulunan herhangi bir tanığın üzerinde","hi":"घटनास्थल पर मौजूद किसी भी गवाह पर","ar":"على أي شهود موجودين في مكان الحادث"}],"e":{"en":"The guard and employer must be able to justify the detention with reasonable grounds; the suspect is not required to prove innocence. Detaining without justification invites liability.","es":"El guardia y el empleador deben poder justificar la detención con motivos razonables; el sospechoso no está obligado a probar su inocencia. Detener sin justificación conlleva responsabilidad.","ru":"Охранник и работодатель должны быть в состоянии обосновать задержание разумными основаниями; подозреваемый не обязан доказывать невиновность. Задержание без обоснования влечёт ответственность.","tr":"Güvenlik görevlisi ve işveren, gözaltını makul gerekçelerle haklı çıkarabilmelidir; şüphelinin masumiyetini kanıtlaması gerekmez. Gerekçesiz gözaltı sorumluluk doğurur.","hi":"गार्ड और नियोक्ता को उचित आधारों के साथ हिरासत को उचित ठहराने में सक्षम होना चाहिए; संदिग्ध को निर्दोषता साबित करने की आवश्यकता नहीं है। बिना औचित्य के हिरासत दायित्व को आमंत्रित करती है।","ar":"يجب أن يكون الحارس وصاحب العمل قادرين على تبرير الاحتجاز بأسباب معقولة؛ وليس على المشتبه به أن يثبت براءته. والاحتجاز دون تبرير يستدعي المساءلة."}},{"cat":"legal","a":2,"q":{"en":"Which of the following best describes proper use of handcuffs by an unarmed guard?","es":"¿Cuál de las siguientes describe mejor el uso adecuado de esposas por parte de un guardia desarmado?","ru":"Что из перечисленного лучше всего описывает надлежащее применение наручников невооружённым охранником?","tr":"Aşağıdakilerden hangisi silahsız bir güvenlik görevlisinin kelepçeleri doğru kullanımını en iyi tanımlar?","hi":"निम्नलिखित में से कौन सा एक निहत्थे गार्ड द्वारा हथकड़ी के उचित उपयोग का सबसे अच्छा वर्णन करता है?","ar":"أي مما يلي يصف على أفضل وجه الاستخدام السليم للأصفاد من قبل حارس غير مسلح؟"},"o":[{"en":"Handcuffs may be used on anyone to make them cooperate","es":"Las esposas pueden usarse en cualquier persona para hacerla cooperar","ru":"Наручники можно применять к любому, чтобы заставить его сотрудничать","tr":"Kelepçeler, işbirliği yapmalarını sağlamak için herkese kullanılabilir","hi":"हथकड़ी किसी को भी सहयोग करने के लिए मजबूर करने हेतु इस्तेमाल की जा सकती है","ar":"يمكن استخدام الأصفاد على أي شخص لإجباره على التعاون"},{"en":"Handcuffs are never allowed for any private guard under any circumstance","es":"Las esposas nunca están permitidas para ningún guardia privado bajo ninguna circunstancia","ru":"Наручники никогда не разрешены для любого частного охранника ни при каких обстоятельствах","tr":"Kelepçeler hiçbir koşulda hiçbir özel güvenlik görevlisi için asla izin verilmez","hi":"किसी भी परिस्थिति में किसी भी निजी गार्ड के लिए हथकड़ी की कभी अनुमति नहीं है","ar":"الأصفاد غير مسموح بها أبداً لأي حارس خاص تحت أي ظرف"},{"en":"Only if trained and authorized, and only reasonable to safely control a lawfully detained person","es":"Solo si está capacitado y autorizado, y solo cuando sea razonable para controlar de forma segura a una persona detenida legalmente","ru":"Только при наличии подготовки и разрешения, и только когда это разумно для безопасного контроля законно задержанного лица","tr":"Yalnızca eğitimli ve yetkiliyse ve yalnızca yasal olarak gözaltına alınan bir kişiyi güvenli şekilde kontrol etmek makul olduğunda","hi":"केवल यदि प्रशिक्षित और अधिकृत हो, और केवल तभी उचित जब कानूनी रूप से हिरासत में लिए व्यक्ति को सुरक्षित रूप से नियंत्रित करना हो","ar":"فقط إذا كان مدرَّباً ومخوَّلاً، وفقط عندما يكون معقولاً للسيطرة الآمنة على شخص محتجَز بشكل قانوني"},{"en":"Whenever a supervisor is not available to make the decision","es":"Siempre que un supervisor no esté disponible para tomar la decisión","ru":"Всякий раз, когда руководитель недоступен для принятия решения","tr":"Kararı verecek bir amir mevcut olmadığında her zaman","hi":"जब भी निर्णय लेने के लिए कोई पर्यवेक्षक उपलब्ध न हो","ar":"كلما لم يكن هناك مشرف متاح لاتخاذ القرار"}],"e":{"en":"Restraints are a use of force and must be reasonable, applied only by trained/authorized guards to safely control a lawfully detained person. Improper handcuffing can create liability. State and employer rules vary.","es":"Las restricciones son un uso de la fuerza y deben ser razonables, aplicadas solo por guardias capacitados/autorizados para controlar de forma segura a una persona detenida legalmente. Esposar de forma indebida puede generar responsabilidad. Las reglas estatales y del empleador varían.","ru":"Средства ограничения — это применение силы, и оно должно быть разумным, применяемым только обученными/уполномоченными охранниками для безопасного контроля законно задержанного лица. Ненадлежащее применение наручников может создать ответственность. Правила штатов и работодателей различаются.","tr":"Kelepçeler bir güç kullanımıdır ve makul olmalı, yalnızca eğitimli/yetkili güvenlik görevlileri tarafından yasal olarak gözaltına alınan bir kişiyi güvenli şekilde kontrol etmek için uygulanmalıdır. Uygunsuz kelepçeleme sorumluluk doğurabilir. Eyalet ve işveren kuralları değişir.","hi":"बंधन बल का प्रयोग हैं और उचित होने चाहिए, केवल प्रशिक्षित/अधिकृत गार्डों द्वारा कानूनी रूप से हिरासत में लिए व्यक्ति को सुरक्षित रूप से नियंत्रित करने के लिए लगाए जाने चाहिए। अनुचित हथकड़ी दायित्व पैदा कर सकती है। राज्य और नियोक्ता के नियम भिन्न होते हैं।","ar":"القيود استخدام للقوة ويجب أن تكون معقولة، ولا يطبقها إلا حراس مدرَّبون/مخوَّلون للسيطرة الآمنة على شخص محتجَز بشكل قانوني. والتكبيل غير السليم قد ينشئ مسؤولية. وتختلف قواعد الولاية وصاحب العمل."}},{"cat":"legal","a":3,"q":{"en":"A guard grabs a customer's purse and searches it against her clear objection. Which statement is correct?","es":"Un guardia agarra el bolso de una clienta y lo registra a pesar de su clara objeción. ¿Qué afirmación es correcta?","ru":"Охранник хватает сумочку клиентки и обыскивает её вопреки её явному возражению. Какое утверждение верно?","tr":"Bir güvenlik görevlisi, bir müşterinin çantasını kapıp onun açık itirazına rağmen arıyor. Hangi ifade doğrudur?","hi":"एक गार्ड एक ग्राहक का पर्स पकड़ता है और उसकी स्पष्ट आपत्ति के बावजूद उसकी तलाशी लेता है। कौन सा कथन सही है?","ar":"يمسك حارس حقيبة يد عميلة ويفتشها رغم اعتراضها الواضح. أي عبارة صحيحة؟"},"o":[{"en":"This is fine because guards may search property inside the store","es":"Esto está bien porque los guardias pueden registrar la propiedad dentro de la tienda","ru":"Это нормально, потому что охранники могут обыскивать имущество внутри магазина","tr":"Bu sorun değil çünkü güvenlik görevlileri mağaza içindeki eşyaları arayabilir","hi":"यह ठीक है क्योंकि गार्ड स्टोर के भीतर संपत्ति की तलाशी ले सकते हैं","ar":"هذا مقبول لأنه يجوز للحراس تفتيش الممتلكات داخل المتجر"},{"en":"This is allowed as long as the guard suspects theft","es":"Esto está permitido siempre que el guardia sospeche de robo","ru":"Это допустимо, если охранник подозревает кражу","tr":"Güvenlik görevlisi hırsızlıktan şüphelendiği sürece buna izin verilir","hi":"यह अनुमत है जब तक गार्ड को चोरी का संदेह हो","ar":"هذا مسموح به طالما اشتبه الحارس في السرقة"},{"en":"This is allowed because entering the store implies consent to searches","es":"Esto está permitido porque entrar a la tienda implica consentimiento para registros","ru":"Это допустимо, потому что вход в магазин подразумевает согласие на обыски","tr":"Mağazaya girmek aramalara rıza anlamına geldiği için buna izin verilir","hi":"यह अनुमत है क्योंकि स्टोर में प्रवेश तलाशी की सहमति दर्शाता है","ar":"هذا مسموح به لأن دخول المتجر يعني ضمناً الموافقة على التفتيش"},{"en":"This is likely an unlawful forced search that can create liability","es":"Esto probablemente sea un registro forzoso ilegal que puede generar responsabilidad","ru":"Это, вероятно, незаконный принудительный обыск, который может повлечь ответственность","tr":"Bu muhtemelen sorumluluk doğurabilecek yasadışı bir zorla aramadır","hi":"यह संभवतः एक अवैध जबरन तलाशी है जो दायित्व पैदा कर सकती है","ar":"من المرجح أن يكون هذا تفتيشاً قسرياً غير قانوني قد ينشئ مسؤولية"}],"e":{"en":"A private guard generally cannot forcibly search a person's belongings over their objection. Doing so can be an unlawful search and lead to civil or criminal liability.","es":"Un guardia privado generalmente no puede registrar por la fuerza las pertenencias de una persona en contra de su objeción. Hacerlo puede ser un registro ilegal y generar responsabilidad civil o penal.","ru":"Частный охранник, как правило, не может принудительно обыскивать вещи человека вопреки его возражению. Это может быть незаконным обыском и повлечь гражданскую или уголовную ответственность.","tr":"Özel bir güvenlik görevlisi genellikle bir kişinin eşyalarını itirazına rağmen zorla arayamaz. Bunu yapmak yasadışı bir arama olabilir ve hukuki veya cezai sorumluluğa yol açabilir.","hi":"एक निजी गार्ड आम तौर पर किसी व्यक्ति की वस्तुओं की उसकी आपत्ति के विरुद्ध जबरन तलाशी नहीं ले सकता। ऐसा करना एक अवैध तलाशी हो सकती है और नागरिक या आपराधिक दायित्व का कारण बन सकती है।","ar":"لا يمكن للحارس الخاص عموماً تفتيش متعلقات شخص قسراً رغم اعتراضه. وقد يشكّل ذلك تفتيشاً غير قانوني ويؤدي إلى مسؤولية مدنية أو جنائية."}},{"cat":"legal","a":0,"q":{"en":"What should a security guard do if a lawful arrest situation is beyond their ability to handle safely?","es":"¿Qué debe hacer un guardia de seguridad si una situación de arresto legal está más allá de su capacidad para manejarla de forma segura?","ru":"Что должен делать охранник, если ситуация с законным арестом выходит за пределы его возможностей справиться безопасно?","tr":"Yasal bir tutuklama durumu, bir güvenlik görevlisinin güvenli bir şekilde başa çıkma kapasitesinin ötesindeyse ne yapmalıdır?","hi":"यदि एक वैध गिरफ्तारी की स्थिति एक सुरक्षा गार्ड की सुरक्षित रूप से संभालने की क्षमता से परे हो तो उसे क्या करना चाहिए?","ar":"ماذا يجب أن يفعل حارس الأمن إذا كان موقف اعتقال قانوني يفوق قدرته على التعامل معه بأمان؟"},"o":[{"en":"Observe, report, and call the police rather than escalate the confrontation","es":"Observar, reportar y llamar a la policía en lugar de escalar la confrontación","ru":"Наблюдать, докладывать и вызвать полицию, а не обострять противостояние","tr":"Karşılaşmayı tırmandırmak yerine gözlemlemek, rapor etmek ve polisi aramak","hi":"टकराव को बढ़ाने के बजाय निरीक्षण करना, रिपोर्ट करना और पुलिस को बुलाना","ar":"المراقبة والإبلاغ واستدعاء الشرطة بدلاً من تصعيد المواجهة"},{"en":"Use whatever force is necessary to win the confrontation","es":"Usar cualquier fuerza necesaria para ganar la confrontación","ru":"Применить любую необходимую силу, чтобы выиграть противостояние","tr":"Karşılaşmayı kazanmak için gerekli olan her türlü gücü kullanmak","hi":"टकराव जीतने के लिए जो भी बल आवश्यक हो उसका प्रयोग करना","ar":"استخدام أي قوة لازمة لكسب المواجهة"},{"en":"Follow the suspect home to gather more evidence","es":"Seguir al sospechoso hasta su casa para reunir más pruebas","ru":"Проследовать за подозреваемым домой, чтобы собрать больше доказательств","tr":"Daha fazla kanıt toplamak için şüpheliyi evine kadar takip etmek","hi":"अधिक साक्ष्य जुटाने के लिए संदिग्ध का पीछा करते हुए उसके घर तक जाना","ar":"تتبع المشتبه به إلى منزله لجمع مزيد من الأدلة"},{"en":"Ignore the situation entirely since guards have no duties","es":"Ignorar la situación por completo, ya que los guardias no tienen deberes","ru":"Полностью проигнорировать ситуацию, поскольку у охранников нет обязанностей","tr":"Güvenlik görevlilerinin görevi olmadığı için durumu tamamen görmezden gelmek","hi":"स्थिति को पूरी तरह अनदेखा करना क्योंकि गार्डों के कोई कर्तव्य नहीं हैं","ar":"تجاهل الموقف تماماً لأن الحراس ليس لديهم واجبات"}],"e":{"en":"The \"observe and report\" role is the safest approach. When a situation exceeds a guard's authority or safety, they should summon police rather than risk injury or liability by escalating.","es":"El papel de \"observar e informar\" es el enfoque más seguro. Cuando una situación excede la autoridad o seguridad de un guardia, debe llamar a la policía en lugar de arriesgar lesiones o responsabilidad al escalar.","ru":"Роль «наблюдать и докладывать» — самый безопасный подход. Когда ситуация превышает полномочия или безопасность охранника, ему следует вызвать полицию, а не рисковать травмами или ответственностью, обостряя ситуацию.","tr":"\"Gözlemle ve rapor et\" rolü en güvenli yaklaşımdır. Bir durum bir güvenlik görevlisinin yetkisini veya güvenliğini aştığında, tırmandırarak yaralanma veya sorumluluk riski almak yerine polisi çağırmalıdır.","hi":"\"निरीक्षण करें और रिपोर्ट करें\" भूमिका सबसे सुरक्षित दृष्टिकोण है। जब कोई स्थिति गार्ड के अधिकार या सुरक्षा से परे हो, तो उन्हें बढ़ाकर चोट या दायित्व का जोखिम लेने के बजाय पुलिस को बुलाना चाहिए।","ar":"دور \"المراقبة والإبلاغ\" هو النهج الأكثر أماناً. عندما يتجاوز موقف ما سلطة الحارس أو سلامته، عليه استدعاء الشرطة بدلاً من المخاطرة بالإصابة أو المساءلة عبر التصعيد."}},{"cat":"legal","a":1,"q":{"en":"How long may a guard hold a lawfully detained shoplifting suspect?","es":"¿Por cuánto tiempo puede un guardia retener a un sospechoso de hurto detenido legalmente?","ru":"Как долго охранник может удерживать законно задержанного подозреваемого в краже?","tr":"Bir güvenlik görevlisi, yasal olarak gözaltına alınan bir hırsızlık şüphelisini ne kadar süre tutabilir?","hi":"एक गार्ड कानूनी रूप से हिरासत में लिए गए चोरी के संदिग्ध को कितनी देर तक रोक सकता है?","ar":"كم من الوقت يجوز للحارس احتجاز مشتبه في سرقته بشكل قانوني؟"},"o":[{"en":"As long as needed to fully interrogate them","es":"El tiempo que sea necesario para interrogarlo por completo","ru":"Столько, сколько нужно для полного допроса","tr":"Onları tamamen sorgulamak için gereken süre kadar","hi":"उतनी देर तक जितनी उन्हें पूरी तरह पूछताछ करने के लिए आवश्यक हो","ar":"طالما يلزم لاستجوابه بالكامل"},{"en":"Only for a reasonable time, generally until police arrive","es":"Solo por un tiempo razonable, generalmente hasta que llegue la policía","ru":"Только в течение разумного времени, как правило, до прибытия полиции","tr":"Yalnızca makul bir süre, genellikle polis gelene kadar","hi":"केवल एक उचित समय के लिए, आम तौर पर पुलिस के आने तक","ar":"فقط لمدة معقولة، عادةً حتى وصول الشرطة"},{"en":"Up to 24 hours in a back room","es":"Hasta 24 horas en un cuarto trasero","ru":"До 24 часов в подсобном помещении","tr":"Bir arka odada 24 saate kadar","hi":"एक पिछले कमरे में 24 घंटे तक","ar":"حتى 24 ساعة في غرفة خلفية"},{"en":"Until the suspect agrees to pay for the merchandise","es":"Hasta que el sospechoso acepte pagar la mercancía","ru":"Пока подозреваемый не согласится оплатить товар","tr":"Şüpheli malın parasını ödemeyi kabul edene kadar","hi":"जब तक संदिग्ध माल के लिए भुगतान करने को सहमत न हो जाए","ar":"حتى يوافق المشتبه به على دفع ثمن البضاعة"}],"e":{"en":"A detention must last only a reasonable time and be conducted in a reasonable manner, normally just long enough to investigate and turn the person over to police. Excessive detention can be false imprisonment.","es":"Una detención debe durar solo un tiempo razonable y realizarse de manera razonable, normalmente lo suficiente para investigar y entregar a la persona a la policía. Una detención excesiva puede ser detención ilegal.","ru":"Задержание должно длиться только разумное время и проводиться разумным образом, обычно ровно столько, сколько нужно для проверки и передачи человека полиции. Чрезмерное задержание может быть незаконным лишением свободы.","tr":"Bir gözaltı yalnızca makul bir süre sürmeli ve makul bir şekilde yürütülmelidir, normalde yalnızca soruşturmaya ve kişiyi polise teslim etmeye yetecek kadar. Aşırı gözaltı haksız hürriyeti kısıtlama olabilir.","hi":"हिरासत केवल एक उचित समय तक चलनी चाहिए और उचित तरीके से की जानी चाहिए, आम तौर पर केवल इतनी देर तक कि जाँच की जा सके और व्यक्ति को पुलिस को सौंपा जा सके। अत्यधिक हिरासत झूठा कारावास हो सकती है।","ar":"يجب أن يستمر الاحتجاز لمدة معقولة فقط وأن يُجرى بطريقة معقولة، عادةً بما يكفي للتحقيق وتسليم الشخص إلى الشرطة. والاحتجاز المفرط قد يكون حبساً غير قانوني."}},{"cat":"legal","a":2,"q":{"en":"Which statement about a guard's authority is most accurate regarding where it applies?","es":"¿Qué afirmación sobre la autoridad de un guardia es más precisa respecto a dónde se aplica?","ru":"Какое утверждение о полномочиях охранника наиболее точно в отношении того, где они применяются?","tr":"Bir güvenlik görevlisinin yetkisinin nerede geçerli olduğu konusunda hangi ifade en doğrudur?","hi":"गार्ड के अधिकार के बारे में कौन सा कथन इस संबंध में सबसे सटीक है कि यह कहाँ लागू होता है?","ar":"أي عبارة حول سلطة الحارس هي الأدق فيما يتعلق بمكان تطبيقها؟"},"o":[{"en":"A guard has police powers throughout the entire city","es":"Un guardia tiene poderes policiales en toda la ciudad","ru":"Охранник обладает полицейскими полномочиями по всему городу","tr":"Bir güvenlik görevlisi tüm şehir genelinde polis yetkilerine sahiptir","hi":"एक गार्ड के पास पूरे शहर में पुलिस शक्तियाँ होती हैं","ar":"يملك الحارس صلاحيات الشرطة في جميع أنحاء المدينة"},{"en":"A guard's authority extends to anyone they personally consider suspicious anywhere","es":"La autoridad de un guardia se extiende a cualquiera que considere personalmente sospechoso en cualquier lugar","ru":"Полномочия охранника распространяются на любого, кого он лично считает подозрительным, где угодно","tr":"Bir güvenlik görevlisinin yetkisi, kişisel olarak şüpheli gördüğü herkese her yerde uzanır","hi":"एक गार्ड का अधिकार किसी भी ऐसे व्यक्ति तक फैला होता है जिसे वे कहीं भी व्यक्तिगत रूप से संदिग्ध मानते हैं","ar":"تمتد سلطة الحارس إلى أي شخص يعتبره شخصياً مشبوهاً في أي مكان"},{"en":"A guard's authority is generally limited to the property they are hired to protect","es":"La autoridad de un guardia generalmente se limita a la propiedad que fue contratado para proteger","ru":"Полномочия охранника, как правило, ограничены территорией, которую он нанят охранять","tr":"Bir güvenlik görevlisinin yetkisi genellikle korumak için işe alındığı mülkle sınırlıdır","hi":"एक गार्ड का अधिकार आम तौर पर उस संपत्ति तक सीमित होता है जिसकी सुरक्षा के लिए उन्हें नियुक्त किया गया है","ar":"تقتصر سلطة الحارس عموماً على الممتلكات التي عُيِّن لحمايتها"},{"en":"A guard has no authority anywhere, even on the property they protect","es":"Un guardia no tiene autoridad en ningún lugar, ni siquiera en la propiedad que protege","ru":"У охранника нет никаких полномочий нигде, даже на охраняемой им территории","tr":"Bir güvenlik görevlisinin hiçbir yerde, koruduğu mülkte bile yetkisi yoktur","hi":"एक गार्ड का कहीं भी कोई अधिकार नहीं है, यहाँ तक कि उस संपत्ति पर भी नहीं जिसकी वे रक्षा करते हैं","ar":"ليس للحارس أي سلطة في أي مكان، حتى في الممتلكات التي يحميها"}],"e":{"en":"A guard's authority generally comes from the property owner and is limited to the site they are assigned to protect. They do not carry police powers into public areas.","es":"La autoridad de un guardia generalmente proviene del propietario y se limita al sitio que se le asigna proteger. No portan poderes policiales en áreas públicas.","ru":"Полномочия охранника, как правило, исходят от собственника и ограничены объектом, который ему поручено охранять. Они не переносят полицейские полномочия в общественные места.","tr":"Bir güvenlik görevlisinin yetkisi genellikle mülk sahibinden gelir ve korumakla görevlendirildiği alanla sınırlıdır. Kamusal alanlara polis yetkisi taşımazlar.","hi":"एक गार्ड का अधिकार आम तौर पर संपत्ति के मालिक से आता है और उस स्थल तक सीमित होता है जिसकी रक्षा के लिए उन्हें नियुक्त किया गया है। वे सार्वजनिक क्षेत्रों में पुलिस शक्तियाँ नहीं ले जाते।","ar":"تأتي سلطة الحارس عموماً من مالك الممتلكات وتقتصر على الموقع المكلَّف بحمايته. وهم لا يحملون صلاحيات الشرطة إلى الأماكن العامة."}},{"cat":"legal","a":3,"q":{"en":"A guard sees a person shove another and steal their phone right in front of him. What is the guard's lawful option?","es":"Un guardia ve a una persona empujar a otra y robarle el teléfono justo frente a él. ¿Cuál es la opción legal del guardia?","ru":"Охранник видит, как человек толкает другого и крадёт его телефон прямо перед ним. Какой законный вариант есть у охранника?","tr":"Bir güvenlik görevlisi, tam önünde bir kişinin başka birini itip telefonunu çaldığını görüyor. Güvenlik görevlisinin yasal seçeneği nedir?","hi":"एक गार्ड देखता है कि एक व्यक्ति दूसरे को धक्का देकर उसका फोन ठीक उसके सामने चुरा लेता है। गार्ड का वैध विकल्प क्या है?","ar":"يرى حارس شخصاً يدفع آخر ويسرق هاتفه أمامه مباشرةً. ما الخيار القانوني للحارس؟"},"o":[{"en":"He must ignore it because guards can never get involved","es":"Debe ignorarlo porque los guardias nunca pueden involucrarse","ru":"Он должен проигнорировать это, потому что охранники никогда не могут вмешиваться","tr":"Görmezden gelmelidir çünkü güvenlik görevlileri asla müdahil olamaz","hi":"उसे इसे अनदेखा करना चाहिए क्योंकि गार्ड कभी शामिल नहीं हो सकते","ar":"يجب أن يتجاهله لأن الحراس لا يمكنهم التدخل أبداً"},{"en":"He may shoot the thief to recover the phone","es":"Puede disparar al ladrón para recuperar el teléfono","ru":"Он может застрелить вора, чтобы вернуть телефон","tr":"Telefonu geri almak için hırsızı vurabilir","hi":"वह फोन वापस पाने के लिए चोर को गोली मार सकता है","ar":"يجوز له إطلاق النار على اللص لاستعادة الهاتف"},{"en":"He must wait a week and then file a police report","es":"Debe esperar una semana y luego presentar un informe policial","ru":"Он должен подождать неделю, а затем подать заявление в полицию","tr":"Bir hafta beklemeli ve sonra bir polis raporu düzenlemelidir","hi":"उसे एक सप्ताह इंतजार करना चाहिए और फिर पुलिस रिपोर्ट दर्ज करनी चाहिए","ar":"يجب أن ينتظر أسبوعاً ثم يقدم بلاغاً للشرطة"},{"en":"He may make a citizen's arrest for the crime committed in his presence and hold the suspect for police","es":"Puede realizar un arresto ciudadano por el delito cometido en su presencia y retener al sospechoso para la policía","ru":"Он может произвести гражданский арест за преступление, совершённое в его присутствии, и удерживать подозреваемого до прибытия полиции","tr":"Huzurunda işlenen suç için vatandaşlık tutuklaması yapabilir ve şüpheliyi polis için tutabilir","hi":"वह अपनी उपस्थिति में किए गए अपराध के लिए नागरिक गिरफ्तारी कर सकता है और संदिग्ध को पुलिस के लिए रोक सकता है","ar":"يجوز له إجراء اعتقال مدني للجريمة المرتكبة في حضوره واحتجاز المشتبه به للشرطة"}],"e":{"en":"Because the crime occurred in the guard's presence, a citizen's arrest is a lawful option using only reasonable force; he then holds the suspect for police. Deadly force to recover property is not justified.","es":"Debido a que el delito ocurrió en presencia del guardia, un arresto ciudadano es una opción legal usando solo fuerza razonable; luego retiene al sospechoso para la policía. La fuerza letal para recuperar propiedad no está justificada.","ru":"Поскольку преступление произошло в присутствии охранника, гражданский арест является законным вариантом с применением только разумной силы; затем он удерживает подозреваемого до прибытия полиции. Смертоносная сила для возврата имущества не оправдана.","tr":"Suç güvenlik görevlisinin huzurunda işlendiği için, yalnızca makul güç kullanarak vatandaşlık tutuklaması yasal bir seçenektir; sonra şüpheliyi polis için tutar. Mülkü geri almak için öldürücü güç haklı değildir.","hi":"चूँकि अपराध गार्ड की उपस्थिति में हुआ, केवल उचित बल का प्रयोग करते हुए नागरिक गिरफ्तारी एक वैध विकल्प है; फिर वह संदिग्ध को पुलिस के लिए रोकता है। संपत्ति वापस पाने के लिए घातक बल उचित नहीं है।","ar":"نظراً لأن الجريمة وقعت في حضور الحارس، فإن الاعتقال المدني خيار قانوني باستخدام قوة معقولة فقط؛ ثم يحتجز المشتبه به للشرطة. والقوة المميتة لاستعادة الممتلكات غير مبررة."}},{"cat":"patrol","a":2,"q":{"en":"Why should a security guard vary the routes and times of foot patrols?","es":"¿Por qué debe un guardia de seguridad variar las rutas y los horarios de las rondas a pie?","ru":"Почему охранник должен менять маршруты и время пеших обходов?","tr":"Bir güvenlik görevlisi yaya devriye rotalarını ve saatlerini neden değiştirmelidir?","hi":"सुरक्षा गार्ड को पैदल गश्त के मार्ग और समय क्यों बदलते रहना चाहिए?","ar":"لماذا ينبغي لحارس الأمن أن يغيّر مسارات وأوقات دوريات المشي؟"},"o":[{"en":"To make the patrol easier and less tiring","es":"Para que la ronda sea más fácil y menos cansada","ru":"Чтобы обход был легче и менее утомительным","tr":"Devriyeyi daha kolay ve daha az yorucu hale getirmek için","hi":"गश्त को आसान और कम थकाऊ बनाने के लिए","ar":"لجعل الدورية أسهل وأقل إرهاقًا"},{"en":"So other guards always know exactly where to find you","es":"Para que otros guardias siempre sepan exactamente dónde encontrarlo","ru":"Чтобы другие охранники всегда точно знали, где вас найти","tr":"Diğer görevlilerin sizi her zaman tam olarak nerede bulacağını bilmesi için","hi":"ताकि अन्य गार्ड हमेशा जानें कि आप ठीक कहाँ हैं","ar":"لكي يعرف الحراس الآخرون دائمًا مكانك بالضبط"},{"en":"To make the guard's movements unpredictable so criminals cannot learn the pattern","es":"Para que los movimientos del guardia sean impredecibles y los delincuentes no aprendan el patrón","ru":"Чтобы передвижения охранника были непредсказуемыми и преступники не могли изучить схему","tr":"Görevlinin hareketlerini öngörülemez kılmak, böylece suçlular deseni öğrenemesin diye","hi":"ताकि गार्ड की गतिविधियाँ अप्रत्याशित हों और अपराधी पैटर्न न सीख सकें","ar":"لجعل تحركات الحارس غير متوقّعة حتى لا يتعلّم المجرمون النمط"},{"en":"Because the law requires a different route every day","es":"Porque la ley exige una ruta diferente cada día","ru":"Потому что закон требует разного маршрута каждый день","tr":"Çünkü yasa her gün farklı bir rota gerektirir","hi":"क्योंकि कानून हर दिन एक अलग मार्ग की माँग करता है","ar":"لأن القانون يفرض مسارًا مختلفًا كل يوم"}],"e":{"en":"Randomizing routes and times keeps patrols unpredictable so intruders cannot time their activity around a fixed schedule. Specific patterns may be set by post orders.","es":"Aleatorizar rutas y horarios mantiene las rondas impredecibles para que los intrusos no planifiquen según un horario fijo. Los patrones específicos pueden fijarse en las órdenes del puesto.","ru":"Случайный выбор маршрутов и времени делает обходы непредсказуемыми, чтобы нарушители не подстраивались под фиксированный график. Конкретные схемы могут задаваться инструкциями поста.","tr":"Rotaları ve saatleri rastgele değiştirmek devriyeleri öngörülemez kılar, böylece davetsiz misafirler sabit bir programa göre zaman ayarlayamaz. Belirli desenler görev talimatlarıyla belirlenebilir.","hi":"मार्ग और समय को यादृच्छिक करने से गश्त अप्रत्याशित रहती है ताकि घुसपैठिए किसी निश्चित समय-सारणी के अनुसार योजना न बना सकें। विशिष्ट पैटर्न पोस्ट ऑर्डर द्वारा तय हो सकते हैं।","ar":"إن جعل المسارات والأوقات عشوائية يبقي الدوريات غير متوقّعة حتى لا يوقّت المتسللون نشاطهم وفق جدول ثابت. وقد تُحدَّد الأنماط المعيّنة بأوامر الموقع."}},{"cat":"patrol","a":0,"q":{"en":"What are the three main purposes of a security patrol?","es":"¿Cuáles son los tres propósitos principales de una patrulla de seguridad?","ru":"Каковы три основные цели патрулирования?","tr":"Bir güvenlik devriyesinin üç ana amacı nedir?","hi":"सुरक्षा गश्त के तीन मुख्य उद्देश्य क्या हैं?","ar":"ما الأغراض الرئيسية الثلاثة للدورية الأمنية؟"},"o":[{"en":"To deter, detect, and report","es":"Disuadir, detectar e informar","ru":"Сдерживать, обнаруживать и докладывать","tr":"Caydırmak, tespit etmek ve rapor etmek","hi":"रोकना, पहचानना और रिपोर्ट करना","ar":"الردع والكشف والإبلاغ"},{"en":"To arrest, punish, and prosecute","es":"Arrestar, castigar y procesar","ru":"Арестовывать, наказывать и преследовать по закону","tr":"Tutuklamak, cezalandırmak ve kovuşturmak","hi":"गिरफ्तार करना, दंड देना और अभियोजन करना","ar":"الاعتقال والعقاب والملاحقة القضائية"},{"en":"To sell, guard, and clean","es":"Vender, custodiar y limpiar","ru":"Продавать, охранять и убирать","tr":"Satmak, korumak ve temizlemek","hi":"बेचना, रक्षा करना और साफ करना","ar":"البيع والحراسة والتنظيف"},{"en":"To relax, socialize, and observe","es":"Relajarse, socializar y observar","ru":"Отдыхать, общаться и наблюдать","tr":"Dinlenmek, sosyalleşmek ve gözlemlemek","hi":"आराम करना, मेलजोल बढ़ाना और अवलोकन करना","ar":"الاسترخاء والتواصل الاجتماعي والملاحظة"}],"e":{"en":"Patrols deter wrongdoers by a visible presence, detect problems early, and report what is found so the right people can act.","es":"Las rondas disuaden a los infractores con una presencia visible, detectan problemas a tiempo e informan lo hallado para que las personas adecuadas actúen.","ru":"Патрули сдерживают правонарушителей заметным присутствием, рано обнаруживают проблемы и докладывают о найденном, чтобы нужные люди могли действовать.","tr":"Devriyeler görünür varlıklarıyla suçluları caydırır, sorunları erkenden tespit eder ve bulunanları rapor eder, böylece doğru kişiler harekete geçebilir.","hi":"गश्त दृश्य उपस्थिति से गलत काम करने वालों को रोकती है, समस्याओं का जल्दी पता लगाती है और मिली बातों की रिपोर्ट करती है ताकि सही लोग कार्रवाई कर सकें।","ar":"تردع الدوريات المخالفين بوجودها المرئي، وتكشف المشكلات مبكرًا، وتُبلغ عمّا يُكتشف حتى يتصرّف الأشخاص المناسبون."}},{"cat":"patrol","a":1,"q":{"en":"When describing a person you observed, which features should you note first?","es":"Al describir a una persona que observó, ¿qué características debe anotar primero?","ru":"При описании замеченного человека какие признаки следует отметить в первую очередь?","tr":"Gözlemlediğiniz bir kişiyi tarif ederken önce hangi özellikleri not etmelisiniz?","hi":"जिस व्यक्ति को आपने देखा उसका वर्णन करते समय आपको पहले कौन-सी विशेषताएँ नोट करनी चाहिए?","ar":"عند وصف شخص لاحظته، ما الملامح التي ينبغي تدوينها أولًا؟"},"o":[{"en":"Clothing color and brand of shoes","es":"El color de la ropa y la marca de los zapatos","ru":"Цвет одежды и марку обуви","tr":"Kıyafet rengi ve ayakkabı markası","hi":"कपड़ों का रंग और जूतों का ब्रांड","ar":"لون الملابس وماركة الحذاء"},{"en":"Unchangeable features such as height, build, gender, age, and race","es":"Rasgos que no cambian, como estatura, complexión, género, edad y raza","ru":"Неизменяемые признаки: рост, телосложение, пол, возраст и раса","tr":"Boy, yapı, cinsiyet, yaş ve ırk gibi değiştirilemez özellikler","hi":"ऊँचाई, कद-काठी, लिंग, आयु और नस्ल जैसी न बदलने वाली विशेषताएँ","ar":"الملامح غير القابلة للتغيير مثل الطول والبنية والجنس والعمر والعِرق"},{"en":"The person's name and address","es":"El nombre y la dirección de la persona","ru":"Имя и адрес человека","tr":"Kişinin adı ve adresi","hi":"व्यक्ति का नाम और पता","ar":"اسم الشخص وعنوانه"},{"en":"What the person was thinking","es":"Lo que la persona estaba pensando","ru":"О чём человек думал","tr":"Kişinin ne düşündüğü","hi":"व्यक्ति क्या सोच रहा था","ar":"ما كان يفكر فيه الشخص"}],"e":{"en":"Note hard-to-change features first (height, build, gender, age, race), then clothing, because a suspect can quickly change or discard clothing.","es":"Anote primero los rasgos difíciles de cambiar (estatura, complexión, género, edad, raza) y luego la ropa, ya que un sospechoso puede cambiarse rápidamente.","ru":"Сначала отмечайте трудноизменяемые признаки (рост, телосложение, пол, возраст, раса), а затем одежду, поскольку подозреваемый может быстро сменить или выбросить одежду.","tr":"Önce değiştirilmesi zor özellikleri (boy, yapı, cinsiyet, yaş, ırk), sonra kıyafeti not edin; çünkü bir şüpheli kıyafetini hızla değiştirebilir veya çıkarabilir.","hi":"पहले कठिनाई से बदलने वाली विशेषताएँ (ऊँचाई, कद-काठी, लिंग, आयु, नस्ल) नोट करें, फिर कपड़े, क्योंकि संदिग्ध कपड़े जल्दी बदल या फेंक सकता है।","ar":"دوّن أولًا الملامح التي يصعب تغييرها (الطول والبنية والجنس والعمر والعِرق) ثم الملابس، لأن المشتبه به قد يغيّر ملابسه أو يتخلّص منها بسرعة."}},{"cat":"patrol","a":3,"q":{"en":"You find a door that is usually locked standing open during patrol. What is the best first step?","es":"Durante la ronda encuentra abierta una puerta que suele estar cerrada con llave. ¿Cuál es el mejor primer paso?","ru":"Во время обхода вы обнаруживаете открытой дверь, которая обычно заперта. Каков наилучший первый шаг?","tr":"Devriye sırasında normalde kilitli olan bir kapıyı açık buluyorsunuz. En iyi ilk adım nedir?","hi":"गश्त के दौरान आपको एक दरवाज़ा खुला मिलता है जो आमतौर पर बंद रहता है। सबसे अच्छा पहला कदम क्या है?","ar":"أثناء الدورية تجد بابًا يُقفل عادةً وهو مفتوح. ما أفضل خطوة أولى؟"},"o":[{"en":"Close and lock it immediately without looking further","es":"Cerrarla y asegurarla de inmediato sin revisar más","ru":"Немедленно закрыть и запереть её, не проверяя дальше","tr":"Daha fazla bakmadan hemen kapatıp kilitlemek","hi":"बिना आगे देखे इसे तुरंत बंद कर लॉक कर देना","ar":"إغلاقه وقفله فورًا دون فحص إضافي"},{"en":"Ignore it because it is probably nothing","es":"Ignorarla porque probablemente no es nada","ru":"Проигнорировать, ведь это, скорее всего, пустяк","tr":"Muhtemelen önemsizdir diye görmezden gelmek","hi":"इसे अनदेखा करना क्योंकि शायद कुछ नहीं है","ar":"تجاهله لأنه على الأرجح لا شيء"},{"en":"Go inside and search the entire building alone","es":"Entrar y registrar todo el edificio solo","ru":"Войти и в одиночку обыскать всё здание","tr":"İçeri girip tüm binayı tek başına aramak","hi":"अंदर जाकर पूरे भवन की अकेले तलाशी लेना","ar":"الدخول وتفتيش المبنى بأكمله بمفردك"},{"en":"Observe from a safe position, stay alert for anyone inside, and report it per post orders","es":"Observar desde una posición segura, estar atento a alguien dentro e informar según las órdenes del puesto","ru":"Наблюдать с безопасной позиции, быть настороже, нет ли кого внутри, и доложить согласно инструкциям поста","tr":"Güvenli bir konumdan gözlemlemek, içeride biri olabileceğine karşı tetikte olmak ve görev talimatlarına göre rapor etmek","hi":"सुरक्षित स्थान से देखना, अंदर किसी के होने के प्रति सतर्क रहना और पोस्ट ऑर्डर के अनुसार रिपोर्ट करना","ar":"المراقبة من موضع آمن، والبقاء متيقظًا لوجود أحد بالداخل، والإبلاغ وفق أوامر الموقع"}],"e":{"en":"An open door that should be locked may mean an intruder is present. Stay alert, do not rush in alone, and follow post orders for reporting and assistance.","es":"Una puerta abierta que debería estar cerrada puede indicar la presencia de un intruso. Manténgase alerta, no entre solo apresuradamente y siga las órdenes del puesto para informar y pedir ayuda.","ru":"Открытая дверь, которая должна быть заперта, может означать присутствие нарушителя. Будьте настороже, не врывайтесь в одиночку и следуйте инструкциям поста по докладу и вызову помощи.","tr":"Kilitli olması gereken açık bir kapı, içeride bir davetsiz misafir olabileceği anlamına gelebilir. Tetikte olun, tek başınıza aceleyle girmeyin ve rapor ile yardım için görev talimatlarını izleyin.","hi":"जो दरवाज़ा बंद होना चाहिए उसका खुला होना घुसपैठिए की उपस्थिति का संकेत हो सकता है। सतर्क रहें, अकेले जल्दबाज़ी में अंदर न जाएँ और रिपोर्टिंग व सहायता के लिए पोस्ट ऑर्डर का पालन करें।","ar":"قد يعني الباب المفتوح الذي يُفترض أن يكون مقفلًا وجود متسلل. ابقَ متيقظًا، ولا تندفع للداخل بمفردك، واتّبع أوامر الموقع للإبلاغ وطلب المساعدة."}},{"cat":"patrol","a":0,"q":{"en":"Which of the following is a common indicator of suspicious behavior?","es":"¿Cuál de los siguientes es un indicador común de conducta sospechosa?","ru":"Что из перечисленного является типичным признаком подозрительного поведения?","tr":"Aşağıdakilerden hangisi şüpheli davranışın yaygın bir göstergesidir?","hi":"निम्नलिखित में से कौन-सा संदिग्ध व्यवहार का एक सामान्य संकेतक है?","ar":"أيٌّ مما يلي مؤشّر شائع على سلوك مشبوه؟"},"o":[{"en":"A person testing door handles or windows to see if they are locked","es":"Una persona que prueba manijas o ventanas para ver si están cerradas","ru":"Человек, дёргающий дверные ручки или окна, чтобы проверить, заперты ли они","tr":"Kapı kollarını veya pencereleri kilitli olup olmadığını görmek için deneyen biri","hi":"कोई व्यक्ति दरवाज़े के हैंडल या खिड़कियाँ यह देखने के लिए आज़मा रहा हो कि वे बंद हैं या नहीं","ar":"شخص يجرّب مقابض الأبواب أو النوافذ لمعرفة ما إذا كانت مقفلة"},{"en":"A customer paying at the register","es":"Un cliente que paga en la caja","ru":"Покупатель, оплачивающий покупки на кассе","tr":"Kasada ödeme yapan bir müşteri","hi":"काउंटर पर भुगतान करता एक ग्राहक","ar":"زبون يدفع عند الصندوق"},{"en":"An employee wearing a visible ID badge","es":"Un empleado que lleva una identificación visible","ru":"Сотрудник с видимым удостоверением","tr":"Görünür kimlik kartı takan bir çalışan","hi":"दिखाई देने वाला पहचान बैज पहने एक कर्मचारी","ar":"موظف يرتدي بطاقة تعريف ظاهرة"},{"en":"A visitor asking the front desk for directions","es":"Un visitante que pide indicaciones en recepción","ru":"Посетитель, спрашивающий дорогу на ресепшене","tr":"Danışmaya yol soran bir ziyaretçi","hi":"रिसेप्शन पर रास्ता पूछता एक आगंतुक","ar":"زائر يسأل مكتب الاستقبال عن الاتجاهات"}],"e":{"en":"Testing doors and windows to find an unlocked entry is classic pre-crime behavior. Legitimate visitors and customers act openly and have a clear purpose.","es":"Probar puertas y ventanas para hallar una entrada abierta es una conducta previa al delito clásica. Los visitantes y clientes legítimos actúan abiertamente y con un propósito claro.","ru":"Проверка дверей и окон в поисках незапертого входа — классическое предпреступное поведение. Законные посетители и покупатели ведут себя открыто и имеют ясную цель.","tr":"Kilitsiz bir giriş bulmak için kapı ve pencereleri denemek klasik bir suç öncesi davranıştır. Meşru ziyaretçiler ve müşteriler açıkça hareket eder ve net bir amaçları vardır.","hi":"खुला प्रवेश ढूँढने के लिए दरवाज़े और खिड़कियाँ आज़माना अपराध-पूर्व का सामान्य व्यवहार है। वैध आगंतुक और ग्राहक खुलेआम काम करते हैं और उनका स्पष्ट उद्देश्य होता है।","ar":"إن تجربة الأبواب والنوافذ للعثور على مدخل غير مقفل سلوك كلاسيكي سابق للجريمة. أما الزوّار والزبائن الشرعيون فيتصرفون علنًا ولديهم غرض واضح."}},{"cat":"patrol","a":1,"q":{"en":"What is the correct attitude toward any alarm activation?","es":"¿Cuál es la actitud correcta ante cualquier activación de alarma?","ru":"Каково правильное отношение к любому срабатыванию сигнализации?","tr":"Herhangi bir alarm etkinleşmesine karşı doğru tutum nedir?","hi":"किसी भी अलार्म के सक्रिय होने के प्रति सही रवैया क्या है?","ar":"ما الموقف الصحيح تجاه أي تفعيل للإنذار؟"},"o":[{"en":"Assume it is a false alarm since most alarms are false","es":"Suponer que es una falsa alarma, ya que la mayoría lo son","ru":"Считать её ложной, ведь большинство тревог ложные","tr":"Çoğu alarm yanlış olduğundan yanlış alarm olduğunu varsaymak","hi":"यह मान लेना कि यह झूठा अलार्म है क्योंकि अधिकांश अलार्म झूठे होते हैं","ar":"افتراض أنه إنذار كاذب لأن معظم الإنذارات كاذبة"},{"en":"Treat every alarm as real until proven otherwise, and respond cautiously","es":"Tratar cada alarma como real hasta que se demuestre lo contrario y responder con cautela","ru":"Считать каждую тревогу настоящей, пока не доказано обратное, и реагировать осторожно","tr":"Aksi kanıtlanana kadar her alarmı gerçek kabul etmek ve temkinli müdahale etmek","hi":"हर अलार्म को तब तक असली मानना जब तक विपरीत सिद्ध न हो, और सतर्कता से प्रतिक्रिया देना","ar":"التعامل مع كل إنذار على أنه حقيقي حتى يثبت العكس، والاستجابة بحذر"},{"en":"Turn off the alarm and go back to your post","es":"Apagar la alarma y volver a su puesto","ru":"Отключить сигнализацию и вернуться на пост","tr":"Alarmı kapatıp görev yerine dönmek","hi":"अलार्म बंद कर अपनी पोस्ट पर लौट जाना","ar":"إيقاف الإنذار والعودة إلى موقعك"},{"en":"Wait for the alarm to stop on its own before doing anything","es":"Esperar a que la alarma se detenga sola antes de hacer algo","ru":"Ждать, пока сигнализация сама отключится, прежде чем что-либо делать","tr":"Bir şey yapmadan önce alarmın kendiliğinden durmasını beklemek","hi":"कुछ भी करने से पहले अलार्म के खुद बंद होने का इंतज़ार करना","ar":"انتظار توقّف الإنذار من تلقاء نفسه قبل فعل أي شيء"}],"e":{"en":"Never assume an alarm is false. Respond to every activation cautiously, verify the cause, and report it as your post orders require.","es":"Nunca suponga que una alarma es falsa. Responda a cada activación con cautela, verifique la causa e informe según lo exijan las órdenes del puesto.","ru":"Никогда не считайте тревогу ложной. Реагируйте на каждое срабатывание осторожно, выясняйте причину и докладывайте, как требуют инструкции поста.","tr":"Bir alarmın yanlış olduğunu asla varsaymayın. Her etkinleşmeye temkinli müdahale edin, nedenini doğrulayın ve görev talimatlarınızın gerektirdiği gibi rapor edin.","hi":"कभी न मानें कि अलार्म झूठा है। हर सक्रियता पर सतर्कता से प्रतिक्रिया दें, कारण की पुष्टि करें और अपने पोस्ट ऑर्डर के अनुसार रिपोर्ट करें।","ar":"لا تفترض أبدًا أن الإنذار كاذب. استجب لكل تفعيل بحذر، وتحقّق من السبب، وأبلغ كما تقتضي أوامر موقعك."}},{"cat":"patrol","a":2,"q":{"en":"An unarmed security guard's primary role in most situations is best described as:","es":"El papel principal de un guardia de seguridad sin armas en la mayoría de las situaciones se describe mejor como:","ru":"Основная роль невооружённого охранника в большинстве ситуаций лучше всего описывается как:","tr":"Silahsız bir güvenlik görevlisinin çoğu durumdaki asıl rolü en iyi şöyle tanımlanır:","hi":"अधिकांश स्थितियों में एक निहत्थे सुरक्षा गार्ड की मुख्य भूमिका का सबसे अच्छा वर्णन है:","ar":"يُوصف الدور الأساسي لحارس الأمن غير المسلّح في معظم المواقف على أفضل نحو بأنه:"},"o":[{"en":"Law enforcement officer with arrest powers","es":"Agente del orden con facultades de arresto","ru":"Сотрудник правоохранительных органов с правом ареста","tr":"Tutuklama yetkisine sahip kolluk görevlisi","hi":"गिरफ्तारी की शक्तियों वाला कानून प्रवर्तन अधिकारी","ar":"ضابط إنفاذ قانون يملك صلاحيات الاعتقال"},{"en":"Physical enforcer who stops crimes by force","es":"Ejecutor físico que detiene delitos por la fuerza","ru":"Силовик, пресекающий преступления с помощью силы","tr":"Suçları güç kullanarak durduran fiziksel bir uygulayıcı","hi":"शारीरिक बल-प्रयोगकर्ता जो बल से अपराध रोकता है","ar":"مُنفِّذ جسدي يوقف الجرائم بالقوة"},{"en":"The 'eyes and ears' of the client who observes and reports","es":"Los 'ojos y oídos' del cliente que observa e informa","ru":"«Глаза и уши» клиента, который наблюдает и докладывает","tr":"Gözlemleyip rapor eden, müşterinin 'gözü ve kulağı'","hi":"ग्राहक की 'आँख और कान' जो अवलोकन कर रिपोर्ट करता है","ar":"'عيون وآذان' العميل الذي يلاحظ ويُبلغ"},{"en":"Maintenance worker for the property","es":"Trabajador de mantenimiento de la propiedad","ru":"Работник по обслуживанию объекта","tr":"Mülkün bakım görevlisi","hi":"संपत्ति के लिए रखरखाव कर्मचारी","ar":"عامل صيانة للممتلكات"}],"e":{"en":"Unarmed guards mainly observe and report, acting as the eyes and ears of the client. They are not police and generally avoid physical intervention.","es":"Los guardias sin armas principalmente observan e informan, actuando como los ojos y oídos del cliente. No son policías y por lo general evitan la intervención física.","ru":"Невооружённые охранники в основном наблюдают и докладывают, выступая глазами и ушами клиента. Они не полиция и, как правило, избегают физического вмешательства.","tr":"Silahsız görevliler esasen gözlemleyip rapor eder ve müşterinin gözü kulağı gibi davranır. Polis değildirler ve genellikle fiziksel müdahaleden kaçınırlar.","hi":"निहत्थे गार्ड मुख्यतः अवलोकन कर रिपोर्ट करते हैं और ग्राहक की आँख-कान के रूप में कार्य करते हैं। वे पुलिस नहीं हैं और आम तौर पर शारीरिक हस्तक्षेप से बचते हैं।","ar":"يقوم الحراس غير المسلّحين أساسًا بالملاحظة والإبلاغ، ويعملون كعيون وآذان للعميل. وهم ليسوا شرطة ويتجنّبون عمومًا التدخّل الجسدي."}},{"cat":"patrol","a":3,"q":{"en":"What is the main advantage of vehicle patrol compared to foot patrol?","es":"¿Cuál es la principal ventaja de la patrulla vehicular frente a la patrulla a pie?","ru":"В чём главное преимущество автопатруля по сравнению с пешим патрулём?","tr":"Araçlı devriyenin yaya devriyeye kıyasla temel avantajı nedir?","hi":"पैदल गश्त की तुलना में वाहन गश्त का मुख्य लाभ क्या है?","ar":"ما الميزة الرئيسية للدورية بالمركبة مقارنةً بدورية المشي؟"},"o":[{"en":"It lets the guard observe fine details more closely","es":"Permite al guardia observar detalles finos más de cerca","ru":"Он позволяет охраннику ближе рассматривать мелкие детали","tr":"Görevlinin ince ayrıntıları daha yakından gözlemlemesini sağlar","hi":"यह गार्ड को बारीक विवरण अधिक निकट से देखने देती है","ar":"يتيح للحارس ملاحظة التفاصيل الدقيقة عن قرب"},{"en":"It removes the need to ever leave the vehicle","es":"Elimina la necesidad de salir del vehículo","ru":"Он избавляет от необходимости когда-либо выходить из машины","tr":"Araçtan hiç inme ihtiyacını ortadan kaldırır","hi":"यह वाहन से कभी बाहर निकलने की आवश्यकता समाप्त कर देती है","ar":"يلغي الحاجة إلى مغادرة المركبة على الإطلاق"},{"en":"It is always safer than being on foot","es":"Siempre es más seguro que ir a pie","ru":"Он всегда безопаснее, чем передвигаться пешком","tr":"Yürümekten her zaman daha güvenlidir","hi":"यह पैदल चलने से हमेशा सुरक्षित होती है","ar":"إنه دائمًا أكثر أمانًا من السير على الأقدام"},{"en":"It covers more ground quickly across a large property","es":"Cubre más terreno rápidamente en una propiedad grande","ru":"Он быстро охватывает большую территорию на крупном объекте","tr":"Geniş bir mülkte hızla daha fazla alanı kapsar","hi":"यह बड़ी संपत्ति में तेज़ी से अधिक क्षेत्र कवर करती है","ar":"يغطي مساحة أكبر بسرعة عبر عقار كبير"}],"e":{"en":"Vehicles cover large areas fast but you see less detail at speed. Park and walk high-risk areas on foot to observe closely. Site rules on vehicle use vary.","es":"Los vehículos cubren grandes áreas rápido, pero se ve menos detalle a velocidad. Estacione y recorra a pie las zonas de alto riesgo para observar de cerca. Las reglas del sitio varían.","ru":"Автомобили быстро охватывают большие площади, но на скорости видно меньше деталей. В зонах повышенного риска паркуйтесь и обходите их пешком для внимательного наблюдения. Правила объекта различаются.","tr":"Araçlar geniş alanları hızlı kapsar ama hızda daha az ayrıntı görürsünüz. Yüksek riskli alanları yakından gözlemlemek için park edip yürüyün. Araç kullanımına dair saha kuralları değişir.","hi":"वाहन बड़े क्षेत्रों को तेज़ी से कवर करते हैं पर गति में कम विवरण दिखता है। उच्च-जोखिम वाले क्षेत्रों में पास से देखने के लिए पार्क कर पैदल चलें। वाहन उपयोग के साइट नियम अलग-अलग होते हैं।","ar":"تغطي المركبات مساحات كبيرة بسرعة لكنك ترى تفاصيل أقل عند السرعة. أوقف المركبة وسِر مشيًا في المناطق عالية الخطورة للملاحظة عن قرب. وتختلف قواعد الموقع بشأن استخدام المركبات."}},{"cat":"patrol","a":0,"q":{"en":"Why is a written key sign-out log important for key control?","es":"¿Por qué es importante un registro escrito de entrega de llaves para el control de llaves?","ru":"Почему письменный журнал выдачи ключей важен для контроля ключей?","tr":"Anahtar kontrolü için yazılı bir anahtar teslim kaydı neden önemlidir?","hi":"चाबी नियंत्रण के लिए लिखित चाबी साइन-आउट लॉग क्यों महत्वपूर्ण है?","ar":"لماذا يُعدّ سجل تسليم المفاتيح المكتوب مهمًا للتحكم بالمفاتيح؟"},"o":[{"en":"It shows who has each key and when it was taken or returned","es":"Muestra quién tiene cada llave y cuándo se retiró o devolvió","ru":"Он показывает, у кого какой ключ и когда его взяли или вернули","tr":"Her anahtarın kimde olduğunu ve ne zaman alındığını veya iade edildiğini gösterir","hi":"यह दिखाता है कि प्रत्येक चाबी किसके पास है और वह कब ली या लौटाई गई","ar":"يبيّن من يحمل كل مفتاح ومتى أُخذ أو أُعيد"},{"en":"It replaces the need to lock any doors","es":"Elimina la necesidad de cerrar puertas con llave","ru":"Он избавляет от необходимости запирать двери","tr":"Herhangi bir kapıyı kilitleme ihtiyacını ortadan kaldırır","hi":"यह किसी भी दरवाज़े को लॉक करने की आवश्यकता समाप्त कर देता है","ar":"يلغي الحاجة إلى قفل أي أبواب"},{"en":"It lets guards keep keys at home for convenience","es":"Permite a los guardias llevarse las llaves a casa por comodidad","ru":"Он позволяет охранникам держать ключи дома для удобства","tr":"Görevlilerin kolaylık için anahtarları evde tutmasına izin verir","hi":"यह गार्ड को सुविधा के लिए चाबियाँ घर पर रखने देता है","ar":"يسمح للحراس بالاحتفاظ بالمفاتيح في المنزل للراحة"},{"en":"It is only needed once a year for the audit","es":"Solo se necesita una vez al año para la auditoría","ru":"Он нужен только раз в год для аудита","tr":"Yalnızca yılda bir kez denetim için gereklidir","hi":"यह केवल वर्ष में एक बार ऑडिट के लिए आवश्यक है","ar":"لا يُحتاج إليه إلا مرة واحدة سنويًا للتدقيق"}],"e":{"en":"A sign-in/out log creates accountability by recording who holds each key and when. This helps trace responsibility and detect missing keys quickly.","es":"Un registro de entrada/salida genera responsabilidad al anotar quién tiene cada llave y cuándo. Ayuda a rastrear la responsabilidad y detectar llaves faltantes rápidamente.","ru":"Журнал выдачи и возврата обеспечивает подотчётность, фиксируя, у кого какой ключ и когда. Это помогает установить ответственность и быстро выявить пропажу ключей.","tr":"Teslim alma/iade kaydı, her anahtarı kimin ne zaman aldığını yazarak hesap verebilirlik sağlar. Bu, sorumluluğu izlemeye ve kayıp anahtarları hızla tespit etmeye yardımcı olur.","hi":"साइन-इन/आउट लॉग यह दर्ज करके जवाबदेही बनाता है कि कौन-सी चाबी किसके पास और कब है। इससे ज़िम्मेदारी का पता लगाने और गायब चाबियों की जल्दी पहचान में मदद मिलती है।","ar":"يُنشئ سجل التسليم والإعادة مساءلةً بتسجيل من يحمل كل مفتاح ومتى. وهذا يساعد على تتبّع المسؤولية واكتشاف المفاتيح المفقودة بسرعة."}},{"cat":"patrol","a":1,"q":{"en":"During patrol you notice a backpack left alone near a busy building entrance. What should you do?","es":"Durante la ronda nota una mochila abandonada cerca de una entrada concurrida. ¿Qué debe hacer?","ru":"Во время обхода вы замечаете оставленный без присмотра рюкзак у оживлённого входа. Что делать?","tr":"Devriye sırasında kalabalık bir bina girişinin yakınında tek başına bırakılmış bir sırt çantası fark ediyorsunuz. Ne yapmalısınız?","hi":"गश्त के दौरान आप एक व्यस्त प्रवेश द्वार के पास अकेला छोड़ा गया एक बैकपैक देखते हैं। आपको क्या करना चाहिए?","ar":"أثناء الدورية تلاحظ حقيبة ظهر متروكة وحدها قرب مدخل مبنى مزدحم. ماذا تفعل؟"},"o":[{"en":"Open it to find out who owns it","es":"Abrirla para averiguar de quién es","ru":"Открыть его, чтобы узнать, чей он","tr":"Sahibini bulmak için açmak","hi":"यह पता लगाने के लिए इसे खोलना कि यह किसका है","ar":"فتحها لمعرفة صاحبها"},{"en":"Do not touch it, keep people away, and report it immediately","es":"No tocarla, mantener a la gente alejada e informar de inmediato","ru":"Не трогать его, отвести людей и немедленно доложить","tr":"Ona dokunmamak, insanları uzak tutmak ve derhal rapor etmek","hi":"इसे न छूना, लोगों को दूर रखना और तुरंत रिपोर्ट करना","ar":"عدم لمسها، وإبعاد الناس عنها، والإبلاغ عنها فورًا"},{"en":"Move it to the lost-and-found","es":"Llevarla a objetos perdidos","ru":"Отнести его в бюро находок","tr":"Kayıp eşya bölümüne götürmek","hi":"इसे खोया-पाया केंद्र में ले जाना","ar":"نقلها إلى قسم المفقودات"},{"en":"Ignore it and continue your patrol","es":"Ignorarla y continuar la ronda","ru":"Проигнорировать и продолжить обход","tr":"Görmezden gelip devriyeye devam etmek","hi":"इसे अनदेखा कर गश्त जारी रखना","ar":"تجاهلها ومتابعة دوريتك"}],"e":{"en":"An unattended item that does not fit could be dangerous. Do not touch or move it, keep people at a safe distance, and report it right away.","es":"Un objeto abandonado que no encaja podría ser peligroso. No lo toque ni lo mueva, mantenga a las personas a una distancia segura e informe de inmediato.","ru":"Оставленный без присмотра неуместный предмет может быть опасен. Не трогайте и не перемещайте его, держите людей на безопасном расстоянии и немедленно доложите.","tr":"Yerinde durmayan sahipsiz bir eşya tehlikeli olabilir. Ona dokunmayın veya kımıldatmayın, insanları güvenli mesafede tutun ve hemen rapor edin.","hi":"जगह से मेल न खाती लावारिस वस्तु खतरनाक हो सकती है। इसे न छुएँ न हिलाएँ, लोगों को सुरक्षित दूरी पर रखें और तुरंत रिपोर्ट करें।","ar":"قد يكون الغرض المتروك غير المناسب للمكان خطيرًا. لا تلمسه أو تحرّكه، وأبقِ الناس على مسافة آمنة، وأبلغ فورًا."}},{"cat":"patrol","a":2,"q":{"en":"Why should a guard record observations in a notebook as soon as possible?","es":"¿Por qué debe un guardia anotar sus observaciones en una libreta lo antes posible?","ru":"Почему охранник должен записывать наблюдения в блокнот как можно скорее?","tr":"Bir görevli gözlemlerini neden mümkün olan en kısa sürede bir deftere yazmalıdır?","hi":"एक गार्ड को अपने अवलोकन यथाशीघ्र नोटबुक में क्यों दर्ज करने चाहिए?","ar":"لماذا ينبغي للحارس أن يدوّن ملاحظاته في دفتر بأسرع وقت ممكن؟"},"o":[{"en":"To pass the time during a slow shift","es":"Para pasar el tiempo en un turno tranquilo","ru":"Чтобы скоротать время в спокойную смену","tr":"Sakin bir vardiyada vakit geçirmek için","hi":"धीमी पाली में समय बिताने के लिए","ar":"لتمضية الوقت في مناوبة هادئة"},{"en":"Because notes are not allowed to be corrected later","es":"Porque las notas no se pueden corregir después","ru":"Потому что записи нельзя исправлять позже","tr":"Çünkü notların sonradan düzeltilmesine izin verilmez","hi":"क्योंकि नोट्स को बाद में सुधारने की अनुमति नहीं है","ar":"لأنه لا يُسمح بتصحيح الملاحظات لاحقًا"},{"en":"Memory fades quickly, and prompt notes keep details accurate","es":"La memoria se desvanece rápido y las notas oportunas mantienen los detalles exactos","ru":"Память быстро угасает, а своевременные записи сохраняют точность деталей","tr":"Hafıza hızla zayıflar; hemen alınan notlar ayrıntıları doğru tutar","hi":"स्मृति जल्दी धुँधली हो जाती है, और तुरंत लिए गए नोट्स विवरण को सटीक रखते हैं","ar":"تتلاشى الذاكرة بسرعة، والملاحظات الفورية تُبقي التفاصيل دقيقة"},{"en":"So the guard does not have to file a report","es":"Para que el guardia no tenga que presentar un informe","ru":"Чтобы охраннику не нужно было составлять отчёт","tr":"Görevlinin rapor yazmak zorunda kalmaması için","hi":"ताकि गार्ड को रिपोर्ट दाखिल न करनी पड़े","ar":"لكي لا يضطر الحارس إلى تقديم تقرير"}],"e":{"en":"People forget details fast, so write down descriptions, times, and events promptly while they are fresh to keep your report accurate.","es":"Las personas olvidan los detalles rápido, así que anote descripciones, horas y sucesos de inmediato mientras están frescos para mantener su informe exacto.","ru":"Люди быстро забывают детали, поэтому записывайте описания, время и события сразу, пока они свежи, чтобы отчёт был точным.","tr":"İnsanlar ayrıntıları hızla unutur; bu yüzden açıklamaları, saatleri ve olayları taze iken hemen yazın ki raporunuz doğru olsun.","hi":"लोग विवरण जल्दी भूल जाते हैं, इसलिए विवरण, समय और घटनाओं को तुरंत ताज़ा रहते हुए लिखें ताकि आपकी रिपोर्ट सटीक रहे।","ar":"ينسى الناس التفاصيل بسرعة، لذا دوّن الأوصاف والأوقات والأحداث فورًا وهي طازجة في ذهنك للحفاظ على دقة تقريرك."}},{"cat":"patrol","a":3,"q":{"en":"What should a guard do immediately after discovering that an assigned key is lost or missing?","es":"¿Qué debe hacer un guardia inmediatamente después de descubrir que una llave asignada se perdió o falta?","ru":"Что должен сделать охранник сразу после обнаружения потери или пропажи закреплённого за ним ключа?","tr":"Bir görevli, kendisine verilen bir anahtarın kaybolduğunu veya eksik olduğunu fark ettiğinde hemen ne yapmalıdır?","hi":"जब किसी गार्ड को पता चले कि उसे सौंपी गई चाबी खो गई है या गायब है, तो उसे तुरंत क्या करना चाहिए?","ar":"ماذا ينبغي للحارس أن يفعل فور اكتشافه فقدان مفتاح مُسلَّم إليه أو ضياعه؟"},"o":[{"en":"Say nothing and hope it turns up later","es":"No decir nada y esperar que aparezca después","ru":"Ничего не говорить и надеяться, что он найдётся позже","tr":"Hiçbir şey söylememek ve sonradan çıkacağını ummak","hi":"कुछ न कहना और उम्मीद करना कि बाद में मिल जाएगी","ar":"عدم قول شيء وأمل أن يظهر لاحقًا"},{"en":"Buy a copy of the key to replace it quietly","es":"Comprar una copia de la llave para reemplazarla en silencio","ru":"Тихо купить копию ключа для замены","tr":"Sessizce değiştirmek için anahtarın bir kopyasını yaptırmak","hi":"चुपचाप बदलने के लिए चाबी की एक प्रति खरीदना","ar":"شراء نسخة من المفتاح لاستبداله بهدوء"},{"en":"Wait until the end of the shift to mention it","es":"Esperar hasta el final del turno para mencionarlo","ru":"Подождать до конца смены, чтобы упомянуть об этом","tr":"Bunu belirtmek için vardiya sonunu beklemek","hi":"इसका उल्लेख करने के लिए पाली के अंत तक इंतज़ार करना","ar":"الانتظار حتى نهاية المناوبة لذكره"},{"en":"Report the lost key to a supervisor right away","es":"Informar de la llave perdida a un supervisor de inmediato","ru":"Немедленно доложить о потерянном ключе руководителю","tr":"Kayıp anahtarı hemen bir amire bildirmek","hi":"खोई हुई चाबी की तुरंत पर्यवेक्षक को रिपोर्ट करना","ar":"إبلاغ المشرف بالمفتاح المفقود على الفور"}],"e":{"en":"A lost key is a serious security breach. Report it immediately so locks can be changed or extra precautions taken before it is misused.","es":"Una llave perdida es una grave brecha de seguridad. Infórmelo de inmediato para que se cambien las cerraduras o se tomen precauciones antes de que se use mal.","ru":"Потерянный ключ — серьёзная брешь в безопасности. Немедленно сообщите об этом, чтобы можно было сменить замки или принять дополнительные меры до его неправомерного использования.","tr":"Kayıp bir anahtar ciddi bir güvenlik ihlalidir. Kilitlerin değiştirilebilmesi veya kötüye kullanılmadan önce ek önlemler alınabilmesi için hemen bildirin.","hi":"खोई हुई चाबी एक गंभीर सुरक्षा उल्लंघन है। इसे तुरंत रिपोर्ट करें ताकि ताले बदले जा सकें या दुरुपयोग से पहले अतिरिक्त सावधानियाँ ली जा सकें।","ar":"المفتاح المفقود اختراق أمني خطير. أبلغ عنه فورًا حتى يمكن تغيير الأقفال أو اتخاذ احتياطات إضافية قبل إساءة استخدامه."}},{"cat":"patrol","a":0,"q":{"en":"What is a systematic way to scan an area so you do not miss anything?","es":"¿Cuál es una forma sistemática de examinar un área para no pasar nada por alto?","ru":"Какой существует системный способ осматривать участок, чтобы ничего не упустить?","tr":"Hiçbir şeyi kaçırmamak için bir alanı sistematik olarak tarama yöntemi nedir?","hi":"किसी क्षेत्र को व्यवस्थित रूप से स्कैन करने का ऐसा कौन-सा तरीका है जिससे कुछ छूटे नहीं?","ar":"ما الطريقة المنهجية لمسح منطقة بحيث لا يفوتك شيء؟"},"o":[{"en":"Scan slowly in a consistent pattern, such as left to right and near to far","es":"Examinar despacio con un patrón constante, como de izquierda a derecha y de cerca a lejos","ru":"Осматривать медленно по постоянной схеме, например слева направо и от ближнего к дальнему","tr":"Soldan sağa ve yakından uzağa gibi tutarlı bir düzende yavaşça taramak","hi":"एक सुसंगत पैटर्न में धीरे-धीरे स्कैन करना, जैसे बाएँ से दाएँ और पास से दूर","ar":"المسح ببطء وفق نمط ثابت، مثل من اليسار إلى اليمين ومن القريب إلى البعيد"},{"en":"Glance around quickly and move on","es":"Echar un vistazo rápido y seguir","ru":"Быстро оглядеться и идти дальше","tr":"Hızlıca göz gezdirip devam etmek","hi":"जल्दी से इधर-उधर देखकर आगे बढ़ जाना","ar":"إلقاء نظرة سريعة والمضي قدمًا"},{"en":"Focus only on the ground in front of you","es":"Concentrarse solo en el suelo frente a usted","ru":"Смотреть только на землю перед собой","tr":"Yalnızca önünüzdeki zemine odaklanmak","hi":"केवल अपने सामने की ज़मीन पर ध्यान देना","ar":"التركيز فقط على الأرض أمامك"},{"en":"Look only where you expect trouble","es":"Mirar solo donde espera problemas","ru":"Смотреть только туда, где ожидаете проблем","tr":"Yalnızca sorun beklediğiniz yere bakmak","hi":"केवल वहीं देखना जहाँ आप परेशानी की उम्मीद करते हैं","ar":"النظر فقط حيث تتوقّع المتاعب"}],"e":{"en":"Scanning in a steady, overlapping pattern (for example left to right, near to far) and pausing on details helps you notice things a quick glance would miss.","es":"Examinar con un patrón constante y superpuesto (por ejemplo, de izquierda a derecha, de cerca a lejos) y detenerse en los detalles le ayuda a notar cosas que un vistazo rápido pasaría por alto.","ru":"Осмотр по ровной, перекрывающейся схеме (например, слева направо, от ближнего к дальнему) с задержкой на деталях помогает заметить то, что упустил бы беглый взгляд.","tr":"Düzenli, örtüşen bir düzende tarama (örneğin soldan sağa, yakından uzağa) ve ayrıntılarda durma, hızlı bir bakışın kaçıracağı şeyleri fark etmenize yardımcı olur.","hi":"एक स्थिर, अतिव्यापी पैटर्न में स्कैन करना (जैसे बाएँ से दाएँ, पास से दूर) और विवरणों पर रुकना आपको वह देखने में मदद करता है जिसे एक झलक चूक जाती।","ar":"يساعدك المسح وفق نمط ثابت متداخل (مثل من اليسار إلى اليمين ومن القريب إلى البعيد) والتوقّف عند التفاصيل على ملاحظة أشياء تفوتها النظرة السريعة."}},{"cat":"patrol","a":1,"q":{"en":"Why should a security guard never lend an assigned key to another person?","es":"¿Por qué un guardia de seguridad nunca debe prestar una llave asignada a otra persona?","ru":"Почему охранник никогда не должен давать закреплённый за ним ключ другому лицу?","tr":"Bir güvenlik görevlisi kendisine verilen anahtarı neden asla başka birine ödünç vermemelidir?","hi":"एक सुरक्षा गार्ड को अपनी सौंपी गई चाबी कभी किसी और को क्यों नहीं देनी चाहिए?","ar":"لماذا يجب على حارس الأمن ألّا يُعير أبدًا مفتاحًا مُسلَّمًا إليه لشخص آخر؟"},"o":[{"en":"Because keys wear out when others use them","es":"Porque las llaves se desgastan cuando otros las usan","ru":"Потому что ключи изнашиваются, когда ими пользуются другие","tr":"Çünkü anahtarlar başkaları kullanınca aşınır","hi":"क्योंकि जब अन्य लोग उपयोग करते हैं तो चाबियाँ घिस जाती हैं","ar":"لأن المفاتيح تبلى عندما يستخدمها آخرون"},{"en":"It breaks the chain of accountability and can allow unauthorized access","es":"Rompe la cadena de responsabilidad y puede permitir accesos no autorizados","ru":"Это разрывает цепочку подотчётности и может дать несанкционированный доступ","tr":"Hesap verebilirlik zincirini kırar ve yetkisiz erişime izin verebilir","hi":"यह जवाबदेही की शृंखला तोड़ता है और अनधिकृत पहुँच की अनुमति दे सकता है","ar":"يكسر سلسلة المساءلة وقد يسمح بدخول غير مصرّح به"},{"en":"Because lending keys is illegal in every state","es":"Porque prestar llaves es ilegal en todos los estados","ru":"Потому что давать ключи взаймы незаконно во всех штатах","tr":"Çünkü anahtar ödünç vermek her eyalette yasa dışıdır","hi":"क्योंकि चाबियाँ उधार देना हर राज्य में अवैध है","ar":"لأن إعارة المفاتيح غير قانونية في كل ولاية"},{"en":"Because other people cannot be trusted to walk","es":"Porque no se puede confiar en que otras personas caminen","ru":"Потому что другим людям нельзя доверить ходить","tr":"Çünkü başkalarına yürümeleri konusunda güvenilemez","hi":"क्योंकि अन्य लोगों पर चलने का भरोसा नहीं किया जा सकता","ar":"لأنه لا يمكن الوثوق بالآخرين في المشي"}],"e":{"en":"Keys are issued to a specific person who is accountable for them. Lending a key lets unauthorized people in and destroys the record of who had access.","es":"Las llaves se entregan a una persona concreta que es responsable de ellas. Prestar una llave permite el ingreso de personas no autorizadas y destruye el registro de quién tuvo acceso.","ru":"Ключи выдаются конкретному лицу, которое за них отвечает. Передача ключа впускает посторонних и уничтожает запись о том, у кого был доступ.","tr":"Anahtarlar, onlardan sorumlu belirli bir kişiye verilir. Anahtar ödünç vermek yetkisiz kişilerin girmesine yol açar ve kimin erişim sağladığına dair kaydı yok eder.","hi":"चाबियाँ एक विशिष्ट व्यक्ति को दी जाती हैं जो उनके लिए जवाबदेह होता है। चाबी उधार देने से अनधिकृत लोग अंदर आ सकते हैं और यह रिकॉर्ड मिट जाता है कि किसके पास पहुँच थी।","ar":"تُصرف المفاتيح لشخص محدّد يكون مسؤولًا عنها. وإعارة المفتاح تُدخل أشخاصًا غير مصرّح لهم وتُتلف سجل من كان لديه إمكانية الوصول."}},{"cat":"patrol","a":2,"q":{"en":"While driving a slow vehicle patrol at night, how can a guard best stay observant?","es":"Al conducir una patrulla vehicular lenta de noche, ¿cómo puede un guardia mantenerse más atento?","ru":"Как охраннику лучше всего сохранять наблюдательность при медленном ночном автопатруле?","tr":"Gece yavaş bir araçlı devriye yaparken bir görevli nasıl en iyi şekilde dikkatli kalabilir?","hi":"रात में धीमी वाहन गश्त चलाते समय एक गार्ड सबसे बेहतर तरीके से सतर्क कैसे रह सकता है?","ar":"أثناء قيادة دورية بمركبة ببطء ليلًا، كيف يمكن للحارس أن يبقى منتبهًا على أفضل نحو؟"},"o":[{"en":"Drive fast so the patrol finishes sooner","es":"Conducir rápido para terminar la ronda antes","ru":"Ехать быстро, чтобы обход закончился раньше","tr":"Devriye daha erken bitsin diye hızlı sürmek","hi":"तेज़ चलाना ताकि गश्त जल्दी खत्म हो","ar":"القيادة بسرعة لتنتهي الدورية أبكر"},{"en":"Keep the radio loud and windows up the whole time","es":"Mantener la radio a todo volumen y las ventanas cerradas todo el tiempo","ru":"Держать радио громким и окна закрытыми всё время","tr":"Radyoyu sürekli açık ve camları hep kapalı tutmak","hi":"पूरे समय रेडियो तेज़ और खिड़कियाँ बंद रखना","ar":"إبقاء الراديو مرتفعًا والنوافذ مغلقة طوال الوقت"},{"en":"Drive slowly, use headlights and a spotlight, and scan constantly","es":"Conducir despacio, usar los faros y un reflector, y examinar constantemente","ru":"Ехать медленно, использовать фары и прожектор и постоянно осматривать","tr":"Yavaş sürmek, farları ve el projektörünü kullanmak ve sürekli taramak","hi":"धीरे चलाना, हेडलाइट व स्पॉटलाइट का उपयोग करना और लगातार स्कैन करना","ar":"القيادة ببطء واستخدام المصابيح الأمامية وكشّاف الضوء والمسح باستمرار"},{"en":"Look only straight ahead at the road","es":"Mirar solo al frente, hacia la carretera","ru":"Смотреть только прямо на дорогу","tr":"Yalnızca yola, ileriye bakmak","hi":"केवल सीधे सड़क की ओर देखना","ar":"النظر فقط إلى الأمام نحو الطريق"}],"e":{"en":"Drive slowly, keep the radio low, and use headlights or a spotlight to check dark areas while scanning your surroundings. Speed reduces what you can observe.","es":"Conduzca despacio, baje la radio y use los faros o un reflector para revisar zonas oscuras mientras examina el entorno. La velocidad reduce lo que puede observar.","ru":"Ехать медленно, приглушить радио и использовать фары или прожектор для осмотра тёмных участков, наблюдая за окружением. Скорость снижает то, что можно заметить.","tr":"Yavaş sürün, radyoyu kısın ve çevrenizi tararken karanlık alanları kontrol etmek için farları veya el projektörünü kullanın. Hız, gözlemleyebildiklerinizi azaltır.","hi":"धीरे चलाएँ, रेडियो धीमा रखें और अपने आस-पास स्कैन करते हुए अँधेरे क्षेत्रों को जाँचने के लिए हेडलाइट या स्पॉटलाइट का उपयोग करें। गति आपके अवलोकन को कम कर देती है।","ar":"قُد ببطء، واخفض صوت الراديو، واستخدم المصابيح الأمامية أو الكشّاف لفحص المناطق المظلمة أثناء مسح محيطك. فالسرعة تقلّل ما يمكنك ملاحظته."}},{"cat":"patrol","a":3,"q":{"en":"An intrusion alarm, a fire alarm, and a panic alarm mainly differ in:","es":"Una alarma de intrusión, una de incendio y una de pánico se diferencian principalmente en:","ru":"Сигнализация проникновения, пожарная и тревожная кнопка в основном различаются:","tr":"Bir izinsiz giriş alarmı, bir yangın alarmı ve bir panik alarmı temelde şu bakımdan farklıdır:","hi":"घुसपैठ अलार्म, अग्नि अलार्म और पैनिक अलार्म मुख्य रूप से किसमें भिन्न होते हैं:","ar":"يختلف إنذار الاقتحام وإنذار الحريق وإنذار الطوارئ أساسًا في:"},"o":[{"en":"The color of the wires used","es":"El color de los cables usados","ru":"Цвете используемых проводов","tr":"Kullanılan kabloların renginde","hi":"उपयोग किए गए तारों के रंग में","ar":"لون الأسلاك المستخدمة"},{"en":"How loud each one sounds","es":"Cuán fuerte suena cada una","ru":"Громкости их звучания","tr":"Her birinin ne kadar yüksek çaldığında","hi":"प्रत्येक के कितने ज़ोर से बजने में","ar":"مدى ارتفاع صوت كل منها"},{"en":"Which company installed them","es":"Qué empresa las instaló","ru":"Компании, которая их установила","tr":"Onları hangi şirketin kurduğunda","hi":"किस कंपनी ने उन्हें स्थापित किया","ar":"الشركة التي ركّبتها"},{"en":"The type of threat they signal and the response each requires","es":"El tipo de amenaza que señalan y la respuesta que requiere cada una","ru":"Типе угрозы, о которой они сигнализируют, и требуемой реакции","tr":"İşaret ettikleri tehdidin türünde ve her birinin gerektirdiği müdahalede","hi":"वे किस प्रकार के खतरे का संकेत देते हैं और प्रत्येक के लिए किस प्रतिक्रिया की आवश्यकता है, इसमें","ar":"نوع التهديد الذي تشير إليه والاستجابة التي يتطلبها كل منها"}],"e":{"en":"Different alarms signal different emergencies (break-in, fire, or a person in danger), and each calls for a different response. Know what each means at your site.","es":"Las distintas alarmas señalan distintas emergencias (robo, incendio o una persona en peligro) y cada una exige una respuesta diferente. Sepa qué significa cada una en su sitio.","ru":"Разные сигнализации сообщают о разных чрезвычайных ситуациях (взлом, пожар или человек в опасности), и каждая требует своей реакции. Знайте, что означает каждая на вашем объекте.","tr":"Farklı alarmlar farklı acil durumları (hırsızlık, yangın veya tehlikedeki bir kişi) bildirir ve her biri farklı bir müdahale gerektirir. Sahanızda her birinin ne anlama geldiğini bilin.","hi":"अलग-अलग अलार्म अलग-अलग आपात स्थितियों (सेंधमारी, आग या खतरे में व्यक्ति) का संकेत देते हैं, और प्रत्येक के लिए अलग प्रतिक्रिया आवश्यक है। जानें कि आपके स्थल पर प्रत्येक का क्या अर्थ है।","ar":"تشير الإنذارات المختلفة إلى حالات طوارئ مختلفة (اقتحام أو حريق أو شخص في خطر)، ويتطلّب كلٌّ منها استجابة مختلفة. اعرف معنى كلٍّ منها في موقعك."}},{"cat":"patrol","a":0,"q":{"en":"A person keeps walking back and forth past a store entrance, watching the guard and cameras. This behavior most likely suggests:","es":"Una persona pasa una y otra vez frente a la entrada de una tienda, observando al guardia y las cámaras. Esta conducta sugiere con mayor probabilidad:","ru":"Человек снова и снова прохаживается мимо входа в магазин, наблюдая за охранником и камерами. Это поведение, скорее всего, указывает на:","tr":"Bir kişi bir mağaza girişinin önünde ileri geri yürüyüp durarak görevliyi ve kameraları izliyor. Bu davranış büyük olasılıkla şuna işaret eder:","hi":"एक व्यक्ति बार-बार किसी दुकान के प्रवेश द्वार के आगे-पीछे चलता है, गार्ड और कैमरों को देखता है। यह व्यवहार सबसे अधिक संभवतः संकेत देता है:","ar":"يواصل شخص التنقل ذهابًا وإيابًا أمام مدخل متجر، ويراقب الحارس والكاميرات. هذا السلوك يشير على الأرجح إلى:"},"o":[{"en":"Possible casing or surveillance of the location before a crime","es":"Posible reconocimiento o vigilancia del lugar antes de un delito","ru":"Возможную разведку или наблюдение за местом перед преступлением","tr":"Bir suç öncesinde mekânın olası keşfi veya gözetlenmesi","hi":"अपराध से पहले स्थान की संभावित रेकी या निगरानी","ar":"احتمال استطلاع الموقع أو مراقبته قبل ارتكاب جريمة"},{"en":"That the person is definitely lost","es":"Que la persona está definitivamente perdida","ru":"Что человек точно заблудился","tr":"Kişinin kesinlikle kaybolduğunu","hi":"कि व्यक्ति निश्चित रूप से खो गया है","ar":"أن الشخص ضائع بالتأكيد"},{"en":"That the person works for the store","es":"Que la persona trabaja para la tienda","ru":"Что человек работает в магазине","tr":"Kişinin mağazada çalıştığını","hi":"कि व्यक्ति दुकान के लिए काम करता है","ar":"أن الشخص يعمل لدى المتجر"},{"en":"That there is nothing worth noting","es":"Que no hay nada digno de mención","ru":"Что нет ничего, что стоило бы отметить","tr":"Kayda değer bir şey olmadığını","hi":"कि ध्यान देने योग्य कुछ नहीं है","ar":"أنه لا شيء يستحق الملاحظة"}],"e":{"en":"Repeatedly watching guards, cameras, and exits can indicate someone is casing the location to plan a crime. Note the details and report while continuing to observe.","es":"Observar repetidamente a los guardias, las cámaras y las salidas puede indicar que alguien está reconociendo el lugar para planear un delito. Anote los detalles e informe mientras sigue observando.","ru":"Постоянное наблюдение за охраной, камерами и выходами может указывать на то, что кто-то изучает место для подготовки преступления. Запишите детали и доложите, продолжая наблюдать.","tr":"Görevlileri, kameraları ve çıkışları tekrar tekrar izlemek, birinin suç planlamak için mekânı keşfettiğine işaret edebilir. Ayrıntıları not edin ve gözlemeye devam ederken rapor edin.","hi":"बार-बार गार्ड, कैमरे और निकास देखना यह संकेत दे सकता है कि कोई अपराध की योजना बनाने के लिए स्थान की रेकी कर रहा है। विवरण नोट करें और अवलोकन जारी रखते हुए रिपोर्ट करें।","ar":"إن مراقبة الحراس والكاميرات والمخارج بشكل متكرّر قد يدلّ على أن أحدهم يستطلع الموقع لتخطيط جريمة. دوّن التفاصيل وأبلغ مع الاستمرار في الملاحظة."}},{"cat":"patrol","a":1,"q":{"en":"Why is a master key considered especially sensitive and in need of extra security?","es":"¿Por qué se considera una llave maestra especialmente sensible y necesitada de seguridad adicional?","ru":"Почему мастер-ключ считается особенно важным и требующим дополнительной защиты?","tr":"Bir ana anahtar neden özellikle hassas kabul edilir ve ekstra güvenlik gerektirir?","hi":"मास्टर चाबी को विशेष रूप से संवेदनशील और अतिरिक्त सुरक्षा की आवश्यकता वाली क्यों माना जाता है?","ar":"لماذا يُعدّ المفتاح الرئيسي حساسًا بشكل خاص ويحتاج إلى أمان إضافي؟"},"o":[{"en":"It is more expensive than other keys","es":"Es más cara que otras llaves","ru":"Он дороже других ключей","tr":"Diğer anahtarlardan daha pahalıdır","hi":"यह अन्य चाबियों से अधिक महँगी होती है","ar":"إنه أغلى من المفاتيح الأخرى"},{"en":"It can open many or all locks, so its loss or misuse is very dangerous","es":"Puede abrir muchas o todas las cerraduras, por lo que su pérdida o mal uso es muy peligroso","ru":"Он может открывать многие или все замки, поэтому его потеря или неправомерное использование очень опасны","tr":"Birçok veya tüm kilidi açabilir, bu yüzden kaybı veya kötüye kullanımı çok tehlikelidir","hi":"यह कई या सभी तालों को खोल सकती है, इसलिए इसका खोना या दुरुपयोग बहुत खतरनाक है","ar":"يمكنه فتح أقفال كثيرة أو جميعها، لذا فقدانه أو إساءة استخدامه خطير جدًا"},{"en":"It is made of a different metal","es":"Está hecha de un metal diferente","ru":"Он сделан из другого металла","tr":"Farklı bir metalden yapılmıştır","hi":"यह एक अलग धातु से बनी होती है","ar":"إنه مصنوع من معدن مختلف"},{"en":"It only works during the day","es":"Solo funciona durante el día","ru":"Он работает только днём","tr":"Yalnızca gündüz çalışır","hi":"यह केवल दिन में काम करती है","ar":"إنه يعمل فقط أثناء النهار"}],"e":{"en":"A master key opens many or all locks in a facility, so if it is lost or copied, an intruder could access everything. It requires the strictest control.","es":"Una llave maestra abre muchas o todas las cerraduras de una instalación, así que si se pierde o se copia, un intruso podría acceder a todo. Requiere el control más estricto.","ru":"Мастер-ключ открывает многие или все замки объекта, поэтому при его потере или копировании нарушитель может получить доступ ко всему. Он требует строжайшего контроля.","tr":"Bir ana anahtar bir tesisteki birçok veya tüm kilidi açar; kaybolur veya kopyalanırsa bir davetsiz misafir her yere erişebilir. En sıkı kontrolü gerektirir.","hi":"मास्टर चाबी किसी सुविधा के कई या सभी तालों को खोलती है, इसलिए यदि यह खो जाए या इसकी नकल बन जाए तो घुसपैठिया हर जगह पहुँच सकता है। इसके लिए सबसे सख्त नियंत्रण आवश्यक है।","ar":"يفتح المفتاح الرئيسي أقفالًا كثيرة أو جميعها في منشأة، فإن فُقد أو نُسخ أمكن لمتسلل الوصول إلى كل شيء. لذا يتطلّب أشدّ تحكّم."}},{"cat":"patrol","a":2,"q":{"en":"You see someone in a restricted employee-only area wearing no ID and unfamiliar to staff. This is an example of:","es":"Ve a alguien en un área restringida solo para empleados, sin identificación y desconocido para el personal. Este es un ejemplo de:","ru":"Вы видите человека в зоне только для сотрудников без удостоверения, незнакомого персоналу. Это пример:","tr":"Yalnızca çalışanlara özel kısıtlı bir alanda, kimliği olmayan ve personelin tanımadığı birini görüyorsunuz. Bu şuna bir örnektir:","hi":"आप केवल कर्मचारियों के लिए प्रतिबंधित क्षेत्र में किसी को बिना पहचान-पत्र और स्टाफ के लिए अपरिचित देखते हैं। यह किसका उदाहरण है:","ar":"ترى شخصًا في منطقة مقيّدة مخصّصة للموظفين فقط، بلا بطاقة تعريف وغير معروف للطاقم. هذا مثال على:"},"o":[{"en":"Normal daily activity you can ignore","es":"Actividad diaria normal que puede ignorar","ru":"Обычную повседневную активность, которую можно проигнорировать","tr":"Görmezden gelebileceğiniz normal günlük etkinlik","hi":"सामान्य दैनिक गतिविधि जिसे आप अनदेखा कर सकते हैं","ar":"نشاط يومي عادي يمكنك تجاهله"},{"en":"A guest who should be given a master key","es":"Un invitado al que se le debe dar una llave maestra","ru":"Гостя, которому следует выдать мастер-ключ","tr":"Kendisine ana anahtar verilmesi gereken bir misafir","hi":"एक अतिथि जिसे मास्टर चाबी दी जानी चाहिए","ar":"ضيف ينبغي إعطاؤه مفتاحًا رئيسيًا"},{"en":"A person who does not belong, which should be checked and reported","es":"Una persona que no pertenece allí, lo cual debe verificarse e informarse","ru":"Постороннего, чьё присутствие нужно проверить и о котором нужно доложить","tr":"Oraya ait olmayan, kontrol edilip rapor edilmesi gereken biri","hi":"एक ऐसा व्यक्ति जो वहाँ का नहीं है, जिसकी जाँच कर रिपोर्ट की जानी चाहिए","ar":"شخص لا ينتمي إلى المكان، وينبغي التحقّق منه والإبلاغ عنه"},{"en":"A reason to leave your post permanently","es":"Una razón para abandonar su puesto de forma permanente","ru":"Повод навсегда покинуть свой пост","tr":"Görev yerinizi kalıcı olarak terk etmek için bir neden","hi":"अपनी पोस्ट को स्थायी रूप से छोड़ने का कारण","ar":"سبب لمغادرة موقعك نهائيًا"}],"e":{"en":"Someone with no credentials in a restricted area who staff do not recognize does not belong. Politely verify their identity and reason for being there, and report it.","es":"Alguien sin credenciales en un área restringida a quien el personal no reconoce no pertenece allí. Verifique con cortesía su identidad y motivo, e informe.","ru":"Человек без пропуска в закрытой зоне, которого не узнаёт персонал, там не должен находиться. Вежливо проверьте его личность и причину нахождения и доложите.","tr":"Kısıtlı bir alanda, personelin tanımadığı ve kimlik belgesi olmayan biri oraya ait değildir. Kimliğini ve orada bulunma nedenini nazikçe doğrulayın ve rapor edin.","hi":"प्रतिबंधित क्षेत्र में बिना पहचान-पत्र वाला व्यक्ति जिसे स्टाफ नहीं पहचानता, वहाँ का नहीं है। विनम्रता से उसकी पहचान और वहाँ होने का कारण सत्यापित करें और रिपोर्ट करें।","ar":"الشخص الذي لا يحمل تصريحًا في منطقة مقيّدة ولا يعرفه الطاقم لا ينتمي إليها. تحقّق بلطف من هويته وسبب وجوده، وأبلغ عن ذلك."}},{"cat":"patrol","a":3,"q":{"en":"What is a key limitation of vehicle patrol that foot patrol does not share?","es":"¿Cuál es una limitación clave de la patrulla vehicular que la patrulla a pie no tiene?","ru":"В чём ключевое ограничение автопатруля, которого нет у пешего патруля?","tr":"Yaya devriyede olmayan, araçlı devriyenin temel bir sınırlaması nedir?","hi":"वाहन गश्त की एक प्रमुख सीमा क्या है जो पैदल गश्त में नहीं होती?","ar":"ما القيد الرئيسي للدورية بالمركبة الذي لا تشترك فيه دورية المشي؟"},"o":[{"en":"It can never be used at night","es":"Nunca se puede usar de noche","ru":"Его нельзя использовать ночью","tr":"Gece asla kullanılamaz","hi":"इसे रात में कभी उपयोग नहीं किया जा सकता","ar":"لا يمكن استخدامها ليلًا أبدًا"},{"en":"It cannot cover outdoor areas","es":"No puede cubrir áreas exteriores","ru":"Он не может охватывать наружные зоны","tr":"Açık alanları kapsayamaz","hi":"यह बाहरी क्षेत्रों को कवर नहीं कर सकती","ar":"لا يمكنها تغطية المناطق الخارجية"},{"en":"It requires two guards at all times","es":"Requiere dos guardias en todo momento","ru":"Он всегда требует двух охранников","tr":"Her zaman iki görevli gerektirir","hi":"इसके लिए हर समय दो गार्ड आवश्यक होते हैं","ar":"تتطلّب حارسين في كل الأوقات"},{"en":"You observe less fine detail and cannot easily reach tight or indoor spaces","es":"Se observa menos detalle fino y no se pueden alcanzar fácilmente espacios estrechos o interiores","ru":"Вы замечаете меньше мелких деталей и не можете легко попасть в тесные или внутренние помещения","tr":"Daha az ince ayrıntı gözlemlersiniz ve dar veya kapalı alanlara kolayca ulaşamazsınız","hi":"आप कम बारीक विवरण देखते हैं और तंग या भीतरी स्थानों तक आसानी से नहीं पहुँच सकते","ar":"تلاحظ تفاصيل دقيقة أقل ولا يمكنك بسهولة الوصول إلى الأماكن الضيّقة أو الداخلية"}],"e":{"en":"From a vehicle you miss fine details and cannot reach stairwells, tight corners, or indoor spaces. That is why guards park and patrol high-risk spots on foot.","es":"Desde un vehículo se pierden detalles finos y no se puede llegar a escaleras, rincones estrechos o espacios interiores. Por eso los guardias estacionan y patrullan a pie los puntos de alto riesgo.","ru":"Из машины вы упускаете мелкие детали и не можете попасть на лестницы, в тесные углы или помещения. Поэтому охранники паркуются и обходят зоны повышенного риска пешком.","tr":"Araçtan ince ayrıntıları kaçırırsınız ve merdiven boşluklarına, dar köşelere veya kapalı alanlara ulaşamazsınız. Bu yüzden görevliler park edip yüksek riskli noktaları yürüyerek devriye gezer.","hi":"वाहन से आप बारीक विवरण चूक जाते हैं और सीढ़ियों, तंग कोनों या भीतरी स्थानों तक नहीं पहुँच सकते। इसीलिए गार्ड पार्क कर उच्च-जोखिम वाले स्थानों पर पैदल गश्त करते हैं।","ar":"من داخل المركبة تفوتك التفاصيل الدقيقة ولا يمكنك الوصول إلى السلالم أو الزوايا الضيّقة أو الأماكن الداخلية. لذلك يوقف الحراس المركبة ويقومون بالدورية مشيًا في النقاط عالية الخطورة."}},{"cat":"emergency","a":0,"q":{"en":"A fire involving ordinary combustibles such as wood, paper, and cloth is classified as which class of fire?","es":"Un incendio que involucra combustibles ordinarios como madera, papel y tela se clasifica como qué clase de fuego?","ru":"Пожар с участием обычных горючих материалов, таких как дерево, бумага и ткань, относится к какому классу пожара?","tr":"Ahşap, kağıt ve kumaş gibi sıradan yanıcı maddelerin bulunduğu bir yangın hangi yangın sınıfına girer?","hi":"लकड़ी, कागज और कपड़े जैसे सामान्य दहनशील पदार्थों वाली आग को किस श्रेणी की आग के रूप में वर्गीकृत किया जाता है?","ar":"الحريق الذي يشمل مواد قابلة للاحتراق عادية مثل الخشب والورق والقماش يُصنَّف ضمن أي فئة من فئات الحرائق؟"},"o":[{"en":"Class A","es":"Clase A","ru":"Класс A","tr":"Sınıf A","hi":"श्रेणी A","ar":"الفئة A"},{"en":"Class B","es":"Clase B","ru":"Класс B","tr":"Sınıf B","hi":"श्रेणी B","ar":"الفئة B"},{"en":"Class C","es":"Clase C","ru":"Класс C","tr":"Sınıf C","hi":"श्रेणी C","ar":"الفئة C"},{"en":"Class K","es":"Clase K","ru":"Класс K","tr":"Sınıf K","hi":"श्रेणी K","ar":"الفئة K"}],"e":{"en":"Class A fires involve ordinary combustibles like wood, paper, cloth, and most plastics, and can be extinguished with water or an ABC dry chemical extinguisher.","es":"Los incendios de Clase A involucran combustibles ordinarios como madera, papel, tela y la mayoría de los plásticos, y pueden extinguirse con agua o un extintor de polvo químico seco ABC.","ru":"Пожары класса A связаны с обычными горючими материалами, такими как дерево, бумага, ткань и большинство пластмасс, и могут быть потушены водой или порошковым огнетушителем ABC.","tr":"Sınıf A yangınları ahşap, kağıt, kumaş ve çoğu plastik gibi sıradan yanıcı maddeleri içerir ve su veya ABC kuru kimyasal söndürücü ile söndürülebilir.","hi":"श्रेणी A की आग में लकड़ी, कागज, कपड़ा और अधिकांश प्लास्टिक जैसे सामान्य दहनशील पदार्थ शामिल होते हैं, और इन्हें पानी या ABC सूखे रसायन अग्निशामक से बुझाया जा सकता है।","ar":"حرائق الفئة A تشمل المواد القابلة للاحتراق العادية مثل الخشب والورق والقماش ومعظم أنواع البلاستيك، ويمكن إخمادها بالماء أو بطفاية مسحوق كيميائي جاف من نوع ABC."}},{"cat":"emergency","a":1,"q":{"en":"A fire fueled by flammable liquids such as gasoline, oil, or paint is classified as which class of fire?","es":"Un incendio alimentado por líquidos inflamables como gasolina, aceite o pintura se clasifica como qué clase de fuego?","ru":"Пожар, вызванный легковоспламеняющимися жидкостями, такими как бензин, масло или краска, относится к какому классу пожара?","tr":"Benzin, yağ veya boya gibi yanıcı sıvıların beslediği bir yangın hangi yangın sınıfına girer?","hi":"पेट्रोल, तेल या पेंट जैसे ज्वलनशील तरल पदार्थों से लगने वाली आग को किस श्रेणी की आग के रूप में वर्गीकृत किया जाता है?","ar":"الحريق الذي تغذّيه السوائل القابلة للاشتعال مثل البنزين أو الزيت أو الطلاء يُصنَّف ضمن أي فئة من فئات الحرائق؟"},"o":[{"en":"Class A","es":"Clase A","ru":"Класс A","tr":"Sınıf A","hi":"श्रेणी A","ar":"الفئة A"},{"en":"Class B","es":"Clase B","ru":"Класс B","tr":"Sınıf B","hi":"श्रेणी B","ar":"الفئة B"},{"en":"Class C","es":"Clase C","ru":"Класс C","tr":"Sınıf C","hi":"श्रेणी C","ar":"الفئة C"},{"en":"Class D","es":"Clase D","ru":"Класс D","tr":"Sınıf D","hi":"श्रेणी D","ar":"الفئة D"}],"e":{"en":"Class B fires involve flammable liquids and gases such as gasoline, oil, grease in liquid form, and paint; never use water, which can spread the fuel.","es":"Los incendios de Clase B involucran líquidos y gases inflamables como gasolina, aceite, grasa en forma líquida y pintura; nunca use agua, que puede propagar el combustible.","ru":"Пожары класса B связаны с легковоспламеняющимися жидкостями и газами, такими как бензин, масло, жир в жидком виде и краска; никогда не используйте воду, которая может распространить топливо.","tr":"Sınıf B yangınları benzin, yağ, sıvı haldeki gres ve boya gibi yanıcı sıvı ve gazları içerir; yakıtı yayabileceği için asla su kullanmayın.","hi":"श्रेणी B की आग में पेट्रोल, तेल, तरल रूप में ग्रीस और पेंट जैसे ज्वलनशील तरल और गैस शामिल होते हैं; कभी पानी का उपयोग न करें, जो ईंधन को फैला सकता है।","ar":"حرائق الفئة B تشمل السوائل والغازات القابلة للاشتعال مثل البنزين والزيت والشحوم السائلة والطلاء؛ لا تستخدم الماء أبدًا لأنه قد ينشر الوقود."}},{"cat":"emergency","a":2,"q":{"en":"A fire involving energized (live) electrical equipment is classified as which class of fire?","es":"Un incendio que involucra equipo eléctrico energizado (con corriente) se clasifica como qué clase de fuego?","ru":"Пожар с участием электрооборудования под напряжением относится к какому классу пожара?","tr":"Enerji altında (elektrik yüklü) elektrikli ekipmanın bulunduğu bir yangın hangi yangın sınıfına girer?","hi":"ऊर्जावान (चालू) विद्युत उपकरण वाली आग को किस श्रेणी की आग के रूप में वर्गीकृत किया जाता है?","ar":"الحريق الذي يشمل معدات كهربائية مكهربة (تحت التيار) يُصنَّف ضمن أي فئة من فئات الحرائق؟"},"o":[{"en":"Class A","es":"Clase A","ru":"Класс A","tr":"Sınıf A","hi":"श्रेणी A","ar":"الفئة A"},{"en":"Class B","es":"Clase B","ru":"Класс B","tr":"Sınıf B","hi":"श्रेणी B","ar":"الفئة B"},{"en":"Class C","es":"Clase C","ru":"Класс C","tr":"Sınıf C","hi":"श्रेणी C","ar":"الفئة C"},{"en":"Class K","es":"Clase K","ru":"Класс K","tr":"Sınıf K","hi":"श्रेणी K","ar":"الفئة K"}],"e":{"en":"Class C fires involve energized electrical equipment; never use water because of the risk of electric shock. Use a Class C or ABC dry chemical extinguisher.","es":"Los incendios de Clase C involucran equipo eléctrico energizado; nunca use agua debido al riesgo de descarga eléctrica. Use un extintor Clase C o de polvo químico seco ABC.","ru":"Пожары класса C связаны с электрооборудованием под напряжением; никогда не используйте воду из-за риска поражения электрическим током. Используйте огнетушитель класса C или порошковый ABC.","tr":"Sınıf C yangınları enerji altındaki elektrikli ekipmanı içerir; elektrik çarpması riski nedeniyle asla su kullanmayın. Sınıf C veya ABC kuru kimyasal söndürücü kullanın.","hi":"श्रेणी C की आग में ऊर्जावान विद्युत उपकरण शामिल होते हैं; बिजली के झटके के जोखिम के कारण कभी पानी का उपयोग न करें। श्रेणी C या ABC सूखे रसायन अग्निशामक का उपयोग करें।","ar":"حرائق الفئة C تشمل المعدات الكهربائية المكهربة؛ لا تستخدم الماء أبدًا بسبب خطر الصعق الكهربائي. استخدم طفاية من الفئة C أو مسحوقًا كيميائيًا جافًا من نوع ABC."}},{"cat":"emergency","a":3,"q":{"en":"In a commercial kitchen, a fire in a deep fryer involving cooking oils and fats requires which class of fire extinguisher?","es":"En una cocina comercial, un incendio en una freidora que involucra aceites y grasas de cocina requiere qué clase de extintor de incendios?","ru":"На коммерческой кухне пожар во фритюрнице с участием кулинарных масел и жиров требует огнетушителя какого класса?","tr":"Ticari bir mutfakta, pişirme yağları ve katı yağların bulunduğu bir fritöz yangını hangi sınıf yangın söndürücüyü gerektirir?","hi":"एक वाणिज्यिक रसोई में, डीप फ्रायर में खाना पकाने के तेल और वसा वाली आग के लिए किस श्रेणी के अग्निशामक की आवश्यकता होती है?","ar":"في مطبخ تجاري، يتطلب حريق المقلاة العميقة الذي يشمل زيوت الطهي والدهون أي فئة من طفايات الحريق؟"},"o":[{"en":"Class A","es":"Clase A","ru":"Класс A","tr":"Sınıf A","hi":"श्रेणी A","ar":"الفئة A"},{"en":"Class B","es":"Clase B","ru":"Класс B","tr":"Sınıf B","hi":"श्रेणी B","ar":"الفئة B"},{"en":"Class C","es":"Clase C","ru":"Класс C","tr":"Sınıf C","hi":"श्रेणी C","ar":"الفئة C"},{"en":"Class K","es":"Clase K","ru":"Класс K","tr":"Sınıf K","hi":"श्रेणी K","ar":"الفئة K"}],"e":{"en":"Class K extinguishers are designed for cooking oils and fats in commercial kitchens; they cool and smother the fire without spreading burning grease.","es":"Los extintores Clase K están diseñados para aceites y grasas de cocina en cocinas comerciales; enfrían y sofocan el fuego sin propagar la grasa ardiente.","ru":"Огнетушители класса K предназначены для кулинарных масел и жиров на коммерческих кухнях; они охлаждают и подавляют огонь, не распространяя горящий жир.","tr":"Sınıf K söndürücüler ticari mutfaklardaki pişirme yağları ve katı yağlar için tasarlanmıştır; yanan gresi yaymadan yangını soğutur ve boğar.","hi":"श्रेणी K अग्निशामक वाणिज्यिक रसोई में खाना पकाने के तेल और वसा के लिए डिज़ाइन किए गए हैं; ये जलती हुई ग्रीस को फैलाए बिना आग को ठंडा और दबा देते हैं।","ar":"طفايات الفئة K مصممة لزيوت الطهي والدهون في المطابخ التجارية؛ فهي تبرّد الحريق وتخنقه دون نشر الشحوم المشتعلة."}},{"cat":"emergency","a":3,"q":{"en":"A fire involving combustible metals such as magnesium, titanium, or sodium is classified as which class of fire?","es":"Un incendio que involucra metales combustibles como magnesio, titanio o sodio se clasifica como qué clase de fuego?","ru":"Пожар с участием горючих металлов, таких как магний, титан или натрий, относится к какому классу пожара?","tr":"Magnezyum, titanyum veya sodyum gibi yanıcı metallerin bulunduğu bir yangın hangi yangın sınıfına girer?","hi":"मैग्नीशियम, टाइटेनियम या सोडियम जैसी दहनशील धातुओं वाली आग को किस श्रेणी की आग के रूप में वर्गीकृत किया जाता है?","ar":"الحريق الذي يشمل معادن قابلة للاحتراق مثل المغنيسيوم أو التيتانيوم أو الصوديوم يُصنَّف ضمن أي فئة من فئات الحرائق؟"},"o":[{"en":"Class A","es":"Clase A","ru":"Класс A","tr":"Sınıf A","hi":"श्रेणी A","ar":"الفئة A"},{"en":"Class B","es":"Clase B","ru":"Класс B","tr":"Sınıf B","hi":"श्रेणी B","ar":"الفئة B"},{"en":"Class C","es":"Clase C","ru":"Класс C","tr":"Sınıf C","hi":"श्रेणी C","ar":"الفئة C"},{"en":"Class D","es":"Clase D","ru":"Класс D","tr":"Sınıf D","hi":"श्रेणी D","ar":"الفئة D"}],"e":{"en":"Class D fires involve combustible metals such as magnesium, titanium, and sodium, and require a special dry powder agent; water or standard extinguishers can make them worse.","es":"Los incendios de Clase D involucran metales combustibles como magnesio, titanio y sodio, y requieren un agente especial de polvo seco; el agua o los extintores estándar pueden empeorarlos.","ru":"Пожары класса D связаны с горючими металлами, такими как магний, титан и натрий, и требуют специального сухого порошкового состава; вода или обычные огнетушители могут их усугубить.","tr":"Sınıf D yangınları magnezyum, titanyum ve sodyum gibi yanıcı metalleri içerir ve özel bir kuru toz ajanı gerektirir; su veya standart söndürücüler durumu kötüleştirebilir.","hi":"श्रेणी D की आग में मैग्नीशियम, टाइटेनियम और सोडियम जैसी दहनशील धातुएं शामिल होती हैं और इनके लिए एक विशेष सूखे पाउडर एजेंट की आवश्यकता होती है; पानी या मानक अग्निशामक इन्हें और बदतर बना सकते हैं।","ar":"حرائق الفئة D تشمل المعادن القابلة للاحتراق مثل المغنيسيوم والتيتانيوم والصوديوم، وتتطلب عامل مسحوق جاف خاص؛ وقد يزيد الماء أو الطفايات العادية الأمر سوءًا."}},{"cat":"emergency","a":0,"q":{"en":"Which type of fire extinguisher is considered multipurpose and effective on Class A, B, and C fires?","es":"Qué tipo de extintor de incendios se considera multiuso y eficaz en incendios de Clase A, B y C?","ru":"Какой тип огнетушителя считается многоцелевым и эффективным при пожарах классов A, B и C?","tr":"Hangi tür yangın söndürücü çok amaçlı kabul edilir ve Sınıf A, B ve C yangınlarında etkilidir?","hi":"किस प्रकार का अग्निशामक बहुउद्देशीय माना जाता है और श्रेणी A, B और C की आग पर प्रभावी है?","ar":"أي نوع من طفايات الحريق يُعدّ متعدد الأغراض وفعّالًا على حرائق الفئات A و B و C؟"},"o":[{"en":"ABC dry chemical extinguisher","es":"Extintor de polvo químico seco ABC","ru":"Порошковый огнетушитель ABC","tr":"ABC kuru kimyasal söndürücü","hi":"ABC सूखा रसायन अग्निशामक","ar":"طفاية مسحوق كيميائي جاف من نوع ABC"},{"en":"Plain water extinguisher","es":"Extintor de agua simple","ru":"Обычный водяной огнетушитель","tr":"Düz su söndürücü","hi":"सादा पानी अग्निशामक","ar":"طفاية ماء عادية"},{"en":"Class D powder extinguisher","es":"Extintor de polvo Clase D","ru":"Порошковый огнетушитель класса D","tr":"Sınıf D toz söndürücü","hi":"श्रेणी D पाउडर अग्निशामक","ar":"طفاية مسحوق من الفئة D"},{"en":"Class K wet chemical extinguisher","es":"Extintor de químico húmedo Clase K","ru":"Огнетушитель с влажным химикатом класса K","tr":"Sınıf K ıslak kimyasal söndürücü","hi":"श्रेणी K गीला रसायन अग्निशामक","ar":"طفاية كيميائية رطبة من الفئة K"}],"e":{"en":"An ABC dry chemical extinguisher is multipurpose and works on ordinary combustibles, flammable liquids, and energized electrical equipment, making it common in many facilities.","es":"Un extintor de polvo químico seco ABC es multiuso y funciona en combustibles ordinarios, líquidos inflamables y equipo eléctrico energizado, lo que lo hace común en muchas instalaciones.","ru":"Порошковый огнетушитель ABC является многоцелевым и работает на обычных горючих материалах, легковоспламеняющихся жидкостях и электрооборудовании под напряжением, что делает его распространенным во многих учреждениях.","tr":"ABC kuru kimyasal söndürücü çok amaçlıdır ve sıradan yanıcı maddeler, yanıcı sıvılar ve enerji altındaki elektrikli ekipman üzerinde çalışır, bu da onu birçok tesiste yaygın kılar.","hi":"ABC सूखा रसायन अग्निशामक बहुउद्देशीय है और सामान्य दहनशील पदार्थों, ज्वलनशील तरल पदार्थों और ऊर्जावान विद्युत उपकरणों पर काम करता है, जिससे यह कई सुविधाओं में आम है।","ar":"طفاية المسحوق الكيميائي الجاف من نوع ABC متعددة الأغراض وتعمل على المواد القابلة للاحتراق العادية والسوائل القابلة للاشتعال والمعدات الكهربائية المكهربة، مما يجعلها شائعة في العديد من المنشآت."}},{"cat":"emergency","a":1,"q":{"en":"What does the acronym PASS stand for when operating a fire extinguisher?","es":"Qué significa el acrónimo PASS al operar un extintor de incendios?","ru":"Что означает аббревиатура PASS при использовании огнетушителя?","tr":"Yangın söndürücü kullanırken PASS kısaltması neyi ifade eder?","hi":"अग्निशामक चलाते समय संक्षिप्त शब्द PASS का क्या अर्थ है?","ar":"ماذا يعني الاختصار PASS عند تشغيل طفاية الحريق؟"},"o":[{"en":"Push, Alarm, Shout, Stop","es":"Empujar, Alarma, Gritar, Detener","ru":"Толкать, Тревога, Кричать, Остановить","tr":"İt, Alarm, Bağır, Dur","hi":"धकेलें, अलार्म, चिल्लाएं, रुकें","ar":"ادفع، إنذار، اصرخ، توقف"},{"en":"Pull the pin, Aim at the base, Squeeze the handle, Sweep side to side","es":"Tirar del pasador, Apuntar a la base, Apretar la palanca, Barrer de lado a lado","ru":"Выдернуть чеку, Направить на основание, Нажать рычаг, Двигать из стороны в сторону","tr":"Pimi çek, Tabana nişan al, Kolu sık, Yanlara doğru süpür","hi":"पिन खींचें, आधार पर निशाना लगाएं, हैंडल दबाएं, अगल-बगल घुमाएं","ar":"اسحب المسمار، صوّب نحو القاعدة، اضغط المقبض، امسح من جانب إلى جانب"},{"en":"Prepare, Assess, Search, Secure","es":"Preparar, Evaluar, Buscar, Asegurar","ru":"Подготовить, Оценить, Искать, Обезопасить","tr":"Hazırlan, Değerlendir, Ara, Güvence altına al","hi":"तैयारी करें, आकलन करें, खोजें, सुरक्षित करें","ar":"استعد، قيّم، ابحث، أمّن"},{"en":"Point, Activate, Spray, Store","es":"Apuntar, Activar, Rociar, Guardar","ru":"Указать, Активировать, Распылить, Хранить","tr":"İşaret et, Etkinleştir, Püskürt, Sakla","hi":"इंगित करें, सक्रिय करें, स्प्रे करें, संग्रहीत करें","ar":"أشِر، فعّل، رُشّ، خزّن"}],"e":{"en":"PASS stands for Pull the pin, Aim at the base of the fire, Squeeze the handle, and Sweep side to side. Aiming at the base targets the fuel source.","es":"PASS significa Tirar del pasador, Apuntar a la base del fuego, Apretar la palanca y Barrer de lado a lado. Apuntar a la base ataca la fuente de combustible.","ru":"PASS означает: Выдернуть чеку, Направить на основание огня, Нажать рычаг и Двигать из стороны в сторону. Направление на основание нацелено на источник топлива.","tr":"PASS, Pimi çek, Yangının tabanına nişan al, Kolu sık ve Yanlara doğru süpür anlamına gelir. Tabana nişan almak yakıt kaynağını hedefler.","hi":"PASS का अर्थ है पिन खींचें, आग के आधार पर निशाना लगाएं, हैंडल दबाएं, और अगल-बगल घुमाएं। आधार पर निशाना लगाने से ईंधन स्रोत को लक्षित किया जाता है।","ar":"يعني PASS: اسحب المسمار، صوّب نحو قاعدة الحريق، اضغط المقبض، وامسح من جانب إلى جانب. التصويب نحو القاعدة يستهدف مصدر الوقود."}},{"cat":"emergency","a":2,"q":{"en":"When using the PASS technique, where should you aim the fire extinguisher nozzle?","es":"Al usar la técnica PASS, hacia dónde debe apuntar la boquilla del extintor?","ru":"При использовании техники PASS куда следует направлять сопло огнетушителя?","tr":"PASS tekniğini kullanırken yangın söndürücü hortumunu nereye nişan almalısınız?","hi":"PASS तकनीक का उपयोग करते समय, आपको अग्निशामक के नोजल को कहां निशाना बनाना चाहिए?","ar":"عند استخدام تقنية PASS، أين يجب أن تصوّب فوهة طفاية الحريق؟"},"o":[{"en":"At the top of the flames","es":"A la parte superior de las llamas","ru":"На верхнюю часть пламени","tr":"Alevlerin üst kısmına","hi":"लपटों के शीर्ष पर","ar":"نحو أعلى اللهب"},{"en":"At the smoke above the fire","es":"Al humo por encima del fuego","ru":"На дым над огнем","tr":"Yangının üstündeki dumana","hi":"आग के ऊपर के धुएं पर","ar":"نحو الدخان فوق النار"},{"en":"At the base of the fire","es":"A la base del fuego","ru":"На основание огня","tr":"Yangının tabanına","hi":"आग के आधार पर","ar":"نحو قاعدة النار"},{"en":"At the ceiling above the fire","es":"Al techo por encima del fuego","ru":"На потолок над огнем","tr":"Yangının üstündeki tavana","hi":"आग के ऊपर छत पर","ar":"نحو السقف فوق النار"}],"e":{"en":"In the PASS method, you aim at the base of the fire because that is where the fuel is burning; aiming at the flames or smoke wastes the agent.","es":"En el método PASS, se apunta a la base del fuego porque ahí es donde arde el combustible; apuntar a las llamas o el humo desperdicia el agente.","ru":"В методе PASS вы направляете струю на основание огня, потому что именно там горит топливо; направление на пламя или дым расходует средство впустую.","tr":"PASS yönteminde yangının tabanına nişan alırsınız çünkü yakıt orada yanmaktadır; alevlere veya dumana nişan almak söndürme maddesini boşa harcar.","hi":"PASS विधि में, आप आग के आधार पर निशाना लगाते हैं क्योंकि वहीं ईंधन जल रहा होता है; लपटों या धुएं पर निशाना लगाने से एजेंट बर्बाद होता है।","ar":"في طريقة PASS، تصوّب نحو قاعدة النار لأن الوقود يحترق هناك؛ أما التصويب نحو اللهب أو الدخان فيهدر مادة الإخماد."}},{"cat":"emergency","a":3,"q":{"en":"During a building fire evacuation, why should you never use the elevators?","es":"Durante una evacuación por incendio en un edificio, por qué nunca debe usar los ascensores?","ru":"Во время эвакуации из здания при пожаре почему никогда нельзя пользоваться лифтами?","tr":"Bir bina yangını tahliyesi sırasında asansörleri neden asla kullanmamalısınız?","hi":"इमारत में आग के दौरान निकासी करते समय, आपको कभी लिफ्ट का उपयोग क्यों नहीं करना चाहिए?","ar":"أثناء إخلاء مبنى بسبب حريق، لماذا يجب ألا تستخدم المصاعد أبدًا؟"},"o":[{"en":"Elevators are always too slow to be useful","es":"Los ascensores siempre son demasiado lentos para ser útiles","ru":"Лифты всегда слишком медленные, чтобы быть полезными","tr":"Asansörler her zaman yararlı olamayacak kadar yavaştır","hi":"लिफ्ट हमेशा उपयोगी होने के लिए बहुत धीमी होती हैं","ar":"المصاعد دائمًا بطيئة جدًا بحيث لا تكون مفيدة"},{"en":"Elevators are reserved only for management","es":"Los ascensores están reservados solo para la gerencia","ru":"Лифты предназначены только для руководства","tr":"Asansörler yalnızca yönetime ayrılmıştır","hi":"लिफ्ट केवल प्रबंधन के लिए आरक्षित हैं","ar":"المصاعد مخصصة للإدارة فقط"},{"en":"Elevators use too much electricity during a fire","es":"Los ascensores consumen demasiada electricidad durante un incendio","ru":"Лифты потребляют слишком много электроэнергии во время пожара","tr":"Asansörler yangın sırasında çok fazla elektrik kullanır","hi":"लिफ्ट आग के दौरान बहुत अधिक बिजली का उपयोग करती हैं","ar":"المصاعد تستهلك كهرباء كثيرة أثناء الحريق"},{"en":"They can lose power and trap occupants, and shafts can fill with smoke","es":"Pueden perder energía y atrapar a los ocupantes, y los huecos pueden llenarse de humo","ru":"Они могут отключиться и запереть людей, а шахты могут заполниться дымом","tr":"Güç kaybedip kişileri hapsedebilir ve boşlukları dumanla dolabilir","hi":"वे बिजली खो सकती हैं और लोगों को फंसा सकती हैं, और शाफ्ट धुएं से भर सकते हैं","ar":"قد تفقد الطاقة وتحبس شاغليها، وقد تمتلئ أعمدتها بالدخان"}],"e":{"en":"Elevators can lose power during a fire and trap occupants, and shafts can act like chimneys that fill with smoke; always use the stairs and follow the site emergency plan.","es":"Los ascensores pueden perder energía durante un incendio y atrapar a los ocupantes, y los huecos pueden actuar como chimeneas que se llenan de humo; use siempre las escaleras y siga el plan de emergencia del sitio.","ru":"Лифты могут отключиться во время пожара и запереть людей, а шахты могут действовать как дымоходы, заполняясь дымом; всегда используйте лестницы и следуйте плану действий при чрезвычайных ситуациях объекта.","tr":"Asansörler yangın sırasında güç kaybedip kişileri hapsedebilir ve boşluklar dumanla dolan bacalar gibi davranabilir; her zaman merdivenleri kullanın ve tesis acil durum planını izleyin.","hi":"आग के दौरान लिफ्ट बिजली खो सकती हैं और लोगों को फंसा सकती हैं, और शाफ्ट चिमनी की तरह काम कर सकते हैं जो धुएं से भर जाते हैं; हमेशा सीढ़ियों का उपयोग करें और साइट की आपातकालीन योजना का पालन करें।","ar":"قد تفقد المصاعد الطاقة أثناء الحريق وتحبس شاغليها، وقد تعمل الأعمدة كمداخن تمتلئ بالدخان؛ استخدم الدرج دائمًا واتّبع خطة الطوارئ الخاصة بالموقع."}},{"cat":"emergency","a":0,"q":{"en":"After evacuating a building, where should security guards direct people to gather?","es":"Después de evacuar un edificio, hacia dónde deben dirigir los guardias de seguridad a las personas para reunirse?","ru":"После эвакуации из здания куда охранники должны направлять людей для сбора?","tr":"Bir binayı tahliye ettikten sonra, güvenlik görevlileri insanları nerede toplanmaya yönlendirmelidir?","hi":"किसी इमारत को खाली करने के बाद, सुरक्षा गार्डों को लोगों को कहां इकट्ठा होने के लिए निर्देशित करना चाहिए?","ar":"بعد إخلاء مبنى، إلى أين يجب أن يوجّه حرّاس الأمن الناس للتجمّع؟"},"o":[{"en":"To designated assembly points a safe distance from the building","es":"A puntos de reunión designados a una distancia segura del edificio","ru":"К назначенным местам сбора на безопасном расстоянии от здания","tr":"Binadan güvenli mesafedeki belirlenmiş toplanma noktalarına","hi":"इमारत से सुरक्षित दूरी पर निर्धारित सभा स्थलों पर","ar":"إلى نقاط تجمّع محددة على مسافة آمنة من المبنى"},{"en":"Back inside the lobby to stay warm","es":"De vuelta al vestíbulo para mantenerse calientes","ru":"Обратно в вестибюль, чтобы согреться","tr":"Isınmak için tekrar lobinin içine","hi":"गर्म रहने के लिए वापस लॉबी के अंदर","ar":"العودة إلى الردهة للبقاء دافئين"},{"en":"To the nearest parking garage stairwell","es":"Al hueco de escaleras del estacionamiento más cercano","ru":"К ближайшей лестничной клетке парковочного гаража","tr":"En yakın otopark merdiven boşluğuna","hi":"निकटतम पार्किंग गैरेज की सीढ़ी तक","ar":"إلى أقرب بئر سلّم في مرآب السيارات"},{"en":"Wherever each person personally prefers to wait","es":"A donde cada persona prefiera esperar personalmente","ru":"Куда каждый человек лично предпочитает ждать","tr":"Her kişinin beklemeyi kişisel olarak tercih ettiği yere","hi":"जहां भी प्रत्येक व्यक्ति व्यक्तिगत रूप से प्रतीक्षा करना पसंद करता है","ar":"إلى أي مكان يفضّل كل شخص الانتظار فيه"}],"e":{"en":"Evacuees should gather at pre-designated assembly points a safe distance from the building so everyone can be accounted for and kept clear of emergency responders.","es":"Los evacuados deben reunirse en puntos de reunión predesignados a una distancia segura del edificio para que todos puedan ser contabilizados y mantenidos lejos de los servicios de emergencia.","ru":"Эвакуированные должны собираться в заранее назначенных местах сбора на безопасном расстоянии от здания, чтобы можно было учесть всех и держать их подальше от аварийных служб.","tr":"Tahliye edilenler, herkesin sayılabilmesi ve acil durum ekiplerinden uzak tutulabilmesi için binadan güvenli mesafedeki önceden belirlenmiş toplanma noktalarında toplanmalıdır.","hi":"निकाले गए लोगों को इमारत से सुरक्षित दूरी पर पूर्व-निर्धारित सभा स्थलों पर इकट्ठा होना चाहिए ताकि सभी की गिनती की जा सके और उन्हें आपातकालीन कर्मियों से दूर रखा जा सके।","ar":"يجب أن يتجمّع من تم إخلاؤهم في نقاط تجمّع محددة مسبقًا على مسافة آمنة من المبنى ليتسنى حصر الجميع وإبقاؤهم بعيدين عن فرق الطوارئ."}},{"cat":"emergency","a":1,"q":{"en":"When a serious medical emergency occurs and a person is seriously injured, what is generally the first action a security guard should take?","es":"Cuando ocurre una emergencia médica grave y una persona está gravemente herida, cuál es generalmente la primera acción que debe tomar un guardia de seguridad?","ru":"Когда происходит серьезная медицинская чрезвычайная ситуация и человек серьезно ранен, какое действие обычно должен предпринять охранник в первую очередь?","tr":"Ciddi bir tıbbi acil durum meydana geldiğinde ve bir kişi ağır yaralandığında, bir güvenlik görevlisinin genellikle atması gereken ilk adım nedir?","hi":"जब कोई गंभीर चिकित्सा आपात स्थिति होती है और कोई व्यक्ति गंभीर रूप से घायल होता है, तो आमतौर पर सुरक्षा गार्ड को सबसे पहले क्या कार्रवाई करनी चाहिए?","ar":"عند وقوع حالة طبية طارئة خطيرة وإصابة شخص إصابة بالغة، ما هو الإجراء الأول الذي يجب أن يتخذه حارس الأمن عادةً؟"},"o":[{"en":"Immediately move the victim to a more comfortable location","es":"Mover de inmediato a la víctima a un lugar más cómodo","ru":"Немедленно переместить пострадавшего в более удобное место","tr":"Mağduru derhal daha rahat bir yere taşımak","hi":"पीड़ित को तुरंत अधिक आरामदायक स्थान पर ले जाना","ar":"نقل المصاب فورًا إلى مكان أكثر راحة"},{"en":"Ensure the scene is safe and call 911 to activate EMS","es":"Asegurarse de que la escena sea segura y llamar al 911 para activar los servicios médicos de emergencia","ru":"Убедиться, что место безопасно, и позвонить 911 для вызова скорой помощи","tr":"Olay yerinin güvenli olduğundan emin olmak ve acil tıbbi servisleri devreye sokmak için 911'i aramak","hi":"यह सुनिश्चित करें कि दृश्य सुरक्षित है और EMS को सक्रिय करने के लिए 911 पर कॉल करें","ar":"التأكد من أن مكان الحادث آمن والاتصال بالرقم 911 لتفعيل خدمات الطوارئ الطبية"},{"en":"Give the victim water and food to keep up their strength","es":"Darle a la víctima agua y comida para mantener sus fuerzas","ru":"Дать пострадавшему воду и еду, чтобы поддержать силы","tr":"Gücünü korumak için mağdura su ve yiyecek vermek","hi":"पीड़ित को ताकत बनाए रखने के लिए पानी और भोजन देना","ar":"إعطاء المصاب ماءً وطعامًا للحفاظ على قوته"},{"en":"Wait until a supervisor arrives before doing anything","es":"Esperar hasta que llegue un supervisor antes de hacer cualquier cosa","ru":"Ждать прибытия руководителя, прежде чем что-либо делать","tr":"Herhangi bir şey yapmadan önce bir amirin gelmesini beklemek","hi":"कुछ भी करने से पहले पर्यवेक्षक के आने तक प्रतीक्षा करना","ar":"الانتظار حتى وصول المشرف قبل القيام بأي شيء"}],"e":{"en":"First ensure the scene is safe for you and the victim, then call 911 to activate EMS; avoid moving a seriously injured person unnecessarily and only give aid you are trained to provide.","es":"Primero asegúrese de que la escena sea segura para usted y la víctima, luego llame al 911 para activar los servicios médicos de emergencia; evite mover innecesariamente a una persona gravemente herida y solo brinde la ayuda para la que esté capacitado.","ru":"Сначала убедитесь, что место безопасно для вас и пострадавшего, затем позвоните 911 для вызова скорой помощи; избегайте ненужного перемещения серьезно раненого человека и оказывайте только ту помощь, которой вы обучены.","tr":"Önce olay yerinin sizin ve mağdur için güvenli olduğundan emin olun, ardından acil tıbbi servisleri devreye sokmak için 911'i arayın; ağır yaralı bir kişiyi gereksiz yere hareket ettirmekten kaçının ve yalnızca eğitim aldığınız yardımı sağlayın.","hi":"पहले सुनिश्चित करें कि दृश्य आपके और पीड़ित के लिए सुरक्षित है, फिर EMS को सक्रिय करने के लिए 911 पर कॉल करें; गंभीर रूप से घायल व्यक्ति को अनावश्यक रूप से हिलाने से बचें और केवल वही सहायता दें जिसके लिए आप प्रशिक्षित हैं।","ar":"تأكد أولًا من أن مكان الحادث آمن لك وللمصاب، ثم اتصل بالرقم 911 لتفعيل خدمات الطوارئ الطبية؛ وتجنّب تحريك الشخص المصاب بشدة دون داعٍ، وقدّم فقط الإسعاف الذي تلقّيت تدريبًا عليه."}},{"cat":"emergency","a":2,"q":{"en":"What is the recommended method to control external bleeding until medical help arrives?","es":"Cuál es el método recomendado para controlar el sangrado externo hasta que llegue la ayuda médica?","ru":"Какой рекомендуемый метод остановки наружного кровотечения до прибытия медицинской помощи?","tr":"Tıbbi yardım gelene kadar dış kanamayı kontrol etmek için önerilen yöntem nedir?","hi":"चिकित्सा सहायता आने तक बाहरी रक्तस्राव को नियंत्रित करने के लिए अनुशंसित विधि क्या है?","ar":"ما هي الطريقة الموصى بها للسيطرة على النزيف الخارجي حتى وصول المساعدة الطبية؟"},"o":[{"en":"Apply a heat pack directly to the wound","es":"Aplicar una compresa caliente directamente sobre la herida","ru":"Приложить грелку непосредственно к ране","tr":"Yaraya doğrudan sıcak kompres uygulamak","hi":"घाव पर सीधे हीट पैक लगाना","ar":"وضع كمادة ساخنة مباشرة على الجرح"},{"en":"Rinse the wound repeatedly with cold water","es":"Enjuagar la herida repetidamente con agua fría","ru":"Многократно промывать рану холодной водой","tr":"Yarayı tekrar tekrar soğuk suyla yıkamak","hi":"घाव को बार-बार ठंडे पानी से धोना","ar":"غسل الجرح مرارًا بالماء البارد"},{"en":"Apply firm direct pressure to the wound with a clean cloth or dressing","es":"Aplicar presión directa y firme sobre la herida con un paño o apósito limpio","ru":"Оказывать сильное прямое давление на рану чистой тканью или повязкой","tr":"Temiz bir bez veya sargı ile yaraya sıkı ve doğrudan baskı uygulamak","hi":"साफ कपड़े या ड्रेसिंग से घाव पर मजबूती से सीधा दबाव डालना","ar":"الضغط المباشر بقوة على الجرح باستخدام قطعة قماش نظيفة أو ضمادة"},{"en":"Elevate the person's head above their heart","es":"Elevar la cabeza de la persona por encima de su corazón","ru":"Поднять голову человека выше уровня сердца","tr":"Kişinin başını kalbinin üzerine kaldırmak","hi":"व्यक्ति के सिर को उनके हृदय से ऊपर उठाना","ar":"رفع رأس الشخص فوق مستوى قلبه"}],"e":{"en":"The standard first-aid method to control external bleeding is firm, direct pressure on the wound with a clean cloth or dressing, and always use universal precautions to avoid contact with bodily fluids.","es":"El método estándar de primeros auxilios para controlar el sangrado externo es la presión directa y firme sobre la herida con un paño o apósito limpio, y siempre use precauciones universales para evitar el contacto con fluidos corporales.","ru":"Стандартный метод первой помощи для остановки наружного кровотечения — это сильное прямое давление на рану чистой тканью или повязкой, и всегда соблюдайте универсальные меры предосторожности, чтобы избежать контакта с биологическими жидкостями.","tr":"Dış kanamayı kontrol etmenin standart ilk yardım yöntemi, temiz bir bez veya sargı ile yaraya sıkı ve doğrudan baskı uygulamaktır ve vücut sıvılarıyla temastan kaçınmak için her zaman evrensel önlemleri kullanın.","hi":"बाहरी रक्तस्राव को नियंत्रित करने की मानक प्राथमिक चिकित्सा विधि साफ कपड़े या ड्रेसिंग से घाव पर मजबूत, सीधा दबाव डालना है, और शारीरिक तरल पदार्थों के संपर्क से बचने के लिए हमेशा सार्वभौमिक सावधानियों का उपयोग करें।","ar":"الطريقة القياسية للإسعافات الأولية للسيطرة على النزيف الخارجي هي الضغط المباشر القوي على الجرح بقطعة قماش نظيفة أو ضمادة، واستخدم دائمًا الاحتياطات العامة لتجنب ملامسة سوائل الجسم."}},{"cat":"emergency","a":3,"q":{"en":"Why should security guards use universal precautions (such as gloves) when giving first aid?","es":"Por qué deben los guardias de seguridad usar precauciones universales (como guantes) al brindar primeros auxilios?","ru":"Почему охранники должны соблюдать универсальные меры предосторожности (например, перчатки) при оказании первой помощи?","tr":"Güvenlik görevlileri ilk yardım yaparken neden evrensel önlemleri (örneğin eldiven) kullanmalıdır?","hi":"प्राथमिक चिकित्सा देते समय सुरक्षा गार्डों को सार्वभौमिक सावधानियों (जैसे दस्ताने) का उपयोग क्यों करना चाहिए?","ar":"لماذا يجب على حرّاس الأمن استخدام الاحتياطات العامة (مثل القفازات) عند تقديم الإسعافات الأولية؟"},"o":[{"en":"To keep their hands warm during the emergency","es":"Para mantener sus manos calientes durante la emergencia","ru":"Чтобы держать руки в тепле во время чрезвычайной ситуации","tr":"Acil durum sırasında ellerini sıcak tutmak için","hi":"आपात स्थिति के दौरान अपने हाथों को गर्म रखने के लिए","ar":"لإبقاء أيديهم دافئة أثناء الحالة الطارئة"},{"en":"To look more professional to bystanders","es":"Para verse más profesionales ante los transeúntes","ru":"Чтобы выглядеть более профессионально перед прохожими","tr":"Etraftakilere karşı daha profesyonel görünmek için","hi":"आसपास खड़े लोगों के सामने अधिक पेशेवर दिखने के लिए","ar":"ليبدوا أكثر احترافية أمام المارّة"},{"en":"To avoid leaving fingerprints at the scene","es":"Para evitar dejar huellas dactilares en la escena","ru":"Чтобы не оставлять отпечатки пальцев на месте происшествия","tr":"Olay yerinde parmak izi bırakmamak için","hi":"दृश्य पर उंगलियों के निशान न छोड़ने के लिए","ar":"لتجنّب ترك بصمات في مكان الحادث"},{"en":"To protect against bloodborne pathogens and other bodily fluids","es":"Para protegerse contra patógenos transmitidos por la sangre y otros fluidos corporales","ru":"Для защиты от патогенов, передающихся через кровь, и других биологических жидкостей","tr":"Kan yoluyla bulaşan patojenlere ve diğer vücut sıvılarına karşı korunmak için","hi":"रक्त-जनित रोगजनकों और अन्य शारीरिक तरल पदार्थों से बचाव के लिए","ar":"للحماية من مسببات الأمراض المنقولة بالدم وسوائل الجسم الأخرى"}],"e":{"en":"Universal precautions treat all blood and bodily fluids as potentially infectious, so wearing gloves protects against bloodborne pathogens and disease transmission.","es":"Las precauciones universales tratan toda la sangre y los fluidos corporales como potencialmente infecciosos, por lo que usar guantes protege contra patógenos transmitidos por la sangre y la transmisión de enfermedades.","ru":"Универсальные меры предосторожности рассматривают всю кровь и биологические жидкости как потенциально заразные, поэтому ношение перчаток защищает от патогенов, передающихся через кровь, и от передачи болезней.","tr":"Evrensel önlemler tüm kan ve vücut sıvılarını potansiyel olarak bulaşıcı kabul eder, bu nedenle eldiven giymek kan yoluyla bulaşan patojenlere ve hastalık bulaşmasına karşı korur.","hi":"सार्वभौमिक सावधानियां सभी रक्त और शारीरिक तरल पदार्थों को संभावित रूप से संक्रामक मानती हैं, इसलिए दस्ताने पहनना रक्त-जनित रोगजनकों और रोग संचरण से बचाता है।","ar":"تتعامل الاحتياطات العامة مع كل الدم وسوائل الجسم على أنها معدية محتملًا، لذا فإن ارتداء القفازات يحمي من مسببات الأمراض المنقولة بالدم ومن انتقال العدوى."}},{"cat":"emergency","a":0,"q":{"en":"If you receive a bomb threat over the phone, what should you do while the caller is still on the line?","es":"Si recibe una amenaza de bomba por teléfono, qué debe hacer mientras la persona que llama sigue en la línea?","ru":"Если вы получаете угрозу взрыва по телефону, что вам следует делать, пока звонящий еще на линии?","tr":"Telefonla bir bomba tehdidi alırsanız, arayan hâlâ hattayken ne yapmalısınız?","hi":"यदि आपको फोन पर बम की धमकी मिलती है, तो कॉल करने वाले के लाइन पर रहने के दौरान आपको क्या करना चाहिए?","ar":"إذا تلقّيت تهديدًا بوجود قنبلة عبر الهاتف، فماذا يجب أن تفعل بينما لا يزال المتصل على الخط؟"},"o":[{"en":"Stay calm, keep the caller talking, and note the exact wording, time, and background noise","es":"Mantener la calma, hacer que la persona siga hablando y anotar las palabras exactas, la hora y el ruido de fondo","ru":"Сохранять спокойствие, поддерживать разговор со звонящим и записывать точные слова, время и фоновый шум","tr":"Sakin kalmak, arayanı konuşturmaya devam etmek ve tam ifadeleri, saati ve arka plan sesini not etmek","hi":"शांत रहें, कॉल करने वाले को बात करते रहने दें, और सटीक शब्द, समय और पृष्ठभूमि शोर को नोट करें","ar":"البقاء هادئًا، وإبقاء المتصل يتحدّث، وتدوين الصياغة الدقيقة والوقت وضجيج الخلفية"},{"en":"Hang up immediately and say nothing to anyone","es":"Colgar de inmediato y no decir nada a nadie","ru":"Немедленно повесить трубку и никому ничего не говорить","tr":"Hemen telefonu kapatmak ve kimseye bir şey söylememek","hi":"तुरंत फोन काट दें और किसी को कुछ न बताएं","ar":"إغلاق الهاتف فورًا وعدم إخبار أي شخص بأي شيء"},{"en":"Argue with the caller to prove the threat is fake","es":"Discutir con la persona que llama para demostrar que la amenaza es falsa","ru":"Спорить со звонящим, чтобы доказать, что угроза ложная","tr":"Tehdidin sahte olduğunu kanıtlamak için arayanla tartışmak","hi":"यह साबित करने के लिए कॉल करने वाले के साथ बहस करें कि धमकी नकली है","ar":"الجدال مع المتصل لإثبات أن التهديد مزيف"},{"en":"Put the phone down and go search the building alone","es":"Dejar el teléfono e ir a registrar el edificio solo","ru":"Положить телефон и пойти обыскивать здание в одиночку","tr":"Telefonu bırakıp binayı tek başına aramaya gitmek","hi":"फोन नीचे रखें और अकेले इमारत की तलाशी लेने जाएं","ar":"ترك الهاتف والذهاب لتفتيش المبنى بمفردك"}],"e":{"en":"During a bomb threat, stay calm, do not hang up, keep the caller talking, and record exact wording, time, background noise, and voice traits, then notify police and management per the facility plan.","es":"Durante una amenaza de bomba, mantenga la calma, no cuelgue, haga que la persona siga hablando y registre las palabras exactas, la hora, el ruido de fondo y los rasgos de la voz, luego notifique a la policía y a la gerencia según el plan de la instalación.","ru":"Во время угрозы взрыва сохраняйте спокойствие, не вешайте трубку, поддерживайте разговор со звонящим и записывайте точные слова, время, фоновый шум и особенности голоса, затем уведомите полицию и руководство согласно плану объекта.","tr":"Bir bomba tehdidi sırasında sakin kalın, telefonu kapatmayın, arayanı konuşturmaya devam edin ve tam ifadeleri, saati, arka plan sesini ve ses özelliklerini kaydedin, ardından tesis planına göre polise ve yönetime bildirin.","hi":"बम की धमकी के दौरान, शांत रहें, फोन न काटें, कॉल करने वाले को बात करते रहने दें, और सटीक शब्द, समय, पृष्ठभूमि शोर और आवाज की विशेषताएं दर्ज करें, फिर सुविधा योजना के अनुसार पुलिस और प्रबंधन को सूचित करें।","ar":"أثناء التهديد بوجود قنبلة، ابقَ هادئًا، ولا تُغلق الهاتف، وأبقِ المتصل يتحدّث، وسجّل الصياغة الدقيقة والوقت وضجيج الخلفية وسمات الصوت، ثم أبلغ الشرطة والإدارة وفقًا لخطة المنشأة."}},{"cat":"emergency","a":1,"q":{"en":"If you discover a suspicious unattended package that may be an explosive device, what should you do?","es":"Si descubre un paquete sospechoso sin vigilancia que podría ser un artefacto explosivo, qué debe hacer?","ru":"Если вы обнаружите подозрительный оставленный без присмотра пакет, который может быть взрывным устройством, что вам следует делать?","tr":"Patlayıcı bir cihaz olabilecek şüpheli, sahipsiz bir paket bulursanız ne yapmalısınız?","hi":"यदि आपको कोई संदिग्ध लावारिस पैकेज मिलता है जो एक विस्फोटक उपकरण हो सकता है, तो आपको क्या करना चाहिए?","ar":"إذا اكتشفت طردًا مشبوهًا غير مراقب قد يكون جهازًا متفجرًا، فماذا يجب أن تفعل؟"},"o":[{"en":"Pick it up and carry it outside to a safe area","es":"Recogerlo y llevarlo afuera a un área segura","ru":"Поднять его и вынести наружу в безопасное место","tr":"Onu alıp güvenli bir alana dışarı taşımak","hi":"इसे उठाकर बाहर सुरक्षित क्षेत्र में ले जाना","ar":"التقاطه وحمله إلى الخارج إلى منطقة آمنة"},{"en":"Do not touch it, keep people away, and notify authorities and management","es":"No tocarlo, mantener a las personas alejadas y notificar a las autoridades y a la gerencia","ru":"Не трогать его, держать людей подальше и уведомить власти и руководство","tr":"Ona dokunmamak, insanları uzak tutmak ve yetkilileri ve yönetimi bilgilendirmek","hi":"इसे न छूएं, लोगों को दूर रखें, और अधिकारियों और प्रबंधन को सूचित करें","ar":"عدم لمسه، وإبعاد الناس عنه، وإبلاغ السلطات والإدارة"},{"en":"Open it carefully to check what is inside","es":"Abrirlo con cuidado para verificar qué hay dentro","ru":"Осторожно открыть его, чтобы проверить, что внутри","tr":"İçinde ne olduğunu kontrol etmek için dikkatlice açmak","hi":"अंदर क्या है यह जांचने के लिए इसे सावधानी से खोलें","ar":"فتحه بحذر للتحقق مما بداخله"},{"en":"Use your radio right next to it to report the find","es":"Usar su radio justo al lado para reportar el hallazgo","ru":"Использовать свою рацию прямо рядом с ним, чтобы сообщить о находке","tr":"Bulguyu bildirmek için telsizinizi hemen yanında kullanmak","hi":"खोज की रिपोर्ट करने के लिए इसके ठीक बगल में अपने रेडियो का उपयोग करें","ar":"استخدام جهاز اللاسلكي الخاص بك بجانبه مباشرة للإبلاغ عن الاكتشاف"}],"e":{"en":"Never touch or move a suspicious object; keep people away, and notify police and management. Many facility policies also warn against using radios or cell phones near a suspected device.","es":"Nunca toque ni mueva un objeto sospechoso; mantenga a las personas alejadas y notifique a la policía y a la gerencia. Muchas políticas de instalaciones también advierten contra el uso de radios o teléfonos celulares cerca de un dispositivo sospechoso.","ru":"Никогда не трогайте и не перемещайте подозрительный предмет; держите людей подальше и уведомите полицию и руководство. Многие правила объектов также предостерегают от использования раций или мобильных телефонов рядом с подозрительным устройством.","tr":"Şüpheli bir nesneye asla dokunmayın veya hareket ettirmeyin; insanları uzak tutun ve polise ve yönetime haber verin. Birçok tesis politikası ayrıca şüpheli bir cihazın yakınında telsiz veya cep telefonu kullanmaya karşı uyarır.","hi":"किसी संदिग्ध वस्तु को कभी न छूएं और न हिलाएं; लोगों को दूर रखें, और पुलिस और प्रबंधन को सूचित करें। कई सुविधा नीतियां संदिग्ध उपकरण के पास रेडियो या सेल फोन का उपयोग करने के खिलाफ भी चेतावनी देती हैं।","ar":"لا تلمس أو تحرّك جسمًا مشبوهًا أبدًا؛ أبعد الناس عنه، وأبلغ الشرطة والإدارة. كما تحذّر العديد من سياسات المنشآت من استخدام أجهزة اللاسلكي أو الهواتف المحمولة بالقرب من جهاز مشتبه به."}},{"cat":"emergency","a":2,"q":{"en":"In the Run-Hide-Fight response to an active threat, what is the first and preferred option if it is safe?","es":"En la respuesta Correr-Esconderse-Luchar ante una amenaza activa, cuál es la primera opción y la preferida si es seguro?","ru":"В реакции «Беги-Прячься-Дерись» на активную угрозу, какой первый и предпочтительный вариант, если это безопасно?","tr":"Aktif bir tehdide karşı Kaç-Saklan-Savaş yaklaşımında, güvenliyse ilk ve tercih edilen seçenek nedir?","hi":"किसी सक्रिय खतरे के लिए भागो-छिपो-लड़ो प्रतिक्रिया में, यदि सुरक्षित हो तो पहला और पसंदीदा विकल्प क्या है?","ar":"في استجابة اهرب-اختبئ-قاوم لتهديد نشط، ما هو الخيار الأول والمفضّل إذا كان الوضع آمنًا؟"},"o":[{"en":"Fight the attacker head-on","es":"Enfrentar al atacante directamente","ru":"Сразиться с нападающим лицом к лицу","tr":"Saldırganla doğrudan savaşmak","hi":"हमलावर से आमने-सामने लड़ना","ar":"مواجهة المهاجم مباشرة"},{"en":"Hide and wait for instructions","es":"Esconderse y esperar instrucciones","ru":"Спрятаться и ждать указаний","tr":"Saklanıp talimat beklemek","hi":"छिपना और निर्देशों की प्रतीक्षा करना","ar":"الاختباء وانتظار التعليمات"},{"en":"Run and evacuate away from the danger","es":"Correr y evacuar alejándose del peligro","ru":"Бежать и эвакуироваться подальше от опасности","tr":"Kaçmak ve tehlikeden uzağa tahliye olmak","hi":"भागना और खतरे से दूर निकलना","ar":"الهروب والإخلاء بعيدًا عن الخطر"},{"en":"Confront the threat to protect property","es":"Enfrentar la amenaza para proteger la propiedad","ru":"Противостоять угрозе, чтобы защитить имущество","tr":"Mülkü korumak için tehditle yüzleşmek","hi":"संपत्ति की रक्षा के लिए खतरे का सामना करना","ar":"مواجهة التهديد لحماية الممتلكات"}],"e":{"en":"In Run-Hide-Fight, running (evacuating) is the first and preferred option when there is a safe escape route; call 911 when it is safe to do so.","es":"En Correr-Esconderse-Luchar, correr (evacuar) es la primera opción y la preferida cuando hay una ruta de escape segura; llame al 911 cuando sea seguro hacerlo.","ru":"В «Беги-Прячься-Дерись» бегство (эвакуация) — это первый и предпочтительный вариант при наличии безопасного пути отхода; звоните 911, когда это безопасно.","tr":"Kaç-Saklan-Savaş'ta güvenli bir kaçış yolu olduğunda kaçmak (tahliye olmak) ilk ve tercih edilen seçenektir; güvenli olduğunda 911'i arayın.","hi":"भागो-छिपो-लड़ो में, जब कोई सुरक्षित निकास मार्ग हो तो भागना (निकलना) पहला और पसंदीदा विकल्प है; जब सुरक्षित हो तब 911 पर कॉल करें।","ar":"في اهرب-اختبئ-قاوم، يكون الهروب (الإخلاء) هو الخيار الأول والمفضّل عند وجود طريق هروب آمن؛ واتصل بالرقم 911 عندما يكون ذلك آمنًا."}},{"cat":"emergency","a":3,"q":{"en":"According to Run-Hide-Fight, when should you attempt to fight an active attacker?","es":"Según Correr-Esconderse-Luchar, cuándo debe intentar luchar contra un atacante activo?","ru":"Согласно принципу «Беги-Прячься-Дерись», когда следует пытаться сразиться с активным нападающим?","tr":"Kaç-Saklan-Savaş'a göre, aktif bir saldırganla ne zaman savaşmayı denemelisiniz?","hi":"भागो-छिपो-लड़ो के अनुसार, आपको सक्रिय हमलावर से लड़ने का प्रयास कब करना चाहिए?","ar":"وفقًا لـ اهرب-اختبئ-قاوم، متى يجب أن تحاول مقاومة مهاجم نشط؟"},"o":[{"en":"As soon as you see the attacker","es":"Tan pronto como vea al atacante","ru":"Как только вы увидите нападающего","tr":"Saldırganı görür görmez","hi":"जैसे ही आप हमलावर को देखें","ar":"بمجرد رؤيتك للمهاجم"},{"en":"Whenever you think you can win the fight","es":"Siempre que crea que puede ganar la pelea","ru":"Всякий раз, когда вы думаете, что можете победить в схватке","tr":"Kavgayı kazanabileceğinizi düşündüğünüz her zaman","hi":"जब भी आपको लगे कि आप लड़ाई जीत सकते हैं","ar":"كلما اعتقدت أنك تستطيع الفوز في المواجهة"},{"en":"Before attempting to run or hide","es":"Antes de intentar correr o esconderse","ru":"Прежде чем пытаться бежать или прятаться","tr":"Kaçmayı veya saklanmayı denemeden önce","hi":"भागने या छिपने का प्रयास करने से पहले","ar":"قبل محاولة الهروب أو الاختباء"},{"en":"Only as an absolute last resort when your life is in imminent danger","es":"Solo como último recurso absoluto cuando su vida está en peligro inminente","ru":"Только в крайнем случае, когда ваша жизнь находится в непосредственной опасности","tr":"Yalnızca hayatınız yakın tehlikedeyken son çare olarak","hi":"केवल अंतिम उपाय के रूप में जब आपका जीवन तत्काल खतरे में हो","ar":"فقط كملاذ أخير مطلق عندما تكون حياتك في خطر وشيك"}],"e":{"en":"Fighting is only an absolute last resort when you cannot run or hide and your life is in imminent danger; commit fully and use any available objects as improvised weapons.","es":"Luchar es solo un último recurso absoluto cuando no puede correr ni esconderse y su vida está en peligro inminente; comprométase por completo y use cualquier objeto disponible como arma improvisada.","ru":"Драка — это крайняя мера, когда вы не можете убежать или спрятаться, а ваша жизнь в непосредственной опасности; действуйте решительно и используйте любые доступные предметы в качестве импровизированного оружия.","tr":"Savaşmak, kaçamadığınız veya saklanamadığınız ve hayatınızın yakın tehlikede olduğu durumlarda yalnızca mutlak son çaredir; tam olarak kararlı olun ve mevcut nesneleri doğaçlama silah olarak kullanın.","hi":"लड़ाई केवल अंतिम उपाय है जब आप भाग या छिप नहीं सकते और आपका जीवन तत्काल खतरे में है; पूरी तरह से प्रतिबद्ध रहें और किसी भी उपलब्ध वस्तु को तात्कालिक हथियार के रूप में उपयोग करें।","ar":"المقاومة هي الملاذ الأخير المطلق فقط عندما لا تستطيع الهروب أو الاختباء وتكون حياتك في خطر وشيك؛ التزم بالكامل واستخدم أي أدوات متاحة كأسلحة مرتجلة."}},{"cat":"emergency","a":0,"q":{"en":"If you must hide during an active-threat lockdown, which of the following is the best practice?","es":"Si debe esconderse durante un confinamiento por amenaza activa, cuál de las siguientes es la mejor práctica?","ru":"Если вам необходимо спрятаться во время блокировки при активной угрозе, что из следующего является лучшей практикой?","tr":"Aktif tehdit kapanması sırasında saklanmanız gerekiyorsa, aşağıdakilerden hangisi en iyi uygulamadır?","hi":"यदि आपको सक्रिय खतरे के लॉकडाउन के दौरान छिपना पड़े, तो निम्नलिखित में से कौन सा सबसे अच्छा अभ्यास है?","ar":"إذا اضطررت إلى الاختباء أثناء إغلاق بسبب تهديد نشط، فأي مما يلي هو أفضل ممارسة؟"},"o":[{"en":"Lock or barricade the door, turn off lights, and silence your phone","es":"Cerrar con llave o bloquear la puerta, apagar las luces y silenciar su teléfono","ru":"Запереть или забаррикадировать дверь, выключить свет и отключить звук телефона","tr":"Kapıyı kilitlemek veya barikat kurmak, ışıkları kapatmak ve telefonunuzu sessize almak","hi":"दरवाजे को बंद करें या बैरिकेड करें, लाइटें बंद करें, और अपने फोन को साइलेंट करें","ar":"قفل الباب أو تحصينه، وإطفاء الأضواء، وكتم صوت هاتفك"},{"en":"Leave the lights on so responders can find you","es":"Dejar las luces encendidas para que los rescatistas puedan encontrarlo","ru":"Оставить свет включенным, чтобы спасатели могли вас найти","tr":"Kurtarma ekiplerinin sizi bulabilmesi için ışıkları açık bırakmak","hi":"लाइटें चालू रखें ताकि बचावकर्मी आपको ढूंढ सकें","ar":"ترك الأضواء مضاءة ليتمكّن رجال الإنقاذ من العثور عليك"},{"en":"Keep your phone ringing so police can locate you","es":"Mantener su teléfono sonando para que la policía pueda localizarlo","ru":"Оставить телефон звонящим, чтобы полиция могла вас найти","tr":"Polisin sizi bulabilmesi için telefonunuzu çalar durumda tutmak","hi":"अपने फोन को बजने दें ताकि पुलिस आपको ढूंढ सके","ar":"إبقاء هاتفك يرنّ ليتمكّن رجال الشرطة من تحديد موقعك"},{"en":"Stand near the door so you can leave quickly","es":"Pararse cerca de la puerta para poder salir rápidamente","ru":"Стоять возле двери, чтобы можно было быстро выйти","tr":"Hızlıca çıkabilmek için kapının yanında durmak","hi":"दरवाजे के पास खड़े हों ताकि आप जल्दी निकल सकें","ar":"الوقوف بالقرب من الباب لتتمكن من المغادرة بسرعة"}],"e":{"en":"When hiding, lock or barricade the door, turn off lights, stay quiet, silence your phone, and stay out of sight until police give the all-clear.","es":"Al esconderse, cierre con llave o bloquee la puerta, apague las luces, mantenga silencio, silencie su teléfono y manténgase fuera de la vista hasta que la policía dé la señal de que todo está despejado.","ru":"Когда прячетесь, заприте или забаррикадируйте дверь, выключите свет, соблюдайте тишину, отключите звук телефона и оставайтесь вне поля зрения, пока полиция не даст сигнал об окончании опасности.","tr":"Saklanırken kapıyı kilitleyin veya barikat kurun, ışıkları kapatın, sessiz kalın, telefonunuzu sessize alın ve polis tehlikenin geçtiğini bildirene kadar görünmeyin.","hi":"छिपते समय, दरवाजे को बंद करें या बैरिकेड करें, लाइटें बंद करें, शांत रहें, अपने फोन को साइलेंट करें, और पुलिस के सुरक्षित होने का संकेत देने तक नजरों से दूर रहें।","ar":"عند الاختباء، اقفل الباب أو حصّنه، وأطفئ الأضواء، والتزم الهدوء، واكتم صوت هاتفك، وابقَ بعيدًا عن الأنظار حتى تعلن الشرطة انتهاء الخطر."}},{"cat":"emergency","a":1,"q":{"en":"What is a primary crowd-control responsibility of a security guard at a busy event?","es":"Cuál es una responsabilidad principal de control de multitudes de un guardia de seguridad en un evento concurrido?","ru":"Какова основная обязанность охранника по управлению толпой на многолюдном мероприятии?","tr":"Kalabalık bir etkinlikte bir güvenlik görevlisinin başlıca kalabalık kontrolü sorumluluğu nedir?","hi":"व्यस्त कार्यक्रम में सुरक्षा गार्ड की भीड़ नियंत्रण की प्राथमिक जिम्मेदारी क्या है?","ar":"ما هي المسؤولية الأساسية للسيطرة على الحشود لدى حارس الأمن في فعالية مزدحمة؟"},"o":[{"en":"Encouraging as many people as possible into one area to save space","es":"Animar a la mayor cantidad posible de personas a un área para ahorrar espacio","ru":"Побуждать как можно больше людей собраться в одной зоне для экономии места","tr":"Yer kazanmak için mümkün olduğunca çok kişiyi bir alana teşvik etmek","hi":"जगह बचाने के लिए अधिक से अधिक लोगों को एक क्षेत्र में प्रोत्साहित करना","ar":"تشجيع أكبر عدد ممكن من الناس على التجمّع في منطقة واحدة لتوفير المساحة"},{"en":"Preventing overcrowding and keeping aisles and exits clear","es":"Prevenir el hacinamiento y mantener despejados los pasillos y las salidas","ru":"Предотвращать переполненность и держать проходы и выходы свободными","tr":"Aşırı kalabalığı önlemek ve koridorları ve çıkışları açık tutmak","hi":"अत्यधिक भीड़ को रोकना और गलियारों और निकास को साफ रखना","ar":"منع الازدحام الزائد والحفاظ على الممرات والمخارج خالية"},{"en":"Letting the crowd manage itself without any guidance","es":"Dejar que la multitud se maneje sola sin ninguna orientación","ru":"Позволять толпе управлять собой без какого-либо руководства","tr":"Kalabalığın hiçbir yönlendirme olmadan kendini yönetmesine izin vermek","hi":"बिना किसी मार्गदर्शन के भीड़ को खुद ही संभालने देना","ar":"ترك الحشد يدير نفسه دون أي توجيه"},{"en":"Blocking the main exits to control who leaves","es":"Bloquear las salidas principales para controlar quién se va","ru":"Блокировать главные выходы, чтобы контролировать, кто уходит","tr":"Kimin ayrıldığını kontrol etmek için ana çıkışları engellemek","hi":"कौन जा रहा है यह नियंत्रित करने के लिए मुख्य निकास को अवरुद्ध करना","ar":"إغلاق المخارج الرئيسية للتحكم في من يغادر"}],"e":{"en":"A key crowd-control duty is preventing overcrowding and keeping aisles and exits clear so people can move and evacuate safely; watch for signs of crush or panic and coordinate with staff and police.","es":"Un deber clave del control de multitudes es prevenir el hacinamiento y mantener despejados los pasillos y las salidas para que las personas puedan moverse y evacuar de forma segura; esté atento a señales de aplastamiento o pánico y coordine con el personal y la policía.","ru":"Ключевая обязанность по управлению толпой — предотвращать переполненность и держать проходы и выходы свободными, чтобы люди могли безопасно передвигаться и эвакуироваться; следите за признаками давки или паники и координируйтесь с персоналом и полицией.","tr":"Kalabalık kontrolünün önemli bir görevi, insanların güvenle hareket edebilmesi ve tahliye olabilmesi için aşırı kalabalığı önlemek ve koridorları ve çıkışları açık tutmaktır; ezilme veya panik belirtilerine dikkat edin ve personel ve polisle koordine olun.","hi":"भीड़ नियंत्रण का एक प्रमुख कर्तव्य अत्यधिक भीड़ को रोकना और गलियारों और निकास को साफ रखना है ताकि लोग सुरक्षित रूप से चल सकें और निकल सकें; कुचलने या घबराहट के संकेतों पर नजर रखें और कर्मचारियों और पुलिस के साथ समन्वय करें।","ar":"من أهم واجبات السيطرة على الحشود منع الازدحام الزائد والحفاظ على الممرات والمخارج خالية ليتمكن الناس من التحرك والإخلاء بأمان؛ راقب علامات التدافع أو الذعر ونسّق مع الطاقم والشرطة."}},{"cat":"emergency","a":2,"q":{"en":"Why is it important to account for all people at the assembly point after an evacuation?","es":"Por qué es importante contabilizar a todas las personas en el punto de reunión después de una evacuación?","ru":"Почему важно учесть всех людей в месте сбора после эвакуации?","tr":"Bir tahliyeden sonra toplanma noktasında tüm kişilerin sayılması neden önemlidir?","hi":"निकासी के बाद सभा स्थल पर सभी लोगों की गिनती करना क्यों महत्वपूर्ण है?","ar":"لماذا من المهم حصر جميع الأشخاص في نقطة التجمّع بعد الإخلاء؟"},"o":[{"en":"To decide who is allowed to leave the property first","es":"Para decidir quién puede salir primero de la propiedad","ru":"Чтобы решить, кому разрешено покинуть территорию первым","tr":"Kimin önce mülkten ayrılabileceğine karar vermek için","hi":"यह तय करने के लिए कि पहले किसे संपत्ति छोड़ने की अनुमति है","ar":"لتحديد من يُسمح له بمغادرة الموقع أولًا"},{"en":"To collect everyone's contact information for marketing","es":"Para recopilar la información de contacto de todos para marketing","ru":"Чтобы собрать контактные данные всех для маркетинга","tr":"Herkesin iletişim bilgilerini pazarlama için toplamak","hi":"मार्केटिंग के लिए सभी की संपर्क जानकारी एकत्र करने के लिए","ar":"لجمع معلومات الاتصال بالجميع لأغراض التسويق"},{"en":"To identify anyone still missing so responders can be told who may be inside","es":"Para identificar a cualquier persona aún desaparecida y así informar a los rescatistas quién podría estar dentro","ru":"Чтобы выявить всех пропавших, чтобы сообщить спасателям, кто может находиться внутри","tr":"Hâlâ kayıp olan kişileri belirlemek ve kurtarma ekiplerine kimin içeride olabileceğini bildirmek için","hi":"अभी भी लापता किसी भी व्यक्ति की पहचान करने के लिए ताकि बचावकर्मियों को बताया जा सके कि कौन अंदर हो सकता है","ar":"لتحديد أي شخص لا يزال مفقودًا حتى يُبلَّغ رجال الإنقاذ بمن قد يكون بالداخل"},{"en":"To make sure no one takes more than their fair share of exits","es":"Para asegurarse de que nadie use más salidas de las que le corresponden","ru":"Чтобы убедиться, что никто не использует больше выходов, чем положено","tr":"Kimsenin hakkından fazla çıkış kullanmadığından emin olmak için","hi":"यह सुनिश्चित करने के लिए कि कोई भी अपने उचित हिस्से से अधिक निकास का उपयोग न करे","ar":"للتأكد من أن لا أحد يستخدم أكثر من نصيبه العادل من المخارج"}],"e":{"en":"Accounting for everyone at the assembly point identifies anyone still missing, so firefighters and other responders can be told who may still be inside the building.","es":"Contabilizar a todos en el punto de reunión identifica a cualquier persona aún desaparecida, para que los bomberos y otros rescatistas puedan saber quién podría seguir dentro del edificio.","ru":"Учет всех в месте сбора позволяет выявить всех пропавших, чтобы пожарным и другим спасателям можно было сообщить, кто может все еще находиться внутри здания.","tr":"Toplanma noktasında herkesin sayılması, hâlâ kayıp olan kişileri belirler, böylece itfaiyecilere ve diğer kurtarma ekiplerine binanın içinde hâlâ kimin olabileceği bildirilebilir.","hi":"सभा स्थल पर सभी की गिनती करने से किसी भी अभी भी लापता व्यक्ति की पहचान होती है, ताकि अग्निशामकों और अन्य बचावकर्मियों को बताया जा सके कि कौन अभी भी इमारत के अंदर हो सकता है।","ar":"حصر الجميع في نقطة التجمّع يحدّد أي شخص لا يزال مفقودًا، حتى يُبلَّغ رجال الإطفاء وغيرهم من فرق الإنقاذ بمن قد يكون لا يزال داخل المبنى."}},{"cat":"reports","a":1,"q":{"en":"When should a security guard take field notes about an incident?","es":"¿Cuándo debe un guardia de seguridad tomar notas de campo sobre un incidente?","ru":"Когда охранник должен делать полевые заметки о происшествии?","tr":"Bir güvenlik görevlisi bir olayla ilgili saha notlarını ne zaman almalıdır?","hi":"सुरक्षा गार्ड को किसी घटना के बारे में फील्ड नोट्स कब लेने चाहिए?","ar":"متى ينبغي لحارس الأمن أن يدوّن ملاحظات ميدانية عن الحادث؟"},"o":[{"en":"Several days later, once things have calmed down","es":"Varios días después, cuando todo se haya calmado","ru":"Через несколько дней, когда всё успокоится","tr":"Birkaç gün sonra, ortalık sakinleştiğinde","hi":"कई दिनों बाद, जब सब कुछ शांत हो जाए","ar":"بعد عدة أيام، عندما تهدأ الأمور"},{"en":"At the scene while the details are still fresh in memory","es":"En el lugar, mientras los detalles aún están frescos en la memoria","ru":"На месте, пока детали ещё свежи в памяти","tr":"Olay yerinde, ayrıntılar hâlâ hafızada tazeyken","hi":"घटनास्थल पर, जब विवरण अभी भी स्मृति में ताज़ा हों","ar":"في مكان الحادث بينما لا تزال التفاصيل حاضرة في الذاكرة"},{"en":"Only if a supervisor specifically orders it","es":"Solo si un supervisor lo ordena específicamente","ru":"Только если руководитель прямо это прикажет","tr":"Yalnızca bir amir özellikle emrederse","hi":"केवल तभी जब कोई पर्यवेक्षक विशेष रूप से आदेश दे","ar":"فقط إذا أمر المشرف بذلك تحديدًا"},{"en":"After you have already submitted the final report","es":"Después de haber entregado el informe final","ru":"После того как вы уже сдали окончательный отчёт","tr":"Nihai raporu zaten teslim ettikten sonra","hi":"अंतिम रिपोर्ट जमा कर देने के बाद","ar":"بعد أن تكون قد سلّمت التقرير النهائي بالفعل"}],"e":{"en":"Notes should be taken at the scene while details are fresh, because memory fades quickly; these notes become the factual basis for the written report.","es":"Las notas deben tomarse en el lugar mientras los detalles están frescos, porque la memoria se desvanece rápido; estas notas son la base fáctica del informe escrito.","ru":"Заметки следует делать на месте, пока детали свежи, ведь память быстро угасает; эти записи становятся фактической основой письменного отчёта.","tr":"Notlar, ayrıntılar tazeyken olay yerinde alınmalıdır çünkü hafıza çabuk zayıflar; bu notlar yazılı raporun olgusal temelini oluşturur.","hi":"नोट्स घटनास्थल पर तब लेने चाहिए जब विवरण ताज़ा हों, क्योंकि स्मृति जल्दी धुँधली हो जाती है; ये नोट्स लिखित रिपोर्ट का तथ्यात्मक आधार बनते हैं।","ar":"ينبغي تدوين الملاحظات في مكان الحادث بينما التفاصيل حاضرة، لأن الذاكرة تتلاشى بسرعة؛ وتصبح هذه الملاحظات الأساس الوقائعي للتقرير المكتوب."}},{"cat":"reports","a":3,"q":{"en":"An incident report should answer six basic questions. What are they?","es":"Un informe de incidente debe responder seis preguntas básicas. ¿Cuáles son?","ru":"Отчёт о происшествии должен отвечать на шесть основных вопросов. Какие это вопросы?","tr":"Bir olay raporu altı temel soruyu yanıtlamalıdır. Bunlar nelerdir?","hi":"एक घटना रिपोर्ट को छह बुनियादी प्रश्नों का उत्तर देना चाहिए। वे कौन से हैं?","ar":"يجب أن يجيب تقرير الحادث عن ستة أسئلة أساسية. ما هي؟"},"o":[{"en":"Who, What, When, Where, Which, Whether","es":"Quién, Qué, Cuándo, Dónde, Cuál, Si","ru":"Кто, Что, Когда, Где, Который, Ли","tr":"Kim, Ne, Ne zaman, Nerede, Hangi, Olup olmadığı","hi":"कौन, क्या, कब, कहाँ, कौन-सा, क्या-यह","ar":"من، ماذا، متى، أين، أيّ، هل"},{"en":"Cost, Time, Place, Weather, People, Damage","es":"Costo, Tiempo, Lugar, Clima, Personas, Daño","ru":"Стоимость, Время, Место, Погода, Люди, Ущерб","tr":"Maliyet, Zaman, Yer, Hava, İnsanlar, Hasar","hi":"लागत, समय, स्थान, मौसम, लोग, क्षति","ar":"التكلفة، الوقت، المكان، الطقس، الأشخاص، الضرر"},{"en":"Name, Rank, Badge, Shift, Post, Signature","es":"Nombre, Rango, Placa, Turno, Puesto, Firma","ru":"Имя, Звание, Жетон, Смена, Пост, Подпись","tr":"İsim, Rütbe, Rozet, Vardiya, Nokta, İmza","hi":"नाम, पद, बैज, पाली, चौकी, हस्ताक्षर","ar":"الاسم، الرتبة، الشارة، الوردية، الموقع، التوقيع"},{"en":"Who, What, When, Where, Why, How","es":"Quién, Qué, Cuándo, Dónde, Por qué, Cómo","ru":"Кто, Что, Когда, Где, Почему, Как","tr":"Kim, Ne, Ne zaman, Nerede, Neden, Nasıl","hi":"कौन, क्या, कब, कहाँ, क्यों, कैसे","ar":"من، ماذا، متى، أين، لماذا، كيف"}],"e":{"en":"A complete report answers Who, What, When, Where, Why, and How; covering these six questions ensures no key detail is left out.","es":"Un informe completo responde Quién, Qué, Cuándo, Dónde, Por qué y Cómo; cubrir estas seis preguntas asegura que no falte ningún detalle clave.","ru":"Полный отчёт отвечает на вопросы Кто, Что, Когда, Где, Почему и Как; охват этих шести вопросов гарантирует, что ни одна ключевая деталь не будет упущена.","tr":"Eksiksiz bir rapor Kim, Ne, Ne zaman, Nerede, Neden ve Nasıl sorularını yanıtlar; bu altı soruyu kapsamak hiçbir önemli ayrıntının atlanmamasını sağlar.","hi":"एक पूर्ण रिपोर्ट कौन, क्या, कब, कहाँ, क्यों और कैसे का उत्तर देती है; इन छह प्रश्नों को शामिल करने से यह सुनिश्चित होता है कि कोई मुख्य विवरण छूटे नहीं।","ar":"يجيب التقرير الكامل عن من، ماذا، متى، أين، لماذا، وكيف؛ وتغطية هذه الأسئلة الستة تضمن عدم إغفال أي تفصيل رئيسي."}},{"cat":"reports","a":0,"q":{"en":"Which of the following is a statement of FACT rather than opinion in a report?","es":"¿Cuál de las siguientes es una declaración de HECHO en lugar de opinión en un informe?","ru":"Что из перечисленного является изложением ФАКТА, а не мнения в отчёте?","tr":"Aşağıdakilerden hangisi bir raporda görüş değil OLGU bildiren bir ifadedir?","hi":"निम्नलिखित में से कौन-सा किसी रिपोर्ट में राय के बजाय तथ्य का कथन है?","ar":"أيّ من العبارات التالية يمثّل بيان واقعة وليس رأيًا في التقرير؟"},"o":[{"en":"The man was holding a metal bar in his right hand","es":"El hombre sostenía una barra de metal en su mano derecha","ru":"Мужчина держал металлический прут в правой руке","tr":"Adam sağ elinde metal bir çubuk tutuyordu","hi":"वह आदमी अपने दाहिने हाथ में एक धातु की छड़ पकड़े हुए था","ar":"كان الرجل يمسك قضيبًا معدنيًا بيده اليمنى"},{"en":"The man looked like a dangerous troublemaker","es":"El hombre parecía un alborotador peligroso","ru":"Мужчина выглядел как опасный смутьян","tr":"Adam tehlikeli bir baş belası gibi görünüyordu","hi":"वह आदमी एक खतरनाक उपद्रवी लग रहा था","ar":"بدا الرجل كمثير مشاكل خطير"},{"en":"The man was obviously going to attack someone","es":"El hombre obviamente iba a atacar a alguien","ru":"Мужчина явно собирался на кого-то напасть","tr":"Adam belli ki birine saldıracaktı","hi":"वह आदमी स्पष्ट रूप से किसी पर हमला करने वाला था","ar":"من الواضح أن الرجل كان سيهاجم أحدًا"},{"en":"The man was probably drunk and up to no good","es":"El hombre probablemente estaba borracho y tramaba algo malo","ru":"Мужчина, вероятно, был пьян и замышлял недоброе","tr":"Adam muhtemelen sarhoştu ve kötü bir niyeti vardı","hi":"वह आदमी शायद नशे में था और कोई गड़बड़ी करने वाला था","ar":"ربما كان الرجل ثملًا وينوي شرًا"}],"e":{"en":"A fact is something you directly observed and can prove, such as an object someone held; the other options are opinions or assumptions and do not belong in a report.","es":"Un hecho es algo que observó directamente y puede probar, como un objeto que alguien sostenía; las otras opciones son opiniones o suposiciones y no deben ir en un informe.","ru":"Факт — это то, что вы непосредственно наблюдали и можете доказать, например предмет в чьей-то руке; остальные варианты — мнения или предположения, которым не место в отчёте.","tr":"Olgu, doğrudan gözlemlediğiniz ve kanıtlayabileceğiniz bir şeydir, örneğin birinin tuttuğu bir nesne; diğer seçenekler görüş veya varsayımdır ve rapora girmemelidir.","hi":"तथ्य वह है जिसे आपने सीधे देखा और सिद्ध कर सकते हैं, जैसे किसी के हाथ में पकड़ी वस्तु; अन्य विकल्प राय या धारणाएँ हैं और रिपोर्ट में नहीं होने चाहिए।","ar":"الواقعة هي ما لاحظته مباشرة ويمكنك إثباته، مثل جسم كان يمسكه شخص ما؛ أما الخيارات الأخرى فهي آراء أو افتراضات ولا مكان لها في التقرير."}},{"cat":"reports","a":2,"q":{"en":"In what verb tense should most of a completed incident report be written?","es":"¿En qué tiempo verbal debe redactarse la mayor parte de un informe de incidente terminado?","ru":"В каком времени должна быть написана большая часть завершённого отчёта о происшествии?","tr":"Tamamlanmış bir olay raporunun büyük bölümü hangi fiil zamanıyla yazılmalıdır?","hi":"पूर्ण की गई घटना रिपोर्ट का अधिकांश भाग किस काल में लिखा जाना चाहिए?","ar":"بأيّ زمن فعلي ينبغي كتابة معظم تقرير الحادث المُنجَز؟"},"o":[{"en":"Future tense","es":"Tiempo futuro","ru":"Будущее время","tr":"Gelecek zaman","hi":"भविष्य काल","ar":"زمن المستقبل"},{"en":"Present tense","es":"Tiempo presente","ru":"Настоящее время","tr":"Şimdiki zaman","hi":"वर्तमान काल","ar":"زمن المضارع"},{"en":"Past tense","es":"Tiempo pasado","ru":"Прошедшее время","tr":"Geçmiş zaman","hi":"भूत काल","ar":"زمن الماضي"},{"en":"It does not matter which tense","es":"No importa qué tiempo","ru":"Время не имеет значения","tr":"Hangi zaman olduğu önemli değil","hi":"कौन-सा काल हो, इससे फर्क नहीं पड़ता","ar":"لا يهم أيّ زمن يُستخدم"}],"e":{"en":"Reports describe events that already happened, so they are written in the past tense to keep them clear and factual.","es":"Los informes describen sucesos que ya ocurrieron, por lo que se redactan en tiempo pasado para mantenerlos claros y objetivos.","ru":"Отчёты описывают уже произошедшие события, поэтому их пишут в прошедшем времени, чтобы они были ясными и фактическими.","tr":"Raporlar zaten gerçekleşmiş olayları anlatır, bu yüzden açık ve olgusal olmaları için geçmiş zamanla yazılır.","hi":"रिपोर्ट पहले घट चुकी घटनाओं का वर्णन करती है, इसलिए उन्हें स्पष्ट और तथ्यपरक रखने के लिए भूत काल में लिखा जाता है।","ar":"تصف التقارير أحداثًا وقعت بالفعل، لذا تُكتب بزمن الماضي لتبقى واضحة ووقائعية."}},{"cat":"reports","a":1,"q":{"en":"Why is it better to record exact times, dates, and locations in a report rather than approximate ones?","es":"¿Por qué es mejor registrar horas, fechas y lugares exactos en un informe en vez de aproximados?","ru":"Почему в отчёте лучше указывать точное время, даты и места, а не приблизительные?","tr":"Bir raporda yaklaşık yerine tam saat, tarih ve konumların kaydedilmesi neden daha iyidir?","hi":"रिपोर्ट में अनुमानित के बजाय सटीक समय, तिथियाँ और स्थान दर्ज करना क्यों बेहतर है?","ar":"لماذا يُفضَّل تسجيل الأوقات والتواريخ والمواقع الدقيقة في التقرير بدلًا من التقريبية؟"},"o":[{"en":"It makes the report look longer and more impressive","es":"Hace que el informe parezca más largo e impresionante","ru":"Это делает отчёт длиннее и внушительнее","tr":"Raporu daha uzun ve etkileyici gösterir","hi":"इससे रिपोर्ट लंबी और प्रभावशाली दिखती है","ar":"يجعل التقرير يبدو أطول وأكثر إبهارًا"},{"en":"Specific details make the report more accurate and credible if it is used later","es":"Los detalles específicos hacen el informe más preciso y creíble si se usa después","ru":"Конкретные детали делают отчёт точнее и достовернее, если он понадобится позже","tr":"Belirli ayrıntılar, rapor daha sonra kullanılırsa onu daha doğru ve inandırıcı kılar","hi":"विशिष्ट विवरण रिपोर्ट को अधिक सटीक और विश्वसनीय बनाते हैं यदि इसका बाद में उपयोग हो","ar":"التفاصيل المحددة تجعل التقرير أكثر دقة ومصداقية إذا استُخدم لاحقًا"},{"en":"Approximate times are illegal in every state","es":"Las horas aproximadas son ilegales en todos los estados","ru":"Приблизительное время незаконно в каждом штате","tr":"Yaklaşık saatler her eyalette yasa dışıdır","hi":"अनुमानित समय हर राज्य में अवैध है","ar":"الأوقات التقريبية غير قانونية في كل ولاية"},{"en":"So the guard can charge more for the shift","es":"Para que el guardia pueda cobrar más por el turno","ru":"Чтобы охранник мог брать больше за смену","tr":"Görevli vardiya için daha fazla ücret alabilsin diye","hi":"ताकि गार्ड पाली के लिए अधिक शुल्क ले सके","ar":"لكي يتقاضى الحارس أجرًا أعلى عن الوردية"}],"e":{"en":"Exact times, dates, and locations make a report accurate and credible, which matters if it is later used in an investigation or in court.","es":"Las horas, fechas y lugares exactos hacen que un informe sea preciso y creíble, lo cual importa si luego se usa en una investigación o en el tribunal.","ru":"Точное время, даты и места делают отчёт точным и достоверным, что важно, если он позже используется в расследовании или суде.","tr":"Tam saat, tarih ve konumlar bir raporu doğru ve inandırıcı kılar; bu, rapor daha sonra bir soruşturmada veya mahkemede kullanılırsa önemlidir.","hi":"सटीक समय, तिथियाँ और स्थान रिपोर्ट को सटीक और विश्वसनीय बनाते हैं, जो तब मायने रखता है जब इसका बाद में जाँच या अदालत में उपयोग हो।","ar":"الأوقات والتواريخ والمواقع الدقيقة تجعل التقرير دقيقًا وموثوقًا، وهو أمر مهم إذا استُخدم لاحقًا في تحقيق أو في المحكمة."}},{"cat":"reports","a":3,"q":{"en":"Which set of qualities best describes a well-written security report?","es":"¿Qué conjunto de cualidades describe mejor un informe de seguridad bien redactado?","ru":"Какой набор качеств лучше всего описывает хорошо написанный отчёт по безопасности?","tr":"Hangi nitelikler kümesi iyi yazılmış bir güvenlik raporunu en iyi tanımlar?","hi":"कौन-सा गुणों का समूह एक अच्छी तरह लिखी गई सुरक्षा रिपोर्ट का सबसे अच्छा वर्णन करता है?","ar":"أيّ مجموعة من الصفات تصف على أفضل وجه تقرير أمن مكتوب جيدًا؟"},"o":[{"en":"Long, detailed, emotional, and persuasive","es":"Largo, detallado, emotivo y persuasivo","ru":"Длинный, подробный, эмоциональный и убедительный","tr":"Uzun, ayrıntılı, duygusal ve ikna edici","hi":"लंबा, विस्तृत, भावनात्मक और प्रेरक","ar":"طويل، مفصّل، عاطفي، ومقنِع"},{"en":"Creative, colorful, opinionated, and dramatic","es":"Creativo, colorido, con opiniones y dramático","ru":"Творческий, красочный, с мнениями и драматичный","tr":"Yaratıcı, renkli, görüş dolu ve dramatik","hi":"रचनात्मक, रंगीन, राय-भरा और नाटकीय","ar":"إبداعي، ملوّن، مليء بالآراء، ودرامي"},{"en":"Brief, vague, informal, and flexible","es":"Breve, vago, informal y flexible","ru":"Краткий, расплывчатый, неформальный и гибкий","tr":"Kısa, belirsiz, resmî olmayan ve esnek","hi":"संक्षिप्त, अस्पष्ट, अनौपचारिक और लचीला","ar":"موجز، غامض، غير رسمي، ومرن"},{"en":"Factual, accurate, clear, concise, complete, and objective","es":"Objetivo en hechos, exacto, claro, conciso, completo e imparcial","ru":"Фактический, точный, ясный, лаконичный, полный и объективный","tr":"Olgusal, doğru, açık, öz, eksiksiz ve nesnel","hi":"तथ्यपरक, सटीक, स्पष्ट, संक्षिप्त, पूर्ण और वस्तुनिष्ठ","ar":"وقائعي، دقيق، واضح، موجز، كامل، وموضوعي"}],"e":{"en":"A good report is factual, accurate, clear, concise, complete, and objective; it reports what happened without emotion, drama, or personal opinion.","es":"Un buen informe es objetivo, exacto, claro, conciso, completo e imparcial; relata lo ocurrido sin emoción, drama ni opinión personal.","ru":"Хороший отчёт является фактическим, точным, ясным, лаконичным, полным и объективным; он излагает произошедшее без эмоций, драмы и личных мнений.","tr":"İyi bir rapor olgusal, doğru, açık, öz, eksiksiz ve nesneldir; olanı duygu, dram veya kişisel görüş katmadan aktarır.","hi":"अच्छी रिपोर्ट तथ्यपरक, सटीक, स्पष्ट, संक्षिप्त, पूर्ण और वस्तुनिष्ठ होती है; यह भावना, नाटक या व्यक्तिगत राय के बिना बताती है कि क्या हुआ।","ar":"التقرير الجيد وقائعي ودقيق وواضح وموجز وكامل وموضوعي؛ يروي ما حدث دون عاطفة أو دراما أو رأي شخصي."}},{"cat":"reports","a":0,"q":{"en":"Why should slang, jargon, and abbreviations generally be avoided in a written report?","es":"¿Por qué se deben evitar en general la jerga, los tecnicismos y las abreviaturas en un informe escrito?","ru":"Почему в письменном отчёте обычно следует избегать сленга, жаргона и сокращений?","tr":"Yazılı bir raporda argo, jargon ve kısaltmalardan genel olarak neden kaçınılmalıdır?","hi":"लिखित रिपोर्ट में आम तौर पर अपशब्द, विशिष्ट-शब्दजाल और संक्षिप्तियों से क्यों बचना चाहिए?","ar":"لماذا ينبغي عمومًا تجنّب العامية والمصطلحات المهنية والاختصارات في التقرير المكتوب؟"},"o":[{"en":"So anyone who reads the report later can understand it clearly","es":"Para que cualquiera que lea el informe después pueda entenderlo con claridad","ru":"Чтобы любой, кто прочтёт отчёт позже, мог ясно его понять","tr":"Raporu sonradan okuyan herkes onu net biçimde anlayabilsin diye","hi":"ताकि जो कोई भी बाद में रिपोर्ट पढ़े, उसे स्पष्ट रूप से समझ सके","ar":"لكي يفهمه بوضوح أيّ شخص يقرأ التقرير لاحقًا"},{"en":"Because slang makes the guard sound more experienced","es":"Porque la jerga hace que el guardia suene con más experiencia","ru":"Потому что сленг делает охранника более опытным на слух","tr":"Çünkü argo, görevliyi daha deneyimli gösterir","hi":"क्योंकि अपशब्द गार्ड को अधिक अनुभवी दिखाते हैं","ar":"لأن العامية تجعل الحارس يبدو أكثر خبرة"},{"en":"Because reports are never read by anyone else","es":"Porque nadie más lee nunca los informes","ru":"Потому что отчёты никто больше не читает","tr":"Çünkü raporları başka kimse okumaz","hi":"क्योंकि रिपोर्ट को और कोई कभी नहीं पढ़ता","ar":"لأن التقارير لا يقرؤها أحد آخر أبدًا"},{"en":"Because plain words are against company policy","es":"Porque las palabras sencillas van contra la política de la empresa","ru":"Потому что простые слова противоречат политике компании","tr":"Çünkü sade kelimeler şirket politikasına aykırıdır","hi":"क्योंकि सरल शब्द कंपनी की नीति के विरुद्ध हैं","ar":"لأن الكلمات البسيطة تخالف سياسة الشركة"}],"e":{"en":"Reports may be read by supervisors, police, lawyers, or a court, so plain, clear language ensures everyone understands exactly what happened.","es":"Los informes pueden ser leídos por supervisores, policía, abogados o un tribunal, así que un lenguaje sencillo y claro asegura que todos entiendan exactamente lo ocurrido.","ru":"Отчёты могут читать руководители, полиция, юристы или суд, поэтому простой и ясный язык обеспечивает, что все точно поймут произошедшее.","tr":"Raporları amirler, polis, avukatlar veya mahkeme okuyabilir; bu yüzden sade ve açık dil, herkesin tam olarak ne olduğunu anlamasını sağlar.","hi":"रिपोर्ट को पर्यवेक्षक, पुलिस, वकील या अदालत पढ़ सकती है, इसलिए सरल, स्पष्ट भाषा यह सुनिश्चित करती है कि सभी समझें कि वास्तव में क्या हुआ।","ar":"قد يقرأ التقارير المشرفون أو الشرطة أو المحامون أو المحكمة، لذا فإن اللغة البسيطة والواضحة تضمن أن يفهم الجميع ما حدث بالضبط."}},{"cat":"reports","a":2,"q":{"en":"What does it mean for a report to be 'objective'?","es":"¿Qué significa que un informe sea 'objetivo'?","ru":"Что означает, что отчёт является «объективным»?","tr":"Bir raporun 'nesnel' olması ne demektir?","hi":"किसी रिपोर्ट के 'वस्तुनिष्ठ' होने का क्या अर्थ है?","ar":"ماذا يعني أن يكون التقرير 'موضوعيًا'؟"},"o":[{"en":"It focuses on the guard's personal feelings about the event","es":"Se centra en los sentimientos personales del guardia sobre el suceso","ru":"Он сосредоточен на личных чувствах охранника по поводу события","tr":"Görevlinin olayla ilgili kişisel duygularına odaklanır","hi":"यह घटना के बारे में गार्ड की व्यक्तिगत भावनाओं पर केंद्रित होती है","ar":"يركّز على مشاعر الحارس الشخصية تجاه الحدث"},{"en":"It argues that one person involved is guilty","es":"Sostiene que una de las personas implicadas es culpable","ru":"Он утверждает, что один из участников виновен","tr":"Olaya karışan bir kişinin suçlu olduğunu savunur","hi":"यह तर्क देती है कि शामिल एक व्यक्ति दोषी है","ar":"يجادل بأن أحد المتورّطين مذنب"},{"en":"It sticks to observable facts without personal bias or emotion","es":"Se ciñe a hechos observables sin sesgo personal ni emoción","ru":"Он придерживается наблюдаемых фактов без личной предвзятости и эмоций","tr":"Kişisel önyargı veya duygu katmadan gözlemlenebilir olgulara bağlı kalır","hi":"यह व्यक्तिगत पूर्वाग्रह या भावना के बिना अवलोकनीय तथ्यों पर टिकी रहती है","ar":"يلتزم بالوقائع القابلة للملاحظة دون تحيّز شخصي أو عاطفة"},{"en":"It predicts what the people involved will do next","es":"Predice lo que harán a continuación las personas implicadas","ru":"Он предсказывает, что дальше сделают участники","tr":"Olaya karışan kişilerin bundan sonra ne yapacağını tahmin eder","hi":"यह भविष्यवाणी करती है कि शामिल लोग आगे क्या करेंगे","ar":"يتنبّأ بما سيفعله المتورّطون لاحقًا"}],"e":{"en":"An objective report presents only observable facts without the writer's personal bias, emotion, or conclusions about guilt.","es":"Un informe objetivo presenta solo hechos observables, sin el sesgo personal, la emoción ni las conclusiones del autor sobre la culpa.","ru":"Объективный отчёт содержит только наблюдаемые факты без личной предвзятости, эмоций или выводов автора о виновности.","tr":"Nesnel bir rapor yalnızca gözlemlenebilir olguları sunar; yazarın kişisel önyargısı, duygusu veya suçluluk hakkında vardığı sonuçlar yoktur.","hi":"वस्तुनिष्ठ रिपोर्ट केवल अवलोकनीय तथ्य प्रस्तुत करती है, लेखक के व्यक्तिगत पूर्वाग्रह, भावना या दोष के बारे में निष्कर्ष के बिना।","ar":"يقدّم التقرير الموضوعي الوقائع القابلة للملاحظة فقط، دون تحيّز الكاتب الشخصي أو عاطفته أو استنتاجاته بشأن الإدانة."}},{"cat":"reports","a":1,"q":{"en":"What is the main purpose of the 'chain of custody' for evidence?","es":"¿Cuál es el propósito principal de la 'cadena de custodia' de la evidencia?","ru":"Какова основная цель «цепочки хранения» вещественных доказательств?","tr":"Delil için 'gözetim zinciri'nin temel amacı nedir?","hi":"साक्ष्य के लिए 'अभिरक्षा की श्रृंखला' (चेन ऑफ कस्टडी) का मुख्य उद्देश्य क्या है?","ar":"ما الغرض الأساسي من 'سلسلة حيازة' الأدلة؟"},"o":[{"en":"To make evidence look more important to a jury","es":"Hacer que la evidencia parezca más importante ante un jurado","ru":"Сделать доказательства более важными на вид для присяжных","tr":"Delili bir jüriye daha önemli göstermek","hi":"जूरी के सामने साक्ष्य को अधिक महत्वपूर्ण दिखाना","ar":"جعل الدليل يبدو أكثر أهمية أمام هيئة المحلفين"},{"en":"To document who handled the evidence and when, so it stays admissible","es":"Documentar quién manejó la evidencia y cuándo, para que siga siendo admisible","ru":"Документировать, кто и когда обращался с доказательствами, чтобы они оставались допустимыми","tr":"Delili kimin ne zaman ellediğini belgelemek, böylece delil kabul edilebilir kalsın diye","hi":"यह दस्तावेज़ करना कि साक्ष्य को किसने और कब संभाला, ताकि वह ग्राह्य बना रहे","ar":"توثيق من تعامل مع الدليل ومتى، لكي يبقى مقبولًا"},{"en":"To decide how much the evidence is worth in dollars","es":"Decidir cuánto vale la evidencia en dólares","ru":"Определить, сколько стоят доказательства в долларах","tr":"Delilin dolar cinsinden değerini belirlemek","hi":"यह तय करना कि साक्ष्य का मूल्य डॉलर में कितना है","ar":"تحديد قيمة الدليل بالدولار"},{"en":"To let anyone borrow the evidence when they need it","es":"Permitir que cualquiera tome prestada la evidencia cuando la necesite","ru":"Позволять любому брать доказательства, когда они нужны","tr":"İhtiyaç duyan herkesin delili ödünç almasına izin vermek","hi":"किसी को भी ज़रूरत होने पर साक्ष्य उधार लेने देना","ar":"السماح لأي شخص باستعارة الدليل عند حاجته"}],"e":{"en":"Chain of custody is a documented record of everyone who handled evidence and when; an unbroken chain keeps the evidence admissible in court.","es":"La cadena de custodia es un registro documentado de todos los que manejaron la evidencia y cuándo; una cadena ininterrumpida mantiene la evidencia admisible en el tribunal.","ru":"Цепочка хранения — это документированная запись обо всех, кто и когда обращался с доказательствами; непрерывная цепочка сохраняет их допустимость в суде.","tr":"Gözetim zinciri, delili kimin ne zaman ellediğine dair belgelenmiş bir kayıttır; kesintisiz bir zincir delilin mahkemede kabul edilebilir kalmasını sağlar.","hi":"अभिरक्षा की श्रृंखला एक दस्तावेज़ित रिकॉर्ड है कि साक्ष्य को किसने और कब संभाला; एक अखंडित श्रृंखला साक्ष्य को अदालत में ग्राह्य बनाए रखती है।","ar":"سلسلة الحيازة سجلّ موثّق لكل من تعامل مع الدليل ومتى؛ والسلسلة غير المنقطعة تُبقي الدليل مقبولًا في المحكمة."}},{"cat":"reports","a":0,"q":{"en":"After a guard collects a piece of evidence, what should be done to preserve the chain of custody?","es":"Después de que un guardia recoge una pieza de evidencia, ¿qué debe hacerse para preservar la cadena de custodia?","ru":"После того как охранник собрал вещественное доказательство, что нужно сделать для сохранения цепочки хранения?","tr":"Bir görevli bir delil parçasını topladıktan sonra, gözetim zincirini korumak için ne yapılmalıdır?","hi":"जब कोई गार्ड कोई साक्ष्य एकत्र कर ले, तो अभिरक्षा की श्रृंखला बनाए रखने के लिए क्या करना चाहिए?","ar":"بعد أن يجمع الحارس قطعة دليل، ماذا ينبغي فعله للحفاظ على سلسلة الحيازة؟"},"o":[{"en":"Label and secure it, and log each person who handles it and the time","es":"Etiquetarla y asegurarla, y registrar a cada persona que la manipule y la hora","ru":"Пометить и надёжно хранить, регистрируя каждого, кто с ней обращается, и время","tr":"Etiketleyip güvence altına almak ve onu elleyen her kişiyi ve zamanı kaydetmek","hi":"उस पर लेबल लगाना और सुरक्षित करना, और हर व्यक्ति व समय को दर्ज करना जो उसे संभाले","ar":"وسمها وتأمينها، وتسجيل كل شخص يتعامل معها والوقت"},{"en":"Pass it around to coworkers so they can see it","es":"Pasarla entre los compañeros para que la vean","ru":"Передавать её коллегам, чтобы они посмотрели","tr":"İş arkadaşlarının görmesi için elden ele dolaştırmak","hi":"सहकर्मियों के बीच घुमाना ताकि वे देख सकें","ar":"تمريرها بين الزملاء لكي يروها"},{"en":"Clean it thoroughly before storing it","es":"Limpiarla a fondo antes de guardarla","ru":"Тщательно очистить её перед хранением","tr":"Saklamadan önce iyice temizlemek","hi":"संग्रहीत करने से पहले उसे अच्छी तरह साफ़ करना","ar":"تنظيفها جيدًا قبل تخزينها"},{"en":"Keep it at home until the investigator asks for it","es":"Guardarla en casa hasta que el investigador la pida","ru":"Держать её дома, пока следователь не запросит","tr":"Soruşturmacı isteyene kadar evde saklamak","hi":"जब तक अन्वेषक न माँगे, उसे घर पर रखना","ar":"الاحتفاظ بها في المنزل حتى يطلبها المحقق"}],"e":{"en":"Evidence must be labeled, secured, and logged with each handler and time to keep an unbroken record; passing it around or cleaning it can destroy its value.","es":"La evidencia debe etiquetarse, asegurarse y registrarse con cada persona que la manipula y la hora para mantener un registro ininterrumpido; pasarla o limpiarla puede destruir su valor.","ru":"Доказательства нужно пометить, надёжно хранить и вести журнал с указанием каждого, кто с ними работал, и времени, чтобы запись была непрерывной; передача из рук в руки или очистка могут уничтожить их ценность.","tr":"Delil, kesintisiz bir kayıt tutmak için etiketlenmeli, güvence altına alınmalı ve onu elleyen her kişi ile zaman kaydedilmelidir; elden ele dolaştırmak veya temizlemek değerini yok edebilir.","hi":"साक्ष्य पर लेबल लगाना, सुरक्षित करना और हर संभालने वाले व समय को दर्ज करना आवश्यक है ताकि रिकॉर्ड अखंडित रहे; उसे घुमाना या साफ़ करना उसका मूल्य नष्ट कर सकता है।","ar":"يجب وسم الدليل وتأمينه وتسجيل كل من تعامل معه والوقت للحفاظ على سجلّ غير منقطع؛ وتمريره أو تنظيفه قد يدمّر قيمته."}},{"cat":"reports","a":2,"q":{"en":"On the radio, why do many security agencies now prefer plain language over 10-codes?","es":"En la radio, ¿por qué muchas agencias de seguridad prefieren ahora el lenguaje sencillo en lugar de los códigos 10?","ru":"Почему многие охранные агентства теперь предпочитают в радиосвязи простую речь, а не 10-коды?","tr":"Telsizde, birçok güvenlik şirketi neden artık 10-kodları yerine sade dili tercih ediyor?","hi":"रेडियो पर, अब कई सुरक्षा एजेंसियाँ 10-कोड के बजाय सरल भाषा को क्यों प्राथमिकता देती हैं?","ar":"في اللاسلكي، لماذا تفضّل كثير من شركات الأمن الآن اللغة الواضحة بدلًا من رموز الـ10؟"},"o":[{"en":"Plain language sounds more impressive to the public","es":"El lenguaje sencillo suena más impresionante para el público","ru":"Простая речь звучит внушительнее для публики","tr":"Sade dil halka daha etkileyici gelir","hi":"सरल भाषा जनता को अधिक प्रभावशाली लगती है","ar":"اللغة الواضحة تبدو أكثر إبهارًا للجمهور"},{"en":"10-codes are illegal for private security to use","es":"Los códigos 10 son ilegales para la seguridad privada","ru":"10-коды запрещено использовать частной охране","tr":"10-kodları özel güvenliğin kullanması yasa dışıdır","hi":"निजी सुरक्षा के लिए 10-कोड का उपयोग अवैध है","ar":"رموز الـ10 غير قانونية لاستخدام الأمن الخاص"},{"en":"10-codes vary between agencies, so plain language keeps everyone on the same page","es":"Los códigos 10 varían entre agencias, así que el lenguaje sencillo mantiene a todos en la misma sintonía","ru":"10-коды различаются между агентствами, поэтому простая речь помогает всем понимать друг друга","tr":"10-kodları şirketten şirkete değişir, bu yüzden sade dil herkesin aynı anlayışta olmasını sağlar","hi":"10-कोड एजेंसियों के बीच भिन्न होते हैं, इसलिए सरल भाषा सभी को एक ही समझ पर रखती है","ar":"رموز الـ10 تختلف بين الشركات، لذا تُبقي اللغة الواضحة الجميع على فهم مشترك"},{"en":"Plain language lets guards talk longer on the radio","es":"El lenguaje sencillo permite a los guardias hablar más tiempo por la radio","ru":"Простая речь позволяет охранникам дольше говорить по рации","tr":"Sade dil, görevlilerin telsizde daha uzun konuşmasına izin verir","hi":"सरल भाषा गार्ड को रेडियो पर अधिक देर बात करने देती है","ar":"اللغة الواضحة تتيح للحراس التحدث لفترة أطول على اللاسلكي"}],"e":{"en":"10-codes differ from agency to agency, so plain (clear-text) language improves interoperability and ensures everyone, including police and medics, understands the message.","es":"Los códigos 10 difieren de una agencia a otra, así que el lenguaje sencillo (texto claro) mejora la interoperabilidad y asegura que todos, incluidos policía y paramédicos, entiendan el mensaje.","ru":"10-коды отличаются от агентства к агентству, поэтому простая речь (открытый текст) улучшает взаимодействие и гарантирует, что все, включая полицию и медиков, поймут сообщение.","tr":"10-kodları şirketten şirkete farklıdır; bu yüzden sade (açık metin) dil, birlikte çalışabilirliği artırır ve polis ile sağlıkçılar dâhil herkesin mesajı anlamasını sağlar.","hi":"10-कोड एजेंसी-दर-एजेंसी भिन्न होते हैं, इसलिए सरल (स्पष्ट-पाठ) भाषा अंतर-संचालन में सुधार करती है और सुनिश्चित करती है कि पुलिस व चिकित्सकों सहित सभी संदेश समझें।","ar":"تختلف رموز الـ10 من شركة إلى أخرى، لذا تُحسّن اللغة الواضحة (النص الصريح) قابلية التشغيل البيني وتضمن أن يفهم الجميع الرسالة، بمن فيهم الشرطة والمسعفون."}},{"cat":"reports","a":3,"q":{"en":"Which practice reflects good radio discipline for a security guard?","es":"¿Qué práctica refleja una buena disciplina de radio para un guardia de seguridad?","ru":"Какая практика отражает хорошую дисциплину радиосвязи для охранника?","tr":"Hangi uygulama bir güvenlik görevlisi için iyi telsiz disiplinini yansıtır?","hi":"कौन-सी प्रथा सुरक्षा गार्ड के लिए अच्छे रेडियो अनुशासन को दर्शाती है?","ar":"أيّ ممارسة تعكس انضباطًا لاسلكيًا جيدًا لحارس الأمن؟"},"o":[{"en":"Using profanity to show urgency","es":"Usar groserías para mostrar urgencia","ru":"Использовать ругательства, чтобы показать срочность","tr":"Aciliyeti göstermek için küfür kullanmak","hi":"तात्कालिकता दिखाने के लिए गाली-गलौज करना","ar":"استخدام الألفاظ البذيئة لإظهار الاستعجال"},{"en":"Chatting about personal topics to fill dead air","es":"Charlar sobre temas personales para llenar el silencio","ru":"Болтать на личные темы, чтобы заполнить паузы","tr":"Sessizliği doldurmak için kişisel konularda sohbet etmek","hi":"खाली समय भरने के लिए निजी विषयों पर गपशप करना","ar":"الدردشة في مواضيع شخصية لملء الصمت"},{"en":"Broadcasting a resident's full name and address to everyone","es":"Difundir el nombre completo y la dirección de un residente a todos","ru":"Передавать всем полное имя и адрес жильца","tr":"Bir sakinin tam adını ve adresini herkese yayınlamak","hi":"किसी निवासी का पूरा नाम और पता सभी को प्रसारित करना","ar":"إذاعة الاسم الكامل والعنوان لأحد السكان للجميع"},{"en":"Identifying yourself, keeping traffic brief, and staying professional","es":"Identificarse, mantener las transmisiones breves y ser profesional","ru":"Представляться, вести переговоры кратко и держаться профессионально","tr":"Kendinizi tanıtmak, konuşmayı kısa tutmak ve profesyonel kalmak","hi":"अपनी पहचान देना, संचार संक्षिप्त रखना और पेशेवर बने रहना","ar":"التعريف بنفسك، وإبقاء الاتصال موجزًا، والحفاظ على المهنية"}],"e":{"en":"Good radio discipline means identifying yourself, keeping transmissions short and professional, avoiding profanity, and not carelessly broadcasting sensitive information.","es":"La buena disciplina de radio significa identificarse, mantener las transmisiones cortas y profesionales, evitar groserías y no difundir descuidadamente información sensible.","ru":"Хорошая дисциплина радиосвязи означает представляться, вести передачи кратко и профессионально, избегать ругани и не передавать беспечно конфиденциальную информацию.","tr":"İyi telsiz disiplini; kendinizi tanıtmak, konuşmaları kısa ve profesyonel tutmak, küfürden kaçınmak ve hassas bilgileri dikkatsizce yayınlamamak demektir.","hi":"अच्छा रेडियो अनुशासन का अर्थ है अपनी पहचान देना, संचार को संक्षिप्त और पेशेवर रखना, गाली-गलौज से बचना और संवेदनशील जानकारी को लापरवाही से प्रसारित न करना।","ar":"الانضباط اللاسلكي الجيد يعني التعريف بنفسك، وإبقاء الإرسال قصيرًا ومهنيًا، وتجنّب الألفاظ البذيئة، وعدم إذاعة المعلومات الحساسة بإهمال."}},{"cat":"reports","a":0,"q":{"en":"You are called to testify in court about an incident you reported. What should you do beforehand?","es":"Lo llaman a testificar en el tribunal sobre un incidente que reportó. ¿Qué debe hacer de antemano?","ru":"Вас вызвали в суд для дачи показаний о происшествии, о котором вы сообщили. Что следует сделать заранее?","tr":"Bildirdiğiniz bir olay hakkında mahkemede tanıklık etmeye çağrıldınız. Öncesinde ne yapmalısınız?","hi":"आपको उस घटना के बारे में अदालत में गवाही देने के लिए बुलाया गया है जिसकी आपने रिपोर्ट की थी। पहले से आपको क्या करना चाहिए?","ar":"استُدعيت للإدلاء بشهادة في المحكمة عن حادث أبلغت عنه. ماذا ينبغي أن تفعل مسبقًا؟"},"o":[{"en":"Review your own report so your testimony matches the facts you recorded","es":"Repasar su propio informe para que su testimonio coincida con los hechos que registró","ru":"Просмотреть свой отчёт, чтобы показания совпадали с записанными фактами","tr":"Kendi raporunuzu gözden geçirmek, böylece tanıklığınız kaydettiğiniz olgularla örtüşsün","hi":"अपनी रिपोर्ट की समीक्षा करना ताकि आपकी गवाही आपके द्वारा दर्ज तथ्यों से मेल खाए","ar":"مراجعة تقريرك بنفسك لكي تتطابق شهادتك مع الوقائع التي دوّنتها"},{"en":"Memorize a more dramatic version of the story","es":"Memorizar una versión más dramática de la historia","ru":"Заучить более драматичную версию истории","tr":"Hikâyenin daha dramatik bir versiyonunu ezberlemek","hi":"कहानी का अधिक नाटकीय संस्करण याद करना","ar":"حفظ نسخة أكثر درامية من القصة"},{"en":"Prepare guesses to fill any gaps in your memory","es":"Preparar suposiciones para llenar los vacíos de su memoria","ru":"Подготовить догадки, чтобы заполнить пробелы в памяти","tr":"Hafızanızdaki boşlukları doldurmak için tahminler hazırlamak","hi":"अपनी स्मृति के अंतराल भरने के लिए अनुमान तैयार करना","ar":"إعداد تخمينات لملء أي فجوات في ذاكرتك"},{"en":"Agree in advance with one side on what to say","es":"Acordar de antemano con una de las partes qué decir","ru":"Заранее договориться с одной из сторон о том, что говорить","tr":"Ne söyleyeceğiniz konusunda önceden bir tarafla anlaşmak","hi":"पहले से एक पक्ष के साथ तय कर लेना कि क्या कहना है","ar":"الاتفاق مسبقًا مع أحد الطرفين على ما ستقوله"}],"e":{"en":"Before testifying, review your report so your testimony is consistent with the facts you documented; never invent, dramatize, or coordinate a false story.","es":"Antes de testificar, repase su informe para que su testimonio sea consistente con los hechos que documentó; nunca invente, dramatice ni coordine una historia falsa.","ru":"Перед дачей показаний просмотрите свой отчёт, чтобы показания соответствовали задокументированным фактам; никогда не выдумывайте, не драматизируйте и не согласовывайте ложную версию.","tr":"Tanıklıktan önce raporunuzu gözden geçirin, böylece tanıklığınız belgelediğiniz olgularla tutarlı olsun; asla uydurmayın, dramatize etmeyin veya yanlış bir hikâye üzerinde anlaşmayın.","hi":"गवाही देने से पहले अपनी रिपोर्ट की समीक्षा करें ताकि आपकी गवाही आपके द्वारा दर्ज तथ्यों के अनुरूप हो; कभी भी झूठी कहानी न गढ़ें, न नाटकीय बनाएँ, न मिलीभगत करें।","ar":"قبل الإدلاء بالشهادة، راجع تقريرك لكي تكون شهادتك متسقة مع الوقائع التي وثّقتها؛ ولا تختلق أو تبالغ أو تنسّق قصة كاذبة أبدًا."}},{"cat":"reports","a":1,"q":{"en":"While testifying, the attorney asks a question you do not know the answer to. What is the best response?","es":"Mientras testifica, el abogado hace una pregunta cuya respuesta desconoce. ¿Cuál es la mejor respuesta?","ru":"Во время дачи показаний адвокат задаёт вопрос, ответа на который вы не знаете. Как лучше всего ответить?","tr":"Tanıklık ederken avukat, cevabını bilmediğiniz bir soru sorar. En iyi yanıt nedir?","hi":"गवाही देते समय वकील ऐसा प्रश्न पूछता है जिसका उत्तर आप नहीं जानते। सबसे अच्छा जवाब क्या है?","ar":"أثناء الشهادة، يطرح المحامي سؤالًا لا تعرف إجابته. ما أفضل رد؟"},"o":[{"en":"Make your best guess so you seem knowledgeable","es":"Adivinar lo mejor posible para parecer entendido","ru":"Сделать наилучшее предположение, чтобы казаться осведомлённым","tr":"Bilgili görünmek için en iyi tahmininizi yapmak","hi":"जानकार दिखने के लिए अपना सर्वोत्तम अनुमान लगाना","ar":"تخمين أفضل ما لديك لتبدو مطّلعًا"},{"en":"Simply and honestly say that you do not know or do not recall","es":"Decir de forma simple y honesta que no lo sabe o no lo recuerda","ru":"Просто и честно сказать, что вы не знаете или не помните","tr":"Basitçe ve dürüstçe bilmediğinizi veya hatırlamadığınızı söylemek","hi":"सरलता और ईमानदारी से कहना कि आप नहीं जानते या याद नहीं है","ar":"أن تقول ببساطة وصدق إنك لا تعرف أو لا تتذكر"},{"en":"Change the subject to something you do know","es":"Cambiar de tema a algo que sí sepa","ru":"Сменить тему на то, что вы знаете","tr":"Konuyu bildiğiniz bir şeye çevirmek","hi":"विषय को किसी ऐसी बात पर बदलना जो आप जानते हों","ar":"تغيير الموضوع إلى شيء تعرفه"},{"en":"Ask the judge to skip the question","es":"Pedir al juez que omita la pregunta","ru":"Попросить судью пропустить вопрос","tr":"Hâkimden soruyu atlamasını istemek","hi":"न्यायाधीश से प्रश्न छोड़ देने के लिए कहना","ar":"أن تطلب من القاضي تخطي السؤال"}],"e":{"en":"If you do not know or cannot remember, say so honestly; guessing under oath can damage your credibility and the case.","es":"Si no lo sabe o no lo recuerda, dígalo con honestidad; adivinar bajo juramento puede dañar su credibilidad y el caso.","ru":"Если вы не знаете или не можете вспомнить, честно скажите об этом; догадки под присягой могут подорвать вашу достоверность и дело.","tr":"Bilmiyorsanız veya hatırlayamıyorsanız, bunu dürüstçe söyleyin; yemin altında tahmin yürütmek güvenilirliğinize ve davaya zarar verebilir.","hi":"यदि आप नहीं जानते या याद नहीं कर सकते, तो ईमानदारी से कहें; शपथ के तहत अनुमान लगाना आपकी विश्वसनीयता और मामले को नुकसान पहुँचा सकता है।","ar":"إذا كنت لا تعرف أو لا تستطيع التذكّر، فقل ذلك بصدق؛ فالتخمين تحت القسم قد يضرّ بمصداقيتك وبالقضية."}},{"cat":"reports","a":2,"q":{"en":"Where should a security guard keep field notes taken during a shift?","es":"¿Dónde debe un guardia de seguridad guardar las notas de campo tomadas durante un turno?","ru":"Где охранник должен хранить полевые заметки, сделанные во время смены?","tr":"Bir güvenlik görevlisi vardiya sırasında aldığı saha notlarını nerede tutmalıdır?","hi":"सुरक्षा गार्ड को पाली के दौरान लिए गए फील्ड नोट्स कहाँ रखने चाहिए?","ar":"أين ينبغي لحارس الأمن أن يحتفظ بالملاحظات الميدانية التي دوّنها أثناء الوردية؟"},"o":[{"en":"On loose scraps of paper thrown away at the end of the shift","es":"En papeles sueltos que se tiran al final del turno","ru":"На отдельных клочках бумаги, выбрасываемых в конце смены","tr":"Vardiya sonunda atılan gevşek kâğıt parçalarında","hi":"अलग-अलग कागज़ के टुकड़ों पर जो पाली के अंत में फेंक दिए जाएँ","ar":"على قصاصات ورق متفرقة تُرمى في نهاية الوردية"},{"en":"Only in the guard's phone as text messages","es":"Solo en el teléfono del guardia como mensajes de texto","ru":"Только в телефоне охранника в виде текстовых сообщений","tr":"Yalnızca görevlinin telefonunda kısa mesaj olarak","hi":"केवल गार्ड के फ़ोन में टेक्स्ट संदेश के रूप में","ar":"فقط في هاتف الحارس على شكل رسائل نصية"},{"en":"In a dedicated notebook so they are organized and can be located later","es":"En un cuaderno dedicado para que estén organizadas y se puedan localizar después","ru":"В отдельном блокноте, чтобы они были упорядочены и их можно было найти позже","tr":"Ayrılmış bir deftere, böylece düzenli olsunlar ve sonradan bulunabilsinler","hi":"एक समर्पित नोटबुक में ताकि वे व्यवस्थित रहें और बाद में मिल सकें","ar":"في دفتر مخصص لتكون منظمة ويمكن العثور عليها لاحقًا"},{"en":"There is no need to keep notes after writing the report","es":"No hay necesidad de guardar las notas después de escribir el informe","ru":"Нет необходимости хранить заметки после написания отчёта","tr":"Rapor yazıldıktan sonra notları saklamaya gerek yoktur","hi":"रिपोर्ट लिखने के बाद नोट्स रखने की कोई आवश्यकता नहीं","ar":"لا حاجة للاحتفاظ بالملاحظات بعد كتابة التقرير"}],"e":{"en":"Field notes should be kept in a dedicated notebook so they stay organized and can be retrieved later, for example to prepare for court; agency policy may vary.","es":"Las notas de campo deben guardarse en un cuaderno dedicado para que permanezcan organizadas y puedan recuperarse después, por ejemplo para preparar el tribunal; la política de la agencia puede variar.","ru":"Полевые заметки следует хранить в отдельном блокноте, чтобы они были упорядочены и их можно было найти позже, например для подготовки к суду; политика агентства может отличаться.","tr":"Saha notları, düzenli kalmaları ve sonradan (örneğin mahkemeye hazırlık için) bulunabilmeleri amacıyla ayrılmış bir defterde tutulmalıdır; şirket politikası değişebilir.","hi":"फील्ड नोट्स एक समर्पित नोटबुक में रखने चाहिए ताकि वे व्यवस्थित रहें और बाद में, जैसे अदालत की तैयारी के लिए, प्राप्त किए जा सकें; एजेंसी की नीति भिन्न हो सकती है।","ar":"ينبغي الاحتفاظ بالملاحظات الميدانية في دفتر مخصص لتبقى منظمة ويمكن استرجاعها لاحقًا، مثلًا للاستعداد للمحكمة؛ وقد تختلف سياسة الشركة."}},{"cat":"reports","a":3,"q":{"en":"For a report to be 'concise', what should the writer do?","es":"Para que un informe sea 'conciso', ¿qué debe hacer quien lo redacta?","ru":"Чтобы отчёт был «лаконичным», что должен сделать пишущий?","tr":"Bir raporun 'öz' olması için yazan kişi ne yapmalıdır?","hi":"रिपोर्ट को 'संक्षिप्त' बनाने के लिए लिखने वाले को क्या करना चाहिए?","ar":"لكي يكون التقرير 'موجزًا'، ماذا ينبغي أن يفعل الكاتب؟"},"o":[{"en":"Add as many adjectives and adverbs as possible","es":"Agregar tantos adjetivos y adverbios como sea posible","ru":"Добавить как можно больше прилагательных и наречий","tr":"Mümkün olduğunca çok sıfat ve zarf eklemek","hi":"जितने संभव हों उतने विशेषण और क्रियाविशेषण जोड़ना","ar":"إضافة أكبر عدد ممكن من الصفات والظروف"},{"en":"Repeat the key facts several times for emphasis","es":"Repetir los hechos clave varias veces para enfatizar","ru":"Повторять ключевые факты несколько раз для акцента","tr":"Vurgu için önemli olguları birkaç kez tekrarlamak","hi":"ज़ोर देने के लिए मुख्य तथ्यों को कई बार दोहराना","ar":"تكرار الوقائع الرئيسية عدة مرات للتأكيد"},{"en":"Leave out important facts to save space","es":"Omitir hechos importantes para ahorrar espacio","ru":"Опускать важные факты, чтобы сэкономить место","tr":"Yer kazanmak için önemli olguları atlamak","hi":"जगह बचाने के लिए महत्वपूर्ण तथ्य छोड़ देना","ar":"حذف وقائع مهمة لتوفير المساحة"},{"en":"Include all necessary facts using as few words as needed","es":"Incluir todos los hechos necesarios con las menos palabras posibles","ru":"Включить все необходимые факты, используя как можно меньше слов","tr":"Gerekli tüm olguları mümkün olan en az kelimeyle vermek","hi":"सभी आवश्यक तथ्यों को यथासंभव कम शब्दों में शामिल करना","ar":"تضمين جميع الوقائع الضرورية بأقل عدد ممكن من الكلمات"}],"e":{"en":"Concise means saying everything important using no more words than necessary; it does not mean leaving out facts or padding the report.","es":"Conciso significa decir todo lo importante sin usar más palabras de las necesarias; no significa omitir hechos ni rellenar el informe.","ru":"Лаконичность означает изложить всё важное, не используя лишних слов; это не значит опускать факты или разбавлять отчёт.","tr":"Öz olmak, önemli olan her şeyi gereğinden fazla kelime kullanmadan söylemektir; olguları atlamak veya raporu doldurmak anlamına gelmez.","hi":"संक्षिप्त का अर्थ है सभी महत्वपूर्ण बातें आवश्यकता से अधिक शब्दों के बिना कहना; इसका अर्थ तथ्य छोड़ना या रिपोर्ट को भरना नहीं है।","ar":"الإيجاز يعني قول كل ما هو مهم دون استخدام كلمات أكثر من اللازم؛ ولا يعني حذف الوقائع أو حشو التقرير."}},{"cat":"reports","a":0,"q":{"en":"A witness gives you a description of a suspect. How should you record it in your notes?","es":"Un testigo le da la descripción de un sospechoso. ¿Cómo debe registrarla en sus notas?","ru":"Свидетель даёт вам описание подозреваемого. Как следует записать это в заметках?","tr":"Bir tanık size bir şüphelinin eşkâlini veriyor. Bunu notlarınıza nasıl kaydetmelisiniz?","hi":"एक गवाह आपको संदिग्ध का विवरण देता है। आपको इसे अपने नोट्स में कैसे दर्ज करना चाहिए?","ar":"يعطيك شاهد وصفًا لمشتبه به. كيف ينبغي أن تسجّله في ملاحظاتك؟"},"o":[{"en":"Record specific details such as height, clothing, and distinguishing marks","es":"Registrar detalles específicos como estatura, ropa y marcas distintivas","ru":"Записать конкретные детали, такие как рост, одежда и особые приметы","tr":"Boy, kıyafet ve ayırt edici işaretler gibi belirli ayrıntıları kaydetmek","hi":"विशिष्ट विवरण दर्ज करना जैसे कद, कपड़े और पहचान-चिह्न","ar":"تسجيل تفاصيل محددة مثل الطول والملابس والعلامات المميزة"},{"en":"Write only that the suspect 'looked suspicious'","es":"Escribir solo que el sospechoso 'parecía sospechoso'","ru":"Записать только, что подозреваемый «выглядел подозрительно»","tr":"Yalnızca şüphelinin 'şüpheli göründüğünü' yazmak","hi":"केवल यह लिखना कि संदिग्ध 'संदिग्ध लग रहा था'","ar":"كتابة أن المشتبه به 'بدا مريبًا' فقط"},{"en":"Guess the suspect's name and address","es":"Adivinar el nombre y la dirección del sospechoso","ru":"Угадать имя и адрес подозреваемого","tr":"Şüphelinin adını ve adresini tahmin etmek","hi":"संदिग्ध का नाम और पता अनुमान लगाना","ar":"تخمين اسم المشتبه به وعنوانه"},{"en":"Skip the description because witnesses are unreliable","es":"Omitir la descripción porque los testigos no son confiables","ru":"Пропустить описание, потому что свидетели ненадёжны","tr":"Tanıklar güvenilmez olduğu için eşkâli atlamak","hi":"विवरण छोड़ देना क्योंकि गवाह अविश्वसनीय होते हैं","ar":"تجاهل الوصف لأن الشهود غير موثوقين"}],"e":{"en":"Record specific, factual details such as approximate height, build, clothing, and distinguishing marks; vague labels and guesses are not useful evidence.","es":"Registre detalles específicos y objetivos como estatura aproximada, complexión, ropa y marcas distintivas; las etiquetas vagas y las suposiciones no son evidencia útil.","ru":"Записывайте конкретные фактические детали, такие как примерный рост, телосложение, одежда и особые приметы; расплывчатые ярлыки и догадки не являются полезным доказательством.","tr":"Yaklaşık boy, vücut yapısı, kıyafet ve ayırt edici işaretler gibi belirli, olgusal ayrıntıları kaydedin; belirsiz nitelemeler ve tahminler yararlı delil değildir.","hi":"अनुमानित कद, गठन, कपड़े और पहचान-चिह्न जैसे विशिष्ट, तथ्यपरक विवरण दर्ज करें; अस्पष्ट लेबल और अनुमान उपयोगी साक्ष्य नहीं हैं।","ar":"سجّل تفاصيل محددة ووقائعية مثل الطول التقريبي والبنية والملابس والعلامات المميزة؛ فالأوصاف الغامضة والتخمينات ليست دليلًا مفيدًا."}},{"cat":"reports","a":1,"q":{"en":"Which approach shows the best professional communication when a guard receives an important instruction from a supervisor?","es":"¿Qué enfoque muestra la mejor comunicación profesional cuando un guardia recibe una instrucción importante de un supervisor?","ru":"Какой подход демонстрирует наилучшую профессиональную коммуникацию, когда охранник получает важное указание от руководителя?","tr":"Bir görevli amirinden önemli bir talimat aldığında, hangi yaklaşım en iyi profesyonel iletişimi gösterir?","hi":"जब कोई गार्ड पर्यवेक्षक से कोई महत्वपूर्ण निर्देश प्राप्त करता है, तो कौन-सा तरीका सर्वोत्तम पेशेवर संचार दर्शाता है?","ar":"أيّ نهج يُظهر أفضل تواصل مهني عندما يتلقى الحارس تعليمًا مهمًا من مشرف؟"},"o":[{"en":"Assume you understood and walk away without responding","es":"Suponer que entendió y marcharse sin responder","ru":"Предположить, что поняли, и уйти, не ответив","tr":"Anladığınızı varsayıp yanıt vermeden uzaklaşmak","hi":"मान लेना कि आप समझ गए और बिना जवाब दिए चले जाना","ar":"أن تفترض أنك فهمت وتنصرف دون رد"},{"en":"Listen actively, repeat it back to confirm, and ask if anything is unclear","es":"Escuchar activamente, repetirla para confirmar y preguntar si algo no está claro","ru":"Активно слушать, повторить для подтверждения и спросить, если что-то неясно","tr":"Etkin dinlemek, teyit için geri tekrarlamak ve belirsiz bir şey varsa sormak","hi":"सक्रिय रूप से सुनना, पुष्टि के लिए दोहराना, और यदि कुछ स्पष्ट न हो तो पूछना","ar":"الإصغاء الفعّال، وإعادة التعليمة للتأكيد، والسؤال إن كان شيء غير واضح"},{"en":"Argue about whether the instruction is a good idea","es":"Discutir si la instrucción es una buena idea","ru":"Спорить, хорошая ли это идея","tr":"Talimatın iyi bir fikir olup olmadığını tartışmak","hi":"बहस करना कि निर्देश अच्छा विचार है या नहीं","ar":"الجدال حول ما إذا كان التعليم فكرة جيدة"},{"en":"Tell coworkers the supervisor is wrong","es":"Decir a los compañeros que el supervisor se equivoca","ru":"Сказать коллегам, что руководитель неправ","tr":"İş arkadaşlarına amirin yanıldığını söylemek","hi":"सहकर्मियों को बताना कि पर्यवेक्षक गलत है","ar":"إخبار الزملاء بأن المشرف مخطئ"}],"e":{"en":"Active listening, confirming the instruction by repeating it back, and asking clarifying questions prevent misunderstandings and show professionalism.","es":"La escucha activa, confirmar la instrucción repitiéndola y hacer preguntas aclaratorias evitan malentendidos y demuestran profesionalismo.","ru":"Активное слушание, подтверждение указания его повтором и уточняющие вопросы предотвращают недопонимание и демонстрируют профессионализм.","tr":"Etkin dinleme, talimatı geri tekrarlayarak teyit etme ve açıklayıcı sorular sorma, yanlış anlamaları önler ve profesyonelliği gösterir.","hi":"सक्रिय श्रवण, निर्देश को दोहराकर पुष्टि करना और स्पष्टीकरण प्रश्न पूछना गलतफहमियों को रोकते हैं और पेशेवरता दर्शाते हैं।","ar":"الإصغاء الفعّال، وتأكيد التعليمة بإعادتها، وطرح أسئلة توضيحية يمنع سوء الفهم ويُظهر المهنية."}},{"cat":"reports","a":2,"q":{"en":"A guard writes: 'The visitor was clearly lying and trying to steal something.' What is the main problem with this sentence in a report?","es":"Un guardia escribe: 'El visitante claramente mentía e intentaba robar algo.' ¿Cuál es el problema principal de esta frase en un informe?","ru":"Охранник пишет: «Посетитель явно лгал и пытался что-то украсть». В чём основная проблема этого предложения в отчёте?","tr":"Bir görevli şöyle yazıyor: 'Ziyaretçi açıkça yalan söylüyor ve bir şey çalmaya çalışıyordu.' Bu cümlenin bir rapordaki temel sorunu nedir?","hi":"एक गार्ड लिखता है: 'आगंतुक स्पष्ट रूप से झूठ बोल रहा था और कुछ चुराने की कोशिश कर रहा था।' रिपोर्ट में इस वाक्य की मुख्य समस्या क्या है?","ar":"يكتب حارس: 'كان الزائر يكذب بوضوح ويحاول سرقة شيء ما.' ما المشكلة الرئيسية في هذه الجملة داخل التقرير؟"},"o":[{"en":"It is too short to be useful","es":"Es demasiado corta para ser útil","ru":"Оно слишком короткое, чтобы быть полезным","tr":"Yararlı olamayacak kadar kısadır","hi":"यह उपयोगी होने के लिए बहुत छोटा है","ar":"إنها قصيرة جدًا لتكون مفيدة"},{"en":"It uses the wrong verb tense","es":"Usa el tiempo verbal incorrecto","ru":"В нём использовано неправильное время глагола","tr":"Yanlış fiil zamanı kullanmıştır","hi":"इसमें गलत क्रिया-काल का उपयोग हुआ है","ar":"تستخدم زمن الفعل الخطأ"},{"en":"It states opinions and conclusions instead of observed facts","es":"Expresa opiniones y conclusiones en lugar de hechos observados","ru":"Оно излагает мнения и выводы вместо наблюдаемых фактов","tr":"Gözlemlenen olgular yerine görüş ve sonuçlar ifade eder","hi":"यह अवलोकित तथ्यों के बजाय राय और निष्कर्ष बताता है","ar":"تذكر آراء واستنتاجات بدلًا من الوقائع المُلاحَظة"},{"en":"It is written too formally","es":"Está escrita de forma demasiado formal","ru":"Оно написано слишком формально","tr":"Çok resmî bir biçimde yazılmıştır","hi":"यह बहुत औपचारिक रूप से लिखा गया है","ar":"مكتوبة بأسلوب رسمي أكثر من اللازم"}],"e":{"en":"'Clearly lying' and 'trying to steal' are conclusions, not facts; the report should state only what was observed, such as the visitor's exact words and actions.","es":"'Claramente mentía' e 'intentaba robar' son conclusiones, no hechos; el informe debe indicar solo lo observado, como las palabras y acciones exactas del visitante.","ru":"«Явно лгал» и «пытался украсть» — это выводы, а не факты; в отчёте следует указывать только наблюдаемое, например точные слова и действия посетителя.","tr":"'Açıkça yalan söylüyor' ve 'çalmaya çalışıyor' sonuçlardır, olgu değil; rapor yalnızca gözlemleneni, örneğin ziyaretçinin tam sözlerini ve eylemlerini belirtmelidir.","hi":"'स्पष्ट रूप से झूठ' और 'चुराने की कोशिश' निष्कर्ष हैं, तथ्य नहीं; रिपोर्ट में केवल वही बताना चाहिए जो देखा गया, जैसे आगंतुक के सटीक शब्द और कार्य।","ar":"'يكذب بوضوح' و'يحاول السرقة' استنتاجات وليست وقائع؛ وينبغي أن يذكر التقرير ما لوحظ فقط، مثل كلمات الزائر وأفعاله بالضبط."}},{"cat":"reports","a":3,"q":{"en":"When giving a verbal command to a member of the public, a security guard should be:","es":"Al dar una orden verbal a un miembro del público, un guardia de seguridad debe ser:","ru":"Отдавая устную команду представителю публики, охранник должен быть:","tr":"Halktan birine sözlü bir talimat verirken, bir güvenlik görevlisi şöyle olmalıdır:","hi":"जनता के किसी सदस्य को मौखिक आदेश देते समय, सुरक्षा गार्ड को कैसा होना चाहिए:","ar":"عند إعطاء أمر شفهي لأحد أفراد الجمهور، ينبغي لحارس الأمن أن يكون:"},"o":[{"en":"Vague, so people can interpret it their own way","es":"Vago, para que la gente lo interprete a su manera","ru":"Расплывчатым, чтобы люди толковали его по-своему","tr":"Belirsiz, böylece insanlar kendince yorumlasın","hi":"अस्पष्ट, ताकि लोग इसे अपने तरीके से समझें","ar":"غامضًا، لكي يفسّره الناس على طريقتهم"},{"en":"Loud and hostile to show authority","es":"Ruidoso y hostil para mostrar autoridad","ru":"Громким и враждебным, чтобы показать власть","tr":"Otorite göstermek için yüksek sesli ve düşmanca","hi":"अधिकार दिखाने के लिए तेज़ और शत्रुतापूर्ण","ar":"عاليًا وعدائيًا لإظهار السلطة"},{"en":"Silent, using only hand gestures","es":"Silencioso, usando solo gestos con las manos","ru":"Молчаливым, используя только жесты руками","tr":"Sessiz, yalnızca el işaretleri kullanarak","hi":"मौन, केवल हाथ के इशारों का उपयोग करते हुए","ar":"صامتًا، مستخدمًا إشارات اليد فقط"},{"en":"Clear, calm, and courteous so the instruction is understood","es":"Claro, tranquilo y cortés para que la instrucción se entienda","ru":"Ясным, спокойным и вежливым, чтобы указание было понято","tr":"Açık, sakin ve nazik, böylece talimat anlaşılsın","hi":"स्पष्ट, शांत और विनम्र ताकि निर्देश समझा जाए","ar":"واضحًا وهادئًا ولبقًا لكي يُفهم التوجيه"}],"e":{"en":"Verbal commands should be clear, calm, and courteous; this improves cooperation and reduces the chance of a situation escalating.","es":"Las órdenes verbales deben ser claras, tranquilas y corteses; esto mejora la cooperación y reduce la posibilidad de que una situación se agrave.","ru":"Устные команды должны быть ясными, спокойными и вежливыми; это улучшает сотрудничество и снижает вероятность обострения ситуации.","tr":"Sözlü talimatlar açık, sakin ve nazik olmalıdır; bu iş birliğini artırır ve durumun tırmanma olasılığını azaltır.","hi":"मौखिक आदेश स्पष्ट, शांत और विनम्र होने चाहिए; इससे सहयोग बढ़ता है और स्थिति के बिगड़ने की संभावना घटती है।","ar":"ينبغي أن تكون الأوامر الشفهية واضحة وهادئة ولبقة؛ فهذا يحسّن التعاون ويقلّل من احتمال تصعيد الموقف."}},{"cat":"access","a":2,"q":{"en":"When checking a photo ID at an entrance, what is the first thing a guard should confirm?","es":"Al revisar una identificación con foto en una entrada, ¿qué es lo primero que debe confirmar un guardia?","ru":"При проверке удостоверения с фотографией на входе, что охранник должен проверить в первую очередь?","tr":"Bir girişte fotoğraflı kimliği kontrol ederken, bir görevlinin ilk önce neyi doğrulaması gerekir?","hi":"प्रवेश द्वार पर फोटो पहचान-पत्र जाँचते समय गार्ड को सबसे पहले किस बात की पुष्टि करनी चाहिए?","ar":"عند فحص بطاقة هوية بها صورة عند المدخل، ما أول شيء ينبغي للحارس التأكد منه؟"},"o":[{"en":"That the ID card looks new and undamaged","es":"Que la tarjeta parezca nueva y sin daños","ru":"Что карта выглядит новой и неповреждённой","tr":"Kimlik kartının yeni ve hasarsız görünmesi","hi":"कि कार्ड नया और बिना क्षति के दिखता है","ar":"أن تبدو البطاقة جديدة وغير تالفة"},{"en":"That the person is dressed appropriately","es":"Que la persona esté vestida apropiadamente","ru":"Что человек одет надлежащим образом","tr":"Kişinin uygun şekilde giyinmiş olması","hi":"कि व्यक्ति उचित रूप से कपड़े पहने है","ar":"أن يكون الشخص يرتدي ملابس مناسبة"},{"en":"That the photo on the ID actually matches the person presenting it","es":"Que la foto de la identificación coincida realmente con la persona que la presenta","ru":"Что фотография на удостоверении действительно соответствует предъявителю","tr":"Kimlikteki fotoğrafın gerçekten onu ibraz eden kişiyle eşleşmesi","hi":"कि पहचान-पत्र की फोटो वास्तव में उसे प्रस्तुत करने वाले व्यक्ति से मेल खाती है","ar":"أن الصورة في البطاقة تطابق فعليًا الشخص الذي يقدّمها"},{"en":"That the person is in a hurry","es":"Que la persona tenga prisa","ru":"Что человек торопится","tr":"Kişinin acelesi olması","hi":"कि व्यक्ति जल्दी में है","ar":"أن يكون الشخص في عجلة من أمره"}],"e":{"en":"The core purpose of ID verification is confirming identity, so the guard first compares the photo to the face of the person presenting it. A new-looking card means nothing if it is not that person.","es":"El propósito central de verificar una identificación es confirmar la identidad, por eso el guardia primero compara la foto con el rostro de quien la presenta. Una tarjeta de aspecto nuevo no sirve si no es esa persona.","ru":"Основная цель проверки удостоверения — подтвердить личность, поэтому охранник сначала сравнивает фотографию с лицом предъявителя. Новый вид карты ничего не значит, если это не тот человек.","tr":"Kimlik doğrulamanın temel amacı kimliği teyit etmektir; bu yüzden görevli önce fotoğrafı ibraz eden kişinin yüzüyle karşılaştırır. Yeni görünen bir kart, kişi o değilse bir anlam ifade etmez.","hi":"पहचान सत्यापन का मूल उद्देश्य पहचान की पुष्टि करना है, इसलिए गार्ड पहले फोटो की तुलना प्रस्तुत करने वाले के चेहरे से करता है। नया दिखने वाला कार्ड बेकार है यदि वह वह व्यक्ति नहीं है।","ar":"الغرض الأساسي من التحقق من الهوية هو تأكيد الشخصية، لذا يقارن الحارس أولًا الصورة بوجه الشخص الذي يقدّمها. البطاقة الجديدة المظهر لا تعني شيئًا إن لم يكن هو الشخص نفسه."}},{"cat":"access","a":0,"q":{"en":"A visitor presents a driver's license whose expiration date has already passed. What should the guard do under standard access-control policy?","es":"Un visitante presenta una licencia de conducir cuya fecha de vencimiento ya pasó. ¿Qué debe hacer el guardia según la política estándar de control de acceso?","ru":"Посетитель предъявляет водительское удостоверение с уже истёкшим сроком действия. Что должен сделать охранник согласно стандартной политике контроля доступа?","tr":"Bir ziyaretçi, son kullanma tarihi çoktan geçmiş bir ehliyet sunuyor. Standart erişim kontrol politikasına göre görevli ne yapmalıdır?","hi":"एक आगंतुक ऐसा ड्राइविंग लाइसेंस प्रस्तुत करता है जिसकी समाप्ति तिथि पहले ही बीत चुकी है। मानक अभिगम-नियंत्रण नीति के अनुसार गार्ड को क्या करना चाहिए?","ar":"يقدّم زائر رخصة قيادة انتهت صلاحيتها بالفعل. ماذا ينبغي للحارس أن يفعل وفق سياسة التحكم في الدخول القياسية؟"},"o":[{"en":"Treat the ID as invalid and ask for another accepted form of identification","es":"Tratar la identificación como inválida y pedir otra forma de identificación aceptada","ru":"Считать удостоверение недействительным и запросить другой принимаемый документ","tr":"Kimliği geçersiz sayıp kabul edilen başka bir kimlik belgesi istemek","hi":"पहचान-पत्र को अमान्य मानें और पहचान का कोई अन्य स्वीकृत रूप माँगें","ar":"اعتبار البطاقة غير صالحة وطلب شكل آخر مقبول من إثبات الهوية"},{"en":"Accept it anyway because the photo still matches","es":"Aceptarla igual porque la foto todavía coincide","ru":"Всё равно принять, ведь фото совпадает","tr":"Fotoğraf hâlâ eşleştiği için yine de kabul etmek","hi":"फिर भी स्वीकार करें क्योंकि फोटो अब भी मेल खाती है","ar":"قبولها على أي حال لأن الصورة ما زالت مطابقة"},{"en":"Confiscate the license and keep it at the desk","es":"Confiscar la licencia y guardarla en el mostrador","ru":"Изъять удостоверение и оставить его на посту","tr":"Ehliyete el koyup masada tutmak","hi":"लाइसेंस जब्त करें और उसे डेस्क पर रखें","ar":"مصادرة الرخصة والاحتفاظ بها عند المكتب"},{"en":"Let them in but write 'expired' in the log","es":"Dejarlo entrar pero escribir 'vencida' en el registro","ru":"Пропустить, но записать в журнале «просрочено»","tr":"İçeri almak ama kayda 'süresi geçmiş' yazmak","hi":"अंदर जाने दें पर लॉग में 'समाप्त' लिखें","ar":"السماح بالدخول مع كتابة \"منتهية\" في السجل"}],"e":{"en":"An expired ID is generally not a valid document, so the guard should decline it and request another acceptable ID. Guards do not confiscate personal identification unless a specific post order authorizes it.","es":"Una identificación vencida generalmente no es un documento válido, así que el guardia debe rechazarla y pedir otra aceptable. Los guardias no confiscan identificaciones personales salvo que una orden de puesto específica lo autorice.","ru":"Просроченное удостоверение обычно не является действительным документом, поэтому охранник должен отклонить его и запросить другой приемлемый документ. Охранники не изымают личные документы, если это прямо не разрешено инструкцией поста.","tr":"Süresi geçmiş bir kimlik genellikle geçerli bir belge değildir; bu yüzden görevli onu kabul etmeyip başka geçerli bir kimlik istemelidir. Görevliler, belirli bir görev talimatı izin vermedikçe kişisel kimliklere el koymaz.","hi":"समाप्त पहचान-पत्र आम तौर पर वैध दस्तावेज़ नहीं होता, इसलिए गार्ड को इसे अस्वीकार कर कोई अन्य स्वीकार्य पहचान माँगनी चाहिए। जब तक कोई विशिष्ट पोस्ट आदेश अनुमति न दे, गार्ड व्यक्तिगत पहचान जब्त नहीं करते।","ar":"البطاقة المنتهية عمومًا ليست وثيقة صالحة، لذا ينبغي للحارس رفضها وطلب هوية أخرى مقبولة. لا يصادر الحراس الهويات الشخصية إلا إذا سمحت بذلك تعليمات موقع محددة."}},{"cat":"access","a":1,"q":{"en":"Which of the following is a common sign that a photo ID may have been altered or forged?","es":"¿Cuál de los siguientes es un signo común de que una identificación con foto pudo haber sido alterada o falsificada?","ru":"Какой из следующих признаков часто указывает на то, что удостоверение с фотографией могло быть подделано или изменено?","tr":"Aşağıdakilerden hangisi, fotoğraflı bir kimliğin değiştirilmiş veya sahte olabileceğinin yaygın bir işaretidir?","hi":"निम्नलिखित में से कौन-सा एक सामान्य संकेत है कि फोटो पहचान-पत्र में छेड़छाड़ या जालसाजी की गई हो सकती है?","ar":"أي مما يلي علامة شائعة على أن بطاقة الهوية المصوّرة ربما تكون قد عُدِّلت أو زُوِّرت؟"},"o":[{"en":"The ID is issued by another U.S. state","es":"La identificación fue emitida por otro estado de EE. UU.","ru":"Удостоверение выдано другим штатом США","tr":"Kimliğin başka bir ABD eyaleti tarafından verilmiş olması","hi":"पहचान-पत्र किसी अन्य अमेरिकी राज्य द्वारा जारी किया गया है","ar":"أن تكون البطاقة صادرة عن ولاية أمريكية أخرى"},{"en":"Mismatched fonts, peeling lamination, or a photo that appears glued on","es":"Tipografías que no coinciden, laminado que se despega o una foto que parece pegada","ru":"Несовпадающие шрифты, отслаивающаяся ламинация или фотография, будто наклеенная сверху","tr":"Uyumsuz yazı tipleri, soyulan laminasyon veya yapıştırılmış gibi görünen bir fotoğraf","hi":"बेमेल फ़ॉन्ट, उखड़ता लैमिनेशन, या ऐसी फोटो जो चिपकाई हुई लगती हो","ar":"خطوط غير متطابقة أو تغليف متقشّر أو صورة تبدو ملصقة"},{"en":"The person seems nervous at the checkpoint","es":"La persona parece nerviosa en el punto de control","ru":"Человек кажется нервным на контрольном пункте","tr":"Kişinin kontrol noktasında gergin görünmesi","hi":"व्यक्ति चौकी पर घबराया हुआ लगता है","ar":"أن يبدو الشخص متوترًا عند نقطة التفتيش"},{"en":"The ID is a few years old","es":"La identificación tiene algunos años","ru":"Удостоверению несколько лет","tr":"Kimliğin birkaç yıllık olması","hi":"पहचान-पत्र कुछ साल पुराना है","ar":"أن يكون عمر البطاقة بضع سنوات"}],"e":{"en":"Physical tampering signs include mismatched or misaligned fonts, bubbling or peeling lamination, and photos that look added on. An out-of-state or slightly aged ID is not by itself evidence of forgery.","es":"Los signos de manipulación física incluyen tipografías dispares o mal alineadas, laminado con burbujas o despegado y fotos que parecen añadidas. Una identificación de otro estado o algo antigua no es por sí sola prueba de falsificación.","ru":"Признаки физической подделки — несовпадающие или смещённые шрифты, вздувшаяся или отслаивающаяся ламинация и фотографии, выглядящие приклеенными. Удостоверение из другого штата или слегка потёртое само по себе не доказывает подделку.","tr":"Fiziksel kurcalama işaretleri arasında uyumsuz veya hizasız yazı tipleri, kabaran ya da soyulan laminasyon ve sonradan eklenmiş görünen fotoğraflar vardır. Başka eyaletten veya biraz eskimiş bir kimlik tek başına sahtecilik kanıtı değildir.","hi":"भौतिक छेड़छाड़ के संकेतों में बेमेल या ग़लत संरेखित फ़ॉन्ट, बुलबुले उठता या उखड़ता लैमिनेशन, और जोड़ी हुई-सी दिखने वाली फोटो शामिल हैं। दूसरे राज्य का या थोड़ा पुराना पहचान-पत्र अपने आप में जालसाजी का प्रमाण नहीं है।","ar":"من علامات التلاعب المادي: خطوط غير متطابقة أو غير محاذاة، وتغليف متبثّر أو متقشّر، وصور تبدو مُضافة. البطاقة من ولاية أخرى أو القديمة قليلًا ليست بحد ذاتها دليلًا على التزوير."}},{"cat":"access","a":3,"q":{"en":"At a site that keeps an authorized-personnel list, a person's photo ID looks genuine but their name is not on the list. What should the guard do?","es":"En un sitio que mantiene una lista de personal autorizado, la identificación con foto de una persona parece auténtica pero su nombre no está en la lista. ¿Qué debe hacer el guardia?","ru":"На объекте, где ведётся список допущенных лиц, удостоверение с фотографией выглядит подлинным, но имени человека нет в списке. Что должен сделать охранник?","tr":"Yetkili personel listesi tutulan bir tesiste, bir kişinin fotoğraflı kimliği gerçek görünüyor ancak adı listede yok. Görevli ne yapmalıdır?","hi":"एक ऐसे स्थल पर जहाँ अधिकृत-कर्मियों की सूची रखी जाती है, किसी व्यक्ति का फोटो पहचान-पत्र असली लगता है पर उसका नाम सूची में नहीं है। गार्ड को क्या करना चाहिए?","ar":"في موقع يحتفظ بقائمة الأفراد المصرَّح لهم، تبدو بطاقة هوية شخص أصلية لكن اسمه غير مدرج في القائمة. ماذا ينبغي للحارس أن يفعل؟"},"o":[{"en":"Admit the person because the ID is clearly real","es":"Admitir a la persona porque la identificación es claramente real","ru":"Пропустить человека, ведь удостоверение явно настоящее","tr":"Kimlik açıkça gerçek olduğu için kişiyi içeri almak","hi":"व्यक्ति को प्रवेश दें क्योंकि पहचान-पत्र स्पष्ट रूप से असली है","ar":"السماح للشخص بالدخول لأن البطاقة حقيقية بوضوح"},{"en":"Add the name to the list so the record is complete","es":"Agregar el nombre a la lista para que el registro esté completo","ru":"Добавить имя в список, чтобы запись была полной","tr":"Kayıt eksiksiz olsun diye adı listeye eklemek","hi":"रिकॉर्ड पूरा करने के लिए नाम को सूची में जोड़ दें","ar":"إضافة الاسم إلى القائمة ليكتمل السجل"},{"en":"Turn the person away without any explanation","es":"Rechazar a la persona sin ninguna explicación","ru":"Отказать человеку без каких-либо объяснений","tr":"Kişiyi hiçbir açıklama yapmadan geri çevirmek","hi":"बिना किसी स्पष्टीकरण के व्यक्ति को लौटा दें","ar":"صرف الشخص دون أي تفسير"},{"en":"Deny entry and verify with the contact or supervisor before admitting them","es":"Denegar la entrada y verificar con el contacto o el supervisor antes de admitirlo","ru":"Отказать во входе и уточнить у контактного лица или начальника, прежде чем пропускать","tr":"Girişi reddetmek ve içeri almadan önce ilgili kişi veya amirle doğrulamak","hi":"प्रवेश अस्वीकार करें और अंदर जाने देने से पहले संपर्क या पर्यवेक्षक से पुष्टि करें","ar":"منع الدخول والتحقق مع جهة الاتصال أو المشرف قبل السماح له"}],"e":{"en":"A valid-looking ID only proves identity, not authorization. If the name is not on the access list, the guard withholds entry and verifies with the point of contact or supervisor; adding names yourself defeats the list's purpose.","es":"Una identificación de apariencia válida solo prueba la identidad, no la autorización. Si el nombre no está en la lista de acceso, el guardia retiene la entrada y verifica con el contacto o el supervisor; agregar nombres uno mismo anula el propósito de la lista.","ru":"Подлинное на вид удостоверение подтверждает лишь личность, но не право доступа. Если имени нет в списке, охранник не пропускает и проверяет у контактного лица или начальника; самовольно вписывать имена — значит сводить смысл списка на нет.","tr":"Geçerli görünen bir kimlik yalnızca kimliği kanıtlar, yetkiyi değil. Ad erişim listesinde yoksa görevli girişi durdurur ve ilgili kişi veya amirle doğrular; adları kendiniz eklemek listenin amacını ortadan kaldırır.","hi":"वैध दिखने वाला पहचान-पत्र केवल पहचान सिद्ध करता है, अधिकार नहीं। यदि नाम अभिगम सूची में नहीं है, तो गार्ड प्रवेश रोक देता है और संपर्क या पर्यवेक्षक से पुष्टि करता है; स्वयं नाम जोड़ना सूची का उद्देश्य ही विफल कर देता है।","ar":"البطاقة التي تبدو صالحة تثبت الهوية فقط لا التصريح. إذا لم يكن الاسم في قائمة الدخول، يمتنع الحارس عن السماح ويتحقق مع جهة الاتصال أو المشرف؛ وإضافة الأسماء بنفسك تُبطل الغرض من القائمة."}},{"cat":"access","a":0,"q":{"en":"Why should a guard compare a visitor's ID name against the credential or pass they were issued, not just glance at the badge?","es":"¿Por qué debe un guardia comparar el nombre de la identificación del visitante con la credencial o el pase que se le entregó, y no solo mirar la insignia?","ru":"Почему охранник должен сверять имя в удостоверении посетителя с выданным пропуском, а не просто взглянуть на бейдж?","tr":"Bir görevli neden ziyaretçinin kimlik adını yalnızca rozete bakmakla kalmayıp kendisine verilen kart veya geçiş belgesiyle karşılaştırmalıdır?","hi":"गार्ड को आगंतुक के पहचान-पत्र के नाम की तुलना जारी किए गए क्रेडेंशियल या पास से क्यों करनी चाहिए, न कि केवल बैज पर नज़र डालनी चाहिए?","ar":"لماذا ينبغي للحارس مطابقة اسم هوية الزائر مع التصريح أو البطاقة الممنوحة له، وليس مجرد إلقاء نظرة على الشارة؟"},"o":[{"en":"To confirm the credential belongs to that specific person and was not passed to someone else","es":"Para confirmar que la credencial pertenece a esa persona específica y no se pasó a otra","ru":"Чтобы убедиться, что пропуск принадлежит именно этому человеку и не был передан другому","tr":"Kartın tam olarak o kişiye ait olduğunu ve başkasına devredilmediğini doğrulamak için","hi":"यह पुष्टि करने के लिए कि क्रेडेंशियल उसी व्यक्ति का है और किसी और को नहीं दिया गया","ar":"للتأكد من أن التصريح يخص ذلك الشخص تحديدًا ولم يُمرَّر لغيره"},{"en":"To slow down the entry line on purpose","es":"Para retrasar la fila de entrada a propósito","ru":"Чтобы намеренно замедлить очередь на входе","tr":"Giriş sırasını bilerek yavaşlatmak için","hi":"प्रवेश कतार को जानबूझकर धीमा करने के लिए","ar":"لإبطاء طابور الدخول عمدًا"},{"en":"Because badges are decorative only","es":"Porque las insignias son solo decorativas","ru":"Потому что бейджи носят только декоративный характер","tr":"Rozetler yalnızca dekoratif olduğu için","hi":"क्योंकि बैज केवल सजावटी होते हैं","ar":"لأن الشارات للزينة فقط"},{"en":"To collect the visitor's personal data for marketing","es":"Para recopilar los datos personales del visitante con fines de marketing","ru":"Чтобы собрать личные данные посетителя для маркетинга","tr":"Ziyaretçinin kişisel verilerini pazarlama için toplamak","hi":"विपणन के लिए आगंतुक का व्यक्तिगत डेटा एकत्र करने हेतु","ar":"لجمع البيانات الشخصية للزائر لأغراض التسويق"}],"e":{"en":"Matching the ID name to the issued credential prevents pass-back, where a badge or pass is handed to an unauthorized person after entry. It ties the credential to a verified individual.","es":"Cotejar el nombre de la identificación con la credencial emitida evita el 'pase compartido', cuando una insignia o pase se entrega a una persona no autorizada tras el ingreso. Vincula la credencial con un individuo verificado.","ru":"Сверка имени в удостоверении с выданным пропуском предотвращает передачу пропуска другому — неавторизованному — лицу после входа. Это привязывает пропуск к проверенному человеку.","tr":"Kimlik adını verilen kartla eşleştirmek, girişten sonra rozet veya geçişin yetkisiz birine devredilmesini (pass-back) önler. Kartı doğrulanmış bir kişiye bağlar.","hi":"पहचान-पत्र के नाम को जारी क्रेडेंशियल से मिलाना 'पास-बैक' को रोकता है, जहाँ प्रवेश के बाद बैज या पास किसी अनधिकृत व्यक्ति को सौंप दिया जाता है। यह क्रेडेंशियल को एक सत्यापित व्यक्ति से जोड़ता है।","ar":"مطابقة اسم الهوية مع التصريح الممنوح تمنع تمرير الشارة أو البطاقة لشخص غير مصرَّح له بعد الدخول. فهي تربط التصريح بشخص تم التحقق منه."}},{"cat":"access","a":2,"q":{"en":"What information should a visitor sign-in log typically capture?","es":"¿Qué información debe registrar normalmente un libro de firmas de visitantes?","ru":"Какую информацию обычно должен фиксировать журнал регистрации посетителей?","tr":"Bir ziyaretçi giriş kaydı genellikle hangi bilgileri içermelidir?","hi":"आगंतुक साइन-इन लॉग में सामान्यतः कौन-सी जानकारी दर्ज होनी चाहिए?","ar":"ما المعلومات التي ينبغي أن يسجّلها عادةً سجلّ دخول الزوّار؟"},"o":[{"en":"Only the visitor's first name","es":"Solo el nombre de pila del visitante","ru":"Только имя посетителя","tr":"Yalnızca ziyaretçinin adı","hi":"केवल आगंतुक का पहला नाम","ar":"اسم الزائر الأول فقط"},{"en":"The guard's opinion of the visitor","es":"La opinión del guardia sobre el visitante","ru":"Мнение охранника о посетителе","tr":"Görevlinin ziyaretçi hakkındaki görüşü","hi":"आगंतुक के बारे में गार्ड की राय","ar":"رأي الحارس في الزائر"},{"en":"Name, time in and out, who they are visiting, and often the purpose","es":"Nombre, hora de entrada y salida, a quién visita y, a menudo, el motivo","ru":"Имя, время входа и выхода, к кому визит и часто цель","tr":"Ad, giriş ve çıkış saati, kimi ziyaret ettiği ve genellikle amaç","hi":"नाम, प्रवेश और निकास समय, किससे मिलने आए, और अक्सर उद्देश्य","ar":"الاسم، وقت الدخول والخروج، من يزور، وغالبًا الغرض"},{"en":"The visitor's home address only","es":"Solo la dirección del domicilio del visitante","ru":"Только домашний адрес посетителя","tr":"Yalnızca ziyaretçinin ev adresi","hi":"केवल आगंतुक का घर का पता","ar":"عنوان منزل الزائر فقط"}],"e":{"en":"A useful visitor log records name, time in and time out, the person or department being visited, and usually the purpose, creating an accurate account of who was on site and when. Exact fields vary by site post orders.","es":"Un registro de visitantes útil anota nombre, hora de entrada y salida, la persona o el departamento visitado y usualmente el motivo, creando un relato preciso de quién estuvo en el sitio y cuándo. Los campos exactos varían según las órdenes de puesto.","ru":"Полезный журнал посетителей фиксирует имя, время входа и выхода, к кому или в какой отдел визит и обычно цель, создавая точную запись о том, кто и когда был на объекте. Точные поля зависят от инструкций поста.","tr":"Kullanışlı bir ziyaretçi kaydı adı, giriş ve çıkış saatini, ziyaret edilen kişi veya birimi ve genellikle amacı yazar; böylece kimin ne zaman sahada olduğuna dair doğru bir kayıt oluşur. Kesin alanlar görev talimatlarına göre değişir.","hi":"एक उपयोगी आगंतुक लॉग नाम, प्रवेश और निकास समय, जिस व्यक्ति या विभाग से मिलना है, और आमतौर पर उद्देश्य दर्ज करता है, जिससे यह सटीक रिकॉर्ड बनता है कि कौन कब स्थल पर था। सटीक फ़ील्ड साइट पोस्ट आदेशों के अनुसार बदलते हैं।","ar":"السجل المفيد للزوّار يدوّن الاسم، ووقت الدخول والخروج، والشخص أو القسم المُزار، وعادةً الغرض، مما يوفّر سجلًّا دقيقًا لمن كان في الموقع ومتى. تختلف الحقول الدقيقة حسب تعليمات الموقع."}},{"cat":"access","a":1,"q":{"en":"Before issuing a visitor badge, what should a guard normally confirm?","es":"Antes de entregar una insignia de visitante, ¿qué debe confirmar normalmente un guardia?","ru":"Прежде чем выдать бейдж посетителя, что охранник обычно должен подтвердить?","tr":"Bir ziyaretçi rozeti vermeden önce görevli normalde neyi doğrulamalıdır?","hi":"आगंतुक बैज जारी करने से पहले गार्ड को सामान्यतः किसकी पुष्टि करनी चाहिए?","ar":"قبل إصدار شارة زائر، ما الذي ينبغي للحارس أن يؤكّده عادةً؟"},"o":[{"en":"That the visitor tips the front desk","es":"Que el visitante deje propina en la recepción","ru":"Что посетитель даст чаевые на стойке","tr":"Ziyaretçinin resepsiyona bahşiş bıraktığını","hi":"कि आगंतुक फ्रंट डेस्क पर टिप देता है","ar":"أن الزائر يعطي بقشيشًا للاستقبال"},{"en":"That the visitor has a legitimate appointment or authorization to be there","es":"Que el visitante tenga una cita legítima o autorización para estar allí","ru":"Что у посетителя есть законная встреча или разрешение находиться там","tr":"Ziyaretçinin orada bulunmak için geçerli bir randevusu veya izni olduğunu","hi":"कि आगंतुक के पास वहाँ होने के लिए वैध अपॉइंटमेंट या अधिकार है","ar":"أن لدى الزائر موعدًا مشروعًا أو تصريحًا للتواجد هناك"},{"en":"That the visitor is wearing a suit","es":"Que el visitante lleve traje","ru":"Что посетитель одет в костюм","tr":"Ziyaretçinin takım elbise giydiğini","hi":"कि आगंतुक सूट पहने है","ar":"أن الزائر يرتدي بدلة"},{"en":"That the visitor has visited before","es":"Que el visitante haya venido antes","ru":"Что посетитель бывал здесь раньше","tr":"Ziyaretçinin daha önce geldiğini","hi":"कि आगंतुक पहले आ चुका है","ar":"أن الزائر قد زار من قبل"}],"e":{"en":"A visitor badge should only be issued after confirming the person is expected or otherwise authorized, typically by checking an appointment, a host, or an access list. The badge signals verified, temporary access.","es":"Una insignia de visitante solo debe entregarse tras confirmar que la persona es esperada o autorizada, normalmente verificando una cita, un anfitrión o una lista de acceso. La insignia indica acceso temporal verificado.","ru":"Бейдж посетителя следует выдавать только после подтверждения, что человека ждут или он иным образом допущен — обычно проверив встречу, принимающего или список доступа. Бейдж означает проверенный временный доступ.","tr":"Ziyaretçi rozeti yalnızca kişinin beklendiği veya başka şekilde yetkili olduğu doğrulandıktan sonra verilmelidir; bu genellikle bir randevu, bir ev sahibi veya erişim listesi kontrol edilerek yapılır. Rozet, doğrulanmış geçici erişimi gösterir.","hi":"आगंतुक बैज केवल तभी जारी होना चाहिए जब यह पुष्टि हो जाए कि व्यक्ति अपेक्षित है या अन्यथा अधिकृत है, आमतौर पर अपॉइंटमेंट, मेज़बान या अभिगम सूची जाँचकर। बैज सत्यापित, अस्थायी पहुँच का संकेत देता है।","ar":"لا ينبغي إصدار شارة الزائر إلا بعد تأكيد أن الشخص متوقَّع أو مصرَّح له، عادةً بالتحقق من موعد أو مضيف أو قائمة دخول. تدل الشارة على دخول مؤقّت تم التحقق منه."}},{"cat":"access","a":3,"q":{"en":"A contractor with a valid visitor badge wants to enter a restricted server room. What is the standard practice?","es":"Un contratista con una insignia de visitante válida quiere entrar a una sala de servidores restringida. ¿Cuál es la práctica estándar?","ru":"Подрядчик с действительным бейджем посетителя хочет войти в закрытую серверную. Какова стандартная практика?","tr":"Geçerli ziyaretçi rozeti olan bir yüklenici, kısıtlı bir sunucu odasına girmek istiyor. Standart uygulama nedir?","hi":"एक ठेकेदार, जिसके पास वैध आगंतुक बैज है, एक प्रतिबंधित सर्वर रूम में प्रवेश करना चाहता है। मानक प्रथा क्या है?","ar":"مقاول يحمل شارة زائر صالحة يريد دخول غرفة خوادم مقيّدة. ما الممارسة القياسية؟"},"o":[{"en":"Let him roam the restricted area alone since he has a badge","es":"Dejarlo recorrer solo el área restringida ya que tiene una insignia","ru":"Разрешить ему свободно ходить по закрытой зоне, раз у него есть бейдж","tr":"Rozeti olduğu için kısıtlı alanda tek başına dolaşmasına izin vermek","hi":"चूँकि उसके पास बैज है, उसे प्रतिबंधित क्षेत्र में अकेले घूमने दें","ar":"السماح له بالتجوّل وحده في المنطقة المقيّدة لأن لديه شارة"},{"en":"Give him a master key so he can lock up when done","es":"Darle una llave maestra para que cierre al terminar","ru":"Дать ему универсальный ключ, чтобы он закрыл после себя","tr":"İşi bitince kilitlesin diye ona bir ana anahtar vermek","hi":"उसे मास्टर चाबी दें ताकि वह काम के बाद ताला लगा सके","ar":"إعطاؤه مفتاحًا رئيسيًا ليقفل عند الانتهاء"},{"en":"Deny all access to contractors permanently","es":"Denegar permanentemente todo acceso a los contratistas","ru":"Навсегда запретить подрядчикам любой доступ","tr":"Yüklenicilere her türlü erişimi kalıcı olarak reddetmek","hi":"ठेकेदारों को स्थायी रूप से सभी पहुँच से मना करें","ar":"منع كل المقاولين من الدخول نهائيًا"},{"en":"Escort him in restricted areas per post orders, or verify he is authorized and escorted","es":"Escoltarlo en las áreas restringidas según las órdenes de puesto, o verificar que esté autorizado y acompañado","ru":"Сопровождать его в закрытых зонах согласно инструкциям поста или убедиться, что он допущен и сопровождается","tr":"Görev talimatlarına göre kısıtlı alanlarda ona eşlik etmek ya da yetkili ve refakatli olduğunu doğrulamak","hi":"पोस्ट आदेशों के अनुसार प्रतिबंधित क्षेत्रों में उसके साथ चलें, या पुष्टि करें कि वह अधिकृत और अनुरक्षित है","ar":"مرافقته في المناطق المقيّدة وفق تعليمات الموقع، أو التأكد من أنه مصرَّح له ومرافَق"}],"e":{"en":"A visitor badge is not blanket access to restricted zones; standard practice is to escort visitors in such areas and confirm authorization. Guards do not hand over master keys to visitors. Exact escort rules follow site post orders.","es":"Una insignia de visitante no es acceso ilimitado a zonas restringidas; la práctica estándar es escoltar a los visitantes en dichas áreas y confirmar la autorización. Los guardias no entregan llaves maestras a los visitantes. Las reglas exactas de escolta siguen las órdenes de puesto.","ru":"Бейдж посетителя не даёт полного доступа в закрытые зоны; стандартная практика — сопровождать посетителей в таких зонах и подтверждать допуск. Охранники не передают посетителям универсальные ключи. Точные правила сопровождения определяются инструкциями поста.","tr":"Ziyaretçi rozeti kısıtlı bölgelere sınırsız erişim değildir; standart uygulama, ziyaretçilere bu alanlarda eşlik etmek ve yetkiyi doğrulamaktır. Görevliler ziyaretçilere ana anahtar vermez. Kesin refakat kuralları görev talimatlarına göredir.","hi":"आगंतुक बैज प्रतिबंधित क्षेत्रों में असीमित पहुँच नहीं है; मानक प्रथा ऐसे क्षेत्रों में आगंतुकों के साथ चलना और अधिकार की पुष्टि करना है। गार्ड आगंतुकों को मास्टर चाबियाँ नहीं सौंपते। सटीक अनुरक्षण नियम साइट पोस्ट आदेशों के अनुसार होते हैं।","ar":"شارة الزائر ليست تصريحًا شاملًا للمناطق المقيّدة؛ الممارسة القياسية هي مرافقة الزوّار في تلك المناطق وتأكيد التصريح. لا يسلّم الحراس المفاتيح الرئيسية للزوّار. وتتبع قواعد المرافقة الدقيقة تعليمات الموقع."}},{"cat":"access","a":0,"q":{"en":"Why is collecting visitor badges when people leave an important part of visitor management?","es":"¿Por qué recoger las insignias de visitante cuando la gente se va es una parte importante de la gestión de visitantes?","ru":"Почему сбор бейджей посетителей при выходе — важная часть управления посетителями?","tr":"İnsanlar ayrılırken ziyaretçi rozetlerini toplamak neden ziyaretçi yönetiminin önemli bir parçasıdır?","hi":"लोगों के जाते समय आगंतुक बैज एकत्र करना आगंतुक प्रबंधन का महत्वपूर्ण हिस्सा क्यों है?","ar":"لماذا يُعدّ جمع شارات الزوّار عند مغادرتهم جزءًا مهمًا من إدارة الزوّار؟"},"o":[{"en":"It keeps count of who is still inside and stops badges from being reused improperly","es":"Mantiene el conteo de quién sigue dentro e impide que las insignias se reutilicen indebidamente","ru":"Это позволяет учитывать, кто ещё внутри, и не даёт использовать бейджи не по назначению","tr":"İçeride kimin kaldığını takip eder ve rozetlerin uygunsuz şekilde yeniden kullanılmasını önler","hi":"यह गिनती रखता है कि कौन अभी भी अंदर है और बैज के अनुचित पुन: उपयोग को रोकता है","ar":"يحافظ على معرفة من لا يزال في الداخل ويمنع إعادة استخدام الشارات بشكل غير سليم"},{"en":"Badges are expensive jewelry","es":"Las insignias son joyas costosas","ru":"Бейджи — дорогие украшения","tr":"Rozetler pahalı takılardır","hi":"बैज महँगे आभूषण हैं","ar":"الشارات مجوهرات باهظة الثمن"},{"en":"It lets the guard end their shift sooner","es":"Permite que el guardia termine su turno antes","ru":"Это позволяет охраннику раньше закончить смену","tr":"Görevlinin vardiyasını daha erken bitirmesini sağlar","hi":"यह गार्ड को अपनी पाली जल्दी समाप्त करने देता है","ar":"يتيح للحارس إنهاء ورديته مبكرًا"},{"en":"Visitors dislike keeping badges as souvenirs","es":"A los visitantes no les gusta quedarse las insignias de recuerdo","ru":"Посетители не любят оставлять бейджи на память","tr":"Ziyaretçiler rozetleri hatıra olarak saklamayı sevmez","hi":"आगंतुक बैज को स्मृति-चिह्न के रूप में रखना पसंद नहीं करते","ar":"لا يحب الزوّار الاحتفاظ بالشارات كتذكار"}],"e":{"en":"Collecting badges on exit lets the guard reconcile who has left against the sign-in log, so the site knows who remains inside during an emergency, and prevents valid badges from circulating to unauthorized people.","es":"Recoger las insignias a la salida permite al guardia conciliar quién se fue con el registro de entrada, de modo que el sitio sepa quién queda dentro durante una emergencia, y evita que insignias válidas circulen a personas no autorizadas.","ru":"Сбор бейджей при выходе позволяет охраннику сверить, кто ушёл, с журналом регистрации, чтобы объект знал, кто остаётся внутри при ЧС, и не давал действительным бейджам попадать к посторонним.","tr":"Çıkışta rozetleri toplamak, görevlinin kimlerin ayrıldığını giriş kaydıyla karşılaştırmasını sağlar; böylece acil durumda içeride kimin kaldığı bilinir ve geçerli rozetlerin yetkisiz kişilere geçmesi önlenir.","hi":"निकास पर बैज एकत्र करने से गार्ड यह मिलान कर पाता है कि कौन गया, साइन-इन लॉग के अनुसार, ताकि आपात स्थिति में साइट को पता रहे कि कौन अंदर बचा है, और वैध बैज अनधिकृत लोगों तक न पहुँचें।","ar":"جمع الشارات عند الخروج يتيح للحارس مطابقة من غادر مع سجلّ الدخول، فيعرف الموقع من بقي في الداخل أثناء الطوارئ، ويمنع تداول الشارات الصالحة إلى أشخاص غير مصرَّح لهم."}},{"cat":"access","a":2,"q":{"en":"What is the main purpose of contraband screening at an entry point?","es":"¿Cuál es el propósito principal del control de contrabando en un punto de entrada?","ru":"Какова главная цель досмотра на предмет запрещённых предметов на входе?","tr":"Bir giriş noktasında yasak madde taraması yapmanın temel amacı nedir?","hi":"प्रवेश बिंदु पर निषिद्ध-वस्तु जाँच का मुख्य उद्देश्य क्या है?","ar":"ما الغرض الرئيسي من فحص الممنوعات عند نقطة الدخول؟"},"o":[{"en":"To search everyone's phone for personal messages","es":"Registrar el teléfono de todos en busca de mensajes personales","ru":"Проверять телефон каждого на личные сообщения","tr":"Herkesin telefonunu kişisel mesajlar için aramak","hi":"हर किसी के फ़ोन में व्यक्तिगत संदेश खोजना","ar":"تفتيش هاتف الجميع بحثًا عن رسائل شخصية"},{"en":"To find valuables the guard might want","es":"Encontrar objetos de valor que el guardia pudiera querer","ru":"Найти ценности, которые могут понравиться охраннику","tr":"Görevlinin isteyebileceği değerli eşyaları bulmak","hi":"ऐसी क़ीमती चीज़ें ढूँढना जो गार्ड को चाहिए हों","ar":"العثور على أشياء ثمينة قد يرغب فيها الحارس"},{"en":"To keep prohibited or dangerous items such as weapons and drugs out of the facility","es":"Mantener fuera de las instalaciones objetos prohibidos o peligrosos como armas y drogas","ru":"Не допускать в объект запрещённые или опасные предметы, такие как оружие и наркотики","tr":"Silah ve uyuşturucu gibi yasak veya tehlikeli maddeleri tesisten uzak tutmak","hi":"हथियार और नशीले पदार्थ जैसी निषिद्ध या ख़तरनाक वस्तुओं को सुविधा से बाहर रखना","ar":"إبقاء المواد الممنوعة أو الخطرة مثل الأسلحة والمخدرات خارج المنشأة"},{"en":"To delay entry so lines look busy","es":"Retrasar la entrada para que las filas parezcan concurridas","ru":"Задерживать вход, чтобы очереди казались загруженными","tr":"Sıralar meşgul görünsün diye girişi geciktirmek","hi":"प्रवेश में देरी करना ताकि कतारें व्यस्त दिखें","ar":"تأخير الدخول ليبدو الطابور مزدحمًا"}],"e":{"en":"Contraband screening exists to prevent weapons, drugs, and other prohibited or dangerous items from entering the facility, protecting people and property. It is a safety function, not a way to snoop or take property.","es":"El control de contrabando existe para impedir que armas, drogas y otros objetos prohibidos o peligrosos entren a las instalaciones, protegiendo a las personas y los bienes. Es una función de seguridad, no una forma de husmear o tomar propiedad.","ru":"Досмотр на запрещённые предметы существует, чтобы не допустить в объект оружие, наркотики и иные запрещённые или опасные предметы, защищая людей и имущество. Это функция безопасности, а не способ подсматривать или присваивать вещи.","tr":"Yasak madde taraması, silah, uyuşturucu ve diğer yasak ya da tehlikeli maddelerin tesise girmesini önleyerek insanları ve mülkü korumak için vardır. Bu bir güvenlik işlevidir, gözetleme veya mülke el koyma yolu değildir.","hi":"निषिद्ध-वस्तु जाँच का उद्देश्य हथियार, नशीले पदार्थ और अन्य निषिद्ध या ख़तरनाक वस्तुओं को सुविधा में आने से रोकना है, जिससे लोग और संपत्ति सुरक्षित रहें। यह एक सुरक्षा कार्य है, ताक-झाँक या संपत्ति लेने का तरीका नहीं।","ar":"يوجد فحص الممنوعات لمنع دخول الأسلحة والمخدرات وغيرها من المواد الممنوعة أو الخطرة إلى المنشأة، حمايةً للأشخاص والممتلكات. إنها وظيفة أمنية، وليست وسيلة للتجسس أو الاستيلاء على الممتلكات."}},{"cat":"access","a":1,"q":{"en":"To be fair and legally defensible, how should bag checks and screening generally be applied?","es":"Para ser justo y legalmente defendible, ¿cómo deben aplicarse en general las revisiones de bolsos y el control?","ru":"Чтобы быть справедливым и юридически обоснованным, как в целом следует применять проверку сумок и досмотр?","tr":"Adil ve hukuken savunulabilir olmak için çanta kontrolleri ve tarama genel olarak nasıl uygulanmalıdır?","hi":"निष्पक्ष और क़ानूनी रूप से बचाव-योग्य होने के लिए, बैग जाँच और स्क्रीनिंग सामान्यतः कैसे लागू की जानी चाहिए?","ar":"لكي يكون الأمر عادلًا وقابلًا للدفاع قانونيًا، كيف ينبغي عمومًا تطبيق فحص الحقائب والتفتيش؟"},"o":[{"en":"Only on people the guard personally dislikes","es":"Solo a las personas que le caen mal al guardia","ru":"Только к тем, кто лично не нравится охраннику","tr":"Yalnızca görevlinin şahsen sevmediği kişilere","hi":"केवल उन लोगों पर जिन्हें गार्ड व्यक्तिगत रूप से नापसंद करता है","ar":"فقط على الأشخاص الذين لا يحبهم الحارس شخصيًا"},{"en":"Consistently to everyone (or by a neutral rule) under the posted conditions of entry","es":"De forma coherente a todos (o por una regla neutral) bajo las condiciones de entrada publicadas","ru":"Единообразно ко всем (или по нейтральному правилу) согласно объявленным условиям входа","tr":"İlan edilmiş giriş koşulları altında herkese tutarlı biçimde (veya tarafsız bir kurala göre)","hi":"प्रदर्शित प्रवेश शर्तों के तहत सभी पर एक-समान रूप से (या किसी तटस्थ नियम से)","ar":"باتساق على الجميع (أو وفق قاعدة محايدة) ضمن شروط الدخول المعلنة"},{"en":"Randomly based on how busy the guard feels","es":"Al azar según lo ocupado que se sienta el guardia","ru":"Случайно, в зависимости от занятости охранника","tr":"Görevlinin ne kadar meşgul hissettiğine göre rastgele","hi":"गार्ड कितना व्यस्त महसूस करता है, उसके आधार पर यादृच्छिक रूप से","ar":"عشوائيًا بحسب مدى انشغال الحارس"},{"en":"Based on the visitor's appearance or accent","es":"Según la apariencia o el acento del visitante","ru":"На основе внешности или акцента посетителя","tr":"Ziyaretçinin görünüşüne veya aksanına göre","hi":"आगंतुक के रूप या उच्चारण के आधार पर","ar":"بناءً على مظهر الزائر أو لكنته"}],"e":{"en":"Screening should be applied consistently to everyone or by a neutral, published rule, so it is fair and not discriminatory. Basing checks on appearance, accent, or personal bias exposes the guard and employer to liability.","es":"El control debe aplicarse de forma coherente a todos o mediante una regla neutral y publicada, para que sea justo y no discriminatorio. Basar las revisiones en la apariencia, el acento o el sesgo personal expone al guardia y al empleador a responsabilidad.","ru":"Досмотр следует применять единообразно ко всем или по нейтральному, объявленному правилу, чтобы он был справедливым и недискриминационным. Проверки на основе внешности, акцента или личных предубеждений создают ответственность для охранника и работодателя.","tr":"Tarama, adil ve ayrımcı olmayacak şekilde herkese tutarlı biçimde veya tarafsız, ilan edilmiş bir kurala göre uygulanmalıdır. Kontrolleri görünüş, aksan veya kişisel önyargıya dayandırmak, görevliyi ve işvereni sorumluluğa maruz bırakır.","hi":"स्क्रीनिंग सभी पर एक-समान या किसी तटस्थ, प्रकाशित नियम से लागू होनी चाहिए, ताकि वह निष्पक्ष और गैर-भेदभावपूर्ण हो। रूप, उच्चारण या व्यक्तिगत पूर्वाग्रह के आधार पर जाँच गार्ड और नियोक्ता को दायित्व में डालती है।","ar":"ينبغي تطبيق التفتيش باتساق على الجميع أو وفق قاعدة محايدة معلنة، حتى يكون عادلًا وغير تمييزي. أما استناد الفحص إلى المظهر أو اللكنة أو التحيّز الشخصي فيعرّض الحارس وصاحب العمل للمسؤولية."}},{"cat":"access","a":3,"q":{"en":"On private property, what typically gives a guard the authority to inspect bags at the entrance?","es":"En una propiedad privada, ¿qué le da normalmente a un guardia la autoridad para inspeccionar bolsos en la entrada?","ru":"На частной территории что обычно даёт охраннику право досматривать сумки на входе?","tr":"Özel mülkte, bir görevliye girişte çantaları inceleme yetkisini genellikle ne verir?","hi":"निजी संपत्ति पर, गार्ड को प्रवेश द्वार पर बैग जाँचने का अधिकार आमतौर पर किससे मिलता है?","ar":"في الممتلكات الخاصة، ما الذي يمنح الحارس عادةً صلاحية تفتيش الحقائب عند المدخل؟"},"o":[{"en":"The guard's personal judgment on any given day","es":"El juicio personal del guardia en un día cualquiera","ru":"Личное усмотрение охранника в любой день","tr":"Görevlinin herhangi bir günkü kişisel takdiri","hi":"किसी भी दिन गार्ड का व्यक्तिगत विवेक","ar":"التقدير الشخصي للحارس في أي يوم"},{"en":"The right to search anyone by force","es":"El derecho a registrar a cualquiera por la fuerza","ru":"Право обыскивать любого силой","tr":"Herkesi zorla arama hakkı","hi":"किसी को भी बलपूर्वक तलाशी लेने का अधिकार","ar":"الحق في تفتيش أي شخص بالقوة"},{"en":"A federal law requiring searches everywhere","es":"Una ley federal que exige registros en todas partes","ru":"Федеральный закон, требующий обысков повсюду","tr":"Her yerde arama zorunlu kılan federal bir yasa","hi":"हर जगह तलाशी अनिवार्य करने वाला संघीय कानून","ar":"قانون فيدرالي يفرض التفتيش في كل مكان"},{"en":"Posted conditions of entry that visitors consent to by entering","es":"Condiciones de entrada publicadas que los visitantes aceptan al ingresar","ru":"Объявленные условия входа, с которыми посетитель соглашается, входя на территорию","tr":"Ziyaretçilerin girerek kabul ettiği, ilan edilmiş giriş koşulları","hi":"प्रदर्शित प्रवेश शर्तें, जिन्हें आगंतुक प्रवेश करके स्वीकार करते हैं","ar":"شروط دخول معلنة يوافق عليها الزوّار بمجرد الدخول"}],"e":{"en":"On private property, bag inspection authority usually comes from posted conditions of entry: by choosing to enter, visitors consent to the search. A guard cannot force a search; a person who refuses can be denied entry instead. Specifics vary by state and post orders.","es":"En propiedad privada, la autoridad para inspeccionar bolsos suele provenir de las condiciones de entrada publicadas: al elegir entrar, los visitantes consienten el registro. Un guardia no puede forzar un registro; a quien se niegue se le puede negar la entrada. Los detalles varían según el estado y las órdenes de puesto.","ru":"На частной территории право досмотра сумок обычно вытекает из объявленных условий входа: решив войти, посетитель соглашается на досмотр. Охранник не может проводить обыск силой; отказавшемуся можно просто отказать во входе. Детали зависят от штата и инструкций поста.","tr":"Özel mülkte çanta inceleme yetkisi genellikle ilan edilmiş giriş koşullarından gelir: girmeyi seçen ziyaretçiler aramaya rıza gösterir. Görevli aramayı zorla yapamaz; reddeden kişinin girişi engellenebilir. Ayrıntılar eyalete ve görev talimatlarına göre değişir.","hi":"निजी संपत्ति पर बैग जाँच का अधिकार आमतौर पर प्रदर्शित प्रवेश शर्तों से आता है: प्रवेश चुनकर आगंतुक तलाशी के लिए सहमति देते हैं। गार्ड ज़बरदस्ती तलाशी नहीं ले सकता; मना करने वाले को प्रवेश से मना किया जा सकता है। विवरण राज्य और पोस्ट आदेशों के अनुसार बदलते हैं।","ar":"في الممتلكات الخاصة، تنبع صلاحية تفتيش الحقائب عادةً من شروط الدخول المعلنة: فباختيار الدخول يوافق الزوّار على التفتيش. لا يمكن للحارس فرض التفتيش بالقوة؛ ومن يرفض يمكن منعه من الدخول. وتختلف التفاصيل حسب الولاية وتعليمات الموقع."}},{"cat":"access","a":0,"q":{"en":"During a bag check, a guard finds what appears to be an illegal weapon. What is the appropriate response?","es":"Durante una revisión de bolso, un guardia encuentra lo que parece ser un arma ilegal. ¿Cuál es la respuesta apropiada?","ru":"Во время проверки сумки охранник обнаруживает то, что похоже на незаконное оружие. Каков правильный порядок действий?","tr":"Bir çanta kontrolü sırasında görevli, yasa dışı bir silah gibi görünen bir şey buluyor. Uygun tepki nedir?","hi":"बैग जाँच के दौरान गार्ड को कुछ ऐसा मिलता है जो अवैध हथियार प्रतीत होता है। उचित प्रतिक्रिया क्या है?","ar":"أثناء فحص حقيبة، يجد الحارس ما يبدو أنه سلاح غير قانوني. ما الاستجابة المناسبة؟"},"o":[{"en":"Follow policy: deny entry, detain if authorized and safe, and immediately notify a supervisor and/or police","es":"Seguir la política: negar la entrada, detener si está autorizado y es seguro, y notificar de inmediato al supervisor o a la policía","ru":"Действовать по инструкции: не пропускать, задержать при наличии полномочий и безопасности, немедленно уведомить начальника и/или полицию","tr":"Politikayı izlemek: girişi reddetmek, yetkiliyse ve güvenliyse gözaltına almak ve derhal amiri ve/veya polisi bilgilendirmek","hi":"नीति का पालन करें: प्रवेश अस्वीकार करें, अधिकृत और सुरक्षित होने पर हिरासत में लें, और तुरंत पर्यवेक्षक और/या पुलिस को सूचित करें","ar":"اتّباع السياسة: منع الدخول، والاحتجاز إن كان مصرَّحًا وآمنًا، وإبلاغ المشرف و/أو الشرطة فورًا"},{"en":"Keep the weapon for personal protection","es":"Quedarse con el arma para protección personal","ru":"Оставить оружие себе для самозащиты","tr":"Silahı kişisel koruma için alıkoymak","hi":"आत्मरक्षा के लिए हथियार अपने पास रखें","ar":"الاحتفاظ بالسلاح للحماية الشخصية"},{"en":"Ignore it and let the person through to avoid conflict","es":"Ignorarlo y dejar pasar a la persona para evitar conflictos","ru":"Проигнорировать и пропустить человека, чтобы избежать конфликта","tr":"Görmezden gelip çatışmayı önlemek için kişiyi geçirmek","hi":"टकराव से बचने के लिए इसे अनदेखा करें और व्यक्ति को जाने दें","ar":"تجاهله والسماح للشخص بالمرور تفاديًا للنزاع"},{"en":"Post a photo of it on social media","es":"Publicar una foto en redes sociales","ru":"Выложить фото в соцсети","tr":"Sosyal medyada fotoğrafını paylaşmak","hi":"इसकी फोटो सोशल मीडिया पर पोस्ट करें","ar":"نشر صورة له على وسائل التواصل الاجتماعي"}],"e":{"en":"When contraband like a weapon is found, the guard follows post policy: refuse entry, detain only if authorized and safe to do so, and promptly notify a supervisor and law enforcement. Guards never keep, ignore, or publicize contraband.","es":"Cuando se encuentra contrabando como un arma, el guardia sigue la política del puesto: negar la entrada, detener solo si está autorizado y es seguro, y notificar de inmediato al supervisor y a las autoridades. Los guardias nunca conservan, ignoran ni divulgan el contrabando.","ru":"При обнаружении запрещённого предмета, например оружия, охранник действует по инструкции поста: не пропускает, задерживает только при наличии полномочий и безопасности и незамедлительно уведомляет начальника и полицию. Охранники никогда не оставляют себе, не игнорируют и не разглашают контрабанду.","tr":"Silah gibi bir yasak madde bulunduğunda görevli görev talimatını izler: girişi reddeder, yalnızca yetkili ve güvenliyse gözaltına alır ve hemen amiri ile kolluk kuvvetlerini bilgilendirir. Görevliler yasak maddeyi asla alıkoymaz, görmezden gelmez veya ifşa etmez.","hi":"जब हथियार जैसी निषिद्ध वस्तु मिले, तो गार्ड पोस्ट नीति का पालन करता है: प्रवेश अस्वीकार करे, केवल अधिकृत और सुरक्षित होने पर हिरासत में ले, और तुरंत पर्यवेक्षक व पुलिस को सूचित करे। गार्ड निषिद्ध वस्तु को कभी अपने पास नहीं रखते, अनदेखा नहीं करते या सार्वजनिक नहीं करते।","ar":"عند العثور على ممنوعات مثل سلاح، يتّبع الحارس سياسة الموقع: يمنع الدخول، ويحتجز فقط إذا كان مصرَّحًا وآمنًا، ويبلّغ المشرف وجهات إنفاذ القانون فورًا. لا يحتفظ الحراس أبدًا بالممنوعات ولا يتجاهلونها ولا ينشرونها."}},{"cat":"access","a":2,"q":{"en":"Why is controlling a single point of entry a core access-control principle?","es":"¿Por qué controlar un único punto de entrada es un principio fundamental del control de acceso?","ru":"Почему контроль единственной точки входа — базовый принцип контроля доступа?","tr":"Tek bir giriş noktasını kontrol etmek neden temel bir erişim kontrol ilkesidir?","hi":"एकल प्रवेश बिंदु को नियंत्रित करना अभिगम-नियंत्रण का मूल सिद्धांत क्यों है?","ar":"لماذا يُعدّ التحكم في نقطة دخول واحدة مبدأً أساسيًا في التحكم بالدخول؟"},"o":[{"en":"It makes the building look more impressive","es":"Hace que el edificio se vea más impresionante","ru":"Это делает здание более внушительным","tr":"Binayı daha etkileyici gösterir","hi":"यह इमारत को अधिक प्रभावशाली दिखाता है","ar":"يجعل المبنى يبدو أكثر إبهارًا"},{"en":"It lets the guard leave the post more often","es":"Permite que el guardia deje el puesto más a menudo","ru":"Это позволяет охраннику чаще покидать пост","tr":"Görevlinin görevini daha sık terk etmesine izin verir","hi":"यह गार्ड को अधिक बार पोस्ट छोड़ने देता है","ar":"يتيح للحارس ترك موقعه بشكل أكثر"},{"en":"It funnels everyone through one controlled checkpoint so entries can be screened and logged","es":"Canaliza a todos por un único punto de control para poder examinar y registrar los ingresos","ru":"Это направляет всех через один контролируемый пункт, чтобы входы можно было проверять и фиксировать","tr":"Herkesi tek bir kontrollü noktaya yönlendirir, böylece girişler taranıp kaydedilebilir","hi":"यह सभी को एक नियंत्रित चौकी से गुज़ारता है ताकि प्रवेशों की जाँच और लॉगिंग हो सके","ar":"يوجّه الجميع عبر نقطة تفتيش واحدة مضبوطة بحيث يمكن فحص الدخول وتسجيله"},{"en":"It reduces the building's electricity bill","es":"Reduce la factura de electricidad del edificio","ru":"Это снижает счёт за электричество здания","tr":"Binanın elektrik faturasını azaltır","hi":"यह इमारत का बिजली बिल कम करता है","ar":"يقلّل فاتورة كهرباء المبنى"}],"e":{"en":"A single controlled entry point channels all traffic past one checkpoint where identity, authorization, and belongings can be verified and logged, closing off unmonitored ways in. It is about control and accountability, not appearance.","es":"Un único punto de entrada controlado canaliza todo el tránsito por un punto de control donde se pueden verificar y registrar identidad, autorización y pertenencias, cerrando accesos no vigilados. Se trata de control y rendición de cuentas, no de apariencia.","ru":"Единственная контролируемая точка входа направляет весь поток через один пункт, где можно проверить и зафиксировать личность, право доступа и вещи, перекрывая неконтролируемые проходы. Дело в контроле и подотчётности, а не во внешнем виде.","tr":"Tek bir kontrollü giriş noktası tüm trafiği kimliğin, yetkinin ve eşyaların doğrulanıp kaydedilebildiği bir noktadan geçirir ve denetimsiz giriş yollarını kapatır. Mesele görünüş değil, kontrol ve hesap verebilirliktir.","hi":"एकल नियंत्रित प्रवेश बिंदु सारे आवागमन को एक चौकी से गुज़ारता है जहाँ पहचान, अधिकार और सामान की पुष्टि और लॉगिंग हो सकती है, जिससे बिना-निगरानी वाले रास्ते बंद हो जाते हैं। यह नियंत्रण और जवाबदेही की बात है, दिखावे की नहीं।","ar":"نقطة الدخول الواحدة المضبوطة توجّه كل الحركة عبر نقطة تفتيش واحدة يمكن فيها التحقق من الهوية والتصريح والأمتعة وتسجيلها، وتُغلق المداخل غير المراقَبة. الأمر يتعلق بالتحكم والمساءلة، لا بالمظهر."}},{"cat":"access","a":1,"q":{"en":"At a vehicle gate, a delivery driver arrives without the credentials or paperwork the post requires. What should the guard do?","es":"En una puerta vehicular, un repartidor llega sin las credenciales o los documentos que exige el puesto. ¿Qué debe hacer el guardia?","ru":"На автомобильных воротах водитель доставки приезжает без документов или пропуска, которые требуются на посту. Что должен сделать охранник?","tr":"Bir araç kapısında, bir teslimat sürücüsü görevin gerektirdiği belge veya evrak olmadan geliyor. Görevli ne yapmalıdır?","hi":"वाहन गेट पर एक डिलीवरी ड्राइवर उन क्रेडेंशियल या कागज़ात के बिना आता है जो पोस्ट आवश्यक ठहराती है। गार्ड को क्या करना चाहिए?","ar":"عند بوابة المركبات، يصل سائق توصيل دون التصاريح أو الأوراق التي يشترطها الموقع. ماذا ينبغي للحارس أن يفعل؟"},"o":[{"en":"Wave the vehicle through to keep traffic moving","es":"Dejar pasar el vehículo para mantener el tránsito en movimiento","ru":"Пропустить машину, чтобы не задерживать движение","tr":"Trafiği aksatmamak için aracı geçirmek","hi":"यातायात चलता रखने के लिए वाहन को जाने दें","ar":"السماح للمركبة بالمرور لإبقاء الحركة سلسة"},{"en":"Hold the vehicle at the gate and verify the delivery before allowing entry","es":"Detener el vehículo en la puerta y verificar la entrega antes de permitir el ingreso","ru":"Задержать машину у ворот и проверить доставку, прежде чем впускать","tr":"Aracı kapıda tutmak ve girişe izin vermeden önce teslimatı doğrulamak","hi":"वाहन को गेट पर रोकें और प्रवेश देने से पहले डिलीवरी सत्यापित करें","ar":"إيقاف المركبة عند البوابة والتحقق من التوصيل قبل السماح بالدخول"},{"en":"Let the driver in but follow him around the site","es":"Dejar entrar al conductor pero seguirlo por todo el sitio","ru":"Впустить водителя, но ходить за ним по объекту","tr":"Sürücüyü içeri almak ama sahada onu takip etmek","hi":"ड्राइवर को अंदर आने दें पर पूरे स्थल में उसका पीछा करें","ar":"إدخال السائق مع تتبّعه في أنحاء الموقع"},{"en":"Tell the driver to find another entrance","es":"Decirle al conductor que busque otra entrada","ru":"Сказать водителю искать другой въезд","tr":"Sürücüye başka bir giriş bulmasını söylemek","hi":"ड्राइवर से कहें कि कोई और प्रवेश ढूँढे","ar":"إخبار السائق بأن يبحث عن مدخل آخر"}],"e":{"en":"At a gate the guard holds the vehicle and verifies the delivery through the proper contact or paperwork before granting access; convenience does not override credential checks. Directing the driver to a different, uncontrolled entrance would defeat the purpose.","es":"En una puerta, el guardia detiene el vehículo y verifica la entrega a través del contacto o los documentos correctos antes de conceder el acceso; la comodidad no anula la verificación de credenciales. Enviar al conductor a otra entrada no controlada anularía el propósito.","ru":"На воротах охранник задерживает машину и проверяет доставку через нужный контакт или документы, прежде чем дать доступ; удобство не отменяет проверку пропусков. Направить водителя к другому, неконтролируемому въезду означало бы свести цель на нет.","tr":"Kapıda görevli aracı tutar ve erişim vermeden önce teslimatı doğru irtibat veya evrak üzerinden doğrular; kolaylık, belge kontrolünün önüne geçmez. Sürücüyü başka, denetimsiz bir girişe yönlendirmek amacı boşa çıkarır.","hi":"गेट पर गार्ड वाहन रोकता है और पहुँच देने से पहले सही संपर्क या कागज़ात के माध्यम से डिलीवरी सत्यापित करता है; सुविधा क्रेडेंशियल जाँच पर हावी नहीं होती। ड्राइवर को किसी अन्य, अनियंत्रित प्रवेश की ओर भेजना उद्देश्य ही विफल कर देगा।","ar":"عند البوابة يوقف الحارس المركبة ويتحقق من التوصيل عبر جهة الاتصال أو الأوراق الصحيحة قبل السماح بالدخول؛ فالراحة لا تلغي التحقق من التصاريح. وتوجيه السائق إلى مدخل آخر غير مراقَب يُبطل الغرض."}},{"cat":"access","a":0,"q":{"en":"Why should a lobby or gate guard avoid leaving the post unattended, even briefly?","es":"¿Por qué debe un guardia de vestíbulo o puerta evitar dejar el puesto sin vigilancia, aunque sea brevemente?","ru":"Почему охранник в вестибюле или на воротах должен избегать оставлять пост без присмотра, даже ненадолго?","tr":"Bir lobi veya kapı görevlisi, kısa bir süre için bile olsa görev yerini neden gözetimsiz bırakmaktan kaçınmalıdır?","hi":"लॉबी या गेट गार्ड को पोस्ट को थोड़ी देर के लिए भी बिना-निगरानी छोड़ने से क्यों बचना चाहिए?","ar":"لماذا ينبغي لحارس البهو أو البوابة تجنّب ترك الموقع دون مراقبة، ولو لفترة وجيزة؟"},"o":[{"en":"An unattended entry point lets people enter unchecked and unlogged","es":"Un punto de entrada desatendido permite que la gente entre sin control ni registro","ru":"Оставленная без присмотра точка входа позволяет людям входить без проверки и записи","tr":"Gözetimsiz bir giriş noktası, insanların kontrolsüz ve kayıtsız girmesine izin verir","hi":"बिना-निगरानी प्रवेश बिंदु लोगों को बिना जाँच और बिना लॉग के अंदर आने देता है","ar":"نقطة الدخول غير المراقَبة تتيح للناس الدخول دون فحص أو تسجيل"},{"en":"The chair might be taken by someone else","es":"Alguien más podría ocupar la silla","ru":"Стул может занять кто-то другой","tr":"Sandalyeyi başkası kapabilir","hi":"कुर्सी कोई और ले सकता है","ar":"قد يأخذ شخص آخر الكرسي"},{"en":"It is against fire code to sit down","es":"Sentarse va contra el código contra incendios","ru":"Сидеть запрещено правилами пожарной безопасности","tr":"Oturmak yangın yönetmeliğine aykırıdır","hi":"बैठना अग्नि-संहिता के विरुद्ध है","ar":"الجلوس مخالف لقانون الحريق"},{"en":"The guard could miss a personal phone call","es":"El guardia podría perderse una llamada personal","ru":"Охранник может пропустить личный звонок","tr":"Görevli kişisel bir telefon çağrısını kaçırabilir","hi":"गार्ड कोई व्यक्तिगत फ़ोन कॉल चूक सकता है","ar":"قد يفوت الحارس مكالمة هاتفية شخصية"}],"e":{"en":"If the entry point is left unattended, unauthorized people can slip in without being screened or logged, defeating access control. The guard should arrange relief before stepping away rather than abandoning the post.","es":"Si el punto de entrada queda sin vigilancia, personas no autorizadas pueden colarse sin ser examinadas ni registradas, anulando el control de acceso. El guardia debe conseguir un relevo antes de retirarse en lugar de abandonar el puesto.","ru":"Если точку входа оставить без присмотра, посторонние могут проскользнуть без проверки и регистрации, сводя на нет контроль доступа. Прежде чем отойти, охранник должен организовать подмену, а не бросать пост.","tr":"Giriş noktası gözetimsiz kalırsa yetkisiz kişiler taranmadan ve kaydedilmeden içeri sızabilir, bu da erişim kontrolünü boşa çıkarır. Görevli, görevini terk etmek yerine ayrılmadan önce yerine birini ayarlamalıdır.","hi":"यदि प्रवेश बिंदु बिना-निगरानी छोड़ा जाए, तो अनधिकृत लोग बिना जाँच और बिना लॉग के अंदर घुस सकते हैं, जिससे अभिगम-नियंत्रण विफल हो जाता है। गार्ड को हटने से पहले पोस्ट छोड़ने के बजाय राहत (रिलीफ़) की व्यवस्था करनी चाहिए।","ar":"إذا تُركت نقطة الدخول دون مراقبة، يمكن لأشخاص غير مصرَّح لهم التسلل دون فحص أو تسجيل، مما يُبطل التحكم في الدخول. وينبغي للحارس ترتيب من يحلّ محله قبل أن يبتعد بدلًا من التخلّي عن الموقع."}},{"cat":"access","a":3,"q":{"en":"In access control, what does 'tailgating' (also called piggybacking) mean?","es":"En control de acceso, ¿qué significa 'tailgating' (también llamado piggybacking)?","ru":"В контроле доступа что означает «tailgating» (также называемое piggybacking)?","tr":"Erişim kontrolünde 'tailgating' (piggybacking olarak da bilinir) ne anlama gelir?","hi":"अभिगम-नियंत्रण में 'टेलगेटिंग' (जिसे पिगीबैकिंग भी कहते हैं) का क्या अर्थ है?","ar":"في التحكم بالدخول، ماذا يعني \"التلاصق عند الدخول\" (tailgating، ويُسمى أيضًا piggybacking)؟"},"o":[{"en":"Driving too closely behind another vehicle at the gate","es":"Conducir demasiado cerca detrás de otro vehículo en la puerta","ru":"Ехать слишком близко за другой машиной у ворот","tr":"Kapıda başka bir aracın çok yakınından sürmek","hi":"गेट पर किसी अन्य वाहन के बहुत पास चलाना","ar":"القيادة قريبًا جدًا خلف مركبة أخرى عند البوابة"},{"en":"Two coworkers arriving at the same time with valid badges","es":"Dos compañeros que llegan a la vez con insignias válidas","ru":"Двое коллег, пришедших одновременно с действительными бейджами","tr":"İki iş arkadaşının geçerli rozetlerle aynı anda gelmesi","hi":"दो सहकर्मी जो वैध बैज के साथ एक साथ आते हैं","ar":"وصول زميلين في العمل معًا بشارتين صالحتين"},{"en":"Signing the visitor log for someone else as a courtesy","es":"Firmar el registro de visitantes por otra persona como cortesía","ru":"Расписаться в журнале за другого из вежливости","tr":"Nezaketen başkası adına ziyaretçi kaydını imzalamak","hi":"शिष्टाचारवश किसी और के लिए आगंतुक लॉग पर हस्ताक्षर करना","ar":"التوقيع في سجل الزوّار نيابةً عن غيرك مجاملةً"},{"en":"An unauthorized person slipping through a controlled door behind an authorized person","es":"Una persona no autorizada que se cuela por una puerta controlada detrás de una autorizada","ru":"Посторонний, проскальзывающий через контролируемую дверь следом за допущенным лицом","tr":"Yetkisiz bir kişinin, yetkili bir kişinin arkasından kontrollü bir kapıdan sızması","hi":"एक अनधिकृत व्यक्ति जो अधिकृत व्यक्ति के पीछे नियंत्रित दरवाज़े से घुस जाता है","ar":"شخص غير مصرَّح له يتسلّل عبر باب مضبوط خلف شخص مصرَّح له"}],"e":{"en":"Tailgating, or piggybacking, is when an unauthorized person follows an authorized person through a controlled door or gate before it closes, gaining entry without presenting their own credential. It defeats access control and must be challenged.","es":"El 'tailgating' o piggybacking ocurre cuando una persona no autorizada sigue a una autorizada a través de una puerta o portón controlado antes de que se cierre, entrando sin presentar su propia credencial. Anula el control de acceso y debe ser cuestionado.","ru":"Tailgating (piggybacking) — это когда посторонний проходит следом за допущенным лицом через контролируемую дверь или ворота до их закрытия, попадая внутрь без предъявления собственного пропуска. Это сводит на нет контроль доступа, и такому нужно противодействовать.","tr":"Tailgating veya piggybacking, yetkisiz bir kişinin, kontrollü bir kapı ya da giriş kapanmadan önce yetkili bir kişinin ardından geçerek kendi kartını göstermeden içeri girmesidir. Erişim kontrolünü boşa çıkarır ve mutlaka sorgulanmalıdır.","hi":"टेलगेटिंग या पिगीबैकिंग तब होती है जब कोई अनधिकृत व्यक्ति नियंत्रित दरवाज़े या गेट के बंद होने से पहले किसी अधिकृत व्यक्ति के पीछे निकलकर, अपना क्रेडेंशियल दिखाए बिना अंदर आ जाता है। यह अभिगम-नियंत्रण को विफल करता है और इसे रोका-टोका जाना चाहिए।","ar":"التلاصق عند الدخول (piggybacking) هو أن يتبع شخص غير مصرَّح له شخصًا مصرَّحًا عبر باب أو بوابة مضبوطة قبل أن تُغلق، فيدخل دون تقديم تصريحه الخاص. وهو يُبطل التحكم في الدخول ويجب التصدّي له."}},{"cat":"access","a":1,"q":{"en":"Which practice best helps prevent tailgating at a badge-controlled door?","es":"¿Qué práctica ayuda mejor a prevenir el tailgating en una puerta controlada por insignia?","ru":"Какая практика лучше всего помогает предотвратить tailgating у двери с контролем по бейджу?","tr":"Bir rozet kontrollü kapıda tailgating'i önlemeye en iyi hangi uygulama yardımcı olur?","hi":"बैज-नियंत्रित दरवाज़े पर टेलगेटिंग रोकने में कौन-सी प्रथा सबसे अधिक मदद करती है?","ar":"أي ممارسة تساعد أكثر على منع التلاصق عند باب يعمل بالشارة؟"},"o":[{"en":"Propping the door open during busy times to speed things up","es":"Dejar la puerta abierta en horas pico para agilizar","ru":"Подпирать дверь открытой в час пик, чтобы ускорить проход","tr":"Yoğun saatlerde işleri hızlandırmak için kapıyı açık tutmak","hi":"व्यस्त समय में गति बढ़ाने के लिए दरवाज़ा खुला रखना","ar":"إبقاء الباب مفتوحًا في أوقات الازدحام لتسريع الأمور"},{"en":"Requiring one badge swipe per person and challenging anyone who tries to follow through","es":"Exigir un pase de insignia por persona y cuestionar a quien intente colarse detrás","ru":"Требовать по одному проходу бейджа на человека и останавливать всех, кто пытается пройти следом","tr":"Kişi başına bir rozet okutması istemek ve arkadan geçmeye çalışan herkesi sorgulamak","hi":"प्रति व्यक्ति एक बैज स्वाइप आवश्यक करना और पीछे से घुसने की कोशिश करने वाले किसी को भी रोकना-टोकना","ar":"اشتراط تمرير شارة واحدة لكل شخص والتصدّي لأي شخص يحاول الدخول خلف الآخر"},{"en":"Holding the door open for anyone who looks like staff","es":"Sostener la puerta para cualquiera que parezca personal","ru":"Придерживать дверь для любого, кто выглядит как сотрудник","tr":"Personel gibi görünen herkese kapıyı tutmak","hi":"स्टाफ जैसे दिखने वाले किसी के लिए भी दरवाज़ा पकड़े रखना","ar":"إمساك الباب لأي شخص يبدو من الموظفين"},{"en":"Turning off the badge reader to reduce complaints","es":"Apagar el lector de insignias para reducir quejas","ru":"Отключить считыватель бейджей, чтобы уменьшить жалобы","tr":"Şikayetleri azaltmak için rozet okuyucusunu kapatmak","hi":"शिकायतें कम करने के लिए बैज रीडर बंद कर देना","ar":"إيقاف قارئ الشارة لتقليل الشكاوى"}],"e":{"en":"Requiring each person to badge in individually and challenging anyone who tries to follow through the door is the standard defense against tailgating. Propping doors or holding them for strangers, however polite, breaks access control.","es":"Exigir que cada persona registre su insignia individualmente y cuestionar a quien intente pasar detrás es la defensa estándar contra el tailgating. Dejar puertas abiertas o sostenerlas para extraños, por cortés que sea, rompe el control de acceso.","ru":"Требовать, чтобы каждый прикладывал бейдж индивидуально, и останавливать любого, кто пытается пройти следом, — стандартная защита от tailgating. Подпирать двери или придерживать их для незнакомцев, пусть и из вежливости, разрушает контроль доступа.","tr":"Her kişinin ayrı ayrı rozet okutmasını istemek ve kapıdan geçmeye çalışan herkesi sorgulamak, tailgating'e karşı standart savunmadır. Kapıları açık tutmak ya da yabancılara tutmak, ne kadar nazik olursa olsun, erişim kontrolünü bozar.","hi":"प्रत्येक व्यक्ति से अलग-अलग बैज करवाना और दरवाज़े से पीछे आने की कोशिश करने वाले किसी को भी रोकना-टोकना टेलगेटिंग के विरुद्ध मानक बचाव है। दरवाज़े खुले रखना या अजनबियों के लिए पकड़े रखना, चाहे कितना भी विनम्र हो, अभिगम-नियंत्रण तोड़ देता है।","ar":"اشتراط أن يمرّر كل شخص شارته على حدة والتصدّي لأي شخص يحاول العبور خلف الآخر هو الدفاع القياسي ضد التلاصق. أما إبقاء الأبواب مفتوحة أو إمساكها للغرباء، مهما كان ذلك مهذبًا، فيكسر التحكم في الدخول."}},{"cat":"access","a":2,"q":{"en":"What is the ethical rule for using CCTV cameras at a monitored site?","es":"¿Cuál es la regla ética para usar cámaras de CCTV en un sitio vigilado?","ru":"Каково этическое правило использования камер видеонаблюдения на охраняемом объекте?","tr":"İzlenen bir tesiste CCTV kameralarını kullanmanın etik kuralı nedir?","hi":"निगरानी वाले स्थल पर CCTV कैमरों के उपयोग का नैतिक नियम क्या है?","ar":"ما القاعدة الأخلاقية لاستخدام كاميرات المراقبة في موقع خاضع للمراقبة؟"},"o":[{"en":"Cameras may be pointed anywhere the guard is curious about","es":"Las cámaras pueden apuntar a cualquier lugar que despierte la curiosidad del guardia","ru":"Камеры можно направлять куда угодно, что интересно охраннику","tr":"Kameralar görevlinin merak ettiği her yere yöneltilebilir","hi":"कैमरों को कहीं भी घुमाया जा सकता है जहाँ गार्ड की जिज्ञासा हो","ar":"يمكن توجيه الكاميرات إلى أي مكان يثير فضول الحارس"},{"en":"Footage can be shared with friends if nothing sensitive shows","es":"Las grabaciones pueden compartirse con amigos si no muestran nada sensible","ru":"Записью можно делиться с друзьями, если на ней нет ничего личного","tr":"Görüntüler hassas bir şey göstermiyorsa arkadaşlarla paylaşılabilir","hi":"यदि कुछ संवेदनशील न दिखे तो फुटेज दोस्तों के साथ साझा की जा सकती है","ar":"يمكن مشاركة التسجيلات مع الأصدقاء إذا لم تظهر شيئًا حساسًا"},{"en":"Cameras are used only for legitimate security purposes, with privacy respected and footage kept confidential","es":"Las cámaras se usan solo con fines de seguridad legítimos, respetando la privacidad y manteniendo confidenciales las grabaciones","ru":"Камеры используются только в законных целях безопасности, с уважением к приватности и конфиденциальностью записей","tr":"Kameralar yalnızca meşru güvenlik amaçlarıyla kullanılır; mahremiyete saygı gösterilir ve görüntüler gizli tutulur","hi":"कैमरे केवल वैध सुरक्षा उद्देश्यों के लिए उपयोग होते हैं, गोपनीयता का सम्मान करते हुए और फुटेज को गोपनीय रखते हुए","ar":"تُستخدم الكاميرات فقط لأغراض أمنية مشروعة، مع احترام الخصوصية والحفاظ على سرية التسجيلات"},{"en":"Cameras are mainly for entertaining the guard on quiet shifts","es":"Las cámaras sirven sobre todo para entretener al guardia en turnos tranquilos","ru":"Камеры в основном для развлечения охранника в спокойные смены","tr":"Kameralar çoğunlukla sakin vardiyalarda görevliyi eğlendirmek içindir","hi":"कैमरे मुख्यतः शांत पालियों में गार्ड के मनोरंजन के लिए हैं","ar":"الكاميرات أساسًا لتسلية الحارس في الورديات الهادئة"}],"e":{"en":"CCTV must be used strictly for legitimate security, never for spying, voyeurism, or personal amusement. Guards respect privacy, keep footage confidential, and follow site policy on access to recordings.","es":"El CCTV debe usarse estrictamente para seguridad legítima, nunca para espiar, voyerismo o diversión personal. Los guardias respetan la privacidad, mantienen confidenciales las grabaciones y siguen la política del sitio sobre el acceso a las mismas.","ru":"Видеонаблюдение должно использоваться строго в законных целях безопасности, а не для слежки, вуайеризма или личного развлечения. Охранники уважают приватность, хранят записи в тайне и соблюдают правила объекта о доступе к ним.","tr":"CCTV yalnızca meşru güvenlik için kullanılmalı; asla gözetleme, röntgencilik veya kişisel eğlence için değil. Görevliler mahremiyete saygı gösterir, görüntüleri gizli tutar ve kayıtlara erişim konusunda tesis politikasına uyar.","hi":"CCTV का उपयोग कड़ाई से केवल वैध सुरक्षा के लिए होना चाहिए, कभी जासूसी, ताक-झाँक या व्यक्तिगत मनोरंजन के लिए नहीं। गार्ड गोपनीयता का सम्मान करते हैं, फुटेज को गोपनीय रखते हैं, और रिकॉर्डिंग तक पहुँच पर साइट नीति का पालन करते हैं।","ar":"يجب استخدام كاميرات المراقبة حصرًا لأغراض أمنية مشروعة، لا للتجسس أو التلصّص أو التسلية الشخصية. يحترم الحراس الخصوصية، ويحافظون على سرية التسجيلات، ويتبعون سياسة الموقع بشأن الوصول إليها."}},{"cat":"access","a":3,"q":{"en":"Where should security cameras never be installed, according to standard privacy ethics?","es":"Según la ética estándar de privacidad, ¿dónde nunca deben instalarse las cámaras de seguridad?","ru":"Где, согласно стандартной этике приватности, камеры видеонаблюдения никогда не должны устанавливаться?","tr":"Standart mahremiyet etiğine göre güvenlik kameraları asla nereye kurulmamalıdır?","hi":"मानक गोपनीयता नैतिकता के अनुसार, सुरक्षा कैमरे कहाँ कभी नहीं लगाए जाने चाहिए?","ar":"وفق أخلاقيات الخصوصية القياسية، أين يجب ألّا تُركَّب كاميرات المراقبة أبدًا؟"},"o":[{"en":"In parking lots and loading docks","es":"En estacionamientos y muelles de carga","ru":"На парковках и погрузочных площадках","tr":"Otoparklarda ve yükleme rampalarında","hi":"पार्किंग स्थलों और लोडिंग डॉक में","ar":"في مواقف السيارات وأرصفة التحميل"},{"en":"At building entrances and exits","es":"En las entradas y salidas del edificio","ru":"У входов и выходов здания","tr":"Bina giriş ve çıkışlarında","hi":"इमारत के प्रवेश और निकास द्वारों पर","ar":"عند مداخل المبنى ومخارجه"},{"en":"In hallways and stairwells","es":"En pasillos y escaleras","ru":"В коридорах и на лестницах","tr":"Koridorlarda ve merdiven boşluklarında","hi":"गलियारों और सीढ़ियों में","ar":"في الممرات وأدراج السلالم"},{"en":"In restrooms, locker rooms, and changing areas","es":"En baños, vestuarios y probadores","ru":"В туалетах, раздевалках и примерочных","tr":"Tuvaletlerde, soyunma odalarında ve giyinme alanlarında","hi":"शौचालयों, लॉकर रूम और चेंजिंग क्षेत्रों में","ar":"في دورات المياه وغرف تغيير الملابس والمقصورات"}],"e":{"en":"Cameras must never be placed in areas where people have a reasonable expectation of privacy, such as restrooms, locker rooms, and changing areas. Monitoring entrances, hallways, and parking areas for security is generally acceptable.","es":"Nunca deben colocarse cámaras en áreas donde las personas tienen una expectativa razonable de privacidad, como baños, vestuarios y probadores. Vigilar entradas, pasillos y estacionamientos por seguridad es en general aceptable.","ru":"Камеры нельзя размещать там, где люди обоснованно ожидают приватности, — в туалетах, раздевалках и примерочных. Наблюдение за входами, коридорами и парковками в целях безопасности, как правило, допустимо.","tr":"Kameralar, insanların makul mahremiyet beklentisi olduğu tuvalet, soyunma odası ve giyinme alanları gibi yerlere asla konmamalıdır. Girişlerin, koridorların ve otoparkların güvenlik için izlenmesi genellikle kabul edilebilir.","hi":"कैमरे कभी ऐसे स्थानों पर नहीं लगाए जाने चाहिए जहाँ लोगों को गोपनीयता की उचित अपेक्षा हो, जैसे शौचालय, लॉकर रूम और चेंजिंग क्षेत्र। सुरक्षा हेतु प्रवेश, गलियारों और पार्किंग की निगरानी आम तौर पर स्वीकार्य है।","ar":"يجب ألّا تُوضع الكاميرات أبدًا في الأماكن التي يتوقّع فيها الناس خصوصية معقولة، مثل دورات المياه وغرف الخزائن ومقصورات تغيير الملابس. أما مراقبة المداخل والممرات ومواقف السيارات لأغراض أمنية فمقبولة عمومًا."}},{"cat":"conduct","a":2,"q":{"en":"Why is wearing a clean, complete uniform important for a security guard?","es":"¿Por qué es importante que un guardia de seguridad use un uniforme limpio y completo?","ru":"Почему для охранника важно носить чистую и полную форму?","tr":"Bir güvenlik görevlisinin temiz ve eksiksiz bir üniforma giymesi neden önemlidir?","hi":"सुरक्षा गार्ड के लिए साफ और पूरी वर्दी पहनना क्यों महत्वपूर्ण है?","ar":"لماذا يُعدّ ارتداء زيّ نظيف وكامل أمرًا مهمًا لحارس الأمن؟"},"o":[{"en":"It is only important on days when supervisors visit the site","es":"Solo es importante los días en que los supervisores visitan el sitio","ru":"Это важно только в дни, когда руководители посещают объект","tr":"Yalnızca amirlerin sahayı ziyaret ettiği günlerde önemlidir","hi":"यह केवल उन दिनों में महत्वपूर्ण है जब पर्यवेक्षक साइट पर आते हैं","ar":"إنه مهم فقط في الأيام التي يزور فيها المشرفون الموقع"},{"en":"It lets the guard blend in and go unnoticed by everyone","es":"Permite que el guardia se mezcle y pase desapercibido para todos","ru":"Это позволяет охраннику слиться с толпой и остаться незамеченным","tr":"Görevlinin ortama karışıp herkes tarafından fark edilmemesini sağlar","hi":"यह गार्ड को घुलने-मिलने और सबकी नज़र से बचने देती है","ar":"يتيح للحارس الاندماج وعدم ملاحظته من الجميع"},{"en":"It projects authority and professionalism, represents the employer, and helps deter crime","es":"Proyecta autoridad y profesionalismo, representa al empleador y ayuda a disuadir el delito","ru":"Она демонстрирует авторитет и профессионализм, представляет работодателя и помогает сдерживать преступность","tr":"Otorite ve profesyonellik yansıtır, işvereni temsil eder ve suçu caydırmaya yardımcı olur","hi":"यह अधिकार और पेशेवरता दर्शाती है, नियोक्ता का प्रतिनिधित्व करती है और अपराध रोकने में मदद करती है","ar":"يُظهر السلطة والاحترافية، ويمثّل صاحب العمل، ويساعد على ردع الجريمة"},{"en":"It is required only by federal law, not by any employer","es":"Solo lo exige la ley federal, no ningún empleador","ru":"Это требуется только федеральным законом, а не работодателем","tr":"Yalnızca federal yasa gerektirir, hiçbir işveren gerektirmez","hi":"यह केवल संघीय कानून द्वारा आवश्यक है, किसी नियोक्ता द्वारा नहीं","ar":"يفرضه القانون الفيدرالي فقط، وليس أي صاحب عمل"}],"e":{"en":"A clean, complete uniform projects authority and professionalism, represents the employer to the public, and a visible, sharp presence helps deter crime. Specific uniform standards are set by employer/agency policy.","es":"Un uniforme limpio y completo proyecta autoridad y profesionalismo, representa al empleador ante el público, y una presencia visible y pulcra ayuda a disuadir el delito. Las normas específicas del uniforme las fija la política del empleador/agencia.","ru":"Чистая и полная форма демонстрирует авторитет и профессионализм, представляет работодателя перед публикой, а заметное, опрятное присутствие помогает сдерживать преступность. Конкретные требования к форме устанавливаются политикой работодателя/агентства.","tr":"Temiz ve eksiksiz bir üniforma otorite ve profesyonellik yansıtır, işvereni halka temsil eder ve görünür, düzgün bir varlık suçu caydırmaya yardımcı olur. Belirli üniforma standartları işveren/ajans politikasıyla belirlenir.","hi":"साफ और पूरी वर्दी अधिकार और पेशेवरता दर्शाती है, जनता के सामने नियोक्ता का प्रतिनिधित्व करती है, और एक स्पष्ट, दिखाई देने वाली उपस्थिति अपराध रोकने में मदद करती है। विशिष्ट वर्दी मानक नियोक्ता/एजेंसी नीति द्वारा तय होते हैं।","ar":"الزيّ النظيف والكامل يُظهر السلطة والاحترافية، ويمثّل صاحب العمل أمام الجمهور، والحضور الواضح والأنيق يساعد على ردع الجريمة. تُحدَّد معايير الزيّ المحددة بحسب سياسة صاحب العمل/الشركة."}},{"cat":"conduct","a":0,"q":{"en":"What does good posture and staying alert on post communicate to the public?","es":"¿Qué comunica al público una buena postura y mantenerse alerta en el puesto?","ru":"Что хорошая осанка и бдительность на посту сообщают публике?","tr":"Görev yerinde dik duruş ve tetikte olmak halka ne mesaj verir?","hi":"चौकी पर अच्छी मुद्रा और सतर्क रहना जनता को क्या संदेश देता है?","ar":"ماذا يبلّغ الوقوف باعتدال والبقاء متيقظًا في الموقع للجمهور؟"},"o":[{"en":"That the guard is attentive, in control, and ready to respond","es":"Que el guardia está atento, en control y listo para responder","ru":"Что охранник внимателен, контролирует ситуацию и готов реагировать","tr":"Görevlinin dikkatli, kontrol sahibi ve müdahaleye hazır olduğunu","hi":"कि गार्ड चौकस है, नियंत्रण में है और प्रतिक्रिया देने के लिए तैयार है","ar":"أن الحارس منتبه ومسيطر وجاهز للاستجابة"},{"en":"That the guard is bored and wants to go home","es":"Que el guardia está aburrido y quiere irse a casa","ru":"Что охраннику скучно и он хочет домой","tr":"Görevlinin sıkıldığını ve eve gitmek istediğini","hi":"कि गार्ड ऊब गया है और घर जाना चाहता है","ar":"أن الحارس يشعر بالملل ويريد الذهاب إلى المنزل"},{"en":"That posture and alertness have nothing to do with security","es":"Que la postura y el estado de alerta no tienen nada que ver con la seguridad","ru":"Что осанка и бдительность не имеют отношения к безопасности","tr":"Duruş ve tetikte olmanın güvenlikle hiçbir ilgisi olmadığını","hi":"कि मुद्रा और सतर्कता का सुरक्षा से कोई लेना-देना नहीं","ar":"أن الوقوف واليقظة لا علاقة لهما بالأمن"},{"en":"That the guard should avoid eye contact with everyone","es":"Que el guardia debe evitar el contacto visual con todos","ru":"Что охранник должен избегать зрительного контакта со всеми","tr":"Görevlinin herkesle göz temasından kaçınması gerektiğini","hi":"कि गार्ड को सभी से आँख मिलाने से बचना चाहिए","ar":"أن على الحارس تجنّب التواصل البصري مع الجميع"}],"e":{"en":"Good posture and an alert demeanor signal that the guard is attentive and ready to act, which reassures clients and helps deter wrongdoing. A slouching or distracted guard invites problems.","es":"Una buena postura y una actitud alerta indican que el guardia está atento y listo para actuar, lo que tranquiliza a los clientes y ayuda a disuadir el delito. Un guardia encorvado o distraído invita a los problemas.","ru":"Хорошая осанка и бдительный вид показывают, что охранник внимателен и готов действовать, что успокаивает клиентов и помогает сдерживать нарушения. Сутулящийся или отвлечённый охранник провоцирует проблемы.","tr":"Dik duruş ve tetikte bir tavır, görevlinin dikkatli ve harekete hazır olduğunu gösterir; bu müşterilere güven verir ve kötü niyeti caydırmaya yardımcı olur. Kambur veya dikkati dağılmış bir görevli sorun davet eder.","hi":"अच्छी मुद्रा और सतर्क आचरण दर्शाते हैं कि गार्ड चौकस और कार्य करने को तैयार है, जिससे ग्राहकों को भरोसा मिलता है और गलत काम रुकता है। झुका हुआ या ध्यान भटका गार्ड समस्याओं को न्योता देता है।","ar":"الوقوف باعتدال والسلوك اليقظ يدلّان على أن الحارس منتبه وجاهز للتصرف، مما يطمئن العملاء ويساعد على ردع المخالفات. أما الحارس المتراخي أو المشتت فيدعو إلى المشكلات."}},{"cat":"conduct","a":3,"q":{"en":"A guard is scheduled to start a shift at 7:00 a.m. What is the most professional practice?","es":"Un guardia debe iniciar su turno a las 7:00 a.m. ¿Cuál es la práctica más profesional?","ru":"Смена охранника начинается в 7:00. Какая практика наиболее профессиональна?","tr":"Bir görevlinin vardiyası saat 07:00'de başlayacak. En profesyonel uygulama nedir?","hi":"एक गार्ड की पाली सुबह 7:00 बजे शुरू होनी है। सबसे पेशेवर अभ्यास क्या है?","ar":"من المقرر أن يبدأ حارس نوبته في الساعة 7:00 صباحًا. ما هي الممارسة الأكثر احترافية؟"},"o":[{"en":"Arrive around 7:15 a.m. since a few minutes late is normal","es":"Llegar cerca de las 7:15 a.m., ya que unos minutos de retraso son normales","ru":"Прийти около 7:15, так как опоздание на несколько минут — это нормально","tr":"07:15 civarında gelmek, çünkü birkaç dakika gecikme normaldir","hi":"लगभग 7:15 बजे आना, क्योंकि कुछ मिनट की देरी सामान्य है","ar":"الوصول حوالي 7:15 صباحًا لأن التأخر بضع دقائق أمر طبيعي"},{"en":"Arrive exactly at 7:00 a.m. and begin changing into uniform then","es":"Llegar exactamente a las 7:00 a.m. y comenzar a ponerse el uniforme entonces","ru":"Прийти ровно в 7:00 и только тогда начать переодеваться в форму","tr":"Tam 07:00'de gelmek ve o an üniforma giymeye başlamak","hi":"ठीक 7:00 बजे पहुँचना और तभी वर्दी पहनना शुरू करना","ar":"الوصول تمامًا في الساعة 7:00 والبدء حينها بارتداء الزيّ"},{"en":"Call the client the night before to ask if the shift can start later","es":"Llamar al cliente la noche anterior para preguntar si el turno puede empezar más tarde","ru":"Позвонить клиенту накануне вечером и спросить, можно ли начать смену позже","tr":"Bir gece önce müşteriyi arayıp vardiyanın daha geç başlayıp başlayamayacağını sormak","hi":"एक रात पहले ग्राहक को फोन कर पूछना कि क्या पाली देर से शुरू हो सकती है","ar":"الاتصال بالعميل في الليلة السابقة للسؤال عمّا إذا كان يمكن أن تبدأ النوبة لاحقًا"},{"en":"Arrive early, in full uniform, and be ready to take over at 7:00 a.m.","es":"Llegar temprano, con uniforme completo, y estar listo para asumir el puesto a las 7:00 a.m.","ru":"Прийти заранее, в полной форме, и быть готовым заступить на пост в 7:00","tr":"Erken gelmek, tam üniformalı olmak ve 07:00'de görevi devralmaya hazır olmak","hi":"जल्दी पहुँचना, पूरी वर्दी में, और 7:00 बजे कार्यभार संभालने को तैयार रहना","ar":"الوصول مبكرًا بالزيّ الكامل والاستعداد لتسلّم الموقع في الساعة 7:00 صباحًا"}],"e":{"en":"Being on time actually means arriving early enough to be in full uniform and ready to relieve the previous shift right at the scheduled start. Punctuality is a core mark of professionalism.","es":"Ser puntual significa en realidad llegar con suficiente antelación para estar con uniforme completo y listo para relevar el turno anterior justo a la hora de inicio. La puntualidad es una marca central del profesionalismo.","ru":"Быть пунктуальным на самом деле означает прийти достаточно рано, чтобы быть в полной форме и готовым сменить предыдущую смену точно в назначенное время начала. Пунктуальность — ключевой признак профессионализма.","tr":"Dakik olmak aslında, tam üniformalı olacak ve önceki vardiyayı planlanan başlangıç saatinde devralmaya hazır olacak kadar erken gelmek demektir. Dakiklik profesyonelliğin temel bir işaretidir.","hi":"समय पर होने का वास्तविक अर्थ है इतनी जल्दी पहुँचना कि आप पूरी वर्दी में हों और निर्धारित शुरुआत समय पर पिछली पाली से कार्यभार संभालने को तैयार हों। समयनिष्ठता पेशेवरता का मूल चिह्न है।","ar":"الالتزام بالوقت يعني فعليًا الوصول مبكرًا بما يكفي لتكون بالزيّ الكامل وجاهزًا لتسلّم المهام من النوبة السابقة في وقت البدء المحدد تمامًا. الانضباط في المواعيد علامة أساسية على الاحترافية."}},{"cat":"conduct","a":1,"q":{"en":"A friend asks a guard about the security camera locations and alarm codes at the site where the guard works. What should the guard do?","es":"Un amigo le pregunta a un guardia sobre la ubicación de las cámaras y los códigos de alarma del sitio donde trabaja. ¿Qué debe hacer el guardia?","ru":"Друг спрашивает охранника о расположении камер и кодах сигнализации на объекте, где тот работает. Что должен сделать охранник?","tr":"Bir arkadaş, görevlinin çalıştığı sahadaki güvenlik kamerası konumlarını ve alarm kodlarını sorar. Görevli ne yapmalıdır?","hi":"एक दोस्त गार्ड से उस साइट के सुरक्षा कैमरों के स्थान और अलार्म कोड के बारे में पूछता है जहाँ गार्ड काम करता है। गार्ड को क्या करना चाहिए?","ar":"يسأل صديقٌ حارسًا عن مواقع كاميرات المراقبة ورموز الإنذار في الموقع الذي يعمل فيه. ماذا يجب أن يفعل الحارس؟"},"o":[{"en":"Share the details since the person is a trusted friend","es":"Compartir los detalles ya que la persona es un amigo de confianza","ru":"Поделиться сведениями, ведь это доверенный друг","tr":"Kişi güvenilir bir arkadaş olduğu için bilgileri paylaşmak","hi":"चूँकि व्यक्ति भरोसेमंद दोस्त है, इसलिए जानकारी साझा करना","ar":"مشاركة التفاصيل لأن الشخص صديق موثوق"},{"en":"Decline to share it, because site security measures are confidential","es":"Negarse a compartirlo, porque las medidas de seguridad del sitio son confidenciales","ru":"Отказаться делиться, потому что меры безопасности объекта конфиденциальны","tr":"Paylaşmayı reddetmek, çünkü sahanın güvenlik önlemleri gizlidir","hi":"साझा करने से मना करना, क्योंकि साइट के सुरक्षा उपाय गोपनीय हैं","ar":"رفض مشاركتها، لأن تدابير أمن الموقع سرّية"},{"en":"Share only the camera locations but keep the codes secret","es":"Compartir solo la ubicación de las cámaras pero mantener los códigos en secreto","ru":"Поделиться только расположением камер, но сохранить коды в секрете","tr":"Yalnızca kamera konumlarını paylaşmak ama kodları gizli tutmak","hi":"केवल कैमरों के स्थान साझा करना पर कोड गुप्त रखना","ar":"مشاركة مواقع الكاميرات فقط مع إبقاء الرموز سرّية"},{"en":"Post the information online so it is easier to remember","es":"Publicar la información en línea para recordarla más fácilmente","ru":"Разместить информацию в интернете, чтобы легче запомнить","tr":"Hatırlaması kolay olsun diye bilgileri internette paylaşmak","hi":"जानकारी को याद रखने में आसानी के लिए ऑनलाइन पोस्ट करना","ar":"نشر المعلومات على الإنترنت لتسهيل تذكّرها"}],"e":{"en":"Details about a site's security measures are confidential and must never be shared with outsiders, even friends, because disclosure creates a serious security risk. Sensitive information is released only through proper channels.","es":"Los detalles sobre las medidas de seguridad de un sitio son confidenciales y nunca deben compartirse con personas ajenas, ni siquiera amigos, porque su divulgación crea un grave riesgo de seguridad. La información sensible se divulga solo por los canales adecuados.","ru":"Сведения о мерах безопасности объекта конфиденциальны и никогда не должны передаваться посторонним, даже друзьям, так как разглашение создаёт серьёзный риск для безопасности. Конфиденциальная информация передаётся только по надлежащим каналам.","tr":"Bir sahanın güvenlik önlemlerine ilişkin ayrıntılar gizlidir ve arkadaşlar da dâhil hiçbir yabancıyla paylaşılmamalıdır; çünkü ifşa ciddi bir güvenlik riski yaratır. Hassas bilgiler yalnızca uygun kanallardan verilir.","hi":"किसी साइट के सुरक्षा उपायों की जानकारी गोपनीय होती है और इसे बाहरी लोगों, यहाँ तक कि दोस्तों को भी कभी साझा नहीं करना चाहिए, क्योंकि इसका खुलासा गंभीर सुरक्षा जोखिम पैदा करता है। संवेदनशील जानकारी केवल उचित माध्यमों से ही दी जाती है।","ar":"تفاصيل تدابير أمن الموقع سرّية ولا يجوز مطلقًا مشاركتها مع أشخاص من الخارج، حتى الأصدقاء، لأن إفشاءها يخلق خطرًا أمنيًا جسيمًا. تُفصح المعلومات الحساسة عبر القنوات المناسبة فقط."}},{"cat":"conduct","a":2,"q":{"en":"After responding to a theft at a store, may a guard post about the incident on social media?","es":"Después de responder a un robo en una tienda, ¿puede un guardia publicar sobre el incidente en redes sociales?","ru":"После реагирования на кражу в магазине может ли охранник опубликовать сведения об инциденте в соцсетях?","tr":"Bir mağazadaki hırsızlığa müdahale ettikten sonra bir görevli olayı sosyal medyada paylaşabilir mi?","hi":"किसी दुकान में चोरी पर प्रतिक्रिया देने के बाद, क्या गार्ड घटना के बारे में सोशल मीडिया पर पोस्ट कर सकता है?","ar":"بعد الاستجابة لسرقة في متجر، هل يجوز للحارس النشر عن الحادث على وسائل التواصل الاجتماعي؟"},"o":[{"en":"Yes, as long as no names are mentioned","es":"Sí, siempre que no se mencionen nombres","ru":"Да, если не упоминаются имена","tr":"Evet, isim belirtilmediği sürece","hi":"हाँ, जब तक कोई नाम न लिखा जाए","ar":"نعم، ما دام لا يتم ذكر أسماء"},{"en":"Yes, because it shows the guard doing a good job","es":"Sí, porque muestra al guardia haciendo un buen trabajo","ru":"Да, потому что это показывает, что охранник хорошо работает","tr":"Evet, çünkü görevlinin iyi iş yaptığını gösterir","hi":"हाँ, क्योंकि यह गार्ड को अच्छा काम करते दिखाता है","ar":"نعم، لأنه يُظهر الحارس وهو يؤدي عملًا جيدًا"},{"en":"No, incident details are confidential and must not be posted publicly","es":"No, los detalles del incidente son confidenciales y no deben publicarse","ru":"Нет, детали инцидента конфиденциальны и не должны публиковаться","tr":"Hayır, olay ayrıntıları gizlidir ve kamuya açık paylaşılmamalıdır","hi":"नहीं, घटना का विवरण गोपनीय है और सार्वजनिक रूप से पोस्ट नहीं करना चाहिए","ar":"لا، تفاصيل الحادث سرّية ولا يجوز نشرها علنًا"},{"en":"No, but only if the store manager has not approved it yet","es":"No, pero solo si el gerente de la tienda aún no lo ha aprobado","ru":"Нет, но только если управляющий магазином ещё не одобрил это","tr":"Hayır, ama yalnızca mağaza müdürü henüz onaylamadıysa","hi":"नहीं, पर केवल तभी जब दुकान प्रबंधक ने अभी तक मंजूरी न दी हो","ar":"لا، لكن فقط إذا لم يوافق مدير المتجر بعد"}],"e":{"en":"Guards must never post incident details, client information, or site activity on social media; this violates confidentiality and can harm the client and expose the guard to liability. Incidents are reported only through proper internal channels.","es":"Los guardias nunca deben publicar detalles de incidentes, información del cliente ni actividad del sitio en redes sociales; esto viola la confidencialidad y puede perjudicar al cliente y exponer al guardia a responsabilidad. Los incidentes se reportan solo por canales internos adecuados.","ru":"Охранники никогда не должны публиковать в соцсетях детали инцидентов, информацию о клиенте или деятельность объекта; это нарушает конфиденциальность и может навредить клиенту и повлечь ответственность охранника. Об инцидентах сообщают только по надлежащим внутренним каналам.","tr":"Görevliler olay ayrıntılarını, müşteri bilgilerini veya saha faaliyetlerini asla sosyal medyada paylaşmamalıdır; bu gizliliği ihlal eder, müşteriye zarar verebilir ve görevliyi sorumlulukla karşı karşıya bırakır. Olaylar yalnızca uygun iç kanallardan raporlanır.","hi":"गार्ड को कभी भी घटना विवरण, ग्राहक जानकारी या साइट गतिविधि सोशल मीडिया पर पोस्ट नहीं करना चाहिए; इससे गोपनीयता का उल्लंघन होता है, ग्राहक को नुकसान हो सकता है और गार्ड पर दायित्व आ सकता है। घटनाओं की सूचना केवल उचित आंतरिक माध्यमों से दी जाती है।","ar":"يجب ألّا ينشر الحراس مطلقًا تفاصيل الحوادث أو معلومات العملاء أو نشاط الموقع على وسائل التواصل؛ فهذا ينتهك السرّية وقد يضرّ بالعميل ويعرّض الحارس للمسؤولية. تُبلَّغ الحوادث عبر القنوات الداخلية المناسبة فقط."}},{"cat":"conduct","a":0,"q":{"en":"What is the correct way for a guard to report sensitive information about an incident?","es":"¿Cuál es la forma correcta en que un guardia debe reportar información sensible sobre un incidente?","ru":"Каков правильный способ для охранника сообщать конфиденциальную информацию об инциденте?","tr":"Bir görevlinin bir olayla ilgili hassas bilgileri raporlamasının doğru yolu nedir?","hi":"किसी घटना के बारे में संवेदनशील जानकारी की सूचना देने का सही तरीका गार्ड के लिए क्या है?","ar":"ما الطريقة الصحيحة لكي يُبلّغ الحارس عن معلومات حساسة بشأن حادث؟"},"o":[{"en":"Through proper channels, such as a supervisor or written report to authorized personnel","es":"Por los canales adecuados, como un supervisor o un informe escrito al personal autorizado","ru":"По надлежащим каналам, например через руководителя или письменный отчёт уполномоченному персоналу","tr":"Amir gibi uygun kanallardan veya yetkili personele yazılı rapor yoluyla","hi":"उचित माध्यमों से, जैसे पर्यवेक्षक या अधिकृत कर्मियों को लिखित रिपोर्ट","ar":"عبر القنوات المناسبة، مثل المشرف أو تقرير مكتوب إلى الموظفين المخوّلين"},{"en":"By discussing it with customers to get their opinion","es":"Discutiéndolo con los clientes para conocer su opinión","ru":"Обсуждая это с посетителями, чтобы узнать их мнение","tr":"Görüşlerini almak için müşterilerle konuşarak","hi":"ग्राहकों से चर्चा कर उनकी राय जानकर","ar":"بمناقشته مع الزبائن لمعرفة رأيهم"},{"en":"By telling other guards from different companies","es":"Contándolo a otros guardias de diferentes empresas","ru":"Рассказывая охранникам из других компаний","tr":"Farklı şirketlerden görevlilere anlatarak","hi":"अलग कंपनियों के अन्य गार्ड को बताकर","ar":"بإخبار حراس من شركات أخرى"},{"en":"By whichever method is fastest, even a public post","es":"Por el método más rápido, incluso una publicación pública","ru":"Любым самым быстрым способом, даже публичным постом","tr":"En hızlı yöntemle, hatta kamuya açık bir paylaşımla","hi":"जो भी तरीका सबसे तेज़ हो, चाहे सार्वजनिक पोस्ट ही क्यों न हो","ar":"بأي طريقة أسرع، حتى لو كانت منشورًا علنيًا"}],"e":{"en":"Sensitive information must be reported only through proper channels—typically a supervisor and a written incident report to authorized personnel. This protects confidentiality and preserves the accuracy of the record.","es":"La información sensible debe reportarse solo por canales adecuados, normalmente un supervisor y un informe escrito de incidentes al personal autorizado. Esto protege la confidencialidad y preserva la exactitud del registro.","ru":"Конфиденциальную информацию следует сообщать только по надлежащим каналам — обычно руководителю и в письменном отчёте об инциденте уполномоченному персоналу. Это защищает конфиденциальность и сохраняет точность записи.","tr":"Hassas bilgiler yalnızca uygun kanallardan raporlanmalıdır; genellikle bir amire ve yetkili personele yazılı bir olay raporuyla. Bu, gizliliği korur ve kaydın doğruluğunu güvence altına alır.","hi":"संवेदनशील जानकारी केवल उचित माध्यमों से दी जानी चाहिए—आमतौर पर पर्यवेक्षक को और अधिकृत कर्मियों को लिखित घटना रिपोर्ट के माध्यम से। इससे गोपनीयता सुरक्षित रहती है और रिकॉर्ड की सटीकता बनी रहती है।","ar":"يجب الإبلاغ عن المعلومات الحساسة عبر القنوات المناسبة فقط — عادةً المشرف وتقرير حادث مكتوب إلى الموظفين المخوّلين. هذا يحمي السرّية ويحافظ على دقة السجل."}},{"cat":"conduct","a":3,"q":{"en":"A visitor offers a guard $100 to look the other way while they enter a restricted area. What should the guard do?","es":"Un visitante ofrece a un guardia $100 para que mire hacia otro lado mientras entra a una zona restringida. ¿Qué debe hacer el guardia?","ru":"Посетитель предлагает охраннику 100 долларов, чтобы тот отвернулся, пока он проходит в закрытую зону. Что должен сделать охранник?","tr":"Bir ziyaretçi, kısıtlı bir alana girerken görevliye başka tarafa bakması için 100 dolar teklif ediyor. Görevli ne yapmalıdır?","hi":"एक आगंतुक गार्ड को 100 डॉलर देता है ताकि वह प्रतिबंधित क्षेत्र में घुसते समय दूसरी ओर देख ले। गार्ड को क्या करना चाहिए?","ar":"يعرض زائرٌ على حارس 100 دولار كي يتغاضى بينما يدخل منطقة محظورة. ماذا يجب أن يفعل الحارس؟"},"o":[{"en":"Accept the money because it does not hurt anyone","es":"Aceptar el dinero porque no perjudica a nadie","ru":"Взять деньги, ведь это никому не вредит","tr":"Kimseye zarar vermediği için parayı kabul etmek","hi":"पैसे ले लेना क्योंकि इससे किसी को नुकसान नहीं","ar":"قبول المال لأنه لا يضرّ أحدًا"},{"en":"Take the money but still deny entry, keeping both","es":"Tomar el dinero pero igual negar la entrada, quedándose con ambos","ru":"Взять деньги, но всё равно не пустить, оставив и то и другое","tr":"Parayı almak ama yine de girişi reddedip her ikisini de elde tutmak","hi":"पैसे ले लेना पर फिर भी प्रवेश न देना, दोनों रखते हुए","ar":"أخذ المال ومع ذلك منع الدخول، بحيث يحتفظ بالاثنين"},{"en":"Negotiate for a higher amount before deciding","es":"Negociar una cantidad mayor antes de decidir","ru":"Поторговаться о большей сумме, прежде чем решать","tr":"Karar vermeden önce daha yüksek bir miktar için pazarlık etmek","hi":"निर्णय से पहले बड़ी राशि के लिए मोलभाव करना","ar":"التفاوض على مبلغ أكبر قبل اتخاذ القرار"},{"en":"Refuse the bribe, deny entry, and report the attempt to a supervisor","es":"Rechazar el soborno, negar la entrada y reportar el intento a un supervisor","ru":"Отказаться от взятки, не пустить и сообщить о попытке руководителю","tr":"Rüşveti reddetmek, girişi engellemek ve girişimi bir amire bildirmek","hi":"रिश्वत ठुकराना, प्रवेश न देना और प्रयास की सूचना पर्यवेक्षक को देना","ar":"رفض الرشوة، ومنع الدخول، والإبلاغ عن المحاولة إلى المشرف"}],"e":{"en":"Accepting a bribe is a serious breach of integrity that compromises the guard's duty and can be a crime. The guard must refuse, deny access, and report the bribery attempt through proper channels.","es":"Aceptar un soborno es una grave falta de integridad que compromete el deber del guardia y puede ser un delito. El guardia debe rechazarlo, negar el acceso y reportar el intento de soborno por los canales adecuados.","ru":"Принятие взятки — серьёзное нарушение честности, которое компрометирует обязанности охранника и может быть преступлением. Охранник должен отказаться, не пустить и сообщить о попытке подкупа по надлежащим каналам.","tr":"Rüşvet almak, görevlinin görevini tehlikeye atan ciddi bir dürüstlük ihlalidir ve suç olabilir. Görevli reddetmeli, girişi engellemeli ve rüşvet girişimini uygun kanallardan bildirmelidir.","hi":"रिश्वत लेना ईमानदारी का गंभीर उल्लंघन है जो गार्ड के कर्तव्य से समझौता करता है और अपराध हो सकता है। गार्ड को इनकार करना चाहिए, प्रवेश नहीं देना चाहिए और रिश्वत के प्रयास की सूचना उचित माध्यमों से देनी चाहिए।","ar":"قبول الرشوة انتهاك خطير للنزاهة يعرّض واجب الحارس للخطر وقد يكون جريمة. على الحارس أن يرفض ويمنع الدخول ويبلّغ عن محاولة الرشوة عبر القنوات المناسبة."}},{"cat":"conduct","a":1,"q":{"en":"A guard realizes they made a mistake in a logbook entry earlier in the shift. What is the ethical response?","es":"Un guardia se da cuenta de que cometió un error en una anotación del registro antes en el turno. ¿Cuál es la respuesta ética?","ru":"Охранник понимает, что ранее в течение смены допустил ошибку в записи журнала. Каков этичный ответ?","tr":"Bir görevli, vardiyanın başında kayıt defterine yaptığı bir girişte hata yaptığını fark eder. Etik davranış nedir?","hi":"एक गार्ड को पता चलता है कि उसने पाली में पहले लॉगबुक प्रविष्टि में गलती की थी। नैतिक प्रतिक्रिया क्या है?","ar":"يدرك حارسٌ أنه ارتكب خطأً في تدوينة بسجل الدوام في وقت سابق من النوبة. ما هو التصرف الأخلاقي؟"},"o":[{"en":"Erase or hide the entry so no one notices the error","es":"Borrar u ocultar la anotación para que nadie note el error","ru":"Стереть или скрыть запись, чтобы никто не заметил ошибку","tr":"Kimse hatayı fark etmesin diye girişi silmek veya gizlemek","hi":"प्रविष्टि मिटा देना या छिपा देना ताकि किसी को गलती न दिखे","ar":"محو التدوينة أو إخفاؤها كي لا يلاحظ أحد الخطأ"},{"en":"Correct it honestly per procedure and report the error to a supervisor","es":"Corregirlo honestamente según el procedimiento y reportar el error a un supervisor","ru":"Честно исправить по процедуре и сообщить об ошибке руководителю","tr":"Prosedüre göre dürüstçe düzeltmek ve hatayı bir amire bildirmek","hi":"प्रक्रिया के अनुसार ईमानदारी से सुधारना और गलती की सूचना पर्यवेक्षक को देना","ar":"تصحيحها بأمانة وفق الإجراء والإبلاغ عن الخطأ إلى المشرف"},{"en":"Ignore it, since small mistakes do not matter","es":"Ignorarlo, ya que los errores pequeños no importan","ru":"Проигнорировать, ведь мелкие ошибки не важны","tr":"Görmezden gelmek, çünkü küçük hatalar önemli değildir","hi":"अनदेखा करना, क्योंकि छोटी गलतियों से फर्क नहीं पड़ता","ar":"تجاهلها، لأن الأخطاء الصغيرة لا تهم"},{"en":"Blame the previous shift for the error","es":"Culpar al turno anterior por el error","ru":"Свалить ошибку на предыдущую смену","tr":"Hatayı önceki vardiyaya yıkmak","hi":"गलती के लिए पिछली पाली को दोष देना","ar":"إلقاء اللوم في الخطأ على النوبة السابقة"}],"e":{"en":"Integrity requires correcting the error using the proper procedure—usually a single line through the mistake, the correction initialed—and reporting it. Altering or hiding records destroys their credibility and is dishonest.","es":"La integridad exige corregir el error con el procedimiento adecuado —normalmente una sola línea sobre el error y la corrección con iniciales— y reportarlo. Alterar u ocultar registros destruye su credibilidad y es deshonesto.","ru":"Честность требует исправить ошибку по надлежащей процедуре — обычно одной чертой через ошибку с инициалами исправления — и сообщить о ней. Изменение или сокрытие записей уничтожает их достоверность и является нечестным.","tr":"Dürüstlük, hatanın uygun prosedürle düzeltilmesini —genellikle hatanın üzerine tek çizgi çekilip düzeltmenin paraflanması— ve bildirilmesini gerektirir. Kayıtları değiştirmek veya gizlemek güvenilirliklerini yok eder ve dürüst değildir.","hi":"ईमानदारी के लिए गलती को उचित प्रक्रिया से सुधारना ज़रूरी है—आमतौर पर गलती पर एक ही लाइन खींचना और सुधार पर आद्याक्षर—और उसकी सूचना देना। रिकॉर्ड बदलना या छिपाना उनकी विश्वसनीयता नष्ट करता है और बेईमानी है।","ar":"تتطلب النزاهة تصحيح الخطأ بالإجراء الصحيح — عادةً بخط واحد فوق الخطأ مع توقيع التصحيح بالأحرف الأولى — والإبلاغ عنه. تعديل السجلات أو إخفاؤها يدمّر مصداقيتها ويُعدّ عدم أمانة."}},{"cat":"conduct","a":2,"q":{"en":"Which behavior is a conflict of interest or misuse of a guard's position?","es":"¿Cuál conducta constituye un conflicto de interés o un mal uso del cargo de un guardia?","ru":"Какое поведение является конфликтом интересов или злоупотреблением положением охранника?","tr":"Hangi davranış çıkar çatışması veya görevlinin konumunun kötüye kullanımıdır?","hi":"कौन-सा व्यवहार हितों का टकराव या गार्ड के पद का दुरुपयोग है?","ar":"أيّ سلوك يُعدّ تضاربًا في المصالح أو إساءة استخدام لمنصب الحارس؟"},"o":[{"en":"Following post orders exactly as written","es":"Seguir las órdenes del puesto exactamente como están escritas","ru":"Точное соблюдение инструкций поста, как они написаны","tr":"Görev talimatlarını yazıldığı gibi tam olarak uygulamak","hi":"चौकी आदेशों का ठीक वैसे ही पालन करना जैसे लिखे हैं","ar":"اتّباع تعليمات الموقع تمامًا كما هي مكتوبة"},{"en":"Reporting a safety hazard to a supervisor","es":"Reportar un peligro de seguridad a un supervisor","ru":"Сообщение руководителю об угрозе безопасности","tr":"Bir güvenlik tehlikesini bir amire bildirmek","hi":"किसी सुरक्षा खतरे की सूचना पर्यवेक्षक को देना","ar":"الإبلاغ عن خطر يتعلق بالسلامة إلى المشرف"},{"en":"Using the guard position to give a relative special access or favors","es":"Usar el cargo de guardia para dar a un pariente acceso especial o favores","ru":"Использование должности охранника, чтобы дать родственнику особый доступ или поблажки","tr":"Görevli konumunu bir akrabaya özel erişim veya ayrıcalık sağlamak için kullanmak","hi":"किसी रिश्तेदार को विशेष पहुँच या रियायत देने के लिए गार्ड पद का उपयोग","ar":"استخدام منصب الحارس لمنح قريب دخولًا خاصًا أو محاباة"},{"en":"Asking a supervisor a question when a rule is unclear","es":"Preguntar a un supervisor cuando una regla no está clara","ru":"Задать руководителю вопрос, когда правило неясно","tr":"Bir kural belirsiz olduğunda amire soru sormak","hi":"नियम अस्पष्ट होने पर पर्यवेक्षक से प्रश्न पूछना","ar":"سؤال المشرف عندما تكون قاعدة ما غير واضحة"}],"e":{"en":"Using the position to grant favors, special access, or favoritism to friends or relatives is a conflict of interest that undermines fairness and security. Guards must apply rules impartially to everyone.","es":"Usar el cargo para conceder favores, acceso especial o favoritismo a amigos o parientes es un conflicto de interés que socava la imparcialidad y la seguridad. Los guardias deben aplicar las reglas de forma imparcial a todos.","ru":"Использование должности для оказания услуг, особого доступа или фаворитизма друзьям или родственникам — это конфликт интересов, подрывающий справедливость и безопасность. Охранники должны применять правила беспристрастно ко всем.","tr":"Konumu, arkadaşlara veya akrabalara iyilik, özel erişim ya da kayırma sağlamak için kullanmak, adaleti ve güvenliği zedeleyen bir çıkar çatışmasıdır. Görevliler kuralları herkese tarafsızca uygulamalıdır.","hi":"पद का उपयोग दोस्तों या रिश्तेदारों को एहसान, विशेष पहुँच या पक्षपात देने के लिए करना हितों का टकराव है जो निष्पक्षता और सुरक्षा को कमज़ोर करता है। गार्ड को सभी पर नियम निष्पक्ष रूप से लागू करने चाहिए।","ar":"استخدام المنصب لمنح المحاباة أو الدخول الخاص أو التمييز للأصدقاء أو الأقارب هو تضارب في المصالح يقوّض العدالة والأمن. يجب على الحراس تطبيق القواعد بحياد على الجميع."}},{"cat":"conduct","a":0,"q":{"en":"While on duty during a slow overnight shift, may a guard sleep or run a personal side business?","es":"Durante un turno nocturno tranquilo, ¿puede un guardia dormir o manejar un negocio personal?","ru":"Во время спокойной ночной смены может ли охранник спать или вести личный побочный бизнес?","tr":"Sakin bir gece vardiyasında görevli uyuyabilir mi ya da kişisel bir yan iş yürütebilir mi?","hi":"धीमी रात की पाली के दौरान, क्या गार्ड सो सकता है या निजी साइड बिज़नेस चला सकता है?","ar":"أثناء نوبة ليلية هادئة، هل يجوز للحارس أن ينام أو يدير عملًا شخصيًا جانبيًا؟"},"o":[{"en":"No, guards must stay awake, alert, and focused only on their security duties","es":"No, los guardias deben permanecer despiertos, alertas y enfocados solo en sus deberes de seguridad","ru":"Нет, охранники должны бодрствовать, быть бдительными и сосредоточенными только на своих охранных обязанностях","tr":"Hayır, görevliler uyanık, tetikte ve yalnızca güvenlik görevlerine odaklanmış kalmalıdır","hi":"नहीं, गार्ड को जागते, सतर्क और केवल अपने सुरक्षा कर्तव्यों पर केंद्रित रहना चाहिए","ar":"لا، يجب أن يظل الحراس مستيقظين ومتيقظين ومركّزين على مهام الأمن فقط"},{"en":"Yes, as long as nothing happens during the shift","es":"Sí, siempre que no ocurra nada durante el turno","ru":"Да, если за смену ничего не произойдёт","tr":"Evet, vardiya boyunca bir şey olmadığı sürece","hi":"हाँ, जब तक पाली के दौरान कुछ न हो","ar":"نعم، ما دام لا يحدث شيء خلال النوبة"},{"en":"Yes, sleeping is fine if the guard sets an alarm","es":"Sí, dormir está bien si el guardia pone una alarma","ru":"Да, спать можно, если охранник поставит будильник","tr":"Evet, görevli alarm kurarsa uyumak sorun değildir","hi":"हाँ, सोना ठीक है अगर गार्ड अलार्म लगा ले","ar":"نعم، النوم مقبول إذا ضبط الحارس منبّهًا"},{"en":"Yes, a side business is allowed as long as it stays quiet","es":"Sí, se permite un negocio personal siempre que sea silencioso","ru":"Да, побочный бизнес разрешён, если он тихий","tr":"Evet, sessiz kaldığı sürece yan işe izin verilir","hi":"हाँ, साइड बिज़नेस की अनुमति है जब तक वह शांत रहे","ar":"نعم، يُسمح بعمل جانبي ما دام هادئًا"}],"e":{"en":"Sleeping or conducting personal business on duty is prohibited because it means the site is unprotected and defeats the purpose of the post. Guards are paid to remain awake, alert, and fully attentive.","es":"Dormir o hacer negocios personales en servicio está prohibido porque deja el sitio sin protección y anula el propósito del puesto. A los guardias se les paga para permanecer despiertos, alertas y plenamente atentos.","ru":"Спать или заниматься личными делами на дежурстве запрещено, потому что объект остаётся без защиты и теряется смысл поста. Охранникам платят за то, чтобы они бодрствовали, были бдительны и полностью внимательны.","tr":"Görev başında uyumak veya kişisel işlerle uğraşmak yasaktır; çünkü saha korumasız kalır ve görevin amacı boşa çıkar. Görevliler uyanık, tetikte ve tümüyle dikkatli kalmak için maaş alır.","hi":"ड्यूटी पर सोना या निजी काम करना निषिद्ध है क्योंकि इससे साइट असुरक्षित रहती है और चौकी का उद्देश्य विफल हो जाता है। गार्ड को जागते, सतर्क और पूरी तरह चौकस रहने के लिए वेतन मिलता है।","ar":"النوم أو مزاولة أعمال شخصية أثناء الدوام أمر محظور لأنه يترك الموقع بلا حماية ويُبطل الغرض من الموقع. يتقاضى الحراس أجرهم ليبقوا مستيقظين ومتيقظين ومنتبهين تمامًا."}},{"cat":"conduct","a":3,"q":{"en":"An upset person is shouting at a guard about being denied entry. Which is the best de-escalation approach?","es":"Una persona molesta le grita a un guardia por haberle negado la entrada. ¿Cuál es el mejor enfoque de desescalada?","ru":"Раздражённый человек кричит на охранника из-за отказа во входе. Какой подход к деэскалации лучший?","tr":"Öfkeli bir kişi, girişine izin verilmediği için görevliye bağırıyor. En iyi gerginlik azaltma yaklaşımı hangisidir?","hi":"प्रवेश से मना किए जाने पर एक परेशान व्यक्ति गार्ड पर चिल्ला रहा है। तनाव कम करने का सबसे अच्छा तरीका कौन-सा है?","ar":"شخصٌ مستاء يصرخ في وجه حارس بسبب منعه من الدخول. ما أفضل أسلوب لتهدئة الموقف؟"},"o":[{"en":"Shout back louder to show who is in charge","es":"Gritar más fuerte para mostrar quién manda","ru":"Кричать в ответ громче, чтобы показать, кто главный","tr":"Kimin yetkili olduğunu göstermek için daha yüksek sesle bağırmak","hi":"यह दिखाने के लिए और ज़ोर से चिल्लाना कि कौन प्रभारी है","ar":"الصراخ بصوت أعلى لإظهار من هو المسؤول"},{"en":"Threaten to have the person arrested immediately","es":"Amenazar con hacer arrestar a la persona de inmediato","ru":"Пригрозить немедленно арестовать человека","tr":"Kişiyi hemen tutuklatmakla tehdit etmek","hi":"व्यक्ति को तुरंत गिरफ्तार कराने की धमकी देना","ar":"التهديد باعتقال الشخص فورًا"},{"en":"Turn away and ignore the person until they calm down","es":"Darse la vuelta e ignorar a la persona hasta que se calme","ru":"Отвернуться и игнорировать человека, пока он не успокоится","tr":"Sırtını dönüp kişi sakinleşene kadar görmezden gelmek","hi":"मुँह फेर लेना और व्यक्ति के शांत होने तक अनदेखा करना","ar":"الابتعاد وتجاهل الشخص حتى يهدأ"},{"en":"Stay calm, use a calm voice and non-threatening body language, and listen","es":"Mantener la calma, usar una voz tranquila y lenguaje corporal no amenazante, y escuchar","ru":"Сохранять спокойствие, говорить спокойным голосом, использовать неугрожающий язык тела и слушать","tr":"Sakin kalmak, sakin bir ses ve tehditkâr olmayan beden dili kullanmak ve dinlemek","hi":"शांत रहना, शांत आवाज़ और गैर-धमकी भरी शारीरिक भाषा का उपयोग करना, और सुनना","ar":"البقاء هادئًا واستخدام نبرة صوت هادئة ولغة جسد غير مهدِّدة والإنصات"}],"e":{"en":"De-escalation means staying calm, speaking in a calm voice, using non-threatening body language, and actively listening to reduce tension. Shouting, threats, or ignoring the person tends to make the situation worse.","es":"La desescalada significa mantener la calma, hablar con voz tranquila, usar lenguaje corporal no amenazante y escuchar activamente para reducir la tensión. Gritar, amenazar o ignorar a la persona tiende a empeorar la situación.","ru":"Деэскалация означает сохранять спокойствие, говорить спокойным голосом, использовать неугрожающий язык тела и активно слушать, чтобы снизить напряжение. Крик, угрозы или игнорирование обычно только ухудшают ситуацию.","tr":"Gerginliği azaltmak, sakin kalmak, sakin bir sesle konuşmak, tehditkâr olmayan beden dili kullanmak ve gerginliği düşürmek için etkin dinlemek demektir. Bağırmak, tehdit etmek ya da kişiyi görmezden gelmek durumu genellikle kötüleştirir.","hi":"तनाव कम करने का अर्थ है शांत रहना, शांत आवाज़ में बोलना, गैर-धमकी भरी शारीरिक भाषा का उपयोग करना, और तनाव घटाने के लिए सक्रिय रूप से सुनना। चिल्लाना, धमकाना या व्यक्ति को अनदेखा करना स्थिति को अक्सर बिगाड़ देता है।","ar":"تهدئة التصعيد تعني البقاء هادئًا والتحدث بنبرة هادئة واستخدام لغة جسد غير مهدِّدة والإنصات الفعّال لتقليل التوتر. أما الصراخ أو التهديد أو تجاهل الشخص فيميل إلى جعل الموقف أسوأ."}},{"cat":"conduct","a":1,"q":{"en":"Why should a guard give an agitated person some physical space during a confrontation?","es":"¿Por qué debe un guardia dar cierto espacio físico a una persona agitada durante una confrontación?","ru":"Почему охранник должен дать взволнованному человеку немного физического пространства во время конфликта?","tr":"Bir görevli, bir çatışma sırasında tedirgin bir kişiye neden biraz fiziksel alan tanımalıdır?","hi":"टकराव के दौरान गार्ड को उत्तेजित व्यक्ति को कुछ शारीरिक स्थान क्यों देना चाहिए?","ar":"لماذا ينبغي للحارس أن يمنح شخصًا منفعلًا بعض المساحة الجسدية أثناء المواجهة؟"},"o":[{"en":"Because the law prohibits standing near an angry person","es":"Porque la ley prohíbe pararse cerca de una persona enojada","ru":"Потому что закон запрещает стоять рядом с рассерженным человеком","tr":"Çünkü yasa, öfkeli bir kişinin yanında durmayı yasaklar","hi":"क्योंकि कानून गुस्साए व्यक्ति के पास खड़े होने से रोकता है","ar":"لأن القانون يمنع الوقوف قرب شخص غاضب"},{"en":"Crowding a person can feel threatening and escalate their anger","es":"Acorralar a una persona puede sentirse amenazante y aumentar su ira","ru":"Слишком близкое приближение может ощущаться как угроза и усилить гнев","tr":"Kişiye çok yaklaşmak tehditkâr hissettirebilir ve öfkesini artırabilir","hi":"किसी के बहुत करीब जाना धमकी भरा लग सकता है और उसका गुस्सा बढ़ा सकता है","ar":"الاقتراب الشديد من الشخص قد يُشعره بالتهديد ويزيد غضبه"},{"en":"So the guard can quietly walk away and abandon the post","es":"Para que el guardia pueda alejarse en silencio y abandonar el puesto","ru":"Чтобы охранник мог тихо уйти и покинуть пост","tr":"Görevlinin sessizce uzaklaşıp görev yerini terk edebilmesi için","hi":"ताकि गार्ड चुपचाप हटकर चौकी छोड़ सके","ar":"لكي يبتعد الحارس بهدوء ويترك موقعه"},{"en":"Because personal space has no effect on tense situations","es":"Porque el espacio personal no tiene efecto en situaciones tensas","ru":"Потому что личное пространство не влияет на напряжённые ситуации","tr":"Çünkü kişisel alanın gergin durumlara etkisi yoktur","hi":"क्योंकि व्यक्तिगत स्थान का तनावपूर्ण स्थितियों पर कोई असर नहीं","ar":"لأن المساحة الشخصية لا تؤثر في المواقف المتوترة"}],"e":{"en":"Standing too close can feel threatening and provoke a person who is already upset, so giving reasonable space helps lower tension and keeps both parties safer. Space is a key de-escalation tool.","es":"Estar demasiado cerca puede sentirse amenazante y provocar a una persona ya alterada, así que dar un espacio razonable ayuda a bajar la tensión y mantiene a ambas partes más seguras. El espacio es una herramienta clave de desescalada.","ru":"Слишком близкое присутствие может восприниматься как угроза и провоцировать уже раздражённого человека, поэтому разумная дистанция помогает снизить напряжение и обезопасить обе стороны. Пространство — ключевой инструмент деэскалации.","tr":"Çok yakın durmak tehditkâr hissettirebilir ve zaten öfkeli bir kişiyi kışkırtabilir; bu yüzden makul bir alan tanımak gerginliği düşürmeye ve iki tarafı da daha güvende tutmaya yardımcı olur. Alan, gerginliği azaltmanın önemli bir aracıdır.","hi":"बहुत करीब खड़ा होना धमकी भरा लग सकता है और पहले से परेशान व्यक्ति को उकसा सकता है, इसलिए उचित स्थान देने से तनाव घटता है और दोनों पक्ष अधिक सुरक्षित रहते हैं। स्थान तनाव कम करने का एक प्रमुख उपकरण है।","ar":"الوقوف قريبًا جدًا قد يُشعر بالتهديد ويستفزّ شخصًا منفعلًا أصلًا، لذا فإن منح مساحة معقولة يساعد على خفض التوتر ويبقي الطرفين أكثر أمانًا. المساحة أداة أساسية لتهدئة التصعيد."}},{"cat":"conduct","a":2,"q":{"en":"In handling a tense encounter, which order of actions does a professional guard follow?","es":"Al manejar un encuentro tenso, ¿qué orden de acciones sigue un guardia profesional?","ru":"При урегулировании напряжённой ситуации какой порядок действий соблюдает профессиональный охранник?","tr":"Gergin bir karşılaşmayı yönetirken profesyonel bir görevli hangi eylem sırasını izler?","hi":"तनावपूर्ण स्थिति को संभालते समय, एक पेशेवर गार्ड क्रियाओं का कौन-सा क्रम अपनाता है?","ar":"عند التعامل مع موقف متوتر، ما ترتيب الإجراءات الذي يتبعه الحارس المحترف؟"},"o":[{"en":"Use physical force first, then talk if it fails","es":"Usar la fuerza física primero y luego hablar si falla","ru":"Сначала применить физическую силу, а потом говорить, если не сработало","tr":"Önce fiziksel güç kullanmak, işe yaramazsa konuşmak","hi":"पहले शारीरिक बल का उपयोग करना, फिर विफल होने पर बात करना","ar":"استخدام القوة الجسدية أولًا ثم الحديث إن فشلت"},{"en":"Ignore the situation and wait for it to resolve itself","es":"Ignorar la situación y esperar a que se resuelva sola","ru":"Игнорировать ситуацию и ждать, пока она разрешится сама","tr":"Durumu görmezden gelip kendiliğinden çözülmesini beklemek","hi":"स्थिति को अनदेखा करना और उसके अपने आप सुलझने की प्रतीक्षा करना","ar":"تجاهل الموقف وانتظار أن يحلّ نفسه"},{"en":"Try verbal communication and de-escalation before considering any physical response","es":"Intentar la comunicación verbal y la desescalada antes de considerar cualquier respuesta física","ru":"Сначала попробовать словесное общение и деэскалацию, прежде чем рассматривать физические меры","tr":"Herhangi bir fiziksel müdahaleyi düşünmeden önce sözlü iletişimi ve gerginlik azaltmayı denemek","hi":"किसी शारीरिक प्रतिक्रिया पर विचार करने से पहले मौखिक संवाद और तनाव कम करना आज़माना","ar":"تجربة التواصل اللفظي وتهدئة التصعيد قبل التفكير في أي رد جسدي"},{"en":"Call for backup only after the confrontation is over","es":"Pedir refuerzos solo después de que termine la confrontación","ru":"Вызвать подкрепление только после окончания конфликта","tr":"Yalnızca çatışma bittikten sonra destek çağırmak","hi":"टकराव समाप्त होने के बाद ही बैकअप बुलाना","ar":"طلب الدعم فقط بعد انتهاء المواجهة"}],"e":{"en":"Verbal skills and de-escalation should always be tried first; physical force is a last resort, used only when necessary and within legal limits. Talking down a situation is safer for everyone and reduces liability.","es":"Las habilidades verbales y la desescalada deben intentarse siempre primero; la fuerza física es el último recurso, usada solo cuando es necesaria y dentro de los límites legales. Calmar una situación con palabras es más seguro para todos y reduce la responsabilidad.","ru":"Словесные навыки и деэскалацию всегда следует применять в первую очередь; физическая сила — крайняя мера, применяемая только при необходимости и в рамках закона. Урегулирование словами безопаснее для всех и снижает ответственность.","tr":"Önce her zaman sözlü beceriler ve gerginlik azaltma denenmelidir; fiziksel güç son çaredir ve yalnızca gerektiğinde ve yasal sınırlar içinde kullanılır. Bir durumu konuşarak yatıştırmak herkes için daha güvenlidir ve sorumluluğu azaltır.","hi":"मौखिक कौशल और तनाव कम करने को हमेशा पहले आज़माना चाहिए; शारीरिक बल अंतिम उपाय है, केवल आवश्यक होने पर और कानूनी सीमाओं के भीतर उपयोग किया जाता है। बातचीत से स्थिति शांत करना सबके लिए सुरक्षित है और दायित्व घटाता है।","ar":"ينبغي دائمًا تجربة المهارات اللفظية وتهدئة التصعيد أولًا؛ والقوة الجسدية ملاذ أخير لا يُلجأ إليه إلا عند الضرورة وضمن الحدود القانونية. تهدئة الموقف بالكلام أكثر أمانًا للجميع ويقلّل المسؤولية."}},{"cat":"conduct","a":0,"q":{"en":"How should a guard treat people of different races, religions, and nationalities?","es":"¿Cómo debe tratar un guardia a personas de diferentes razas, religiones y nacionalidades?","ru":"Как охранник должен обращаться с людьми разных рас, религий и национальностей?","tr":"Bir görevli farklı ırk, din ve milliyetlerden insanlara nasıl davranmalıdır?","hi":"गार्ड को विभिन्न नस्लों, धर्मों और राष्ट्रीयताओं के लोगों के साथ कैसा व्यवहार करना चाहिए?","ar":"كيف ينبغي للحارس أن يعامل الأشخاص من مختلف الأعراق والأديان والجنسيات؟"},"o":[{"en":"With equal respect and impartiality, regardless of their background","es":"Con igual respeto e imparcialidad, sin importar su origen","ru":"С равным уважением и беспристрастностью, независимо от их происхождения","tr":"Geçmişlerine bakılmaksızın eşit saygı ve tarafsızlıkla","hi":"उनकी पृष्ठभूमि की परवाह किए बिना समान सम्मान और निष्पक्षता के साथ","ar":"باحترام متساوٍ وحياد، بغضّ النظر عن خلفياتهم"},{"en":"With extra suspicion toward those who look or dress differently","es":"Con mayor sospecha hacia quienes se ven o visten diferente","ru":"С повышенной подозрительностью к тем, кто выглядит или одевается иначе","tr":"Farklı görünen veya giyinen kişilere karşı fazladan şüpheyle","hi":"जो अलग दिखते या कपड़े पहनते हैं उनके प्रति अतिरिक्त संदेह के साथ","ar":"بمزيد من الشك تجاه من يبدون أو يلبسون بشكل مختلف"},{"en":"By giving preference to people from the guard's own background","es":"Dando preferencia a las personas del mismo origen que el guardia","ru":"Отдавая предпочтение людям того же происхождения, что и охранник","tr":"Görevliyle aynı geçmişten gelen kişilere öncelik vererek","hi":"गार्ड की अपनी पृष्ठभूमि के लोगों को वरीयता देकर","ar":"بإعطاء الأفضلية لمن هم من خلفية الحارس نفسه"},{"en":"By avoiding contact with anyone who speaks another language","es":"Evitando el contacto con cualquiera que hable otro idioma","ru":"Избегая контакта со всеми, кто говорит на другом языке","tr":"Başka bir dil konuşan herkesle temastan kaçınarak","hi":"किसी भी अन्य भाषा बोलने वाले से संपर्क से बचकर","ar":"بتجنّب التعامل مع أي شخص يتحدث لغة أخرى"}],"e":{"en":"Guards must treat everyone with equal respect and impartiality, without bias or profiling based on race, religion, or nationality. Fair, professional treatment of all people is both ethical and legally required.","es":"Los guardias deben tratar a todos con igual respeto e imparcialidad, sin prejuicios ni perfilamiento por raza, religión o nacionalidad. El trato justo y profesional a todas las personas es tanto ético como exigido por la ley.","ru":"Охранники должны обращаться со всеми с равным уважением и беспристрастностью, без предвзятости и профилирования по расе, религии или национальности. Справедливое, профессиональное обращение со всеми людьми и этично, и требуется законом.","tr":"Görevliler herkese eşit saygı ve tarafsızlıkla davranmalı; ırk, din veya milliyete dayalı önyargı ya da profilleme yapmamalıdır. Tüm insanlara adil ve profesyonel davranmak hem etik hem de yasal bir zorunluluktur.","hi":"गार्ड को सभी के साथ समान सम्मान और निष्पक्षता से व्यवहार करना चाहिए, नस्ल, धर्म या राष्ट्रीयता के आधार पर पूर्वाग्रह या प्रोफाइलिंग के बिना। सभी लोगों के साथ निष्पक्ष, पेशेवर व्यवहार नैतिक भी है और कानूनन आवश्यक भी।","ar":"يجب على الحراس معاملة الجميع باحترام متساوٍ وحياد، دون تحيّز أو تنميط على أساس العرق أو الدين أو الجنسية. المعاملة العادلة والمهنية لجميع الأشخاص واجب أخلاقي وقانوني معًا."}},{"cat":"conduct","a":3,"q":{"en":"A guard notices that a visitor from another culture avoids direct eye contact. How should the guard interpret this?","es":"Un guardia nota que un visitante de otra cultura evita el contacto visual directo. ¿Cómo debe interpretarlo?","ru":"Охранник замечает, что посетитель из другой культуры избегает прямого зрительного контакта. Как это следует истолковать?","tr":"Bir görevli, başka bir kültürden bir ziyaretçinin doğrudan göz temasından kaçındığını fark eder. Bunu nasıl yorumlamalıdır?","hi":"एक गार्ड देखता है कि दूसरी संस्कृति का एक आगंतुक सीधे आँख मिलाने से बचता है। गार्ड को इसे कैसे समझना चाहिए?","ar":"يلاحظ حارسٌ أن زائرًا من ثقافة أخرى يتجنّب التواصل البصري المباشر. كيف ينبغي أن يفسّر ذلك؟"},"o":[{"en":"As certain proof the person is lying and hiding something","es":"Como prueba segura de que la persona miente y oculta algo","ru":"Как верное доказательство того, что человек лжёт и что-то скрывает","tr":"Kişinin yalan söylediğinin ve bir şey sakladığının kesin kanıtı olarak","hi":"इसे पक्के सबूत के रूप में कि व्यक्ति झूठ बोल रहा है और कुछ छिपा रहा है","ar":"كدليل قاطع على أن الشخص يكذب ويخفي شيئًا"},{"en":"As a sign the person must be removed from the property","es":"Como señal de que la persona debe ser retirada de la propiedad","ru":"Как признак того, что человека нужно удалить с территории","tr":"Kişinin mülkten çıkarılması gerektiğinin işareti olarak","hi":"इसे संकेत के रूप में कि व्यक्ति को संपत्ति से हटाया जाना चाहिए","ar":"كإشارة إلى وجوب إخراج الشخص من الممتلكات"},{"en":"As a reason to speak to the person more harshly","es":"Como razón para hablarle a la persona con más dureza","ru":"Как повод говорить с человеком более резко","tr":"Kişiye daha sert konuşmak için bir gerekçe olarak","hi":"इसे व्यक्ति से अधिक कठोरता से बात करने के कारण के रूप में","ar":"كسبب للتحدث إلى الشخص بقسوة أكبر"},{"en":"As possibly a cultural norm, not automatically a sign of guilt","es":"Como posiblemente una norma cultural, no automáticamente una señal de culpa","ru":"Как, возможно, культурную норму, а не автоматический признак вины","tr":"Otomatik olarak suçluluk işareti değil, muhtemel bir kültürel norm olarak","hi":"संभवतः एक सांस्कृतिक मानदंड के रूप में, स्वतः अपराध का संकेत नहीं","ar":"كعُرف ثقافي محتمل، وليس دليلًا تلقائيًا على الذنب"}],"e":{"en":"In many cultures, avoiding direct eye contact is a sign of respect, not deception, so a guard must not assume guilt from it. Cultural awareness prevents unfair profiling and misjudgment.","es":"En muchas culturas, evitar el contacto visual directo es señal de respeto, no de engaño, así que un guardia no debe suponer culpa por ello. La conciencia cultural evita el perfilamiento injusto y los malos juicios.","ru":"Во многих культурах избегание прямого зрительного контакта — знак уважения, а не обмана, поэтому охранник не должен делать из этого вывод о вине. Культурная осведомлённость предотвращает несправедливое профилирование и ошибочные суждения.","tr":"Birçok kültürde doğrudan göz temasından kaçınmak aldatma değil saygı işaretidir; bu yüzden görevli bundan suçluluk çıkarmamalıdır. Kültürel farkındalık, haksız profilleme ve yanlış yargıyı önler.","hi":"कई संस्कृतियों में सीधे आँख मिलाने से बचना सम्मान का संकेत है, धोखे का नहीं, इसलिए गार्ड को इससे अपराध नहीं मान लेना चाहिए। सांस्कृतिक जागरूकता अनुचित प्रोफाइलिंग और गलत निर्णय को रोकती है।","ar":"في كثير من الثقافات، يُعدّ تجنّب التواصل البصري المباشر علامة احترام لا خداع، لذا يجب ألّا يفترض الحارس الذنب منه. الوعي الثقافي يمنع التنميط غير العادل وسوء التقدير."}},{"cat":"conduct","a":1,"q":{"en":"A guard feels unfit for duty after taking medication that causes drowsiness. What is the correct action?","es":"Un guardia se siente no apto para el servicio tras tomar un medicamento que causa somnolencia. ¿Cuál es la acción correcta?","ru":"Охранник чувствует себя непригодным к службе после приёма лекарства, вызывающего сонливость. Каково правильное действие?","tr":"Bir görevli, uyuşukluk yapan bir ilaç aldıktan sonra görev için uygun olmadığını hisseder. Doğru davranış nedir?","hi":"नींद लाने वाली दवा लेने के बाद एक गार्ड खुद को ड्यूटी के लिए अनुपयुक्त महसूस करता है। सही कार्रवाई क्या है?","ar":"يشعر حارسٌ بعدم أهليته للعمل بعد تناوله دواءً يسبّب النعاس. ما التصرف الصحيح؟"},"o":[{"en":"Work the full shift and just try to stay awake","es":"Trabajar todo el turno e intentar mantenerse despierto","ru":"Отработать всю смену и просто стараться не заснуть","tr":"Tüm vardiyayı çalışmak ve sadece uyanık kalmaya çalışmak","hi":"पूरी पाली काम करना और बस जागते रहने की कोशिश करना","ar":"العمل طوال النوبة ومحاولة البقاء مستيقظًا فقط"},{"en":"Notify a supervisor that they are unfit for duty and follow policy","es":"Notificar a un supervisor que no está apto para el servicio y seguir la política","ru":"Уведомить руководителя о непригодности к службе и следовать политике","tr":"Görev için uygun olmadığını bir amire bildirmek ve politikaya uymak","hi":"पर्यवेक्षक को सूचित करना कि वे ड्यूटी के लिए अनुपयुक्त हैं और नीति का पालन करना","ar":"إخطار المشرف بأنه غير مؤهّل للعمل واتّباع السياسة"},{"en":"Drink several coffees and hope the drowsiness passes","es":"Tomar varios cafés y esperar que pase la somnolencia","ru":"Выпить несколько кофе и надеяться, что сонливость пройдёт","tr":"Birkaç kahve içip uyuşukluğun geçmesini ummak","hi":"कई कॉफी पीना और उम्मीद करना कि नींद उतर जाएगी","ar":"شرب عدة أكواب قهوة والأمل في زوال النعاس"},{"en":"Say nothing so the guard does not lose the shift's pay","es":"No decir nada para que el guardia no pierda el pago del turno","ru":"Ничего не говорить, чтобы не потерять оплату за смену","tr":"Vardiya ücretini kaybetmemek için bir şey söylememek","hi":"कुछ न कहना ताकि गार्ड की पाली का वेतन न कटे","ar":"عدم قول شيء كي لا يخسر الحارس أجر النوبة"}],"e":{"en":"A guard must report to duty fit for work; being impaired—by alcohol, drugs, or medication—on duty is prohibited and dangerous. The guard should notify a supervisor and follow the agency's fitness-for-duty policy.","es":"Un guardia debe presentarse al servicio en condiciones de trabajar; estar incapacitado —por alcohol, drogas o medicamentos— en servicio está prohibido y es peligroso. El guardia debe notificar a un supervisor y seguir la política de aptitud para el servicio de la agencia.","ru":"Охранник должен заступать на службу пригодным к работе; находиться на дежурстве в состоянии опьянения — от алкоголя, наркотиков или лекарств — запрещено и опасно. Охранник должен уведомить руководителя и следовать политике агентства о пригодности к службе.","tr":"Bir görevli işe uygun bir hâlde görev başına gelmelidir; alkol, uyuşturucu veya ilaç nedeniyle görev başında bozulmuş olmak yasaktır ve tehlikelidir. Görevli bir amire haber vermeli ve ajansın göreve uygunluk politikasına uymalıdır.","hi":"गार्ड को काम के लिए उपयुक्त होकर ड्यूटी पर आना चाहिए; शराब, नशे या दवा से ड्यूटी पर अक्षम होना निषिद्ध और खतरनाक है। गार्ड को पर्यवेक्षक को सूचित करना चाहिए और एजेंसी की ड्यूटी-योग्यता नीति का पालन करना चाहिए।","ar":"يجب أن يحضر الحارس إلى العمل مؤهَّلًا للأداء؛ فالتواجد أثناء الدوام في حالة ضعف — بسبب الكحول أو المخدرات أو الدواء — أمر محظور وخطير. على الحارس إخطار المشرف واتّباع سياسة الأهلية للعمل لدى الشركة."}},{"cat":"conduct","a":2,"q":{"en":"What is the typical drug and alcohol standard for security guards on duty in most agencies?","es":"¿Cuál es el estándar típico sobre drogas y alcohol para los guardias de seguridad en servicio en la mayoría de las agencias?","ru":"Каков типичный стандарт по наркотикам и алкоголю для охранников на дежурстве в большинстве агентств?","tr":"Çoğu ajansta görevdeki güvenlik görevlileri için tipik uyuşturucu ve alkol standardı nedir?","hi":"अधिकांश एजेंसियों में ड्यूटी पर सुरक्षा गार्ड के लिए नशा और शराब का सामान्य मानक क्या है?","ar":"ما المعيار المعتاد للمخدرات والكحول لحراس الأمن أثناء الدوام في معظم الشركات؟"},"o":[{"en":"A small amount of alcohol is acceptable if the guard feels fine","es":"Una pequeña cantidad de alcohol es aceptable si el guardia se siente bien","ru":"Небольшое количество алкоголя допустимо, если охранник чувствует себя нормально","tr":"Görevli iyi hissediyorsa az miktarda alkol kabul edilebilir","hi":"थोड़ी शराब स्वीकार्य है अगर गार्ड ठीक महसूस करे","ar":"كمية صغيرة من الكحول مقبولة إذا شعر الحارس أنه بخير"},{"en":"Alcohol is banned but recreational drugs are allowed off-site","es":"El alcohol está prohibido pero las drogas recreativas se permiten fuera del sitio","ru":"Алкоголь запрещён, но рекреационные наркотики разрешены вне объекта","tr":"Alkol yasak ama keyif verici uyuşturucular saha dışında serbesttir","hi":"शराब प्रतिबंधित है पर मनोरंजक नशे साइट के बाहर अनुमत हैं","ar":"الكحول ممنوع لكن المخدرات الترفيهية مسموحة خارج الموقع"},{"en":"Zero tolerance: guards must never be under the influence while on duty","es":"Tolerancia cero: los guardias nunca deben estar bajo la influencia mientras están en servicio","ru":"Нулевая терпимость: охранники никогда не должны быть в состоянии опьянения на дежурстве","tr":"Sıfır tolerans: görevliler görev başındayken asla etkisi altında olmamalıdır","hi":"शून्य सहनशीलता: गार्ड को ड्यूटी पर कभी नशे की हालत में नहीं होना चाहिए","ar":"عدم التسامح إطلاقًا: يجب ألّا يكون الحارس تحت التأثير أثناء الدوام"},{"en":"Guards may drink during breaks as long as they do not drive","es":"Los guardias pueden beber en los descansos siempre que no conduzcan","ru":"Охранники могут пить в перерывах, если не садятся за руль","tr":"Görevliler araç kullanmadıkları sürece molalarda içki içebilir","hi":"गार्ड ब्रेक के दौरान पी सकते हैं जब तक वे गाड़ी न चलाएँ","ar":"يجوز للحراس الشرب أثناء الاستراحات ما داموا لا يقودون"}],"e":{"en":"Most security agencies enforce a zero-tolerance policy: a guard must never be under the influence of alcohol or drugs while on duty because impairment endangers safety and judgment. Specific testing and policy details vary by employer.","es":"La mayoría de las agencias de seguridad aplican una política de tolerancia cero: un guardia nunca debe estar bajo la influencia de alcohol o drogas en servicio porque la incapacidad pone en peligro la seguridad y el juicio. Los detalles específicos de pruebas y política varían según el empleador.","ru":"Большинство охранных агентств придерживаются политики нулевой терпимости: охранник никогда не должен быть под воздействием алкоголя или наркотиков на дежурстве, так как опьянение ставит под угрозу безопасность и рассудительность. Конкретные детали тестирования и политики зависят от работодателя.","tr":"Çoğu güvenlik şirketi sıfır tolerans politikası uygular: bir görevli görev başındayken asla alkol veya uyuşturucu etkisi altında olmamalıdır; çünkü bozulma güvenliği ve muhakemeyi tehlikeye atar. Belirli test ve politika ayrıntıları işverene göre değişir.","hi":"अधिकांश सुरक्षा एजेंसियाँ शून्य-सहनशीलता नीति लागू करती हैं: गार्ड को ड्यूटी पर कभी शराब या नशे के प्रभाव में नहीं होना चाहिए क्योंकि अक्षमता सुरक्षा और निर्णय को खतरे में डालती है। विशिष्ट परीक्षण और नीति विवरण नियोक्ता के अनुसार भिन्न होते हैं।","ar":"تطبّق معظم شركات الأمن سياسة عدم التسامح إطلاقًا: يجب ألّا يكون الحارس تحت تأثير الكحول أو المخدرات أثناء الدوام لأن الضعف يعرّض السلامة والتقدير للخطر. تختلف تفاصيل الفحص والسياسة بحسب صاحب العمل."}},{"cat":"conduct","a":0,"q":{"en":"Which of the following best describes workplace sexual harassment?","es":"¿Cuál de las siguientes describe mejor el acoso sexual en el lugar de trabajo?","ru":"Что из перечисленного лучше всего описывает сексуальные домогательства на рабочем месте?","tr":"Aşağıdakilerden hangisi işyerinde cinsel tacizi en iyi tanımlar?","hi":"निम्न में से कौन कार्यस्थल पर यौन उत्पीड़न का सबसे अच्छा वर्णन करता है?","ar":"أيّ ممّا يلي يصف التحرّش الجنسي في مكان العمل على أفضل وجه؟"},"o":[{"en":"Unwelcome conduct or comments of a sexual nature that create a hostile environment","es":"Conducta o comentarios no deseados de naturaleza sexual que crean un ambiente hostil","ru":"Нежелательное поведение или высказывания сексуального характера, создающие враждебную обстановку","tr":"Düşmanca bir ortam yaratan, istenmeyen cinsel nitelikte davranış veya sözler","hi":"अवांछित यौन प्रकृति का आचरण या टिप्पणियाँ जो शत्रुतापूर्ण माहौल बनाती हैं","ar":"سلوك أو تعليقات غير مرغوب فيها ذات طابع جنسي تخلق بيئة عدائية"},{"en":"Any friendly conversation between coworkers","es":"Cualquier conversación amistosa entre compañeros de trabajo","ru":"Любой дружеский разговор между коллегами","tr":"Çalışanlar arasındaki her dostça sohbet","hi":"सहकर्मियों के बीच कोई भी मित्रवत बातचीत","ar":"أي محادثة ودّية بين زملاء العمل"},{"en":"Only physical contact, never words or gestures","es":"Solo el contacto físico, nunca palabras o gestos","ru":"Только физический контакт, никогда слова или жесты","tr":"Yalnızca fiziksel temas, asla sözler veya jestler","hi":"केवल शारीरिक संपर्क, कभी शब्द या इशारे नहीं","ar":"الاتصال الجسدي فقط، وليس الكلمات أو الإيماءات أبدًا"},{"en":"A supervisor giving a work-related instruction","es":"Un supervisor dando una instrucción relacionada con el trabajo","ru":"Руководитель, дающий рабочее указание","tr":"Bir amirin işle ilgili talimat vermesi","hi":"पर्यवेक्षक द्वारा काम से संबंधित निर्देश देना","ar":"مشرف يعطي تعليمًا متعلقًا بالعمل"}],"e":{"en":"Sexual harassment is unwelcome conduct or comments of a sexual nature—words, gestures, or physical acts—that create a hostile or offensive work environment. Guards must never engage in it and must maintain professional boundaries.","es":"El acoso sexual es una conducta o comentarios no deseados de naturaleza sexual —palabras, gestos o actos físicos— que crean un ambiente laboral hostil u ofensivo. Los guardias nunca deben incurrir en ello y deben mantener límites profesionales.","ru":"Сексуальные домогательства — это нежелательное поведение или высказывания сексуального характера — слова, жесты или физические действия — создающие враждебную или оскорбительную рабочую обстановку. Охранники никогда не должны этого допускать и обязаны соблюдать профессиональные границы.","tr":"Cinsel taciz, düşmanca veya rahatsız edici bir çalışma ortamı yaratan, istenmeyen cinsel nitelikte davranış veya sözlerdir; kelimeler, jestler ya da fiziksel eylemler. Görevliler buna asla başvurmamalı ve profesyonel sınırları korumalıdır.","hi":"यौन उत्पीड़न अवांछित यौन प्रकृति का आचरण या टिप्पणियाँ हैं—शब्द, इशारे या शारीरिक कृत्य—जो शत्रुतापूर्ण या आपत्तिजनक कार्य-माहौल बनाते हैं। गार्ड को इसमें कभी शामिल नहीं होना चाहिए और पेशेवर सीमाएँ बनाए रखनी चाहिए।","ar":"التحرّش الجنسي هو سلوك أو تعليقات غير مرغوب فيها ذات طابع جنسي — كلمات أو إيماءات أو أفعال جسدية — تخلق بيئة عمل عدائية أو مسيئة. يجب ألّا يمارسه الحراس مطلقًا وأن يحافظوا على الحدود المهنية."}},{"cat":"conduct","a":3,"q":{"en":"A guard witnesses a coworker repeatedly making unwanted sexual comments to another employee. What should the guard do?","es":"Un guardia presencia que un compañero hace repetidamente comentarios sexuales no deseados a otro empleado. ¿Qué debe hacer el guardia?","ru":"Охранник видит, как коллега неоднократно отпускает нежелательные сексуальные комментарии в адрес другого сотрудника. Что должен сделать охранник?","tr":"Bir görevli, bir iş arkadaşının başka bir çalışana defalarca istenmeyen cinsel yorumlar yaptığına tanık olur. Görevli ne yapmalıdır?","hi":"एक गार्ड देखता है कि एक सहकर्मी बार-बार दूसरे कर्मचारी पर अवांछित यौन टिप्पणियाँ कर रहा है। गार्ड को क्या करना चाहिए?","ar":"يشهد حارسٌ زميلًا يوجّه مرارًا تعليقات جنسية غير مرغوب فيها إلى موظف آخر. ماذا يجب أن يفعل الحارس؟"},"o":[{"en":"Ignore it because it is not the guard's business","es":"Ignorarlo porque no es asunto del guardia","ru":"Проигнорировать, ведь это не касается охранника","tr":"Görevliyi ilgilendirmediği için görmezden gelmek","hi":"अनदेखा करना क्योंकि यह गार्ड का मामला नहीं","ar":"تجاهله لأنه ليس من شأن الحارس"},{"en":"Join in so the coworker does not feel singled out","es":"Unirse para que el compañero no se sienta señalado","ru":"Присоединиться, чтобы коллега не чувствовал себя выделенным","tr":"İş arkadaşı dışlanmış hissetmesin diye katılmak","hi":"शामिल हो जाना ताकि सहकर्मी अलग-थलग महसूस न करे","ar":"المشاركة كي لا يشعر الزميل أنه مستهدف"},{"en":"Confront the coworker physically to make them stop","es":"Enfrentar físicamente al compañero para que se detenga","ru":"Физически противостоять коллеге, чтобы тот прекратил","tr":"Durması için iş arkadaşıyla fiziksel olarak yüzleşmek","hi":"सहकर्मी को रोकने के लिए शारीरिक रूप से भिड़ जाना","ar":"مواجهة الزميل جسديًا لإجباره على التوقف"},{"en":"Report it through the proper channels per company harassment procedures","es":"Reportarlo por los canales adecuados según los procedimientos de acoso de la empresa","ru":"Сообщить об этом по надлежащим каналам согласно процедурам компании по домогательствам","tr":"Şirketin taciz prosedürlerine göre uygun kanallardan bildirmek","hi":"कंपनी की उत्पीड़न प्रक्रियाओं के अनुसार उचित माध्यमों से सूचना देना","ar":"الإبلاغ عنه عبر القنوات المناسبة وفق إجراءات الشركة بشأن التحرّش"}],"e":{"en":"Sexual harassment should be reported through the proper channels defined by company policy, such as a supervisor or HR. Guards should not ignore it, join in, or respond with physical confrontation; reporting procedures vary by employer.","es":"El acoso sexual debe reportarse por los canales adecuados definidos por la política de la empresa, como un supervisor o RR. HH. Los guardias no deben ignorarlo, participar ni responder con confrontación física; los procedimientos de reporte varían según el empleador.","ru":"О сексуальных домогательствах следует сообщать по надлежащим каналам, определённым политикой компании, например руководителю или в отдел кадров. Охранники не должны игнорировать это, присоединяться или отвечать физическим противостоянием; процедуры отчётности зависят от работодателя.","tr":"Cinsel taciz, şirket politikasının belirlediği uygun kanallardan (amir veya İK gibi) bildirilmelidir. Görevliler bunu görmezden gelmemeli, katılmamalı veya fiziksel yüzleşmeyle karşılık vermemelidir; raporlama prosedürleri işverene göre değişir.","hi":"यौन उत्पीड़न की सूचना कंपनी नीति द्वारा तय उचित माध्यमों से देनी चाहिए, जैसे पर्यवेक्षक या मानव संसाधन। गार्ड को इसे अनदेखा नहीं करना, शामिल नहीं होना या शारीरिक टकराव से जवाब नहीं देना चाहिए; रिपोर्टिंग प्रक्रियाएँ नियोक्ता के अनुसार भिन्न होती हैं।","ar":"ينبغي الإبلاغ عن التحرّش الجنسي عبر القنوات المناسبة التي تحدّدها سياسة الشركة، مثل المشرف أو الموارد البشرية. يجب ألّا يتجاهله الحراس أو يشاركوا فيه أو يردّوا بمواجهة جسدية؛ وتختلف إجراءات الإبلاغ بحسب صاحب العمل."}},{"cat":"conduct","a":1,"q":{"en":"A guard sees an armed robbery in progress at the site. What should the guard do first?","es":"Un guardia ve un robo a mano armada en curso en el sitio. ¿Qué debe hacer primero el guardia?","ru":"Охранник видит вооружённое ограбление, происходящее на объекте. Что охранник должен сделать в первую очередь?","tr":"Bir görevli, sahada silahlı bir soygunun gerçekleştiğini görür. Görevli önce ne yapmalıdır?","hi":"एक गार्ड साइट पर सशस्त्र डकैती होते देखता है। गार्ड को पहले क्या करना चाहिए?","ar":"يرى حارسٌ عملية سطو مسلّح جارية في الموقع. ماذا يجب أن يفعل الحارس أولًا؟"},"o":[{"en":"Physically tackle the armed robber to stop the crime","es":"Placar físicamente al ladrón armado para detener el delito","ru":"Физически повалить вооружённого грабителя, чтобы остановить преступление","tr":"Suçu durdurmak için silahlı soyguncuya fiziksel olarak müdahale etmek","hi":"अपराध रोकने के लिए सशस्त्र डकैत को शारीरिक रूप से पकड़ना","ar":"الانقضاض جسديًا على اللص المسلّح لإيقاف الجريمة"},{"en":"Call 911 and observe from safety, giving police accurate information","es":"Llamar al 911 y observar desde un lugar seguro, dando información precisa a la policía","ru":"Позвонить 911 и наблюдать из безопасного места, сообщая полиции точную информацию","tr":"911'i aramak ve güvenli bir yerden gözlemleyerek polise doğru bilgi vermek","hi":"911 पर कॉल करना और सुरक्षित स्थान से देखना, पुलिस को सटीक जानकारी देना","ar":"الاتصال بالطوارئ (911) والمراقبة من مكان آمن مع تزويد الشرطة بمعلومات دقيقة"},{"en":"Chase the suspect off the property alone","es":"Perseguir al sospechoso fuera de la propiedad solo","ru":"В одиночку преследовать подозреваемого за пределами территории","tr":"Şüpheliyi tek başına mülkün dışına kovalamak","hi":"संदिग्ध का अकेले संपत्ति से बाहर पीछा करना","ar":"مطاردة المشتبه به خارج الممتلكات بمفرده"},{"en":"Wait until the shift ends to write a report about it","es":"Esperar hasta que termine el turno para escribir un informe al respecto","ru":"Подождать окончания смены, чтобы написать об этом отчёт","tr":"Bununla ilgili rapor yazmak için vardiyanın bitmesini beklemek","hi":"इसके बारे में रिपोर्ट लिखने के लिए पाली समाप्त होने की प्रतीक्षा करना","ar":"الانتظار حتى انتهاء النوبة لكتابة تقرير عن الأمر"}],"e":{"en":"A crime in progress involving a weapon is far beyond a guard's authority and is a job for the police, so the guard should call 911 immediately and observe safely to give accurate details. An unarmed guard should never try to physically confront an armed robber.","es":"Un delito en curso con un arma está muy por encima de la autoridad de un guardia y es tarea de la policía, así que el guardia debe llamar al 911 de inmediato y observar con seguridad para dar detalles precisos. Un guardia desarmado nunca debe intentar enfrentar físicamente a un ladrón armado.","ru":"Совершаемое преступление с применением оружия намного превышает полномочия охранника и является делом полиции, поэтому охранник должен немедленно позвонить 911 и безопасно наблюдать, чтобы сообщить точные детали. Невооружённый охранник никогда не должен пытаться физически противостоять вооружённому грабителю.","tr":"Silahlı, devam eden bir suç görevlinin yetkisinin çok ötesindedir ve polisin işidir; bu yüzden görevli hemen 911'i aramalı ve doğru ayrıntılar verebilmek için güvenli bir şekilde gözlemlemelidir. Silahsız bir görevli, silahlı bir soyguncuyla asla fiziksel olarak yüzleşmeye çalışmamalıdır.","hi":"हथियार वाला जारी अपराध गार्ड के अधिकार से कहीं ऊपर है और यह पुलिस का काम है, इसलिए गार्ड को तुरंत 911 पर कॉल करना चाहिए और सटीक विवरण देने के लिए सुरक्षित रूप से देखना चाहिए। निहत्थे गार्ड को कभी सशस्त्र डकैत से शारीरिक रूप से भिड़ने का प्रयास नहीं करना चाहिए।","ar":"الجريمة الجارية التي يُستخدم فيها سلاح تفوق صلاحية الحارس بكثير وهي من عمل الشرطة، لذا على الحارس الاتصال بالطوارئ (911) فورًا والمراقبة بأمان لتقديم تفاصيل دقيقة. يجب ألّا يحاول الحارس غير المسلّح مطلقًا مواجهة لصّ مسلّح جسديًا."}}]}